PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE _migrations (
      version INTEGER PRIMARY KEY,
      name TEXT NOT NULL,
      applied_at TEXT NOT NULL,
      checksum TEXT NOT NULL
    );
CREATE TABLE channels (
    id TEXT PRIMARY KEY,
    name TEXT NOT NULL UNIQUE,
    description TEXT,
    type TEXT NOT NULL DEFAULT 'public' CHECK(type IN ('public', 'dm')),
    createdBy TEXT,
    participants TEXT DEFAULT '[]',
    createdAt TEXT NOT NULL, created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id),
    FOREIGN KEY (createdBy) REFERENCES agents(id) ON DELETE SET NULL
);
CREATE TABLE agent_log (
    id TEXT PRIMARY KEY,
    eventType TEXT NOT NULL,
    agentId TEXT,
    taskId TEXT,
    oldValue TEXT,
    newValue TEXT,
    metadata TEXT,
    createdAt TEXT NOT NULL
);
CREATE TABLE channel_messages (
    id TEXT PRIMARY KEY,
    channelId TEXT NOT NULL,
    agentId TEXT,
    content TEXT NOT NULL,
    replyToId TEXT,
    mentions TEXT DEFAULT '[]',
    createdAt TEXT NOT NULL, created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id),
    FOREIGN KEY (channelId) REFERENCES channels(id) ON DELETE CASCADE,
    FOREIGN KEY (agentId) REFERENCES agents(id) ON DELETE CASCADE,
    FOREIGN KEY (replyToId) REFERENCES channel_messages(id) ON DELETE SET NULL
);
CREATE TABLE channel_read_state (
    agentId TEXT NOT NULL,
    channelId TEXT NOT NULL,
    lastReadAt TEXT NOT NULL,
    processing_since TEXT,
    PRIMARY KEY (agentId, channelId),
    FOREIGN KEY (agentId) REFERENCES agents(id) ON DELETE CASCADE,
    FOREIGN KEY (channelId) REFERENCES channels(id) ON DELETE CASCADE
);
CREATE TABLE services (
    id TEXT PRIMARY KEY,
    agentId TEXT NOT NULL,
    name TEXT NOT NULL,
    port INTEGER NOT NULL DEFAULT 3000,
    description TEXT,
    url TEXT,
    healthCheckPath TEXT DEFAULT '/health',
    status TEXT NOT NULL DEFAULT 'starting' CHECK(status IN ('starting', 'healthy', 'unhealthy', 'stopped')),
    script TEXT NOT NULL DEFAULT '',
    cwd TEXT,
    interpreter TEXT,
    args TEXT,
    env TEXT,
    metadata TEXT DEFAULT '{}',
    createdAt TEXT NOT NULL,
    lastUpdatedAt TEXT NOT NULL, created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id),
    FOREIGN KEY (agentId) REFERENCES agents(id) ON DELETE CASCADE,
    UNIQUE(agentId, name)
);
CREATE TABLE session_logs (
    id TEXT PRIMARY KEY,
    taskId TEXT,
    sessionId TEXT NOT NULL,
    iteration INTEGER NOT NULL,
    cli TEXT NOT NULL DEFAULT 'claude',
    content TEXT NOT NULL,
    lineNumber INTEGER NOT NULL,
    createdAt TEXT NOT NULL
);
CREATE TABLE inbox_messages (
    id TEXT PRIMARY KEY,
    agentId TEXT NOT NULL,
    content TEXT NOT NULL,
    source TEXT NOT NULL DEFAULT 'slack',
    status TEXT NOT NULL DEFAULT 'unread' CHECK(status IN ('unread', 'processing', 'read', 'responded', 'delegated')),
    slackChannelId TEXT,
    slackThreadTs TEXT,
    slackUserId TEXT,
    matchedText TEXT,
    delegatedToTaskId TEXT,
    responseText TEXT,
    createdAt TEXT NOT NULL,
    lastUpdatedAt TEXT NOT NULL, created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id),
    FOREIGN KEY (agentId) REFERENCES agents(id) ON DELETE CASCADE,
    FOREIGN KEY (delegatedToTaskId) REFERENCES agent_tasks(id) ON DELETE SET NULL
);
CREATE TABLE swarm_config (
    id TEXT PRIMARY KEY,
    scope TEXT NOT NULL CHECK(scope IN ('global', 'agent', 'repo')),
    scopeId TEXT,
    key TEXT NOT NULL,
    value TEXT NOT NULL,
    isSecret INTEGER NOT NULL DEFAULT 0,
    envPath TEXT,
    description TEXT,
    createdAt TEXT NOT NULL,
    lastUpdatedAt TEXT NOT NULL, encrypted INTEGER NOT NULL DEFAULT 0, created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id),
    UNIQUE(scope, scopeId, key)
);
CREATE TABLE swarm_repos (
    id TEXT PRIMARY KEY,
    url TEXT NOT NULL UNIQUE,
    name TEXT NOT NULL UNIQUE,
    clonePath TEXT NOT NULL UNIQUE,
    defaultBranch TEXT NOT NULL DEFAULT 'main',
    autoClone INTEGER NOT NULL DEFAULT 1,
    createdAt TEXT NOT NULL,
    lastUpdatedAt TEXT NOT NULL
, guidelines TEXT DEFAULT NULL, created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id));
CREATE TABLE agent_memory (
    id TEXT PRIMARY KEY,
    agentId TEXT,
    scope TEXT NOT NULL CHECK(scope IN ('agent', 'swarm')),
    name TEXT NOT NULL,
    content TEXT NOT NULL,
    summary TEXT,
    embedding BLOB,
    source TEXT NOT NULL CHECK(source IN ('manual', 'file_index', 'session_summary', 'task_completion')),
    sourceTaskId TEXT,
    sourcePath TEXT,
    chunkIndex INTEGER DEFAULT 0,
    totalChunks INTEGER DEFAULT 1,
    tags TEXT DEFAULT '[]',
    createdAt TEXT NOT NULL,
    accessedAt TEXT NOT NULL
, expiresAt TEXT, accessCount INTEGER NOT NULL DEFAULT 0, embeddingModel TEXT, alpha REAL NOT NULL DEFAULT 1.0, beta  REAL NOT NULL DEFAULT 1.0, created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id));
CREATE TABLE active_sessions (
    id TEXT PRIMARY KEY,
    agentId TEXT NOT NULL,
    taskId TEXT UNIQUE,
    triggerType TEXT NOT NULL,
    inboxMessageId TEXT,
    taskDescription TEXT,
    startedAt TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%fZ', 'now')),
    lastHeartbeatAt TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%fZ', 'now')), runnerSessionId TEXT, providerSessionId TEXT,
    FOREIGN KEY (agentId) REFERENCES agents(id) ON DELETE CASCADE
);
CREATE TABLE agentmail_inbox_mappings (
    id TEXT PRIMARY KEY,
    inboxId TEXT NOT NULL UNIQUE,
    agentId TEXT NOT NULL,
    inboxEmail TEXT,
    createdAt TEXT NOT NULL, created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id),
    FOREIGN KEY (agentId) REFERENCES agents(id)
);
CREATE TABLE context_versions (
    id TEXT PRIMARY KEY,
    agentId TEXT NOT NULL,
    field TEXT NOT NULL,
    content TEXT NOT NULL,
    version INTEGER NOT NULL,
    changeSource TEXT NOT NULL,
    changedByAgentId TEXT,
    changeReason TEXT,
    contentHash TEXT NOT NULL,
    previousVersionId TEXT,
    createdAt TEXT NOT NULL,
    FOREIGN KEY (agentId) REFERENCES agents(id) ON DELETE CASCADE,
    FOREIGN KEY (changedByAgentId) REFERENCES agents(id) ON DELETE SET NULL,
    FOREIGN KEY (previousVersionId) REFERENCES context_versions(id) ON DELETE SET NULL
);
CREATE TABLE scheduled_tasks (
    id TEXT PRIMARY KEY,
    name TEXT NOT NULL UNIQUE,
    description TEXT,
    cronExpression TEXT,
    intervalMs INTEGER,
    taskTemplate TEXT NOT NULL,
    taskType TEXT,
    tags TEXT DEFAULT '[]',
    priority INTEGER DEFAULT 50,
    targetAgentId TEXT,
    enabled INTEGER DEFAULT 1,
    lastRunAt TEXT,
    nextRunAt TEXT,
    createdByAgentId TEXT,
    timezone TEXT DEFAULT 'UTC',
    consecutiveErrors INTEGER DEFAULT 0,
    lastErrorAt TEXT,
    lastErrorMessage TEXT,
    model TEXT,
    scheduleType TEXT NOT NULL DEFAULT 'recurring' CHECK(scheduleType IN ('recurring', 'one_time')),
    createdAt TEXT NOT NULL,
    lastUpdatedAt TEXT NOT NULL, created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id), modelTier TEXT,
    CHECK (
        (scheduleType = 'recurring' AND (cronExpression IS NOT NULL OR intervalMs IS NOT NULL))
        OR
        (scheduleType = 'one_time')
    )
);
CREATE TABLE workflows (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL UNIQUE,
  description TEXT,
  enabled INTEGER NOT NULL DEFAULT 1,
  definition TEXT NOT NULL,
  triggers TEXT NOT NULL DEFAULT '[]',
  cooldown TEXT,
  input TEXT,
  createdByAgentId TEXT,
  createdAt TEXT NOT NULL DEFAULT (datetime('now')),
  lastUpdatedAt TEXT NOT NULL DEFAULT (datetime('now'))
, triggerSchema TEXT, dir TEXT, vcs_repo TEXT, created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id));
CREATE TABLE workflow_versions (
  id TEXT PRIMARY KEY,
  workflowId TEXT NOT NULL REFERENCES workflows(id) ON DELETE CASCADE,
  version INTEGER NOT NULL,
  snapshot TEXT NOT NULL,
  changedByAgentId TEXT,
  createdAt TEXT NOT NULL DEFAULT (datetime('now')), created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id),
  UNIQUE(workflowId, version)
);
CREATE TABLE oauth_apps (
    id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
    provider TEXT NOT NULL UNIQUE,
    clientId TEXT NOT NULL,
    clientSecret TEXT NOT NULL,
    authorizeUrl TEXT NOT NULL,
    tokenUrl TEXT NOT NULL,
    redirectUri TEXT NOT NULL,
    scopes TEXT NOT NULL,
    metadata TEXT DEFAULT '{}',
    createdAt TEXT NOT NULL DEFAULT (datetime('now')),
    updatedAt TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE oauth_tokens (
    id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
    provider TEXT NOT NULL UNIQUE,
    accessToken TEXT NOT NULL,
    refreshToken TEXT,
    expiresAt TEXT NOT NULL,
    scope TEXT,
    createdAt TEXT NOT NULL DEFAULT (datetime('now')),
    updatedAt TEXT NOT NULL DEFAULT (datetime('now')),
    FOREIGN KEY (provider) REFERENCES oauth_apps(provider)
);
CREATE TABLE tracker_sync (
    id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
    provider TEXT NOT NULL,
    entityType TEXT NOT NULL CHECK (entityType IN ('task', 'epic')),
    providerEntityType TEXT,
    swarmId TEXT NOT NULL,
    externalId TEXT NOT NULL,
    externalIdentifier TEXT,
    externalUrl TEXT,
    lastSyncedAt TEXT NOT NULL DEFAULT (datetime('now')),
    lastSyncOrigin TEXT CHECK (lastSyncOrigin IN ('swarm', 'external')),
    lastDeliveryId TEXT,
    syncDirection TEXT NOT NULL DEFAULT 'inbound' CHECK (syncDirection IN ('inbound', 'outbound', 'bidirectional')),
    createdAt TEXT NOT NULL DEFAULT (datetime('now')),
    UNIQUE(provider, entityType, swarmId),
    UNIQUE(provider, entityType, externalId)
);
CREATE TABLE tracker_agent_mapping (
    id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
    provider TEXT NOT NULL,
    agentId TEXT NOT NULL,
    externalUserId TEXT NOT NULL,
    agentName TEXT NOT NULL,
    createdAt TEXT NOT NULL DEFAULT (datetime('now')),
    UNIQUE(provider, agentId),
    UNIQUE(provider, externalUserId)
);
CREATE TABLE prompt_templates (
    id TEXT PRIMARY KEY,
    eventType TEXT NOT NULL,
    scope TEXT NOT NULL CHECK(scope IN ('global', 'agent', 'repo')),
    scopeId TEXT,
    state TEXT NOT NULL DEFAULT 'enabled' CHECK(state IN ('enabled', 'default_prompt_fallback', 'skip_event')),
    body TEXT NOT NULL,
    isDefault INTEGER NOT NULL DEFAULT 0,
    version INTEGER NOT NULL DEFAULT 1,
    createdBy TEXT,
    createdAt TEXT NOT NULL,
    updatedAt TEXT NOT NULL, created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id),
    UNIQUE(eventType, scope, scopeId)
);
CREATE TABLE prompt_template_history (
    id TEXT PRIMARY KEY,
    templateId TEXT NOT NULL,
    version INTEGER NOT NULL,
    body TEXT NOT NULL,
    state TEXT NOT NULL,
    changedBy TEXT,
    changedAt TEXT NOT NULL,
    changeReason TEXT
, created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id));
CREATE TABLE channel_activity_cursors (
  channelId TEXT PRIMARY KEY,
  lastSeenTs TEXT NOT NULL,
  updatedAt TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE skills (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  description TEXT NOT NULL,
  content TEXT NOT NULL DEFAULT '',

  -- Type & ownership
  type TEXT NOT NULL DEFAULT 'personal'
    CHECK (type IN ('remote', 'personal')),
  scope TEXT NOT NULL DEFAULT 'agent'
    CHECK (scope IN ('global', 'swarm', 'agent')),
  ownerAgentId TEXT,

  -- Remote skill metadata
  sourceUrl TEXT,
  sourceRepo TEXT,
  sourcePath TEXT,
  sourceBranch TEXT DEFAULT 'main',
  sourceHash TEXT,
  isComplex INTEGER DEFAULT 0,

  -- Parsed frontmatter cache (denormalized)
  allowedTools TEXT,
  model TEXT,
  effort TEXT,
  context TEXT,
  agent TEXT,
  disableModelInvocation INTEGER DEFAULT 0,
  userInvocable INTEGER DEFAULT 1,

  -- Metadata
  version INTEGER NOT NULL DEFAULT 1,
  isEnabled INTEGER NOT NULL DEFAULT 1,

  createdAt TEXT NOT NULL,
  lastUpdatedAt TEXT NOT NULL,
  lastFetchedAt TEXT, systemDefault INTEGER NOT NULL DEFAULT 0, created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id),

  FOREIGN KEY (ownerAgentId) REFERENCES agents(id)
);
CREATE TABLE agent_skills (
  id TEXT PRIMARY KEY,
  agentId TEXT NOT NULL,
  skillId TEXT NOT NULL,
  isActive INTEGER NOT NULL DEFAULT 1,
  installedAt TEXT NOT NULL,

  FOREIGN KEY (agentId) REFERENCES agents(id),
  FOREIGN KEY (skillId) REFERENCES skills(id) ON DELETE CASCADE,
  UNIQUE(agentId, skillId)
);
CREATE TABLE approval_requests (
  id TEXT PRIMARY KEY,                    -- UUID
  title TEXT NOT NULL,                    -- Display title for the request
  questions JSONB NOT NULL,              -- Array of Question objects

  -- Source context (one of these pairs will be set)
  workflowRunId TEXT,                    -- FK → workflow_runs.id (if from workflow)
  workflowRunStepId TEXT,               -- FK → workflow_run_steps.id (if from workflow)
  sourceTaskId TEXT,                     -- FK → agent_tasks.id (if from agent tool)

  -- Approver policy
  approvers JSONB NOT NULL,             -- { users: [...], roles: [...], policy: "any"|"all"|{min:N} }

  -- State
  status TEXT NOT NULL DEFAULT 'pending' CHECK (status IN ('pending', 'approved', 'rejected', 'timeout')),
  responses JSONB,                      -- Keyed by question ID
  resolvedBy TEXT,                      -- user ID of who responded
  resolvedAt DATETIME,                  -- when resolved

  -- Timeout
  timeoutSeconds INTEGER,              -- NULL = no timeout
  expiresAt DATETIME,                  -- computed: createdAt + timeoutSeconds

  -- Notifications sent
  notificationChannels JSONB,          -- [{ channel: "slack", target: "...", messageTs: "..." }]

  -- Metadata
  createdAt DATETIME DEFAULT CURRENT_TIMESTAMP,
  updatedAt DATETIME DEFAULT CURRENT_TIMESTAMP
, created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id));
CREATE TABLE events (
    id TEXT PRIMARY KEY,
    category TEXT NOT NULL,
    event TEXT NOT NULL,
    status TEXT NOT NULL DEFAULT 'ok',
    source TEXT NOT NULL,
    agentId TEXT,
    taskId TEXT,
    sessionId TEXT,
    parentEventId TEXT,
    numericValue REAL,
    durationMs INTEGER,
    data TEXT,
    createdAt TEXT NOT NULL
);
CREATE TABLE task_context_snapshots (
    id TEXT PRIMARY KEY,
    taskId TEXT NOT NULL REFERENCES agent_tasks(id) ON DELETE CASCADE,
    agentId TEXT NOT NULL REFERENCES agents(id) ON DELETE CASCADE,
    sessionId TEXT NOT NULL,

    -- Context window state
    contextUsedTokens INTEGER,
    contextTotalTokens INTEGER,
    contextPercent REAL,

    -- Event metadata
    eventType TEXT NOT NULL CHECK (eventType IN ('progress', 'compaction', 'completion')),

    -- Compaction-specific (NULL for non-compaction)
    compactTrigger TEXT CHECK (compactTrigger IN ('auto', 'manual') OR compactTrigger IS NULL),
    preCompactTokens INTEGER,

    -- Cumulative counters at this point
    cumulativeInputTokens INTEGER DEFAULT 0,
    cumulativeOutputTokens INTEGER DEFAULT 0,

    createdAt TEXT NOT NULL
, contextFormula TEXT);
CREATE TABLE mcp_servers (
    id TEXT PRIMARY KEY,
    name TEXT NOT NULL,
    description TEXT,
    scope TEXT NOT NULL CHECK(scope IN ('global', 'swarm', 'agent')),
    ownerAgentId TEXT REFERENCES agents(id),
    transport TEXT NOT NULL CHECK(transport IN ('stdio', 'http', 'sse')),
    -- Stdio fields
    command TEXT,
    args TEXT,          -- JSON array string
    -- HTTP/SSE fields
    url TEXT,
    headers TEXT,       -- JSON object string (non-secret headers only)
    -- Secret references (keys in swarm_config, NOT actual values)
    envConfigKeys TEXT,     -- JSON object: {"ENV_VAR": "config-key-name"}
    headerConfigKeys TEXT,  -- JSON object: {"Header-Name": "config-key-name"}
    -- Metadata
    isEnabled INTEGER NOT NULL DEFAULT 1,
    version INTEGER NOT NULL DEFAULT 1,
    createdAt TEXT NOT NULL,
    lastUpdatedAt TEXT NOT NULL
, authMethod TEXT NOT NULL DEFAULT 'static'
    CHECK(authMethod IN ('static','oauth','auto')), created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id));
CREATE TABLE agent_mcp_servers (
    id TEXT PRIMARY KEY,
    agentId TEXT NOT NULL REFERENCES agents(id),
    mcpServerId TEXT NOT NULL REFERENCES mcp_servers(id) ON DELETE CASCADE,
    isActive INTEGER NOT NULL DEFAULT 1,
    installedAt TEXT NOT NULL,
    UNIQUE(agentId, mcpServerId)
);
CREATE TABLE IF NOT EXISTS "workflow_runs" (
  id TEXT PRIMARY KEY,
  workflowId TEXT NOT NULL REFERENCES workflows(id) ON DELETE CASCADE,
  status TEXT NOT NULL DEFAULT 'running'
    CHECK (status IN ('running', 'waiting', 'completed', 'failed', 'skipped', 'cancelled')),
  triggerData TEXT,
  context TEXT,
  error TEXT,
  startedAt TEXT NOT NULL DEFAULT (datetime('now')),
  lastUpdatedAt TEXT NOT NULL DEFAULT (datetime('now')),
  finishedAt TEXT
, created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id));
CREATE TABLE IF NOT EXISTS "workflow_run_steps" (
  id TEXT PRIMARY KEY,
  runId TEXT NOT NULL REFERENCES workflow_runs(id) ON DELETE CASCADE,
  nodeId TEXT NOT NULL,
  nodeType TEXT NOT NULL,
  status TEXT NOT NULL DEFAULT 'running'
    CHECK (status IN ('pending', 'running', 'waiting', 'completed', 'failed', 'skipped', 'cancelled')),
  input TEXT,
  output TEXT,
  error TEXT,
  startedAt TEXT NOT NULL DEFAULT (datetime('now')),
  finishedAt TEXT,
  retryCount INTEGER NOT NULL DEFAULT 0,
  maxRetries INTEGER NOT NULL DEFAULT 0,
  nextRetryAt TEXT,
  idempotencyKey TEXT UNIQUE,
  diagnostics TEXT,
  nextPort TEXT
, created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id));
CREATE TABLE api_key_status (
  id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
  -- Which credential type: 'CLAUDE_CODE_OAUTH_TOKEN' or 'ANTHROPIC_API_KEY'
  keyType TEXT NOT NULL,
  -- Last 5 characters of the key (for identification without storing secrets)
  keySuffix TEXT NOT NULL,
  -- Position in the comma-separated credential pool (0-based)
  keyIndex INTEGER NOT NULL,
  -- Scope mirrors swarm_config (global, agent, repo)
  scope TEXT NOT NULL DEFAULT 'global',
  scopeId TEXT NOT NULL DEFAULT '',
  -- Current status
  status TEXT NOT NULL DEFAULT 'available' CHECK(status IN ('available', 'rate_limited')),
  -- When the rate limit expires (ISO timestamp from retry-after)
  rateLimitedUntil TEXT,
  -- Tracking timestamps
  lastUsedAt TEXT,
  lastRateLimitAt TEXT,
  -- Counters
  totalUsageCount INTEGER NOT NULL DEFAULT 0,
  rateLimitCount INTEGER NOT NULL DEFAULT 0,
  -- Metadata
  createdAt TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%fZ', 'now')),
  updatedAt TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%fZ', 'now')), name TEXT, provider TEXT NOT NULL DEFAULT 'claude',
  -- Unique constraint: one entry per key type + suffix + scope.
  -- Known limitation: two different keys sharing the same last 5 chars will collide,
  -- causing the ON CONFLICT upsert to overwrite keyIndex. In practice this is rare
  -- (1 in ~60M for random alphanumeric suffixes) and the impact is minor (wrong index
  -- logged, but rate-limit tracking still works since suffix is the real identifier).
  UNIQUE(keyType, keySuffix, scope, scopeId)
);
CREATE TABLE mcp_oauth_tokens (
    id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
    mcpServerId TEXT NOT NULL REFERENCES mcp_servers(id) ON DELETE CASCADE,
    userId TEXT REFERENCES users(id) ON DELETE CASCADE,

    -- Token material (AES-256-GCM, base64-encoded; never plaintext)
    accessToken TEXT NOT NULL,
    refreshToken TEXT,
    tokenType TEXT NOT NULL DEFAULT 'Bearer',
    expiresAt TEXT,
    scope TEXT,

    -- Authorization server context (discovered via PRMD/AS metadata at connect time)
    resourceUrl TEXT NOT NULL,
    authorizationServerIssuer TEXT NOT NULL,
    authorizeUrl TEXT NOT NULL,
    tokenUrl TEXT NOT NULL,
    revocationUrl TEXT,

    -- Client credentials (either RFC 7591 DCR result or user-supplied)
    dcrClientId TEXT,
    dcrClientSecret TEXT,
    clientSource TEXT NOT NULL CHECK(clientSource IN ('dcr','manual','preregistered')),

    -- Connection state surfaced to the UI
    status TEXT NOT NULL CHECK(status IN ('connected','expired','error','revoked')) DEFAULT 'connected',
    lastErrorMessage TEXT,
    lastRefreshedAt TEXT,

    -- Audit
    connectedByUserId TEXT REFERENCES users(id),
    createdAt TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%fZ', 'now')),
    updatedAt TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%fZ', 'now')), created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id),

    UNIQUE(mcpServerId, userId)
);
CREATE TABLE mcp_oauth_pending (
    state TEXT PRIMARY KEY,
    mcpServerId TEXT NOT NULL REFERENCES mcp_servers(id) ON DELETE CASCADE,
    userId TEXT REFERENCES users(id),
    codeVerifier TEXT NOT NULL,
    nonce TEXT,
    resourceUrl TEXT NOT NULL,
    authorizationServerIssuer TEXT NOT NULL,
    authorizeUrl TEXT NOT NULL,
    tokenUrl TEXT NOT NULL,
    revocationUrl TEXT,
    scopes TEXT,
    dcrClientId TEXT,
    dcrClientSecret TEXT,
    redirectUri TEXT NOT NULL,
    finalRedirect TEXT,
    createdAt TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%fZ', 'now'))
, created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id));
CREATE TABLE wait_states (
  id TEXT PRIMARY KEY,
  workflowRunId TEXT NOT NULL,
  workflowRunStepId TEXT NOT NULL,
  mode TEXT NOT NULL CHECK (mode IN ('time', 'event')),
  wakeUpAt DATETIME,                       -- mode='time'; NULL for event mode
  eventName TEXT,                          -- mode='event'
  eventFilter JSONB,                       -- mode='event'; flat key/val match or arrow-fn body
  expiresAt DATETIME,                      -- mode='event' optional timeout
  status TEXT NOT NULL DEFAULT 'pending'
    CHECK (status IN ('pending', 'fired', 'timeout')),
  firedPayload JSONB,                      -- payload that satisfied an event wait
  resolvedAt DATETIME,
  createdAt DATETIME DEFAULT CURRENT_TIMESTAMP,
  updatedAt DATETIME DEFAULT CURRENT_TIMESTAMP
, eventScope TEXT NOT NULL DEFAULT 'run'
    CHECK (eventScope IN ('run', 'global')));
CREATE TABLE memory_retrieval (
  id          TEXT PRIMARY KEY,
  taskId      TEXT,
  agentId     TEXT NOT NULL,
  sessionId   TEXT,
  memoryId    TEXT NOT NULL,
  similarity  REAL,
  retrievedAt TEXT NOT NULL,
  FOREIGN KEY (taskId) REFERENCES agent_tasks(id) ON DELETE CASCADE
);
CREATE TABLE memory_rating (
  id        TEXT PRIMARY KEY,
  memoryId  TEXT NOT NULL,
  taskId    TEXT,
  source    TEXT NOT NULL,
  signal    REAL NOT NULL,
  weight    REAL NOT NULL,
  reasoning TEXT,
  createdAt TEXT NOT NULL,
  FOREIGN KEY (taskId) REFERENCES agent_tasks(id) ON DELETE CASCADE
);
CREATE TABLE agent_memory_edge (
  from_id   TEXT NOT NULL,                                                -- memory id
  to_id     TEXT NOT NULL,                                                -- free-form external entity id (Q2 contract)
  type      TEXT NOT NULL CHECK (type = 'references-source'),             -- v1.5: ONE type only
  alpha     REAL NOT NULL DEFAULT 1.0,
  beta      REAL NOT NULL DEFAULT 1.0,
  createdAt TEXT NOT NULL,
  PRIMARY KEY (from_id, to_id, type),
  FOREIGN KEY (from_id) REFERENCES agent_memory(id) ON DELETE CASCADE
);
CREATE TABLE IF NOT EXISTS "agents" (
    id TEXT PRIMARY KEY,
    name TEXT NOT NULL,
    isLead INTEGER NOT NULL DEFAULT 0,
    status TEXT NOT NULL
      CHECK(status IN ('idle', 'busy', 'offline', 'waiting_for_credentials')),
    description TEXT,
    role TEXT,
    capabilities TEXT DEFAULT '[]',
    maxTasks INTEGER DEFAULT 1,
    emptyPollCount INTEGER DEFAULT 0,
    claudeMd TEXT,
    soulMd TEXT,
    identityMd TEXT,
    setupScript TEXT,
    toolsMd TEXT,
    lastActivityAt TEXT,
    createdAt TEXT NOT NULL,
    lastUpdatedAt TEXT NOT NULL,
    heartbeatMd TEXT DEFAULT NULL,
    provider TEXT,
    credentialMissing TEXT
, harness_provider TEXT NULL, cred_status TEXT, created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id));
CREATE TABLE IF NOT EXISTS "agent_tasks" (
  id TEXT PRIMARY KEY,
  agentId TEXT,
  creatorAgentId TEXT,
  task TEXT NOT NULL,
  status TEXT NOT NULL DEFAULT 'pending',
  source TEXT NOT NULL DEFAULT 'mcp',
  taskType TEXT,
  tags TEXT DEFAULT '[]',
  priority INTEGER DEFAULT 50,
  dependsOn TEXT DEFAULT '[]',
  offeredTo TEXT,
  offeredAt TEXT,
  acceptedAt TEXT,
  rejectionReason TEXT,
  slackChannelId TEXT,
  slackThreadTs TEXT,
  slackUserId TEXT,
  mentionMessageId TEXT,
  mentionChannelId TEXT,
  vcsProvider TEXT,
  vcsRepo TEXT,
  vcsEventType TEXT,
  vcsNumber INTEGER,
  vcsCommentId INTEGER,
  vcsAuthor TEXT,
  vcsUrl TEXT,
  parentTaskId TEXT,
  claudeSessionId TEXT,
  agentmailInboxId TEXT,
  agentmailMessageId TEXT,
  agentmailThreadId TEXT,
  model TEXT,
  scheduleId TEXT,
  workflowRunId TEXT REFERENCES workflow_runs(id),
  workflowRunStepId TEXT REFERENCES workflow_run_steps(id),
  createdAt TEXT NOT NULL,
  lastUpdatedAt TEXT NOT NULL,
  finishedAt TEXT,
  failureReason TEXT,
  output TEXT,
  progress TEXT,
  notifiedAt TEXT,
  dir TEXT,
  outputSchema TEXT,
  compactionCount INTEGER DEFAULT 0,
  peakContextPercent REAL,
  peakContextTokens INTEGER,
  contextWindowSize INTEGER,
  was_paused INTEGER NOT NULL DEFAULT 0,
  credentialKeySuffix TEXT,
  credentialKeyType TEXT,
  requestedByUserId TEXT REFERENCES users(id),
  vcsInstallationId INTEGER,
  vcsNodeId TEXT,
  slackReplySent INTEGER DEFAULT 0,
  swarmVersion TEXT,
  contextKey TEXT,
  provider TEXT,
  providerMeta TEXT
, followUpConfig TEXT, created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id), harnessVariant TEXT, harnessVariantMeta TEXT, modelTier TEXT, slackProgressMessageTs TEXT, slackTreeRootMessageTs TEXT);
CREATE TABLE inbox_item_state (
  id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
  userId TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  itemType TEXT NOT NULL,
  itemId TEXT NOT NULL,
  status TEXT NOT NULL DEFAULT 'open',
  snoozeUntil TEXT,
  dismissedAt TEXT,
  doneAt TEXT,
  createdAt TEXT NOT NULL DEFAULT (datetime('now')),
  lastUpdatedAt TEXT NOT NULL DEFAULT (datetime('now')), created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id),
  UNIQUE(userId, itemType, itemId)
);
CREATE TABLE task_templates (
  id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
  title TEXT NOT NULL,
  description TEXT NOT NULL,
  prompt TEXT NOT NULL,
  kind TEXT NOT NULL DEFAULT 'task' CHECK(kind IN ('task','workflow','schedule')),
  payload TEXT NOT NULL DEFAULT '{}',
  category TEXT,
  tags TEXT NOT NULL DEFAULT '[]',
  createdAt TEXT NOT NULL DEFAULT (datetime('now'))
, created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id));
CREATE TABLE page_versions (
  id                  TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
  pageId              TEXT NOT NULL REFERENCES pages(id) ON DELETE CASCADE,
  version             INTEGER NOT NULL,
  snapshot            TEXT NOT NULL,  -- JSON: PageSnapshot
  changedByAgentId    TEXT,
  createdAt           TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id),
  UNIQUE (pageId, version)
);
CREATE TABLE kv_entries (
  namespace   TEXT NOT NULL,
  key         TEXT NOT NULL,
  value       TEXT NOT NULL,
  value_type  TEXT NOT NULL DEFAULT 'json'
                CHECK (value_type IN ('json','string','integer')),
  expires_at  INTEGER,
  created_at  INTEGER NOT NULL DEFAULT (CAST(unixepoch('subsec') * 1000 AS INTEGER)),
  updated_at  INTEGER NOT NULL DEFAULT (CAST(unixepoch('subsec') * 1000 AS INTEGER)), created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id),
  PRIMARY KEY (namespace, key)
) WITHOUT ROWID;
CREATE TABLE IF NOT EXISTS "pricing" (
  provider TEXT NOT NULL,
  model TEXT NOT NULL,
  token_class TEXT NOT NULL,
  effective_from INTEGER NOT NULL,
  price_per_million_usd REAL NOT NULL,
  createdAt INTEGER NOT NULL,
  lastUpdatedAt INTEGER NOT NULL, created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id),
  PRIMARY KEY (provider, model, token_class, effective_from)
);
CREATE TABLE IF NOT EXISTS "session_costs" (
    id TEXT PRIMARY KEY,
    sessionId TEXT NOT NULL,
    taskId TEXT,
    agentId TEXT NOT NULL,
    totalCostUsd REAL NOT NULL,
    inputTokens INTEGER NOT NULL DEFAULT 0,
    outputTokens INTEGER NOT NULL DEFAULT 0,
    cacheReadTokens INTEGER NOT NULL DEFAULT 0,
    -- Migration 063: nullable. Codex SDK can't surface cache writes, so we
    -- store null instead of faking a 0 that mixes with real zeros.
    cacheWriteTokens INTEGER DEFAULT 0,
    durationMs INTEGER NOT NULL,
    -- Migration 063: nullable. Claude when `num_turns` is absent can't honestly
    -- report a turn count; null is preferred over a faked 1.
    numTurns INTEGER,
    model TEXT NOT NULL,
    isError INTEGER NOT NULL DEFAULT 0,
    costSource TEXT NOT NULL DEFAULT 'harness',
    reasoningOutputTokens INTEGER NOT NULL DEFAULT 0,
    thinkingTokens INTEGER NOT NULL DEFAULT 0,
    createdAt TEXT NOT NULL,
    FOREIGN KEY (agentId) REFERENCES agents(id) ON DELETE CASCADE,
    FOREIGN KEY (taskId) REFERENCES agent_tasks(id) ON DELETE SET NULL
);
CREATE TABLE scripts (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  scope TEXT NOT NULL CHECK(scope IN ('global', 'agent')),
  scopeId TEXT,
  source TEXT NOT NULL,
  description TEXT NOT NULL,
  intent TEXT NOT NULL,
  signatureJson TEXT NOT NULL,
  contentHash TEXT NOT NULL,
  version INTEGER NOT NULL DEFAULT 1,
  isScratch INTEGER NOT NULL DEFAULT 0,
  typeChecked INTEGER NOT NULL DEFAULT 0,
  fsMode TEXT NOT NULL DEFAULT 'none' CHECK(fsMode IN ('none', 'workspace-rw')),
  createdByAgentId TEXT,
  createdAt TEXT NOT NULL DEFAULT (datetime('now')),
  updatedAt TEXT NOT NULL DEFAULT (datetime('now'))
, argsJsonSchema TEXT, created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id));
CREATE TABLE script_versions (
  id TEXT PRIMARY KEY,
  scriptId TEXT NOT NULL REFERENCES scripts(id) ON DELETE CASCADE,
  version INTEGER NOT NULL,
  source TEXT NOT NULL,
  description TEXT NOT NULL,
  intent TEXT NOT NULL,
  signatureJson TEXT NOT NULL,
  contentHash TEXT NOT NULL,
  changedByAgentId TEXT,
  changedAt TEXT NOT NULL DEFAULT (datetime('now')),
  changeReason TEXT, created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id),
  UNIQUE(scriptId, version)
);
CREATE TABLE script_embeddings (
  scriptId TEXT PRIMARY KEY REFERENCES scripts(id) ON DELETE CASCADE,
  embedding BLOB NOT NULL,
  embeddingModel TEXT NOT NULL,
  embeddedText TEXT NOT NULL,
  embeddedAt TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE user_external_ids (
  kind TEXT NOT NULL,
  externalId TEXT NOT NULL,
  userId TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  createdAt TEXT NOT NULL DEFAULT (datetime('now')), created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id),
  PRIMARY KEY (kind, externalId)
);
CREATE TABLE user_tokens (
  id TEXT PRIMARY KEY,
  userId TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  label TEXT,
  tokenHash TEXT NOT NULL UNIQUE,
  tokenPreview TEXT NOT NULL,
  createdAt TEXT NOT NULL DEFAULT (datetime('now')),
  lastUsedAt TEXT,
  revokedAt TEXT
, created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id));
CREATE TABLE IF NOT EXISTS "users" (
  id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
  name TEXT NOT NULL,
  email TEXT,
  role TEXT,
  notes TEXT,
  emailAliases TEXT DEFAULT '[]',
  preferredChannel TEXT DEFAULT 'slack',
  timezone TEXT,
  metadata TEXT,
  dailyBudgetUsd REAL,
  status TEXT NOT NULL DEFAULT 'active'
    CHECK (status IN ('invited', 'active', 'suspended')),
  createdAt TEXT NOT NULL DEFAULT (datetime('now')),
  lastUpdatedAt TEXT NOT NULL DEFAULT (datetime('now'))
, created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id));
CREATE TABLE IF NOT EXISTS "user_identity_events" (
  id TEXT PRIMARY KEY,
  userId TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  eventType TEXT NOT NULL CHECK (eventType IN (
    'auto_merge',
    'manual_merge',
    'identity_added',
    'identity_removed',
    'email_added',
    'email_removed',
    'token_minted',
    'token_revoked',
    'budget_changed',
    'status_changed',
    'profile_changed'
  )),
  actor TEXT NOT NULL,
  beforeJson TEXT,
  afterJson TEXT,
  createdAt TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE seed_state (
  kind TEXT NOT NULL,
  key TEXT NOT NULL,
  seededHash TEXT NOT NULL,
  seededAt TEXT NOT NULL DEFAULT (datetime('now')),
  PRIMARY KEY (kind, key)
);
CREATE TABLE task_attachments (
  id           TEXT PRIMARY KEY,
  task_id      TEXT NOT NULL REFERENCES agent_tasks(id) ON DELETE CASCADE,
  agent_id     TEXT,                          -- agent that added it (nullable)
  name         TEXT NOT NULL,                 -- display name
  kind         TEXT NOT NULL CHECK (kind IN ('agent-fs','url','shared-fs','page')),
  url          TEXT,                          -- kind='url'
  path         TEXT,                          -- kind='agent-fs' or 'shared-fs'
  page_id      TEXT,                          -- kind='page'
  mime_type    TEXT,
  size_bytes   INTEGER,                       -- optional metadata only (no enforcement)
  sha256       TEXT,
  intent       TEXT,                          -- WHY this attachment exists
  description  TEXT,                          -- optional: what it is
  is_primary   INTEGER NOT NULL DEFAULT 0,
  -- ISO-8601 UTC (T separator, trailing Z) so rows satisfy the
  -- `z.iso.datetime()` shape on `TaskAttachmentSchema.createdAt`. Plain
  -- `datetime('now')` yields a space-separated, Z-less string that fails
  -- that validator. Matches the `session_costs` insert convention.
  created_at   TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%fZ', 'now'))
, agent_fs_org_id   TEXT, agent_fs_drive_id TEXT, created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id));
CREATE TABLE IF NOT EXISTS "budgets" (
  scope TEXT NOT NULL,
  scope_id TEXT NOT NULL,
  daily_budget_usd REAL NOT NULL,
  createdAt INTEGER NOT NULL,
  lastUpdatedAt INTEGER NOT NULL, created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id),
  PRIMARY KEY (scope, scope_id),
  CHECK (scope IN ('global', 'agent', 'user')),
  CHECK (daily_budget_usd >= 0)
);
CREATE TABLE IF NOT EXISTS "budget_refusal_notifications" (
  task_id TEXT NOT NULL,
  date TEXT NOT NULL,
  agent_id TEXT NOT NULL,
  cause TEXT NOT NULL,
  agent_spend_usd REAL,
  agent_budget_usd REAL,
  global_spend_usd REAL,
  global_budget_usd REAL,
  user_spend_usd REAL,
  user_budget_usd REAL,
  follow_up_task_id TEXT,
  createdAt INTEGER NOT NULL,
  PRIMARY KEY (task_id, date),
  CHECK (cause IN ('agent', 'global', 'user'))
);
CREATE TABLE oauth_refresh_locks (
  provider  TEXT PRIMARY KEY,
  owner     TEXT NOT NULL,
  expiresAt TEXT NOT NULL,
  createdAt TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%fZ', 'now')),
  updatedAt TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%fZ', 'now'))
);
CREATE TABLE metrics (
  id           TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
  agentId      TEXT NOT NULL,
  slug         TEXT NOT NULL,
  title        TEXT NOT NULL,
  description  TEXT,
  definition   TEXT NOT NULL,
  createdAt    TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updatedAt    TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id),
  UNIQUE (agentId, slug)
);
CREATE TABLE metric_versions (
  id                  TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
  metricId            TEXT NOT NULL REFERENCES metrics(id) ON DELETE CASCADE,
  version             INTEGER NOT NULL,
  snapshot            TEXT NOT NULL,
  changedByAgentId    TEXT,
  createdAt           TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by TEXT REFERENCES users(id), updated_by TEXT REFERENCES users(id),
  UNIQUE (metricId, version)
);
CREATE TABLE script_runs (
  id                TEXT PRIMARY KEY,
  agentId           TEXT NOT NULL,
  scriptName        TEXT,
  source            TEXT NOT NULL,
  args              TEXT NOT NULL DEFAULT 'null',
  status            TEXT NOT NULL DEFAULT 'running'
    CHECK(status IN (
      'running',
      'paused',
      'completed',
      'failed',
      'cancelled',
      'aborted_limit'
    )),
  pid               INTEGER,
  startedAt         TEXT NOT NULL DEFAULT (datetime('now')),
  finishedAt        TEXT,
  output            TEXT,
  error             TEXT,
  last_heartbeat_at TEXT,
  idempotencyKey    TEXT UNIQUE,
  requestedByUserId TEXT REFERENCES users(id),
  created_by        TEXT REFERENCES users(id),
  updated_by        TEXT REFERENCES users(id)
, kind TEXT NOT NULL DEFAULT 'workflow'
  CHECK(kind IN ('workflow', 'inline')));
CREATE TABLE script_run_journal (
  id          TEXT PRIMARY KEY,
  runId       TEXT NOT NULL REFERENCES script_runs(id) ON DELETE CASCADE,
  stepKey     TEXT NOT NULL,
  stepType    TEXT NOT NULL,
  config      TEXT NOT NULL DEFAULT '{}',
  status      TEXT NOT NULL CHECK(status IN ('completed','failed')),
  result      TEXT,
  error       TEXT,
  startedAt   TEXT NOT NULL DEFAULT (datetime('now')),
  completedAt TEXT,
  created_by  TEXT REFERENCES users(id),
  updated_by  TEXT REFERENCES users(id), durationMs INTEGER,
  UNIQUE(runId, stepKey)
);
CREATE TABLE IF NOT EXISTS "pages" (
  id           TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
  agentId      TEXT NOT NULL,
  slug         TEXT NOT NULL,
  title        TEXT NOT NULL,
  description  TEXT,
  contentType  TEXT NOT NULL CHECK (contentType IN ('text/html','application/json')),
  authMode     TEXT NOT NULL DEFAULT 'authed' CHECK (authMode IN ('public','authed','password')),
  passwordHash TEXT,
  body         TEXT NOT NULL,
  needsCredentials TEXT,
  createdAt    TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updatedAt    TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  view_count   INTEGER NOT NULL DEFAULT 0,
  created_by   TEXT REFERENCES users(id),
  updated_by   TEXT REFERENCES users(id),
  UNIQUE (agentId, slug)
);
CREATE TABLE skill_files (
  id TEXT PRIMARY KEY,
  skillId TEXT NOT NULL REFERENCES skills(id) ON DELETE CASCADE,
  path TEXT NOT NULL,
  content TEXT NOT NULL,
  mimeType TEXT NOT NULL DEFAULT 'text/plain',
  isBinary INTEGER NOT NULL DEFAULT 0,
  size INTEGER,
  createdAt TEXT NOT NULL,
  lastUpdatedAt TEXT NOT NULL,
  created_by TEXT REFERENCES users(id),
  updated_by TEXT REFERENCES users(id),
  UNIQUE(skillId, path)
);
