INSERT INTO prompt_templates VALUES('7aee58ae-5685-47a1-90ec-62936a7e06f4','system.session.worker.pi','global',NULL,'enabled',unistr('{{@template[system.agent.role]}}\u000a\u000a{{@template[system.agent.register]}}\u000a{{@template[system.agent.worker]}}\u000a{{@template[system.agent.filesystem]}}\u000a{{@template[system.agent.self_awareness]}}\u000a\u000a{{@template[system.agent.system]}}\u000a{{@template[system.agent.share_urls]}}\u000a{{@template[system.agent.code_quality]}}'),1,1,'system','2026-06-11T22:38:21.860Z','2026-06-11T22:38:21.860Z',NULL,NULL);
INSERT INTO prompt_templates VALUES('75c99c42-72be-4b86-85a7-1acd0c9859d6','system.agent.worker.remote','global',NULL,'enabled',unistr('\u000aAs a worker agent of the swarm, you are responsible for executing tasks assigned by the lead agent.\u000a\u000a- Each worker focuses on specific tasks or objectives, contributing to the overall goals of the swarm.\u000a- Workers MUST report their progress back to the lead and collaborate with other workers as needed.\u000a\u000a#### How Tasks Work\u000a\u000aYou receive tasks via the session prompt. Each task has a description of what needs to be done.\u000a\u000a#### Completing Tasks\u000a\u000aWhen you finish a task:\u000a- Provide a clear summary of what you accomplished in your final message\u000a- If you created a PR, include the PR URL\u000a- If you encountered blockers, explain what blocked you and what you tried\u000a\u000aYour output is captured automatically — focus on doing the work and communicating results clearly.\u000a'),1,1,'system','2026-06-11T22:38:21.861Z','2026-06-11T22:38:21.861Z',NULL,NULL);
INSERT INTO prompt_templates VALUES('ce2d8c81-ae98-41fd-8167-9d1444d0eadf','system.session.worker.remote','global',NULL,'enabled',unistr('{{@template[system.agent.role]}}\u000a\u000a{{@template[system.agent.worker.remote]}}'),1,1,'system','2026-06-11T22:38:21.861Z','2026-06-11T22:38:21.861Z',NULL,NULL);
INSERT INTO prompt_templates VALUES('1dae1f66-e21d-48f1-a424-9bb92b87953e','task.trigger.assigned','global',NULL,'enabled','{{work_on_task_cmd}} {{task_id}}{{task_desc_section}}{{output_instructions}}',1,1,'system','2026-06-11T22:38:21.861Z','2026-06-11T22:38:21.861Z',NULL,NULL);
INSERT INTO prompt_templates VALUES('b5b2c90c-8a1a-4db1-b0e3-9d4d9bcb3ae9','task.trigger.offered','global',NULL,'enabled',unistr('{{review_offered_task_cmd}} {{task_id}}{{task_desc_section}}\u000a\u000aAccept if you have capacity and skills. Reject with a reason if you cannot handle it.'),1,1,'system','2026-06-11T22:38:21.861Z','2026-06-11T22:38:21.861Z',NULL,NULL);
INSERT INTO prompt_templates VALUES('228bdfc4-b8ef-4024-b38b-10e003628013','task.trigger.unread_mentions','global',NULL,'enabled',unistr('You have {{mention_count}} mention(s) in chat channels.\u000a\u000a1. Use `read-messages` with unreadOnly: true to see them\u000a2. Respond to questions or requests directed at you\u000a3. If a message requires work, create a task using `send-task`'),1,1,'system','2026-06-11T22:38:21.861Z','2026-06-11T22:38:21.861Z',NULL,NULL);
INSERT INTO prompt_templates VALUES('fcd81b8a-11c2-46cc-acc6-2066892bec29','task.trigger.pool_available','global',NULL,'enabled',unistr('{{task_count}} task(s) available in the pool.\u000a\u000a1. Run `get-tasks` with unassigned: true to browse\u000a2. Pick one matching your skills\u000a3. Run `task-action` with action: "claim" and taskId: "<id>"\u000a\u000aNote: Claims are first-come-first-serve. If claim fails, pick another.'),1,1,'system','2026-06-11T22:38:21.861Z','2026-06-11T22:38:21.861Z',NULL,NULL);
INSERT INTO prompt_templates VALUES('a46eb85f-6fa2-42b3-9117-1358373dc784','task.trigger.channel_activity','global',NULL,'enabled',unistr('## Slack Channel Activity\u000a\u000a{{message_count}} new message(s) in monitored Slack channels:\u000a\u000a{{messages_detail}}\u000a## Your Task\u000a\u000aReview these messages and decide if any require action:\u000a1. If a message is a question or request, respond using `slack-reply` or create a task with `send-task`\u000a2. If a message is informational, no action needed\u000a3. Use `slack-read` with the channelId to get more context if needed'),1,1,'system','2026-06-11T22:38:21.861Z','2026-06-11T22:38:21.861Z',NULL,NULL);
INSERT INTO prompt_templates VALUES('cb3bc7b4-7626-4686-bcf3-2c1426abaa65','task.resumption.with_progress','global',NULL,'enabled',unistr('{{work_on_task_cmd}} {{task_id}}\u000a\u000a**RESUMED TASK** - This task was interrupted during a deployment and is being resumed.\u000a\u000aTask: "{{task_description}}"\u000a\u000aPrevious Progress:\u000a{{progress}}\u000a\u000aContinue from where you left off. Review the progress above and complete the remaining work.{{completion_instructions}}'),1,1,'system','2026-06-11T22:38:21.862Z','2026-06-11T22:38:21.862Z',NULL,NULL);
INSERT INTO prompt_templates VALUES('2d1f847d-fcfa-413c-bb12-ef3f53bae5da','task.resumption.no_progress','global',NULL,'enabled',unistr('{{work_on_task_cmd}} {{task_id}}\u000a\u000a**RESUMED TASK** - This task was interrupted during a deployment and is being resumed.\u000a\u000aTask: "{{task_description}}"\u000a\u000aNo progress was saved before the interruption. Start the task fresh but be aware files may have been partially modified.{{completion_instructions}}'),1,1,'system','2026-06-11T22:38:21.862Z','2026-06-11T22:38:21.862Z',NULL,NULL);
INSERT INTO prompt_templates VALUES('b446d387-2693-4404-a543-a123cb3bdc17','kapso.message.received','global',NULL,'enabled',unistr('# WhatsApp inbound (Kapso)\u000a\u000aA Kapso webhook fired on the swarm''s provisioned WhatsApp number. Load the `kapso-whatsapp` skill, then triage this like any other interaction and reply on WhatsApp by quote-replying the inbound WAMID (`context.message_id`).\u000a\u000a## Source: WhatsApp (Kapso)\u000a- conversation_id: {{conversation_id}}\u000a- inbound_wamid: {{inbound_wamid}}\u000a- sender_phone: {{sender_phone}}\u000a- contact_name: {{contact_name}}\u000a- phone_number_id: {{phone_number_id}}{{test_note}}\u000a\u000a## Message\u000a{{message_text}}'),1,1,'system','2026-06-11T22:38:21.862Z','2026-06-11T22:38:21.862Z',NULL,NULL);
INSERT INTO prompt_templates VALUES('333a564c-a17b-457e-bf16-b20c73216549','task.worker.completed','global',NULL,'enabled',unistr('Worker task completed — review needed.\u000a\u000aAgent: {{agent_name}}\u000aOriginal task created by agent {{creator_agent}}\u000aTask: "{{task_desc}}"\u000a\u000aOutput:\u000a{{output_summary}}{{follow_up_instructions}}\u000a\u000aIMPORTANT: Do NOT re-delegate or re-answer the original request. The worker has already handled it. Your job is ONLY to:\u000a1. Review the output above\u000a2. If the task has Slack metadata, use `slack-reply` to post the result to the thread (if the worker hasn''t already)\u000a3. Complete this follow-up task\u000a\u000aUse `get-task-details` with taskId "{{task_id}}" for full details.'),1,1,'system','2026-06-11T22:38:21.862Z','2026-06-11T22:38:21.862Z',NULL,NULL);
INSERT INTO prompt_templates VALUES('9fcf7d9f-0143-4525-8187-8e7430901a49','hitl.follow_up','global',NULL,'enabled',unistr('Human responded to your approval request ({{request_id}}).\u000a\u000aTitle: {{title}}\u000aStatus: {{status}}\u000a\u000aQuestions and responses:\u000a{{responses}}\u000a\u000aContinue your work based on the human''s input.'),1,1,'system','2026-06-11T22:38:21.862Z','2026-06-11T22:38:21.862Z',NULL,NULL);
INSERT INTO prompt_templates VALUES('6ae4eb49-9163-4464-a706-1456e1e7a076','task.worker.failed','global',NULL,'enabled',unistr('Worker task failed — action needed.\u000a\u000aAgent: {{agent_name}}\u000aOriginal task created by agent {{creator_agent}}\u000aTask: "{{task_desc}}"\u000a\u000aFailure reason: {{failure_reason}}{{follow_up_instructions}}\u000a\u000aDecide whether to reassign, retry, or handle the failure. Use `get-task-details` with taskId "{{task_id}}" for full details.'),1,1,'system','2026-06-11T22:38:21.862Z','2026-06-11T22:38:21.862Z',NULL,NULL);
INSERT INTO prompt_templates VALUES('949a5efe-19cd-4cae-bec3-3003a10a46a8','task.budget.refused','global',NULL,'enabled',unistr('Budget refusal — task is blocked.\u000a\u000aCause: {{cause}}\u000aAgent: {{agent_name}}\u000aTask: {{task_desc}}\u000aSpend / budget: {{spend_summary}}\u000aResets at: {{reset_at}}\u000a\u000aDecide whether to raise the budget, reassign, or wait for the daily reset.\u000aUse `get-task-details` with taskId "{{task_id}}" for full details.'),1,1,'system','2026-06-11T22:38:21.862Z','2026-06-11T22:38:21.862Z',NULL,NULL);
INSERT INTO prompt_templates VALUES('18255779-8025-4a4e-8801-7918ad492cfd','agentmail.email.followup','global',NULL,'enabled',unistr('From: {{from}}\u000aSubject: {{subject}}\u000aInbox: {{inbox_id}}\u000aThread: {{thread_id}}\u000a\u000a{{preview}}'),1,1,'system','2026-06-11T22:38:21.862Z','2026-06-11T22:38:21.862Z',NULL,NULL);
