INSERT INTO prompt_templates VALUES('65a7c294-92f4-410f-a285-d1d13d9dd64b','common.delegation_instruction','global',NULL,'enabled','⚠️ As lead, DELEGATE this task to a worker agent - do not tackle it yourself.',1,1,'system','2026-06-11T22:38:21.863Z','2026-06-11T22:38:21.863Z',NULL,NULL);
