INSERT INTO prompt_templates VALUES('08fb6f9e-1c00-4f00-bd78-dbac8043d9af','github.pull_request.assigned','global',NULL,'enabled',unistr('Assigned to: @{{bot_name}}\u000aFrom: {{sender_login}}\u000aRepo: {{repo_full_name}}\u000aBranch: {{head_ref}} → {{base_ref}}\u000aURL: {{pr_url}}\u000a\u000aContext:\u000a{{context}}\u000a\u000a---\u000a{{@template[common.delegation_instruction]}}\u000a{{@template[common.command_suggestions.github_pr]}}'),1,1,'system','2026-06-11T22:38:21.864Z','2026-06-11T22:38:21.864Z',NULL,NULL);
