INSERT INTO prompt_templates VALUES('37cc7458-5c54-4af2-8850-038c022c5a05','github.pull_request.closed','global',NULL,'enabled',unistr('PR: {{pr_title}}\u000aRepo: {{repo_full_name}}\u000aURL: {{pr_url}}\u000a\u000a---\u000aRelated task: {{related_task_id}}\u000a🔀 Consider routing to the same agent working on the related task.\u000a{{follow_up_suggestion}}'),1,1,'system','2026-06-11T22:38:21.864Z','2026-06-11T22:38:21.864Z',NULL,NULL);
INSERT INTO prompt_templates VALUES('d22d2056-52da-4748-83ff-b88794859008','github.pull_request.synchronize','global',NULL,'enabled',unistr('PR: {{pr_title}}\u000aRepo: {{repo_full_name}}\u000aBranch: {{head_ref}}\u000aNew HEAD: {{head_sha_short}}\u000aURL: {{pr_url}}\u000a\u000a---\u000aRelated task: {{related_task_id}}\u000a🔀 Consider routing to the same agent working on the related task.\u000a💡 New commits were pushed. CI will re-run - monitor for results.'),1,1,'system','2026-06-11T22:38:21.864Z','2026-06-11T22:38:21.864Z',NULL,NULL);
