INSERT INTO prompt_templates VALUES('017017a6-d5eb-4f99-84bb-3fd4025f51cd','common.delegation_instruction.gitlab','global',NULL,'enabled',unistr('\u000a\u000a**Delegation instruction:** As the lead agent, analyze this and decide whether to handle it yourself or delegate to a worker agent. Use `send-task` to delegate with clear instructions.'),1,1,'system','2026-06-11T22:38:21.865Z','2026-06-11T22:38:21.865Z',NULL,NULL);
