INSERT INTO prompt_template_history VALUES('7aac5679-5cf6-4ffd-9d2e-43ee0a28aa97','cb3bc7b4-7626-4686-bcf3-2c1426abaa65',1,unistr('{{work_on_task_cmd}} {{task_id}}\u000a\u000a**RESUMED TASK** - This task was interrupted during a deployment and is being resumed.\u000a\u000aTask: "{{task_description}}"\u000a\u000aPrevious Progress:\u000a{{progress}}\u000a\u000aContinue from where you left off. Review the progress above and complete the remaining work.{{completion_instructions}}'),'enabled','system','2026-06-11T22:38:21.862Z','Seeded from code registry',NULL,NULL);
