INSERT INTO scripts VALUES('5a903cc9-8d9d-490c-8178-a1507e5c01a9','gh-pr-snapshot','global',NULL,unistr('import { z } from "zod";\u000a\u000aexport const argsSchema = z.object({\u000a  repo: z.string().describe("Repository in ''owner/name'' form, e.g. ''owner/name''"),\u000a  number: z.number().int().positive().describe("Pull request number"),\u000a  token: z\u000a    .string()\u000a    .optional()\u000a    .describe("GitHub token override; falls back to the GITHUB_TOKEN swarm config"),\u000a});\u000a\u000aasync function resolveSecret(ctx: any, key: string, override: unknown): Promise<string | null> {\u000a  if (typeof override === "string" && override.length > 0) return override;\u000a  try {\u000a    const base = ctx.stdlib.Redacted.value(ctx.swarm.config.mcpBaseUrl).replace(/\\/+$/, "");\u000a    const apiKey = ctx.stdlib.Redacted.value(ctx.swarm.config.apiKey);\u000a    const res: any = await ctx.stdlib.fetchJson(\u000a      base + "/api/config/resolved?includeSecrets=true",\u000a      { headers: { Authorization: "Bearer " + apiKey } },\u000a    );\u000a    const configs: any = res && Array.isArray(res.configs) ? res.configs : [];\u000a    for (const c of configs) {\u000a      if (c && c.key === key && typeof c.value === "string" && c.value.length > 0) {\u000a        return c.value;\u000a      }\u000a    }\u000a  } catch {\u000a    // Best-effort: a missing config row just means we proceed unauthenticated.\u000a  }\u000a  return null;\u000a}\u000a\u000a/** One-call GitHub PR snapshot: state, draft, mergeable, CI checks and review tallies. */\u000aexport default async function ghPrSnapshot(args: any, ctx: any) {\u000a  const parsed = argsSchema.safeParse(args);\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a  const { repo, number } = parsed.data;\u000a  if (!/^[^/\\s]+\\/[^/\\s]+$/.test(repo)) {\u000a    return { error: "repo must be in ''owner/name'' form" };\u000a  }\u000a\u000a  const token = await resolveSecret(ctx, "GITHUB_TOKEN", parsed.data.token);\u000a  const headers: any = {\u000a    Accept: "application/vnd.github+json",\u000a    "User-Agent": "agent-swarm-scripts",\u000a  };\u000a  if (token) headers.Authorization = "Bearer " + token;\u000a\u000a  const api = "https://api.github.com/repos/" + repo;\u000a  const pr: any = await ctx.stdlib.fetchJson(api + "/pulls/" + number, { headers });\u000a  if (!pr || typeof pr.number !== "number") {\u000a    const why = pr && pr.message ? pr.message : "not found or not accessible";\u000a    return { error: "PR " + repo + "#" + number + ": " + why };\u000a  }\u000a\u000a  const checks = { passed: 0, failed: 0, pending: 0 };\u000a  const sha = pr.head && pr.head.sha ? pr.head.sha : null;\u000a  if (sha) {\u000a    const runs: any = await ctx.stdlib.fetchJson(api + "/commits/" + sha + "/check-runs", {\u000a      headers,\u000a    });\u000a    const list: any = runs && Array.isArray(runs.check_runs) ? runs.check_runs : [];\u000a    for (const run of list) {\u000a      if (run.status !== "completed") checks.pending++;\u000a      else if (run.conclusion === "success") checks.passed++;\u000a      else if (\u000a        run.conclusion === "failure" ||\u000a        run.conclusion === "timed_out" ||\u000a        run.conclusion === "cancelled" ||\u000a        run.conclusion === "action_required"\u000a      ) {\u000a        checks.failed++;\u000a      }\u000a    }\u000a  }\u000a\u000a  const reviewsRaw: any = await ctx.stdlib.fetchJson(api + "/pulls/" + number + "/reviews", {\u000a    headers,\u000a  });\u000a  const reviewList: any = Array.isArray(reviewsRaw) ? reviewsRaw : [];\u000a  const latestByUser: any = {};\u000a  for (const r of reviewList) {\u000a    const user = r && r.user && r.user.login ? r.user.login : "unknown";\u000a    if (r.state === "APPROVED" || r.state === "CHANGES_REQUESTED") {\u000a      latestByUser[user] = r.state;\u000a    }\u000a  }\u000a  const reviews = { approved: 0, changesRequested: 0, pending: 0 };\u000a  for (const user of Object.keys(latestByUser)) {\u000a    if (latestByUser[user] === "APPROVED") reviews.approved++;\u000a    else reviews.changesRequested++;\u000a  }\u000a  reviews.pending = Array.isArray(pr.requested_reviewers) ? pr.requested_reviewers.length : 0;\u000a\u000a  return {\u000a    title: pr.title,\u000a    state: pr.merged_at ? "merged" : pr.state,\u000a    draft: Boolean(pr.draft),\u000a    mergeable: pr.mergeable,\u000a    checks,\u000a    reviews,\u000a    url: pr.html_url,\u000a  };\u000a}\u000a'),'One-call GitHub pull request snapshot: title, state, draft, mergeable, CI check tallies (passed/failed/pending) and review tallies (approved/changes-requested/pending).','Triage a GitHub PR''s status in a single call instead of running several gh pr view / gh pr checks / gh api invocations.','{"argsType":"any","resultType":"unknown","description":"One-call GitHub PR snapshot: state, draft, mergeable, CI checks and review tallies."}','023ffb9c44b5ff4f2d85addfdb1d098224a8ac12dbaa9ed7cc3f7a3770a085b4',1,0,1,'none',NULL,'2026-06-11T22:38:22.199Z','2026-06-11T22:38:22.199Z','{"$schema":"https://json-schema.org/draft/2020-12/schema","type":"object","properties":{"repo":{"type":"string","description":"Repository in ''owner/name'' form, e.g. ''owner/name''"},"number":{"type":"integer","exclusiveMinimum":0,"maximum":9007199254740991,"description":"Pull request number","minimum":-9007199254740991},"token":{"description":"GitHub token override; falls back to the GITHUB_TOKEN swarm config","type":"string"}},"required":["repo","number"],"additionalProperties":false}',NULL,NULL);
INSERT INTO scripts VALUES('52ce70b3-ab75-4eda-99ff-cd88c43598d6','fetch-readable','global',NULL,unistr('import { z } from "zod";\u000a\u000aexport const argsSchema = z.object({\u000a  url: z.string().describe("Absolute http(s) URL of the page to extract"),\u000a  maxChars: z\u000a    .number()\u000a    .int()\u000a    .positive()\u000a    .optional()\u000a    .describe("Truncate extracted text to this many characters (default 20000)"),\u000a});\u000a\u000aconst ENTITIES: any = {\u000a  "&amp;": "&",\u000a  "&lt;": "<",\u000a  "&gt;": ">",\u000a  "&quot;": ''"'',\u000a  "&#39;": "''",\u000a  "&apos;": "''",\u000a  "&nbsp;": " ",\u000a};\u000a\u000afunction decodeEntities(input: string): string {\u000a  let out = input.replace(/&(amp|lt|gt|quot|#39|apos|nbsp);/g, (m: string) => ENTITIES[m] || m);\u000a  out = out.replace(/&#(\\d+);/g, (_m: string, code: string) =>\u000a    String.fromCodePoint(Number.parseInt(code, 10)),\u000a  );\u000a  out = out.replace(/&#x([0-9a-fA-F]+);/g, (_m: string, code: string) =>\u000a    String.fromCodePoint(Number.parseInt(code, 16)),\u000a  );\u000a  return out;\u000a}\u000a\u000a/** Fetch a web page and return readable article text with nav/ads/boilerplate stripped. */\u000aexport default async function fetchReadable(args: any, ctx: any) {\u000a  const parsed = argsSchema.safeParse(args);\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a  const { url } = parsed.data;\u000a  if (!/^https?:\\/\\//i.test(url)) return { error: "url must be an absolute http(s) URL" };\u000a  const maxChars = parsed.data.maxChars || 20000;\u000a\u000a  const html: any = await ctx.stdlib.fetchJson(url, {\u000a    headers: { "User-Agent": "agent-swarm-scripts", Accept: "text/html,*/*" },\u000a  });\u000a  const raw = typeof html === "string" ? html : JSON.stringify(html);\u000a\u000a  const titleMatch = raw.match(/<title[^>]*>([\\s\\S]*?)<\\/title>/i);\u000a  const ogMatch = raw.match(\u000a    /<meta[^>]+property=["'']og:title["''][^>]+content=["'']([^"'']+)["'']/i,\u000a  );\u000a  const title = decodeEntities((ogMatch?.[1] ?? titleMatch?.[1] ?? "").trim());\u000a\u000a  let body = raw;\u000a  // Drop non-content regions entirely (tag + inner content).\u000a  body = body.replace(\u000a    /<(script|style|noscript|nav|header|footer|aside|svg|template|form|iframe)\\b[^>]*>[\\s\\S]*?<\\/\\1>/gi,\u000a    " ",\u000a  );\u000a  body = body.replace(/<!--[\\s\\S]*?-->/g, " ");\u000a  // Keep block boundaries as newlines so paragraphs survive.\u000a  body = body.replace(/<\\/(p|div|section|article|li|h[1-6]|br|tr)>/gi, "\\n");\u000a  body = body.replace(/<br\\s*\\/?>/gi, "\\n");\u000a  // Strip all remaining tags.\u000a  body = body.replace(/<[^>]+>/g, " ");\u000a  body = decodeEntities(body);\u000a  body = body\u000a    .split("\\n")\u000a    .map((line: string) => line.replace(/[ \\t\\f\\v ]+/g, " ").trim())\u000a    .filter((line: string) => line.length > 0)\u000a    .join("\\n");\u000a  body = body.replace(/\\n{3,}/g, "\\n\\n");\u000a\u000a  const truncated = body.length > maxChars;\u000a  if (truncated) body = body.slice(0, maxChars);\u000a\u000a  return { title, text: body, url, length: body.length, truncated };\u000a}\u000a'),'Fetch a web page and extract clean readable article text — strips scripts, styles, nav, headers, footers, ads and HTML tags, and decodes entities.','Read the actual content of a URL without wading through raw HTML; readable-article / reader-mode extraction.','{"argsType":"any","resultType":"unknown","description":"Fetch a web page and return readable article text with nav/ads/boilerplate stripped."}','fc50aa7e13c71c36cd6af15e101b6ab380f978d56f80d581dffbacd0756f39b1',1,0,1,'none',NULL,'2026-06-11T22:38:22.346Z','2026-06-11T22:38:22.346Z','{"$schema":"https://json-schema.org/draft/2020-12/schema","type":"object","properties":{"url":{"type":"string","description":"Absolute http(s) URL of the page to extract"},"maxChars":{"description":"Truncate extracted text to this many characters (default 20000)","type":"integer","exclusiveMinimum":0,"maximum":9007199254740991,"minimum":-9007199254740991}},"required":["url"],"additionalProperties":false}',NULL,NULL);
INSERT INTO scripts VALUES('4cf0e0fa-f341-4ebd-aaee-921965e8a2c8','json-query','global',NULL,unistr('import { z } from "zod";\u000a\u000aexport const argsSchema = z.object({\u000a  data: z.unknown().describe("Any JSON value to query (object, array, or scalar)"),\u000a  query: z\u000a    .string()\u000a    .describe(\u000a      "jq-style path: dot fields, [n] index, [] iterate, | pipe, and keys/values/length/type",\u000a    ),\u000a});\u000a\u000afunction getProp(value: any, key: string): any {\u000a  if (value == null) return undefined;\u000a  if (typeof value !== "object") return undefined;\u000a  return value[key];\u000a}\u000a\u000afunction applyToken(stream: any[], token: string): any[] {\u000a  const next: any[] = [];\u000a  for (const value of stream) {\u000a    if (token === "[]") {\u000a      if (Array.isArray(value)) {\u000a        for (const item of value) next.push(item);\u000a      } else if (value && typeof value === "object") {\u000a        for (const k of Object.keys(value)) next.push(value[k]);\u000a      }\u000a      continue;\u000a    }\u000a    const idx = token.match(/^\\[(-?\\d+)\\]$/);\u000a    if (idx) {\u000a      let i = Number.parseInt(idx[1] as string, 10);\u000a      if (Array.isArray(value) && i < 0) i += value.length;\u000a      next.push(Array.isArray(value) ? value[i] : undefined);\u000a      continue;\u000a    }\u000a    const quoted = token.match(/^\\["([^"]*)"\\]$/);\u000a    if (quoted) {\u000a      next.push(getProp(value, quoted[1] as string));\u000a      continue;\u000a    }\u000a    const field = token.match(/^\\.([a-zA-Z_$][\\w$]*)$/);\u000a    if (field) {\u000a      next.push(getProp(value, field[1] as string));\u000a      continue;\u000a    }\u000a    if (token === "." || token === "") {\u000a      next.push(value);\u000a      continue;\u000a    }\u000a    throw "unrecognized path token: " + token;\u000a  }\u000a  return next;\u000a}\u000a\u000afunction applyFunction(stream: any[], name: string): any[] {\u000a  return stream.map((value: any) => {\u000a    if (name === "length") {\u000a      if (Array.isArray(value) || typeof value === "string") return value.length;\u000a      if (value && typeof value === "object") return Object.keys(value).length;\u000a      return 0;\u000a    }\u000a    if (name === "keys") {\u000a      return value && typeof value === "object" ? Object.keys(value) : [];\u000a    }\u000a    if (name === "values") {\u000a      if (Array.isArray(value)) return value;\u000a      return value && typeof value === "object" ? Object.values(value) : [];\u000a    }\u000a    if (name === "type") {\u000a      if (value === null) return "null";\u000a      if (Array.isArray(value)) return "array";\u000a      return typeof value;\u000a    }\u000a    throw "unknown function: " + name;\u000a  });\u000a}\u000a\u000afunction applyStage(stream: any[], stage: string): any[] {\u000a  const trimmed = stage.trim();\u000a  if (/^(keys|values|length|type)$/.test(trimmed)) {\u000a    return applyFunction(stream, trimmed);\u000a  }\u000a  let rest = trimmed;\u000a  let current = stream;\u000a  if (rest === "." || rest === "") return current;\u000a  while (rest.length > 0) {\u000a    const m = rest.match(/^(\\[\\]|\\[-?\\d+\\]|\\["[^"]*"\\]|\\.[a-zA-Z_$][\\w$]*|\\.)/);\u000a    if (!m) throw "could not parse path near: " + rest;\u000a    const token = m[1] as string;\u000a    current = applyToken(current, token);\u000a    rest = rest.slice(token.length);\u000a  }\u000a  return current;\u000a}\u000a\u000a/** Run a jq-style path/filter query over a JSON value — replaces curl|jq pipelines. */\u000aexport default async function jsonQuery(args: any, _ctx: any) {\u000a  const parsed = argsSchema.safeParse(args);\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a  const { query } = parsed.data;\u000a\u000a  let data: any = parsed.data.data;\u000a  if (typeof data === "string") {\u000a    const t = data.trim();\u000a    if (t.startsWith("{") || t.startsWith("[")) {\u000a      try {\u000a        data = JSON.parse(t);\u000a      } catch {\u000a        // Leave as a plain string if it is not valid JSON.\u000a      }\u000a    }\u000a  }\u000a\u000a  try {\u000a    let stream: any[] = [data];\u000a    for (const stage of query.split("|")) {\u000a      stream = applyStage(stream, stage);\u000a    }\u000a    const result = stream.length === 1 ? stream[0] : stream;\u000a    return { result, matches: stream.length };\u000a  } catch (err) {\u000a    return { error: typeof err === "string" ? err : "query failed" };\u000a  }\u000a}\u000a'),'Run a jq-style path/filter query over any JSON value: dot fields, [n] indexing, [] iteration, | pipes, and keys/values/length/type functions.','Extract a value from a JSON blob without shelling out to a curl | jq pipeline.','{"argsType":"any","resultType":"unknown","description":"Run a jq-style path/filter query over a JSON value — replaces curl|jq pipelines."}','88f200ba0d090c85112465316655d2a5869263def915bb9b0b2808d98dbb49b4',1,0,1,'none',NULL,'2026-06-11T22:38:22.490Z','2026-06-11T22:38:22.490Z','{"$schema":"https://json-schema.org/draft/2020-12/schema","type":"object","properties":{"data":{"description":"Any JSON value to query (object, array, or scalar)"},"query":{"type":"string","description":"jq-style path: dot fields, [n] index, [] iterate, | pipe, and keys/values/length/type"}},"required":["data","query"],"additionalProperties":false}',NULL,NULL);
INSERT INTO scripts VALUES('19e282df-8147-4338-99e9-085e2a1152c7','group-count','global',NULL,unistr('import { z } from "zod";\u000a\u000aexport const argsSchema = z.object({\u000a  items: z.array(z.unknown()).describe("Array of objects to aggregate"),\u000a  by: z.string().describe("Field name (dotted paths allowed) to group by"),\u000a  sum: z\u000a    .string()\u000a    .optional()\u000a    .describe("Optional numeric field name to sum within each group"),\u000a  limit: z\u000a    .number()\u000a    .int()\u000a    .positive()\u000a    .optional()\u000a    .describe("Return only the top N groups by count (default: all)"),\u000a});\u000a\u000afunction dig(obj: any, path: string): any {\u000a  let cur = obj;\u000a  for (const part of path.split(".")) {\u000a    if (cur == null || typeof cur !== "object") return undefined;\u000a    cur = cur[part];\u000a  }\u000a  return cur;\u000a}\u000a\u000afunction keyOf(value: any): string {\u000a  if (value === undefined) return "(undefined)";\u000a  if (value === null) return "(null)";\u000a  if (typeof value === "object") return JSON.stringify(value);\u000a  return String(value);\u000a}\u000a\u000a/** Group an array of objects by a field, returning per-group count and optional sum. */\u000aexport default async function groupCount(args: any, _ctx: any) {\u000a  const parsed = argsSchema.safeParse(args);\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a  const { items, by } = parsed.data;\u000a  const sumField = parsed.data.sum;\u000a\u000a  const groups: any = {};\u000a  let totalSum = 0;\u000a  for (const item of items) {\u000a    const key = keyOf(dig(item, by));\u000a    if (!groups[key]) groups[key] = { key, count: 0, sum: 0 };\u000a    groups[key].count++;\u000a    if (sumField) {\u000a      const raw = dig(item, sumField);\u000a      const num = typeof raw === "number" ? raw : Number(raw);\u000a      if (!Number.isNaN(num)) {\u000a        groups[key].sum += num;\u000a        totalSum += num;\u000a      }\u000a    }\u000a  }\u000a\u000a  let rows: any[] = Object.keys(groups).map((k: string) => {\u000a    const g = groups[k];\u000a    return sumField ? { key: g.key, count: g.count, sum: g.sum } : { key: g.key, count: g.count };\u000a  });\u000a  rows.sort((a: any, b: any) => b.count - a.count);\u000a  if (parsed.data.limit) rows = rows.slice(0, parsed.data.limit);\u000a\u000a  return {\u000a    groups: rows,\u000a    groupCount: rows.length,\u000a    total: items.length,\u000a    totalSum: sumField ? totalSum : undefined,\u000a  };\u000a}\u000a'),'Group an array of objects by a field (dotted paths supported), returning per-group counts sorted by frequency plus an optional numeric sum.','Aggregate or tally records — counts and sums by category — without writing ad-hoc reduce code.','{"argsType":"any","resultType":"unknown","description":"Group an array of objects by a field, returning per-group count and optional sum."}','428efdd1d1886b26a31ea3f29ed623b0a087da2615b8e55ef1cfc1f659a59c4e',1,0,1,'none',NULL,'2026-06-11T22:38:22.628Z','2026-06-11T22:38:22.628Z','{"$schema":"https://json-schema.org/draft/2020-12/schema","type":"object","properties":{"items":{"type":"array","items":{},"description":"Array of objects to aggregate"},"by":{"type":"string","description":"Field name (dotted paths allowed) to group by"},"sum":{"description":"Optional numeric field name to sum within each group","type":"string"},"limit":{"description":"Return only the top N groups by count (default: all)","type":"integer","exclusiveMinimum":0,"maximum":9007199254740991,"minimum":-9007199254740991}},"required":["items","by"],"additionalProperties":false}',NULL,NULL);
INSERT INTO scripts VALUES('acfd7980-2422-496b-9085-3297d18753c2','date-resolve','global',NULL,unistr('import { z } from "zod";\u000a\u000aexport const argsSchema = z.object({\u000a  expr: z\u000a    .string()\u000a    .describe("Natural date expression: yesterday, last week, Thursday, 7d ago, 2026-01-01"),\u000a  now: z\u000a    .string()\u000a    .optional()\u000a    .describe("ISO timestamp to resolve relative to (default: current time)"),\u000a});\u000a\u000aconst DAY = 86400000;\u000aconst WEEKDAYS = ["sunday", "monday", "tuesday", "wednesday", "thursday", "friday", "saturday"];\u000aconst UNIT_MS: any = {\u000a  hour: 3600000,\u000a  hours: 3600000,\u000a  h: 3600000,\u000a  day: DAY,\u000a  days: DAY,\u000a  d: DAY,\u000a  week: 7 * DAY,\u000a  weeks: 7 * DAY,\u000a  w: 7 * DAY,\u000a};\u000a\u000afunction ymd(d: Date): string {\u000a  return d.toISOString().slice(0, 10);\u000a}\u000a\u000afunction startOfDay(d: Date): Date {\u000a  return new Date(Date.UTC(d.getUTCFullYear(), d.getUTCMonth(), d.getUTCDate()));\u000a}\u000a\u000afunction single(d: Date): any {\u000a  return { iso: d.toISOString(), date: ymd(d) };\u000a}\u000a\u000afunction range(start: Date, end: Date): any {\u000a  return { start: start.toISOString(), end: end.toISOString() };\u000a}\u000a\u000a/** Resolve a natural date expression to an ISO date or a {start,end} range. */\u000aexport default async function dateResolve(args: any, _ctx: any) {\u000a  const parsed = argsSchema.safeParse(args);\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a\u000a  const nowMs = parsed.data.now ? Date.parse(parsed.data.now) : Date.now();\u000a  if (Number.isNaN(nowMs)) return { error: "invalid ''now'' timestamp" };\u000a  const now = new Date(nowMs);\u000a  const today = startOfDay(now);\u000a  const expr = parsed.data.expr.trim().toLowerCase();\u000a\u000a  if (expr === "now") return single(now);\u000a  if (expr === "today") return single(today);\u000a  if (expr === "yesterday") return single(new Date(today.getTime() - DAY));\u000a  if (expr === "tomorrow") return single(new Date(today.getTime() + DAY));\u000a\u000a  if (/^\\d{4}-\\d{2}-\\d{2}/.test(expr)) {\u000a    const ms = Date.parse(parsed.data.expr.trim());\u000a    if (Number.isNaN(ms)) return { error: "unparseable ISO date" };\u000a    return single(new Date(ms));\u000a  }\u000a\u000a  // "N <unit> ago" / "in N <unit>" / "Nd ago"\u000a  const rel = expr.match(/^(?:in\\s+)?(\\d+)\\s*([a-z]+)\\s*(ago)?$/);\u000a  if (rel) {\u000a    const amount = Number.parseInt(rel[1] as string, 10);\u000a    const unitMs = UNIT_MS[rel[2] as string];\u000a    if (unitMs) {\u000a      const dir = rel[3] === "ago" ? -1 : 1;\u000a      return single(new Date(now.getTime() + dir * amount * unitMs));\u000a    }\u000a  }\u000a\u000a  // Weekday name → most recent occurrence on or before today.\u000a  const wd = WEEKDAYS.indexOf(expr);\u000a  if (wd >= 0) {\u000a    let back = today.getUTCDay() - wd;\u000a    if (back < 0) back += 7;\u000a    return single(new Date(today.getTime() - back * DAY));\u000a  }\u000a\u000a  // Week ranges (weeks start Monday).\u000a  const weekMatch = expr.match(/^(last|this|next)\\s+week$/);\u000a  if (weekMatch) {\u000a    const offset = today.getUTCDay() === 0 ? 6 : today.getUTCDay() - 1;\u000a    const monday = new Date(today.getTime() - offset * DAY);\u000a    const shift = weekMatch[1] === "last" ? -7 : weekMatch[1] === "next" ? 7 : 0;\u000a    const start = new Date(monday.getTime() + shift * DAY);\u000a    return range(start, new Date(start.getTime() + 7 * DAY));\u000a  }\u000a\u000a  // Month ranges.\u000a  const monthMatch = expr.match(/^(last|this|next)\\s+month$/);\u000a  if (monthMatch) {\u000a    const delta = monthMatch[1] === "last" ? -1 : monthMatch[1] === "next" ? 1 : 0;\u000a    const start = new Date(Date.UTC(today.getUTCFullYear(), today.getUTCMonth() + delta, 1));\u000a    const end = new Date(Date.UTC(today.getUTCFullYear(), today.getUTCMonth() + delta + 1, 1));\u000a    return range(start, end);\u000a  }\u000a\u000a  return { error: "could not resolve expression: " + parsed.data.expr };\u000a}\u000a'),'Resolve a natural-language date expression (yesterday, last week, Thursday, 7d ago, an ISO date) into an ISO timestamp or a {start,end} range.','Turn fuzzy human date phrases into concrete timestamps for filtering, querying or scheduling.','{"argsType":"any","resultType":"unknown","description":"Resolve a natural date expression to an ISO date or a {start,end} range."}','1b998fc4be3a734d1901e72561fbc2fe0ac111b963495de6de5073464e7a90fb',1,0,1,'none',NULL,'2026-06-11T22:38:22.771Z','2026-06-11T22:38:22.771Z','{"$schema":"https://json-schema.org/draft/2020-12/schema","type":"object","properties":{"expr":{"type":"string","description":"Natural date expression: yesterday, last week, Thursday, 7d ago, 2026-01-01"},"now":{"description":"ISO timestamp to resolve relative to (default: current time)","type":"string"}},"required":["expr"],"additionalProperties":false}',NULL,NULL);
INSERT INTO scripts VALUES('43cca088-38f5-4d7e-977a-10f4d7696cea','text-diff','global',NULL,unistr('import { z } from "zod";\u000a\u000aexport const argsSchema = z.object({\u000a  a: z.string().describe("Original / left-hand text"),\u000a  b: z.string().describe("Updated / right-hand text"),\u000a  context: z\u000a    .number()\u000a    .int()\u000a    .nonnegative()\u000a    .optional()\u000a    .describe("Lines of unchanged context to keep around each change (default 3)"),\u000a});\u000a\u000aconst MAX_LINES = 5000;\u000a\u000afunction lcsOps(a: string[], b: string[]): any[] {\u000a  const n = a.length;\u000a  const m = b.length;\u000a  const dp: any[] = [];\u000a  for (let i = 0; i <= n; i++) dp.push(new Array(m + 1).fill(0));\u000a  for (let i = n - 1; i >= 0; i--) {\u000a    for (let j = m - 1; j >= 0; j--) {\u000a      dp[i][j] = a[i] === b[j] ? dp[i + 1][j + 1] + 1 : Math.max(dp[i + 1][j], dp[i][j + 1]);\u000a    }\u000a  }\u000a  const ops: any[] = [];\u000a  let i = 0;\u000a  let j = 0;\u000a  while (i < n && j < m) {\u000a    if (a[i] === b[j]) {\u000a      ops.push({ type: "eq", text: a[i] });\u000a      i++;\u000a      j++;\u000a    } else if (dp[i + 1][j] >= dp[i][j + 1]) {\u000a      ops.push({ type: "del", text: a[i] });\u000a      i++;\u000a    } else {\u000a      ops.push({ type: "ins", text: b[j] });\u000a      j++;\u000a    }\u000a  }\u000a  while (i < n) {\u000a    ops.push({ type: "del", text: a[i] });\u000a    i++;\u000a  }\u000a  while (j < m) {\u000a    ops.push({ type: "ins", text: b[j] });\u000a    j++;\u000a  }\u000a  return ops;\u000a}\u000a\u000a/** Compare two strings line-by-line and return a unified-diff summary. */\u000aexport default async function textDiff(args: any, _ctx: any) {\u000a  const parsed = argsSchema.safeParse(args);\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a  const ctxLines = parsed.data.context == null ? 3 : parsed.data.context;\u000a\u000a  const aLines = parsed.data.a.split("\\n");\u000a  const bLines = parsed.data.b.split("\\n");\u000a  if (aLines.length > MAX_LINES || bLines.length > MAX_LINES) {\u000a    return { error: "input too large: max " + MAX_LINES + " lines per side" };\u000a  }\u000a\u000a  const ops = lcsOps(aLines, bLines);\u000a  let added = 0;\u000a  let removed = 0;\u000a  let unchanged = 0;\u000a  for (const op of ops) {\u000a    if (op.type === "ins") added++;\u000a    else if (op.type === "del") removed++;\u000a    else unchanged++;\u000a  }\u000a\u000a  if (added === 0 && removed === 0) {\u000a    return { added, removed, unchanged, identical: true, diff: "" };\u000a  }\u000a\u000a  // Keep only context lines around runs of changes.\u000a  const keep: boolean[] = ops.map(() => false);\u000a  for (let k = 0; k < ops.length; k++) {\u000a    if (ops[k].type !== "eq") {\u000a      for (let w = Math.max(0, k - ctxLines); w <= Math.min(ops.length - 1, k + ctxLines); w++) {\u000a        keep[w] = true;\u000a      }\u000a    }\u000a  }\u000a  const lines: string[] = [];\u000a  let lastKept = false;\u000a  for (let k = 0; k < ops.length; k++) {\u000a    if (!keep[k]) {\u000a      lastKept = false;\u000a      continue;\u000a    }\u000a    if (!lastKept && lines.length > 0) lines.push("@@");\u000a    const op = ops[k];\u000a    const prefix = op.type === "ins" ? "+" : op.type === "del" ? "-" : " ";\u000a    lines.push(prefix + op.text);\u000a    lastKept = true;\u000a  }\u000a\u000a  return { added, removed, unchanged, identical: false, diff: lines.join("\\n") };\u000a}\u000a'),'Compare two strings line-by-line with an LCS diff and return a unified-diff summary plus added/removed/unchanged counts.','See exactly what changed between two versions of a text, config or document.','{"argsType":"any","resultType":"unknown","description":"Compare two strings line-by-line and return a unified-diff summary."}','5757420b2624fe414711b7127930247aaa937bfd415d7e0308e9ed4b11238b5a',1,0,1,'none',NULL,'2026-06-11T22:38:22.905Z','2026-06-11T22:38:22.905Z','{"$schema":"https://json-schema.org/draft/2020-12/schema","type":"object","properties":{"a":{"type":"string","description":"Original / left-hand text"},"b":{"type":"string","description":"Updated / right-hand text"},"context":{"description":"Lines of unchanged context to keep around each change (default 3)","type":"integer","minimum":0,"maximum":9007199254740991}},"required":["a","b"],"additionalProperties":false}',NULL,NULL);
INSERT INTO scripts VALUES('72d3122e-4c96-489f-9787-baac5b3f5dc0','task-failure-audit','global',NULL,unistr('export type CatalogReportFinding = {\u000a  id: string;\u000a  severity?: string;\u000a  summary: string;\u000a  action?: string;\u000a  samples?: unknown[];\u000a};\u000a\u000aexport type CatalogReportSection = {\u000a  key: string;\u000a  label?: string;\u000a  goal: string;\u000a  findingCount?: number;\u000a  checks?: Record<string, unknown>;\u000a  findings?: CatalogReportFinding[];\u000a};\u000a\u000aexport type CatalogReport = {\u000a  title: string;\u000a  slug: string;\u000a  description: string;\u000a  generatedAt: string;\u000a  lede: string;\u000a  metrics: Array<[string, unknown]>;\u000a  sections: CatalogReportSection[];\u000a  appendix: unknown;\u000a};\u000a\u000afunction catalogReportAsText(value: unknown): string {\u000a  return typeof value === "string" ? value : value == null ? "" : JSON.stringify(value);\u000a}\u000a\u000afunction catalogReportHtmlEscape(value: unknown): string {\u000a  return catalogReportAsText(value)\u000a    .replace(/&/g, "&amp;")\u000a    .replace(/</g, "&lt;")\u000a    .replace(/>/g, "&gt;")\u000a    .replace(/"/g, "&quot;");\u000a}\u000a\u000afunction catalogReportHumanLabel(value: string): string {\u000a  return value\u000a    .replace(/([a-z0-9])([A-Z])/g, "$1 $2")\u000a    .replace(/[-_.]+/g, " ")\u000a    .replace(/\\b\\w/g, (char) => char.toUpperCase());\u000a}\u000a\u000afunction catalogReportFormatMetric(value: unknown): string {\u000a  if (typeof value === "number") return new Intl.NumberFormat("en-US").format(value);\u000a  return catalogReportAsText(value);\u000a}\u000a\u000afunction catalogReportSeverityTone(value?: string): string {\u000a  if (value === "critical") return "danger";\u000a  if (value === "high") return "warn";\u000a  if (value === "medium") return "note";\u000a  return "low";\u000a}\u000a\u000afunction catalogReportRenderSampleValue(value: unknown): string {\u000a  if (Array.isArray(value)) {\u000a    return value\u000a      .map((item) => (typeof item === "object" && item !== null ? JSON.stringify(item) : catalogReportAsText(item)))\u000a      .join(", ");\u000a  }\u000a  if (value && typeof value === "object") return JSON.stringify(value);\u000a  return catalogReportAsText(value);\u000a}\u000a\u000afunction catalogReportRenderSamples(samples?: unknown[]): string {\u000a  if (!Array.isArray(samples) || samples.length === 0) return "";\u000a  const normalized = samples.map((sampleRow) =>\u000a    sampleRow && typeof sampleRow === "object" && !Array.isArray(sampleRow)\u000a      ? (sampleRow as Record<string, unknown>)\u000a      : { value: sampleRow },\u000a  );\u000a  const columns = Array.from(\u000a    new Set(normalized.flatMap((sampleRow) => Object.keys(sampleRow).slice(0, 6))),\u000a  ).slice(0, 6);\u000a  if (columns.length === 0) return "";\u000a  const rows = normalized\u000a    .map(\u000a      (sampleRow) =>\u000a        `<tr>${columns\u000a          .map((column) => `<td>${catalogReportHtmlEscape(catalogReportRenderSampleValue(sampleRow[column]))}</td>`)\u000a          .join("")}</tr>`,\u000a    )\u000a    .join("");\u000a  return `<div class="sample-table" aria-label="Sample rows">\u000a    <table>\u000a      <thead><tr>${columns.map((column) => `<th>${catalogReportHtmlEscape(catalogReportHumanLabel(column))}</th>`).join("")}</tr></thead>\u000a      <tbody>${rows}</tbody>\u000a    </table>\u000a  </div>`;\u000a}\u000a\u000aexport function renderCatalogReportPage(report: CatalogReport): string {\u000a  const sections = report.sections\u000a    .map((section) => {\u000a      const findings = (section.findings || [])\u000a        .map(\u000a          (finding) => `<article class="finding ${catalogReportHtmlEscape(catalogReportSeverityTone(finding.severity))}">\u000a            <div class="finding-head">\u000a              <div>\u000a                <p class="finding-id">${catalogReportHtmlEscape(finding.id)}</p>\u000a                <h3>${catalogReportHtmlEscape(finding.summary)}</h3>\u000a              </div>\u000a              <span class="pill ${catalogReportHtmlEscape(catalogReportSeverityTone(finding.severity))}">${catalogReportHtmlEscape(\u000a                finding.severity || "low",\u000a              )}</span>\u000a            </div>\u000a            ${finding.action ? `<p class="action">${catalogReportHtmlEscape(finding.action)}</p>` : ""}\u000a            ${catalogReportRenderSamples(finding.samples)}\u000a          </article>`,\u000a        )\u000a        .join("");\u000a      const checks = Object.entries(section.checks || {})\u000a        .map(\u000a          ([label, value]) =>\u000a            `<div class="check"><span>${catalogReportHtmlEscape(catalogReportHumanLabel(label))}</span><strong>${catalogReportHtmlEscape(\u000a              catalogReportFormatMetric(value),\u000a            )}</strong></div>`,\u000a        )\u000a        .join("");\u000a      return `<section class="section">\u000a        <div class="section-grid">\u000a          <aside class="checks">\u000a            <p class="section-kicker">${catalogReportHtmlEscape(section.label || catalogReportHumanLabel(section.key))}</p>\u000a            <div class="check-list">${checks}</div>\u000a          </aside>\u000a          <div>\u000a            <div class="section-head">\u000a              <h2>${catalogReportHtmlEscape(section.goal)}</h2>\u000a              <span>${catalogReportHtmlEscape(catalogReportFormatMetric(section.findingCount ?? section.findings?.length ?? 0))} finding(s)</span>\u000a            </div>\u000a            <div class="findings">\u000a              ${findings || ''<p class="empty">No actionable findings in this cluster.</p>''}\u000a            </div>\u000a          </div>\u000a        </div>\u000a      </section>`;\u000a    })\u000a    .join("\\n");\u000a  return `<!doctype html>\u000a<html lang="en">\u000a<head>\u000a  <meta charset="utf-8">\u000a  <meta name="viewport" content="width=device-width, initial-scale=1">\u000a  <meta name="theme-color" content="#f5f2ea">\u000a  <title>${catalogReportHtmlEscape(report.title)}</title>\u000a  <style>\u000a    :root {\u000a      color-scheme: light;\u000a      --bg: #f5f2ea;\u000a      --panel: #ffffff;\u000a      --ink: #18181b;\u000a      --muted: #5f6368;\u000a      --line: #ded8cb;\u000a      --accent: #255c99;\u000a      --danger: #b42318;\u000a      --danger-bg: #fff1f0;\u000a      --warn: #b54708;\u000a      --warn-bg: #fff7ed;\u000a      --note: #175cd3;\u000a      --note-bg: #eff6ff;\u000a      --low: #067647;\u000a      --low-bg: #ecfdf3;\u000a      --radius: 8px;\u000a      --shadow: 0 1px 2px rgba(24, 24, 27, 0.06), 0 14px 36px rgba(24, 24, 27, 0.07);\u000a    }\u000a    * { box-sizing: border-box; }\u000a    body {\u000a      margin: 0;\u000a      background: var(--bg);\u000a      color: var(--ink);\u000a      font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;\u000a      font-size: 16px;\u000a      line-height: 1.55;\u000a    }\u000a    main {\u000a      width: min(1120px, calc(100% - 32px));\u000a      margin: 0 auto;\u000a      padding: 48px 0 72px;\u000a    }\u000a    header { margin-bottom: 28px; }\u000a    .eyebrow {\u000a      margin: 0 0 8px;\u000a      color: var(--muted);\u000a      font-size: 13px;\u000a      font-weight: 750;\u000a      letter-spacing: 0.08em;\u000a      text-transform: uppercase;\u000a    }\u000a    h1 {\u000a      margin: 0;\u000a      max-width: 860px;\u000a      font-size: clamp(2rem, 4vw, 3rem);\u000a      line-height: 1.05;\u000a      letter-spacing: 0;\u000a    }\u000a    .lede {\u000a      max-width: 780px;\u000a      margin: 16px 0 0;\u000a      color: var(--muted);\u000a      font-size: 18px;\u000a    }\u000a    .metrics {\u000a      display: grid;\u000a      grid-template-columns: repeat(4, minmax(0, 1fr));\u000a      gap: 12px;\u000a      margin: 32px 0;\u000a    }\u000a    .metric, .section, details {\u000a      background: var(--panel);\u000a      border: 1px solid var(--line);\u000a      border-radius: var(--radius);\u000a      box-shadow: var(--shadow);\u000a    }\u000a    .metric { padding: 18px; }\u000a    .metric strong {\u000a      display: block;\u000a      font-size: 32px;\u000a      line-height: 1;\u000a      font-variant-numeric: tabular-nums;\u000a    }\u000a    .metric span {\u000a      display: block;\u000a      margin-top: 8px;\u000a      color: var(--muted);\u000a      font-size: 13px;\u000a      font-weight: 650;\u000a    }\u000a    .section {\u000a      margin-top: 18px;\u000a      padding: 24px;\u000a    }\u000a    .section-grid {\u000a      display: grid;\u000a      grid-template-columns: 260px minmax(0, 1fr);\u000a      gap: 28px;\u000a    }\u000a    .section-kicker {\u000a      margin: 0 0 12px;\u000a      color: var(--accent);\u000a      font-size: 13px;\u000a      font-weight: 800;\u000a      letter-spacing: 0.08em;\u000a      text-transform: uppercase;\u000a    }\u000a    .check-list {\u000a      display: grid;\u000a      gap: 8px;\u000a    }\u000a    .check {\u000a      display: flex;\u000a      align-items: baseline;\u000a      justify-content: space-between;\u000a      gap: 12px;\u000a      padding: 10px 0;\u000a      border-bottom: 1px solid var(--line);\u000a    }\u000a    .check span {\u000a      color: var(--muted);\u000a      font-size: 13px;\u000a    }\u000a    .check strong {\u000a      font-size: 18px;\u000a      font-variant-numeric: tabular-nums;\u000a    }\u000a    .section-head {\u000a      display: flex;\u000a      align-items: start;\u000a      justify-content: space-between;\u000a      gap: 16px;\u000a      margin-bottom: 16px;\u000a    }\u000a    .section-head h2 {\u000a      max-width: 680px;\u000a      margin: 0;\u000a      font-size: 24px;\u000a      line-height: 1.2;\u000a      letter-spacing: 0;\u000a    }\u000a    .section-head > span {\u000a      flex: 0 0 auto;\u000a      color: var(--muted);\u000a      font-size: 13px;\u000a      font-weight: 700;\u000a      white-space: nowrap;\u000a    }\u000a    .findings {\u000a      display: grid;\u000a      gap: 12px;\u000a    }\u000a    .finding {\u000a      border: 1px solid var(--line);\u000a      border-left: 4px solid var(--note);\u000a      border-radius: var(--radius);\u000a      padding: 16px;\u000a      background: #fffdf8;\u000a    }\u000a    .finding.danger { border-left-color: var(--danger); }\u000a    .finding.warn { border-left-color: var(--warn); }\u000a    .finding.low { border-left-color: var(--low); }\u000a    .finding-head {\u000a      display: flex;\u000a      align-items: start;\u000a      justify-content: space-between;\u000a      gap: 16px;\u000a    }\u000a    .finding-id {\u000a      margin: 0 0 4px;\u000a      color: var(--muted);\u000a      font-family: ui-monospace, SFMono-Regular, Menlo, Consolas, monospace;\u000a      font-size: 12px;\u000a    }\u000a    h3 {\u000a      margin: 0;\u000a      font-size: 17px;\u000a      line-height: 1.3;\u000a      letter-spacing: 0;\u000a    }\u000a    .pill {\u000a      display: inline-flex;\u000a      align-items: center;\u000a      min-height: 26px;\u000a      padding: 4px 9px;\u000a      border-radius: 999px;\u000a      font-size: 12px;\u000a      font-weight: 800;\u000a      text-transform: uppercase;\u000a      white-space: nowrap;\u000a    }\u000a    .pill.danger { background: var(--danger-bg); color: var(--danger); }\u000a    .pill.warn { background: var(--warn-bg); color: var(--warn); }\u000a    .pill.note { background: var(--note-bg); color: var(--note); }\u000a    .pill.low { background: var(--low-bg); color: var(--low); }\u000a    .action {\u000a      margin: 10px 0 0;\u000a      color: var(--muted);\u000a    }\u000a    .sample-table {\u000a      margin-top: 14px;\u000a      overflow-x: auto;\u000a      border: 1px solid var(--line);\u000a      border-radius: var(--radius);\u000a      background: var(--panel);\u000a    }\u000a    table {\u000a      width: 100%;\u000a      min-width: 640px;\u000a      border-collapse: collapse;\u000a    }\u000a    th, td {\u000a      padding: 10px 12px;\u000a      border-bottom: 1px solid var(--line);\u000a      text-align: left;\u000a      vertical-align: top;\u000a    }\u000a    th {\u000a      color: var(--muted);\u000a      font-size: 12px;\u000a      font-weight: 800;\u000a      letter-spacing: 0.06em;\u000a      text-transform: uppercase;\u000a    }\u000a    td {\u000a      max-width: 360px;\u000a      color: #27272a;\u000a      font-size: 13px;\u000a      overflow-wrap: anywhere;\u000a    }\u000a    tr:last-child td { border-bottom: 0; }\u000a    .empty {\u000a      margin: 0;\u000a      color: var(--muted);\u000a    }\u000a    details {\u000a      margin-top: 24px;\u000a      padding: 18px;\u000a    }\u000a    summary {\u000a      cursor: pointer;\u000a      font-weight: 800;\u000a    }\u000a    pre {\u000a      margin: 16px 0 0;\u000a      max-height: 560px;\u000a      overflow: auto;\u000a      padding: 16px;\u000a      border-radius: var(--radius);\u000a      background: #111827;\u000a      color: #f9fafb;\u000a      font-size: 12px;\u000a      line-height: 1.45;\u000a    }\u000a    @media (max-width: 860px) {\u000a      main { width: min(100% - 24px, 1120px); padding-top: 32px; }\u000a      .metrics { grid-template-columns: repeat(2, minmax(0, 1fr)); }\u000a      .section-grid { grid-template-columns: 1fr; gap: 18px; }\u000a      .section { padding: 18px; }\u000a      .section-head { display: block; }\u000a      .section-head > span { display: block; margin-top: 8px; }\u000a    }\u000a    @media (max-width: 520px) {\u000a      .metrics { grid-template-columns: 1fr; }\u000a      .lede { font-size: 16px; }\u000a      .finding-head { display: block; }\u000a      .pill { margin-top: 10px; }\u000a    }\u000a  </style>\u000a</head>\u000a<body>\u000a  <main>\u000a    <header>\u000a      <p class="eyebrow">Generated ${catalogReportHtmlEscape(report.generatedAt)}</p>\u000a      <h1>${catalogReportHtmlEscape(report.title)}</h1>\u000a      <p class="lede">${catalogReportHtmlEscape(report.lede)}</p>\u000a    </header>\u000a    <section class="metrics" aria-label="Audit summary">\u000a      ${report.metrics\u000a        .map(\u000a          ([label, value]) =>\u000a            `<div class="metric"><strong>${catalogReportHtmlEscape(catalogReportFormatMetric(value))}</strong><span>${catalogReportHtmlEscape(\u000a              label,\u000a            )}</span></div>`,\u000a        )\u000a        .join("")}\u000a    </section>\u000a    ${sections}\u000a    <details>\u000a      <summary>Compressed JSON appendix</summary>\u000a      <pre>${catalogReportHtmlEscape(JSON.stringify(report.appendix, null, 2))}</pre>\u000a    </details>\u000a  </main>\u000a</body>\u000a</html>`;\u000a}\u000a\u000aexport async function publishCatalogReportPage(report: CatalogReport, ctx: any): Promise<any> {\u000a  const response = await ctx.swarm.page_create({\u000a    title: report.title,\u000a    slug: report.slug,\u000a    description: report.description,\u000a    contentType: "text/html",\u000a    authMode: "authed",\u000a    body: renderCatalogReportPage(report),\u000a  });\u000a  const payload = response?.data ?? response;\u000a  if (payload?.success === false) return { error: payload.error || "page_create failed" };\u000a  return {\u000a    id: payload?.id ?? payload?.page?.id ?? null,\u000a    appUrl: payload?.appUrl ?? payload?.app_url ?? null,\u000a    apiUrl: payload?.apiUrl ?? payload?.api_url ?? null,\u000a    version: payload?.version ?? payload?.page?.version ?? null,\u000a  };\u000a}\u000a\u000a\u000aimport { z } from "zod";\u000aexport const argsSchema = z.object({\u000a  days: z\u000a    .number()\u000a    .int()\u000a    .positive()\u000a    .optional()\u000a    .describe("Look back this many days for failed tasks (default 7)"),\u000a  groupBy: z\u000a    .enum(["reason", "agent", "schedule"])\u000a    .optional()\u000a    .describe("Cluster failures by failure reason, agent, or schedule (default reason)"),\u000a  limit: z\u000a    .number()\u000a    .int()\u000a    .positive()\u000a    .optional()\u000a    .describe("Max failed tasks to scan (default 500)"),\u000a  publishPage: z.boolean().optional().describe("Publish an authed HTML page (default true)"),\u000a});\u000a\u000aconst REASON_PATTERNS: any[] = [\u000a  { key: "sigterm/killed", re: /sigterm|sigkill|killed|143|137/i },\u000a  { key: "timeout", re: /time?d?\\s*out|timeout|deadline/i },\u000a  { key: "context-window", re: /context (window|limit|saturat)|peakcontext|compact/i },\u000a  { key: "not-found", re: /not found|404|missing|no such/i },\u000a  { key: "auth/credentials", re: /unauthorized|401|403|credential|token|forbidden/i },\u000a  { key: "ci/checks-failed", re: /ci|check.?s? fail|lint|tsc|test.?s? fail/i },\u000a  { key: "network", re: /network|econn|fetch failed|socket|dns|502|503|504/i },\u000a  { key: "cancelled", re: /cancel|aborted/i },\u000a];\u000a\u000afunction reasonCluster(reason: string): string {\u000a  const r = (reason || "").trim();\u000a  if (!r) return "(no reason given)";\u000a  for (const p of REASON_PATTERNS) {\u000a    if (p.re.test(r)) return p.key;\u000a  }\u000a  return r.toLowerCase().slice(0, 48);\u000a}\u000a\u000a/** Cluster recently failed swarm tasks by reason, agent, or schedule. */\u000aexport default async function taskFailureAudit(args: any, ctx: any) {\u000a  const parsed = argsSchema.safeParse(args);\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a  const days = parsed.data.days || 7;\u000a  const groupBy = parsed.data.groupBy || "reason";\u000a  const limit = parsed.data.limit || 500;\u000a  const publishPage = parsed.data.publishPage !== false;\u000a\u000a  const since = new Date(Date.now() - days * 86400000).toISOString();\u000a  const res: any = await ctx.swarm.task_list({\u000a    status: "failed",\u000a    createdAfter: since,\u000a    limit,\u000a  });\u000a  if (res && res.success === false) {\u000a    return { error: "task_list failed with status " + res.status };\u000a  }\u000a  const payload: any = res && res.data ? res.data : res;\u000a  const tasks: any = payload && Array.isArray(payload.tasks) ? payload.tasks : [];\u000a\u000a  const groups: any = {};\u000a  for (const t of tasks) {\u000a    let key: string;\u000a    if (groupBy === "agent") key = t.agentId || "(unassigned)";\u000a    else if (groupBy === "schedule") key = t.scheduleId || "(not scheduled)";\u000a    else key = reasonCluster(t.failureReason || "");\u000a    if (!groups[key]) groups[key] = { key, count: 0, taskIds: [], sampleReason: "" };\u000a    groups[key].count++;\u000a    if (groups[key].taskIds.length < 5) groups[key].taskIds.push(t.id);\u000a    if (!groups[key].sampleReason && t.failureReason) {\u000a      groups[key].sampleReason = String(t.failureReason).slice(0, 200);\u000a    }\u000a  }\u000a\u000a  const rows: any[] = Object.keys(groups)\u000a    .map((k: string) => groups[k])\u000a    .sort((a: any, b: any) => b.count - a.count);\u000a\u000a  const result: any = {\u000a    days,\u000a    groupBy,\u000a    totalFailed: tasks.length,\u000a    clusterCount: rows.length,\u000a    groups: rows,\u000a  };\u000a\u000a  if (publishPage) {\u000a    result.page = await publishCatalogReportPage(\u000a      {\u000a        title: "Task Failure Audit",\u000a        slug: "task-failure-audit",\u000a        description: "Clustered audit of recently failed swarm tasks.",\u000a        generatedAt: new Date().toISOString(),\u000a        lede: `Clustered ${tasks.length} failed task(s) over ${days} day(s) by ${groupBy}.`,\u000a        metrics: [\u000a          ["Failed tasks", tasks.length],\u000a          ["Clusters", rows.length],\u000a          ["Days", days],\u000a          ["Limit", limit],\u000a        ],\u000a        sections: [\u000a          {\u000a            key: "failure-clusters",\u000a            goal: "Surface repeated failure modes before they become operational drift.",\u000a            findingCount: rows.length,\u000a            checks: { totalFailed: tasks.length, clusterCount: rows.length, groupBy },\u000a            findings: rows.map((group: any) => ({\u000a              id: `failure.${group.key}`,\u000a              severity: group.count >= 5 ? "high" : group.count >= 2 ? "medium" : "low",\u000a              summary: `${group.count} failed task(s) in ${group.key}.`,\u000a              action: "Inspect the sample task IDs and decide whether this needs a fix, retry, or HEARTBEAT watch item.",\u000a              samples: [\u000a                {\u000a                  key: group.key,\u000a                  count: group.count,\u000a                  taskIds: group.taskIds,\u000a                  sampleReason: group.sampleReason,\u000a                },\u000a              ],\u000a            })),\u000a          },\u000a        ],\u000a        appendix: result,\u000a      },\u000a      ctx,\u000a    );\u000a  }\u000a\u000a  return result;\u000a}\u000a'),'Scan recently failed swarm tasks and cluster them by failure reason, agent or schedule to surface recurring problems.','Find patterns in swarm task failures — which agent, schedule or error keeps breaking — for a reliability review.','{"argsType":"any","resultType":"unknown","description":"Cluster recently failed swarm tasks by reason, agent, or schedule."}','519728190085f68c0e43cdacebdf998e581dacb782a604a24be0d3c39ccf4ad0',1,0,1,'none',NULL,'2026-06-11T22:38:23.047Z','2026-06-11T22:38:23.047Z','{"$schema":"https://json-schema.org/draft/2020-12/schema","type":"object","properties":{"days":{"description":"Look back this many days for failed tasks (default 7)","type":"integer","exclusiveMinimum":0,"maximum":9007199254740991,"minimum":-9007199254740991},"groupBy":{"description":"Cluster failures by failure reason, agent, or schedule (default reason)","type":"string","enum":["reason","agent","schedule"]},"limit":{"description":"Max failed tasks to scan (default 500)","type":"integer","exclusiveMinimum":0,"maximum":9007199254740991,"minimum":-9007199254740991},"publishPage":{"description":"Publish an authed HTML page (default true)","type":"boolean"}},"additionalProperties":false}',NULL,NULL);
INSERT INTO scripts VALUES('fcf1bed5-7b3c-4de3-8f26-e46b50bee551','memory-dedup-check','global',NULL,unistr('import { z } from "zod";\u000a\u000aexport const argsSchema = z.object({\u000a  text: z.string().describe("Candidate memory text to check for near-duplicates"),\u000a  threshold: z\u000a    .number()\u000a    .min(0)\u000a    .max(1)\u000a    .optional()\u000a    .describe("Minimum cosine similarity to count as a duplicate (default 0.85)"),\u000a  limit: z\u000a    .number()\u000a    .int()\u000a    .positive()\u000a    .optional()\u000a    .describe("Max existing memories to compare against (default 10)"),\u000a});\u000a\u000a/** Semantic-search existing memories and flag near-duplicates before you save a new one. */\u000aexport default async function memoryDedupCheck(args: any, ctx: any) {\u000a  const parsed = argsSchema.safeParse(args);\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a  const text = parsed.data.text.trim();\u000a  if (!text) return { error: "text must not be empty" };\u000a  const threshold = parsed.data.threshold == null ? 0.85 : parsed.data.threshold;\u000a  const limit = parsed.data.limit || 10;\u000a\u000a  const res: any = await ctx.swarm.memory_search({ query: text, scope: "all", limit });\u000a  if (res && res.success === false) {\u000a    return { error: "memory_search failed with status " + res.status };\u000a  }\u000a  const payload: any = res && res.data ? res.data : res;\u000a  const results: any = payload && Array.isArray(payload.results) ? payload.results : [];\u000a\u000a  const duplicates: any[] = [];\u000a  for (const r of results) {\u000a    const score = typeof r.similarity === "number" ? r.similarity : 0;\u000a    if (score >= threshold) {\u000a      duplicates.push({\u000a        id: r.id,\u000a        name: r.name,\u000a        similarity: Math.round(score * 1000) / 1000,\u000a        scope: r.scope,\u000a        source: r.source,\u000a        preview: typeof r.content === "string" ? r.content.slice(0, 200) : "",\u000a      });\u000a    }\u000a  }\u000a  duplicates.sort((a: any, b: any) => b.similarity - a.similarity);\u000a\u000a  return {\u000a    isDuplicate: duplicates.length > 0,\u000a    duplicateCount: duplicates.length,\u000a    threshold,\u000a    comparedAgainst: results.length,\u000a    topSimilarity: results.length > 0 && typeof results[0].similarity === "number"\u000a      ? Math.round(results[0].similarity * 1000) / 1000\u000a      : 0,\u000a    duplicates,\u000a  };\u000a}\u000a'),'Semantic-search existing swarm memories for near-duplicates of a candidate text and report matches above a similarity threshold.','Avoid writing a redundant memory — check whether something equivalent is already stored before saving.','{"argsType":"any","resultType":"unknown","description":"Semantic-search existing memories and flag near-duplicates before you save a new one."}','e86cdf31958ae2d11319a60f7530fef52e010edf316bc62afa868ea68b58ce5f',1,0,1,'none',NULL,'2026-06-11T22:38:23.174Z','2026-06-11T22:38:23.174Z','{"$schema":"https://json-schema.org/draft/2020-12/schema","type":"object","properties":{"text":{"type":"string","description":"Candidate memory text to check for near-duplicates"},"threshold":{"description":"Minimum cosine similarity to count as a duplicate (default 0.85)","type":"number","minimum":0,"maximum":1},"limit":{"description":"Max existing memories to compare against (default 10)","type":"integer","exclusiveMinimum":0,"maximum":9007199254740991,"minimum":-9007199254740991}},"required":["text"],"additionalProperties":false}',NULL,NULL);
INSERT INTO scripts VALUES('a66c75b2-ec9d-41aa-b508-0586252cdbbd','linear-issue','global',NULL,unistr('import { z } from "zod";\u000a\u000aexport const argsSchema = z.object({\u000a  key: z.string().describe("Linear issue identifier, e.g. ''DES-123''"),\u000a  token: z\u000a    .string()\u000a    .optional()\u000a    .describe("Linear API key override; falls back to the LINEAR_API_KEY swarm config"),\u000a});\u000a\u000aasync function resolveSecret(ctx: any, key: string, override: unknown): Promise<string | null> {\u000a  if (typeof override === "string" && override.length > 0) return override;\u000a  try {\u000a    const base = ctx.stdlib.Redacted.value(ctx.swarm.config.mcpBaseUrl).replace(/\\/+$/, "");\u000a    const apiKey = ctx.stdlib.Redacted.value(ctx.swarm.config.apiKey);\u000a    const res: any = await ctx.stdlib.fetchJson(\u000a      base + "/api/config/resolved?includeSecrets=true",\u000a      { headers: { Authorization: "Bearer " + apiKey } },\u000a    );\u000a    const configs: any = res && Array.isArray(res.configs) ? res.configs : [];\u000a    for (const c of configs) {\u000a      if (c && c.key === key && typeof c.value === "string" && c.value.length > 0) {\u000a        return c.value;\u000a      }\u000a    }\u000a  } catch {\u000a    // Best-effort.\u000a  }\u000a  return null;\u000a}\u000a\u000a/** Fetch a Linear issue (title, status, assignee, comments) by its DES-123 identifier. */\u000aexport default async function linearIssue(args: any, ctx: any) {\u000a  const parsed = argsSchema.safeParse(args);\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a  const key = parsed.data.key.trim().toUpperCase();\u000a  const m = key.match(/^([A-Z][A-Z0-9]*)-(\\d+)$/);\u000a  if (!m) return { error: "key must look like ''DES-123''" };\u000a  const teamKey = m[1] as string;\u000a  const number = Number.parseInt(m[2] as string, 10);\u000a\u000a  const token = await resolveSecret(ctx, "LINEAR_API_KEY", parsed.data.token);\u000a  if (!token) {\u000a    return {\u000a      error: "no Linear API key available",\u000a      hint: "set the LINEAR_API_KEY swarm config or pass a ''token'' arg",\u000a    };\u000a  }\u000a\u000a  const query = `query {\u000a    issues(filter: { team: { key: { eq: "${teamKey}" } }, number: { eq: ${number} } }, first: 1) {\u000a      nodes {\u000a        identifier\u000a        title\u000a        url\u000a        priorityLabel\u000a        state { name type }\u000a        assignee { name displayName }\u000a        comments(first: 50) {\u000a          nodes { body createdAt user { name displayName } }\u000a        }\u000a      }\u000a    }\u000a  }`;\u000a\u000a  const res: any = await ctx.stdlib.fetchJson("https://api.linear.app/graphql", {\u000a    method: "POST",\u000a    headers: { "Content-Type": "application/json", Authorization: token },\u000a    body: JSON.stringify({ query }),\u000a  });\u000a  if (res && res.errors && res.errors.length > 0) {\u000a    return { error: "Linear API error: " + (res.errors[0].message || "unknown") };\u000a  }\u000a  const nodes: any =\u000a    res && res.data && res.data.issues && Array.isArray(res.data.issues.nodes)\u000a      ? res.data.issues.nodes\u000a      : [];\u000a  if (nodes.length === 0) return { error: "issue " + key + " not found" };\u000a\u000a  const issue: any = nodes[0];\u000a  const assignee = issue.assignee\u000a    ? issue.assignee.displayName || issue.assignee.name || null\u000a    : null;\u000a  const comments: any[] = (\u000a    issue.comments && Array.isArray(issue.comments.nodes) ? issue.comments.nodes : []\u000a  ).map((c: any) => ({\u000a    body: c.body,\u000a    author: c.user ? c.user.displayName || c.user.name : "unknown",\u000a    createdAt: c.createdAt,\u000a  }));\u000a\u000a  return {\u000a    key: issue.identifier,\u000a    title: issue.title,\u000a    status: issue.state ? issue.state.name : "unknown",\u000a    statusType: issue.state ? issue.state.type : null,\u000a    priority: issue.priorityLabel || null,\u000a    assignee,\u000a    url: issue.url,\u000a    commentCount: comments.length,\u000a    comments,\u000a  };\u000a}\u000a'),'Fetch a Linear issue by its identifier (e.g. DES-123): title, status, priority, assignee and comments.','Pull Linear ticket context into a task without leaving the swarm or opening a browser.','{"argsType":"any","resultType":"unknown","description":"Fetch a Linear issue (title, status, assignee, comments) by its DES-123 identifier."}','11bb732c6165e6f46c502b5f3c89ef17ef2d8f3226f6b1325483af85bdf1eebb',1,0,1,'none',NULL,'2026-06-11T22:38:23.300Z','2026-06-11T22:38:23.300Z','{"$schema":"https://json-schema.org/draft/2020-12/schema","type":"object","properties":{"key":{"type":"string","description":"Linear issue identifier, e.g. ''DES-123''"},"token":{"description":"Linear API key override; falls back to the LINEAR_API_KEY swarm config","type":"string"}},"required":["key"],"additionalProperties":false}',NULL,NULL);
INSERT INTO scripts VALUES('ff9b7185-e466-4885-82df-49827905d6de','slack-thread-flatten','global',NULL,unistr('import { z } from "zod";\u000a\u000aexport const argsSchema = z.object({\u000a  channelId: z.string().describe("Slack channel ID, e.g. ''C0AR967K0KZ''"),\u000a  threadTs: z.string().describe("Thread timestamp (ts) of the root message"),\u000a  token: z\u000a    .string()\u000a    .optional()\u000a    .describe("Slack bot token override; falls back to the SLACK_BOT_TOKEN swarm config"),\u000a});\u000a\u000aasync function resolveSecret(ctx: any, key: string, override: unknown): Promise<string | null> {\u000a  if (typeof override === "string" && override.length > 0) return override;\u000a  try {\u000a    const base = ctx.stdlib.Redacted.value(ctx.swarm.config.mcpBaseUrl).replace(/\\/+$/, "");\u000a    const apiKey = ctx.stdlib.Redacted.value(ctx.swarm.config.apiKey);\u000a    const res: any = await ctx.stdlib.fetchJson(\u000a      base + "/api/config/resolved?includeSecrets=true",\u000a      { headers: { Authorization: "Bearer " + apiKey } },\u000a    );\u000a    const configs: any = res && Array.isArray(res.configs) ? res.configs : [];\u000a    for (const c of configs) {\u000a      if (c && c.key === key && typeof c.value === "string" && c.value.length > 0) {\u000a        return c.value;\u000a      }\u000a    }\u000a  } catch {\u000a    // Best-effort.\u000a  }\u000a  return null;\u000a}\u000a\u000afunction tsToIso(ts: string): string {\u000a  const seconds = Number.parseFloat(ts);\u000a  return Number.isNaN(seconds) ? ts : new Date(seconds * 1000).toISOString();\u000a}\u000a\u000a/** Flatten a Slack thread into a readable, chronological transcript. */\u000aexport default async function slackThreadFlatten(args: any, ctx: any) {\u000a  const parsed = argsSchema.safeParse(args);\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a  const { channelId, threadTs } = parsed.data;\u000a\u000a  const token = await resolveSecret(ctx, "SLACK_BOT_TOKEN", parsed.data.token);\u000a  if (!token) {\u000a    return {\u000a      error: "no Slack bot token available",\u000a      hint: "set the SLACK_BOT_TOKEN swarm config or pass a ''token'' arg",\u000a    };\u000a  }\u000a\u000a  const url =\u000a    "https://slack.com/api/conversations.replies?channel=" +\u000a    encodeURIComponent(channelId) +\u000a    "&ts=" +\u000a    encodeURIComponent(threadTs) +\u000a    "&limit=1000";\u000a  const res: any = await ctx.stdlib.fetchJson(url, {\u000a    headers: { Authorization: "Bearer " + token },\u000a  });\u000a  if (!res || res.ok !== true) {\u000a    return { error: "Slack API error: " + (res && res.error ? res.error : "unknown") };\u000a  }\u000a\u000a  const raw: any = Array.isArray(res.messages) ? res.messages : [];\u000a  const messages: any[] = raw.map((m: any) => ({\u000a    author: m.username || m.user || m.bot_id || "unknown",\u000a    text: typeof m.text === "string" ? m.text : "",\u000a    ts: m.ts,\u000a    at: m.ts ? tsToIso(m.ts) : null,\u000a  }));\u000a  messages.sort((a: any, b: any) => Number.parseFloat(a.ts || "0") - Number.parseFloat(b.ts || "0"));\u000a\u000a  const transcript = messages\u000a    .map((m: any) => "[" + (m.at || m.ts) + "] " + m.author + ": " + m.text)\u000a    .join("\\n");\u000a\u000a  return {\u000a    channelId,\u000a    threadTs,\u000a    messageCount: messages.length,\u000a    hasMore: Boolean(res.has_more),\u000a    transcript,\u000a    messages,\u000a  };\u000a}\u000a'),'Fetch a Slack thread by channel + thread timestamp and flatten it into a readable chronological transcript.','Turn a Slack thread into plain text for summarizing or as task context.','{"argsType":"any","resultType":"unknown","description":"Flatten a Slack thread into a readable, chronological transcript."}','f3cefa176e7d39c0c7fb5e26d059089d5bdf1b9fa12b249188d86fb52482b7a2',1,0,1,'none',NULL,'2026-06-11T22:38:23.423Z','2026-06-11T22:38:23.423Z','{"$schema":"https://json-schema.org/draft/2020-12/schema","type":"object","properties":{"channelId":{"type":"string","description":"Slack channel ID, e.g. ''C0AR967K0KZ''"},"threadTs":{"type":"string","description":"Thread timestamp (ts) of the root message"},"token":{"description":"Slack bot token override; falls back to the SLACK_BOT_TOKEN swarm config","type":"string"}},"required":["channelId","threadTs"],"additionalProperties":false}',NULL,NULL);
INSERT INTO scripts VALUES('972543be-a0f9-434a-b5d0-7945b0dcf021','smart-recall','global',NULL,unistr('import { z } from "zod";\u000a\u000aexport const argsSchema = z.object({\u000a  queries: z\u000a    .array(z.string())\u000a    .min(1)\u000a    .describe("One or more search queries to fan out against the memory store"),\u000a  scope: z\u000a    .enum(["all", "agent", "swarm"])\u000a    .optional()\u000a    .describe("Memory scope filter (default all)"),\u000a  limit: z\u000a    .number()\u000a    .int()\u000a    .positive()\u000a    .optional()\u000a    .describe("Max results per query (default 10)"),\u000a  dedupThreshold: z\u000a    .number()\u000a    .optional()\u000a    .describe("Similarity threshold for dedup — memories above this are merged (default 0.92)"),\u000a});\u000a\u000a/** Multi-query fan-out memory recall with dedup and composite reranking. */\u000aexport default async function smartRecall(args: any, ctx: any) {\u000a  const parsed = argsSchema.safeParse(args);\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a  const { queries, scope = "all", limit = 10, dedupThreshold = 0.92 } = parsed.data;\u000a\u000a  const allResults: any[] = [];\u000a  for (const q of queries) {\u000a    const res: any = await ctx.swarm.memory_search({ query: q, limit, scope });\u000a    const payload = res?.data ?? res;\u000a    const results = payload?.results ?? [];\u000a    for (const r of results) {\u000a      allResults.push({ ...r, querySource: q });\u000a    }\u000a  }\u000a\u000a  // Dedup by ID, keeping best similarity per memory\u000a  const seen = new Map<string, any>();\u000a  const hitCounts = new Map<string, number>();\u000a  for (const r of allResults) {\u000a    hitCounts.set(r.id, (hitCounts.get(r.id) ?? 0) + 1);\u000a    const existing = seen.get(r.id);\u000a    if (!existing || r.similarity > existing.similarity) {\u000a      seen.set(r.id, r);\u000a    }\u000a  }\u000a\u000a  // Composite rerank: bestSimilarity + 0.05 * hitCount\u000a  const deduped = Array.from(seen.values()).map((r) => ({\u000a    ...r,\u000a    hits: hitCounts.get(r.id) ?? 1,\u000a    compositeScore: r.similarity + 0.05 * (hitCounts.get(r.id) ?? 1),\u000a  }));\u000a  deduped.sort((a: any, b: any) => b.compositeScore - a.compositeScore);\u000a\u000a  return {\u000a    queriesRun: queries.length,\u000a    totalCandidates: allResults.length,\u000a    uniqueMemories: deduped.length,\u000a    memories: deduped.slice(0, limit * 2),\u000a  };\u000a}\u000a'),'Multi-query fan-out memory search with dedup and composite reranking (bestSimilarity + 0.05 * hitCount). Returns unique memories across all queries.','Recall relevant memories using multiple search angles — better coverage than a single query. Use for task onboarding, context gathering, or before writing new memories.','{"argsType":"any","resultType":"unknown","description":"Multi-query fan-out memory recall with dedup and composite reranking."}','dcd3679c8573998b71c3da0a1fe3d033f638740566352250ae8af81ce47cf960',1,0,1,'none',NULL,'2026-06-11T22:38:23.549Z','2026-06-11T22:38:23.549Z','{"$schema":"https://json-schema.org/draft/2020-12/schema","type":"object","properties":{"queries":{"minItems":1,"type":"array","items":{"type":"string"},"description":"One or more search queries to fan out against the memory store"},"scope":{"description":"Memory scope filter (default all)","type":"string","enum":["all","agent","swarm"]},"limit":{"description":"Max results per query (default 10)","type":"integer","exclusiveMinimum":0,"maximum":9007199254740991,"minimum":-9007199254740991},"dedupThreshold":{"description":"Similarity threshold for dedup — memories above this are merged (default 0.92)","type":"number"}},"required":["queries"],"additionalProperties":false}',NULL,NULL);
INSERT INTO scripts VALUES('3898797c-96df-4f19-90a7-a5f2ac203eed','task-context-gathering','global',NULL,unistr('import { z } from "zod";\u000a\u000aexport const argsSchema = z.object({\u000a  taskId: z.string().describe("Task ID to fetch details for"),\u000a  queries: z\u000a    .array(z.string())\u000a    .min(1)\u000a    .describe("Search queries from the task description — 2-4 recommended"),\u000a  scope: z\u000a    .enum(["all", "agent", "swarm"])\u000a    .optional()\u000a    .describe("Memory scope filter (default all)"),\u000a  memoryLimit: z\u000a    .number()\u000a    .int()\u000a    .positive()\u000a    .optional()\u000a    .describe("Max memories per query before dedup (default 8)"),\u000a});\u000a\u000afunction slimTask(task: any) {\u000a  if (!task || typeof task !== "object") return null;\u000a  return {\u000a    id: task.id,\u000a    status: task.status,\u000a    description: task.task,\u000a    dependsOn: task.dependsOn,\u000a    slackChannelId: task.slackChannelId,\u000a    slackThreadTs: task.slackThreadTs,\u000a    createdAt: task.createdAt,\u000a    finishedAt: task.finishedAt,\u000a    agentId: task.agentId,\u000a    output: task.output,\u000a    failureReason: task.failureReason,\u000a  };\u000a}\u000a\u000a/** Fetch slim task details plus deduped multi-query memories for task onboarding. */\u000aexport default async function taskContextGathering(args: any, ctx: any) {\u000a  const parsed = argsSchema.safeParse(args);\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a  const { taskId, queries, scope = "all", memoryLimit = 8 } = parsed.data;\u000a\u000a  const taskRes: any = await ctx.swarm.task_get({ taskId });\u000a  const taskPayload = taskRes?.data ?? taskRes;\u000a  if (taskPayload?.success === false) {\u000a    return { error: taskPayload.message ?? "task_get failed", taskId };\u000a  }\u000a\u000a  const allResults: any[] = [];\u000a  for (const query of queries) {\u000a    const res: any = await ctx.swarm.memory_search({ query, scope, limit: memoryLimit });\u000a    const payload = res?.data ?? res;\u000a    const results = payload?.results ?? [];\u000a    for (const memory of results) {\u000a      allResults.push({ ...memory, querySource: query });\u000a    }\u000a  }\u000a\u000a  const byId = new Map<string, any>();\u000a  const hitCounts = new Map<string, number>();\u000a  for (const memory of allResults) {\u000a    const id = typeof memory.id === "string" ? memory.id : JSON.stringify(memory);\u000a    hitCounts.set(id, (hitCounts.get(id) ?? 0) + 1);\u000a    const existing = byId.get(id);\u000a    const similarity = typeof memory.similarity === "number" ? memory.similarity : 0;\u000a    const existingSimilarity =\u000a      existing && typeof existing.similarity === "number" ? existing.similarity : -Infinity;\u000a    if (!existing || similarity > existingSimilarity) byId.set(id, memory);\u000a  }\u000a\u000a  const memories = Array.from(byId.entries()).map(([id, memory]) => {\u000a    const hits = hitCounts.get(id) ?? 1;\u000a    const similarity = typeof memory.similarity === "number" ? memory.similarity : 0;\u000a    return {\u000a      ...memory,\u000a      hits,\u000a      compositeScore: similarity + 0.05 * hits,\u000a    };\u000a  });\u000a  memories.sort((a: any, b: any) => b.compositeScore - a.compositeScore);\u000a\u000a  return {\u000a    task: slimTask(taskPayload?.task),\u000a    requestedBy: taskPayload?.requestedBy,\u000a    attachments: taskPayload?.attachments ?? [],\u000a    queriesRun: queries.length,\u000a    totalCandidates: allResults.length,\u000a    uniqueMemories: memories.length,\u000a    memories: memories.slice(0, memoryLimit * 2),\u000a  };\u000a}\u000a'),'Get task details and recall relevant memories in one call — returns a slimmed task projection plus deduped and reranked memories from multi-query fan-out.','Task onboarding: one call instead of task_get plus multiple memory_search calls. Pass the task description split into 2-4 natural-language queries.','{"argsType":"any","resultType":"unknown","description":"Fetch slim task details plus deduped multi-query memories for task onboarding."}','a613b00f65e74479f011aceb6674fa1bcb5892e267fd3d70a72a6ca11c6c4bcb',1,0,1,'none',NULL,'2026-06-11T22:38:23.679Z','2026-06-11T22:38:23.679Z','{"$schema":"https://json-schema.org/draft/2020-12/schema","type":"object","properties":{"taskId":{"type":"string","description":"Task ID to fetch details for"},"queries":{"minItems":1,"type":"array","items":{"type":"string"},"description":"Search queries from the task description — 2-4 recommended"},"scope":{"description":"Memory scope filter (default all)","type":"string","enum":["all","agent","swarm"]},"memoryLimit":{"description":"Max memories per query before dedup (default 8)","type":"integer","exclusiveMinimum":0,"maximum":9007199254740991,"minimum":-9007199254740991}},"required":["taskId","queries"],"additionalProperties":false}',NULL,NULL);
INSERT INTO scripts VALUES('b2d83689-526a-423e-a45f-f4fb48fd2e2a','schedule-health','global',NULL,unistr('export type CatalogReportFinding = {\u000a  id: string;\u000a  severity?: string;\u000a  summary: string;\u000a  action?: string;\u000a  samples?: unknown[];\u000a};\u000a\u000aexport type CatalogReportSection = {\u000a  key: string;\u000a  label?: string;\u000a  goal: string;\u000a  findingCount?: number;\u000a  checks?: Record<string, unknown>;\u000a  findings?: CatalogReportFinding[];\u000a};\u000a\u000aexport type CatalogReport = {\u000a  title: string;\u000a  slug: string;\u000a  description: string;\u000a  generatedAt: string;\u000a  lede: string;\u000a  metrics: Array<[string, unknown]>;\u000a  sections: CatalogReportSection[];\u000a  appendix: unknown;\u000a};\u000a\u000afunction catalogReportAsText(value: unknown): string {\u000a  return typeof value === "string" ? value : value == null ? "" : JSON.stringify(value);\u000a}\u000a\u000afunction catalogReportHtmlEscape(value: unknown): string {\u000a  return catalogReportAsText(value)\u000a    .replace(/&/g, "&amp;")\u000a    .replace(/</g, "&lt;")\u000a    .replace(/>/g, "&gt;")\u000a    .replace(/"/g, "&quot;");\u000a}\u000a\u000afunction catalogReportHumanLabel(value: string): string {\u000a  return value\u000a    .replace(/([a-z0-9])([A-Z])/g, "$1 $2")\u000a    .replace(/[-_.]+/g, " ")\u000a    .replace(/\\b\\w/g, (char) => char.toUpperCase());\u000a}\u000a\u000afunction catalogReportFormatMetric(value: unknown): string {\u000a  if (typeof value === "number") return new Intl.NumberFormat("en-US").format(value);\u000a  return catalogReportAsText(value);\u000a}\u000a\u000afunction catalogReportSeverityTone(value?: string): string {\u000a  if (value === "critical") return "danger";\u000a  if (value === "high") return "warn";\u000a  if (value === "medium") return "note";\u000a  return "low";\u000a}\u000a\u000afunction catalogReportRenderSampleValue(value: unknown): string {\u000a  if (Array.isArray(value)) {\u000a    return value\u000a      .map((item) => (typeof item === "object" && item !== null ? JSON.stringify(item) : catalogReportAsText(item)))\u000a      .join(", ");\u000a  }\u000a  if (value && typeof value === "object") return JSON.stringify(value);\u000a  return catalogReportAsText(value);\u000a}\u000a\u000afunction catalogReportRenderSamples(samples?: unknown[]): string {\u000a  if (!Array.isArray(samples) || samples.length === 0) return "";\u000a  const normalized = samples.map((sampleRow) =>\u000a    sampleRow && typeof sampleRow === "object" && !Array.isArray(sampleRow)\u000a      ? (sampleRow as Record<string, unknown>)\u000a      : { value: sampleRow },\u000a  );\u000a  const columns = Array.from(\u000a    new Set(normalized.flatMap((sampleRow) => Object.keys(sampleRow).slice(0, 6))),\u000a  ).slice(0, 6);\u000a  if (columns.length === 0) return "";\u000a  const rows = normalized\u000a    .map(\u000a      (sampleRow) =>\u000a        `<tr>${columns\u000a          .map((column) => `<td>${catalogReportHtmlEscape(catalogReportRenderSampleValue(sampleRow[column]))}</td>`)\u000a          .join("")}</tr>`,\u000a    )\u000a    .join("");\u000a  return `<div class="sample-table" aria-label="Sample rows">\u000a    <table>\u000a      <thead><tr>${columns.map((column) => `<th>${catalogReportHtmlEscape(catalogReportHumanLabel(column))}</th>`).join("")}</tr></thead>\u000a      <tbody>${rows}</tbody>\u000a    </table>\u000a  </div>`;\u000a}\u000a\u000aexport function renderCatalogReportPage(report: CatalogReport): string {\u000a  const sections = report.sections\u000a    .map((section) => {\u000a      const findings = (section.findings || [])\u000a        .map(\u000a          (finding) => `<article class="finding ${catalogReportHtmlEscape(catalogReportSeverityTone(finding.severity))}">\u000a            <div class="finding-head">\u000a              <div>\u000a                <p class="finding-id">${catalogReportHtmlEscape(finding.id)}</p>\u000a                <h3>${catalogReportHtmlEscape(finding.summary)}</h3>\u000a              </div>\u000a              <span class="pill ${catalogReportHtmlEscape(catalogReportSeverityTone(finding.severity))}">${catalogReportHtmlEscape(\u000a                finding.severity || "low",\u000a              )}</span>\u000a            </div>\u000a            ${finding.action ? `<p class="action">${catalogReportHtmlEscape(finding.action)}</p>` : ""}\u000a            ${catalogReportRenderSamples(finding.samples)}\u000a          </article>`,\u000a        )\u000a        .join("");\u000a      const checks = Object.entries(section.checks || {})\u000a        .map(\u000a          ([label, value]) =>\u000a            `<div class="check"><span>${catalogReportHtmlEscape(catalogReportHumanLabel(label))}</span><strong>${catalogReportHtmlEscape(\u000a              catalogReportFormatMetric(value),\u000a            )}</strong></div>`,\u000a        )\u000a        .join("");\u000a      return `<section class="section">\u000a        <div class="section-grid">\u000a          <aside class="checks">\u000a            <p class="section-kicker">${catalogReportHtmlEscape(section.label || catalogReportHumanLabel(section.key))}</p>\u000a            <div class="check-list">${checks}</div>\u000a          </aside>\u000a          <div>\u000a            <div class="section-head">\u000a              <h2>${catalogReportHtmlEscape(section.goal)}</h2>\u000a              <span>${catalogReportHtmlEscape(catalogReportFormatMetric(section.findingCount ?? section.findings?.length ?? 0))} finding(s)</span>\u000a            </div>\u000a            <div class="findings">\u000a              ${findings || ''<p class="empty">No actionable findings in this cluster.</p>''}\u000a            </div>\u000a          </div>\u000a        </div>\u000a      </section>`;\u000a    })\u000a    .join("\\n");\u000a  return `<!doctype html>\u000a<html lang="en">\u000a<head>\u000a  <meta charset="utf-8">\u000a  <meta name="viewport" content="width=device-width, initial-scale=1">\u000a  <meta name="theme-color" content="#f5f2ea">\u000a  <title>${catalogReportHtmlEscape(report.title)}</title>\u000a  <style>\u000a    :root {\u000a      color-scheme: light;\u000a      --bg: #f5f2ea;\u000a      --panel: #ffffff;\u000a      --ink: #18181b;\u000a      --muted: #5f6368;\u000a      --line: #ded8cb;\u000a      --accent: #255c99;\u000a      --danger: #b42318;\u000a      --danger-bg: #fff1f0;\u000a      --warn: #b54708;\u000a      --warn-bg: #fff7ed;\u000a      --note: #175cd3;\u000a      --note-bg: #eff6ff;\u000a      --low: #067647;\u000a      --low-bg: #ecfdf3;\u000a      --radius: 8px;\u000a      --shadow: 0 1px 2px rgba(24, 24, 27, 0.06), 0 14px 36px rgba(24, 24, 27, 0.07);\u000a    }\u000a    * { box-sizing: border-box; }\u000a    body {\u000a      margin: 0;\u000a      background: var(--bg);\u000a      color: var(--ink);\u000a      font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;\u000a      font-size: 16px;\u000a      line-height: 1.55;\u000a    }\u000a    main {\u000a      width: min(1120px, calc(100% - 32px));\u000a      margin: 0 auto;\u000a      padding: 48px 0 72px;\u000a    }\u000a    header { margin-bottom: 28px; }\u000a    .eyebrow {\u000a      margin: 0 0 8px;\u000a      color: var(--muted);\u000a      font-size: 13px;\u000a      font-weight: 750;\u000a      letter-spacing: 0.08em;\u000a      text-transform: uppercase;\u000a    }\u000a    h1 {\u000a      margin: 0;\u000a      max-width: 860px;\u000a      font-size: clamp(2rem, 4vw, 3rem);\u000a      line-height: 1.05;\u000a      letter-spacing: 0;\u000a    }\u000a    .lede {\u000a      max-width: 780px;\u000a      margin: 16px 0 0;\u000a      color: var(--muted);\u000a      font-size: 18px;\u000a    }\u000a    .metrics {\u000a      display: grid;\u000a      grid-template-columns: repeat(4, minmax(0, 1fr));\u000a      gap: 12px;\u000a      margin: 32px 0;\u000a    }\u000a    .metric, .section, details {\u000a      background: var(--panel);\u000a      border: 1px solid var(--line);\u000a      border-radius: var(--radius);\u000a      box-shadow: var(--shadow);\u000a    }\u000a    .metric { padding: 18px; }\u000a    .metric strong {\u000a      display: block;\u000a      font-size: 32px;\u000a      line-height: 1;\u000a      font-variant-numeric: tabular-nums;\u000a    }\u000a    .metric span {\u000a      display: block;\u000a      margin-top: 8px;\u000a      color: var(--muted);\u000a      font-size: 13px;\u000a      font-weight: 650;\u000a    }\u000a    .section {\u000a      margin-top: 18px;\u000a      padding: 24px;\u000a    }\u000a    .section-grid {\u000a      display: grid;\u000a      grid-template-columns: 260px minmax(0, 1fr);\u000a      gap: 28px;\u000a    }\u000a    .section-kicker {\u000a      margin: 0 0 12px;\u000a      color: var(--accent);\u000a      font-size: 13px;\u000a      font-weight: 800;\u000a      letter-spacing: 0.08em;\u000a      text-transform: uppercase;\u000a    }\u000a    .check-list {\u000a      display: grid;\u000a      gap: 8px;\u000a    }\u000a    .check {\u000a      display: flex;\u000a      align-items: baseline;\u000a      justify-content: space-between;\u000a      gap: 12px;\u000a      padding: 10px 0;\u000a      border-bottom: 1px solid var(--line);\u000a    }\u000a    .check span {\u000a      color: var(--muted);\u000a      font-size: 13px;\u000a    }\u000a    .check strong {\u000a      font-size: 18px;\u000a      font-variant-numeric: tabular-nums;\u000a    }\u000a    .section-head {\u000a      display: flex;\u000a      align-items: start;\u000a      justify-content: space-between;\u000a      gap: 16px;\u000a      margin-bottom: 16px;\u000a    }\u000a    .section-head h2 {\u000a      max-width: 680px;\u000a      margin: 0;\u000a      font-size: 24px;\u000a      line-height: 1.2;\u000a      letter-spacing: 0;\u000a    }\u000a    .section-head > span {\u000a      flex: 0 0 auto;\u000a      color: var(--muted);\u000a      font-size: 13px;\u000a      font-weight: 700;\u000a      white-space: nowrap;\u000a    }\u000a    .findings {\u000a      display: grid;\u000a      gap: 12px;\u000a    }\u000a    .finding {\u000a      border: 1px solid var(--line);\u000a      border-left: 4px solid var(--note);\u000a      border-radius: var(--radius);\u000a      padding: 16px;\u000a      background: #fffdf8;\u000a    }\u000a    .finding.danger { border-left-color: var(--danger); }\u000a    .finding.warn { border-left-color: var(--warn); }\u000a    .finding.low { border-left-color: var(--low); }\u000a    .finding-head {\u000a      display: flex;\u000a      align-items: start;\u000a      justify-content: space-between;\u000a      gap: 16px;\u000a    }\u000a    .finding-id {\u000a      margin: 0 0 4px;\u000a      color: var(--muted);\u000a      font-family: ui-monospace, SFMono-Regular, Menlo, Consolas, monospace;\u000a      font-size: 12px;\u000a    }\u000a    h3 {\u000a      margin: 0;\u000a      font-size: 17px;\u000a      line-height: 1.3;\u000a      letter-spacing: 0;\u000a    }\u000a    .pill {\u000a      display: inline-flex;\u000a      align-items: center;\u000a      min-height: 26px;\u000a      padding: 4px 9px;\u000a      border-radius: 999px;\u000a      font-size: 12px;\u000a      font-weight: 800;\u000a      text-transform: uppercase;\u000a      white-space: nowrap;\u000a    }\u000a    .pill.danger { background: var(--danger-bg); color: var(--danger); }\u000a    .pill.warn { background: var(--warn-bg); color: var(--warn); }\u000a    .pill.note { background: var(--note-bg); color: var(--note); }\u000a    .pill.low { background: var(--low-bg); color: var(--low); }\u000a    .action {\u000a      margin: 10px 0 0;\u000a      color: var(--muted);\u000a    }\u000a    .sample-table {\u000a      margin-top: 14px;\u000a      overflow-x: auto;\u000a      border: 1px solid var(--line);\u000a      border-radius: var(--radius);\u000a      background: var(--panel);\u000a    }\u000a    table {\u000a      width: 100%;\u000a      min-width: 640px;\u000a      border-collapse: collapse;\u000a    }\u000a    th, td {\u000a      padding: 10px 12px;\u000a      border-bottom: 1px solid var(--line);\u000a      text-align: left;\u000a      vertical-align: top;\u000a    }\u000a    th {\u000a      color: var(--muted);\u000a      font-size: 12px;\u000a      font-weight: 800;\u000a      letter-spacing: 0.06em;\u000a      text-transform: uppercase;\u000a    }\u000a    td {\u000a      max-width: 360px;\u000a      color: #27272a;\u000a      font-size: 13px;\u000a      overflow-wrap: anywhere;\u000a    }\u000a    tr:last-child td { border-bottom: 0; }\u000a    .empty {\u000a      margin: 0;\u000a      color: var(--muted);\u000a    }\u000a    details {\u000a      margin-top: 24px;\u000a      padding: 18px;\u000a    }\u000a    summary {\u000a      cursor: pointer;\u000a      font-weight: 800;\u000a    }\u000a    pre {\u000a      margin: 16px 0 0;\u000a      max-height: 560px;\u000a      overflow: auto;\u000a      padding: 16px;\u000a      border-radius: var(--radius);\u000a      background: #111827;\u000a      color: #f9fafb;\u000a      font-size: 12px;\u000a      line-height: 1.45;\u000a    }\u000a    @media (max-width: 860px) {\u000a      main { width: min(100% - 24px, 1120px); padding-top: 32px; }\u000a      .metrics { grid-template-columns: repeat(2, minmax(0, 1fr)); }\u000a      .section-grid { grid-template-columns: 1fr; gap: 18px; }\u000a      .section { padding: 18px; }\u000a      .section-head { display: block; }\u000a      .section-head > span { display: block; margin-top: 8px; }\u000a    }\u000a    @media (max-width: 520px) {\u000a      .metrics { grid-template-columns: 1fr; }\u000a      .lede { font-size: 16px; }\u000a      .finding-head { display: block; }\u000a      .pill { margin-top: 10px; }\u000a    }\u000a  </style>\u000a</head>\u000a<body>\u000a  <main>\u000a    <header>\u000a      <p class="eyebrow">Generated ${catalogReportHtmlEscape(report.generatedAt)}</p>\u000a      <h1>${catalogReportHtmlEscape(report.title)}</h1>\u000a      <p class="lede">${catalogReportHtmlEscape(report.lede)}</p>\u000a    </header>\u000a    <section class="metrics" aria-label="Audit summary">\u000a      ${report.metrics\u000a        .map(\u000a          ([label, value]) =>\u000a            `<div class="metric"><strong>${catalogReportHtmlEscape(catalogReportFormatMetric(value))}</strong><span>${catalogReportHtmlEscape(\u000a              label,\u000a            )}</span></div>`,\u000a        )\u000a        .join("")}\u000a    </section>\u000a    ${sections}\u000a    <details>\u000a      <summary>Compressed JSON appendix</summary>\u000a      <pre>${catalogReportHtmlEscape(JSON.stringify(report.appendix, null, 2))}</pre>\u000a    </details>\u000a  </main>\u000a</body>\u000a</html>`;\u000a}\u000a\u000aexport async function publishCatalogReportPage(report: CatalogReport, ctx: any): Promise<any> {\u000a  const response = await ctx.swarm.page_create({\u000a    title: report.title,\u000a    slug: report.slug,\u000a    description: report.description,\u000a    contentType: "text/html",\u000a    authMode: "authed",\u000a    body: renderCatalogReportPage(report),\u000a  });\u000a  const payload = response?.data ?? response;\u000a  if (payload?.success === false) return { error: payload.error || "page_create failed" };\u000a  return {\u000a    id: payload?.id ?? payload?.page?.id ?? null,\u000a    appUrl: payload?.appUrl ?? payload?.app_url ?? null,\u000a    apiUrl: payload?.apiUrl ?? payload?.api_url ?? null,\u000a    version: payload?.version ?? payload?.page?.version ?? null,\u000a  };\u000a}\u000a\u000a\u000aimport { z } from "zod";\u000aexport const argsSchema = z.object({\u000a  days: z\u000a    .number()\u000a    .int()\u000a    .positive()\u000a    .optional()\u000a    .describe("Look back this many days (default 7)"),\u000a  failureThreshold: z\u000a    .number()\u000a    .optional()\u000a    .describe("Flag schedules with failure rate above this (0-1, default 0.2)"),\u000a  publishPage: z.boolean().optional().describe("Publish an authed HTML page (default true)"),\u000a});\u000a\u000a/** Per-schedule health check: failure rates and flagging unhealthy schedules. */\u000aexport default async function scheduleHealth(args: any, ctx: any) {\u000a  const parsed = argsSchema.safeParse(args);\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a  const days = parsed.data.days || 7;\u000a  const threshold = parsed.data.failureThreshold ?? 0.2;\u000a  const publishPage = parsed.data.publishPage !== false;\u000a  const since = new Date(Date.now() - days * 86400000).toISOString();\u000a\u000a  // Get schedules\u000a  const schedRes: any = await ctx.swarm.schedule_list({});\u000a  const schedPayload = schedRes?.data ?? schedRes;\u000a  const schedules: any[] = schedPayload?.schedules ?? [];\u000a\u000a  if (!schedules.length) {\u000a    const result: any = { days, threshold, totalSchedules: 0, flaggedCount: 0, schedules: [], flagged: [] };\u000a    if (publishPage) {\u000a      result.page = await publishCatalogReportPage(\u000a        {\u000a          title: "Schedule Health Audit",\u000a          slug: "schedule-health",\u000a          description: "Per-schedule failure rate audit.",\u000a          generatedAt: new Date().toISOString(),\u000a          lede: "No schedules were returned for the selected window.",\u000a          metrics: [\u000a            ["Schedules", 0],\u000a            ["Flagged", 0],\u000a            ["Days", days],\u000a            ["Threshold", threshold],\u000a          ],\u000a          sections: [\u000a            {\u000a              key: "schedule-health",\u000a              goal: "Keep recurring schedules healthy and visible.",\u000a              findingCount: 0,\u000a              checks: { schedules: 0, flagged: 0 },\u000a              findings: [],\u000a            },\u000a          ],\u000a          appendix: result,\u000a        },\u000a        ctx,\u000a      );\u000a    }\u000a    return result;\u000a  }\u000a\u000a  // Get recent tasks to correlate with schedules\u000a  const taskRes: any = await ctx.swarm.task_list({ createdAfter: since, limit: 2000 });\u000a  const taskPayload = taskRes?.data ?? taskRes;\u000a  const tasks: any[] = taskPayload?.tasks ?? [];\u000a\u000a  // Group by scheduleId\u000a  const bySchedule = new Map<string, { total: number; failed: number; completed: number }>();\u000a  for (const t of tasks) {\u000a    if (!t.scheduleId) continue;\u000a    const entry = bySchedule.get(t.scheduleId) ?? { total: 0, failed: 0, completed: 0 };\u000a    entry.total++;\u000a    if (t.status === "failed") entry.failed++;\u000a    if (t.status === "completed") entry.completed++;\u000a    bySchedule.set(t.scheduleId, entry);\u000a  }\u000a\u000a  const results = schedules.map((s: any) => {\u000a    const stats = bySchedule.get(s.id) ?? { total: 0, failed: 0, completed: 0 };\u000a    const failureRate = stats.total > 0 ? stats.failed / stats.total : 0;\u000a    return {\u000a      id: s.id,\u000a      name: s.name,\u000a      enabled: s.enabled,\u000a      targetAgentId: s.targetAgentId,\u000a      runs: stats.total,\u000a      failed: stats.failed,\u000a      completed: stats.completed,\u000a      failureRate: Math.round(failureRate * 1000) / 1000,\u000a      flagged: stats.total >= 3 && failureRate > threshold,\u000a    };\u000a  });\u000a\u000a  const flagged = results.filter((r: any) => r.flagged);\u000a\u000a  const result: any = {\u000a    days,\u000a    threshold,\u000a    totalSchedules: schedules.length,\u000a    flaggedCount: flagged.length,\u000a    schedules: results.sort((a: any, b: any) => b.failureRate - a.failureRate),\u000a    flagged,\u000a  };\u000a\u000a  if (publishPage) {\u000a    result.page = await publishCatalogReportPage(\u000a      {\u000a        title: "Schedule Health Audit",\u000a        slug: "schedule-health",\u000a        description: "Per-schedule failure rate audit.",\u000a        generatedAt: new Date().toISOString(),\u000a        lede: `Checked ${schedules.length} schedule(s) over ${days} day(s); ${flagged.length} exceeded the configured failure threshold.`,\u000a        metrics: [\u000a          ["Schedules", schedules.length],\u000a          ["Flagged", flagged.length],\u000a          ["Days", days],\u000a          ["Threshold", threshold],\u000a        ],\u000a        sections: [\u000a          {\u000a            key: "schedule-health",\u000a            goal: "Keep recurring schedules healthy and visible.",\u000a            findingCount: flagged.length,\u000a            checks: {\u000a              totalSchedules: schedules.length,\u000a              flaggedSchedules: flagged.length,\u000a              threshold,\u000a              scannedTasks: tasks.length,\u000a            },\u000a            findings: flagged.map((schedule: any) => ({\u000a              id: `schedule.${schedule.id}`,\u000a              severity: schedule.failureRate >= 0.5 ? "high" : "medium",\u000a              summary: `${schedule.name} failed ${schedule.failed}/${schedule.runs} recent run(s).`,\u000a              action: "Review the latest failed tasks and disable, repair, or retarget this schedule.",\u000a              samples: [schedule],\u000a            })),\u000a          },\u000a        ],\u000a        appendix: result,\u000a      },\u000a      ctx,\u000a    );\u000a  }\u000a\u000a  return result;\u000a}\u000a'),'Per-schedule failure rate check over recent tasks — flags schedules with failure rates above a configurable threshold.','Find unhealthy schedules that keep failing — for daily compounding, reliability reviews, or ops triage.','{"argsType":"any","resultType":"unknown","description":"Per-schedule health check: failure rates and flagging unhealthy schedules."}','69c68d5bc828d20cddcde57ff69f30965549bb3b136b315295fb760beab6fffe',1,0,1,'none',NULL,'2026-06-11T22:38:23.825Z','2026-06-11T22:38:23.825Z','{"$schema":"https://json-schema.org/draft/2020-12/schema","type":"object","properties":{"days":{"description":"Look back this many days (default 7)","type":"integer","exclusiveMinimum":0,"maximum":9007199254740991,"minimum":-9007199254740991},"failureThreshold":{"description":"Flag schedules with failure rate above this (0-1, default 0.2)","type":"number"},"publishPage":{"description":"Publish an authed HTML page (default true)","type":"boolean"}},"additionalProperties":false}',NULL,NULL);
INSERT INTO scripts VALUES('bb3189d0-d123-4443-8f1c-f07ff75a292f','tool-usage','global',NULL,unistr('import { z } from "zod";\u000a\u000aexport const argsSchema = z.object({\u000a  days: z\u000a    .number()\u000a    .int()\u000a    .positive()\u000a    .optional()\u000a    .describe("Look back this many days (default 7)"),\u000a  agentId: z.string().optional().describe("Filter by agent ID (default: all agents)"),\u000a  limit: z\u000a    .number()\u000a    .int()\u000a    .positive()\u000a    .optional()\u000a    .describe("Top N tools to return (default 20)"),\u000a});\u000a\u000a/** Tool usage histogram from session_logs — top tools by call count. */\u000aexport default async function toolUsage(args: any, ctx: any) {\u000a  const parsed = argsSchema.safeParse(args);\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a  const days = parsed.data.days || 7;\u000a  const limit = parsed.data.limit || 20;\u000a  const agentId = parsed.data.agentId;\u000a\u000a  const agentFilter = agentId ? `AND agent_id = ''${agentId}''` : "";\u000a  const sql = `\u000a    SELECT tool_name, count(*) as calls\u000a    FROM session_logs\u000a    WHERE tool_name IS NOT NULL\u000a      AND created_at > datetime(''now'', ''-${days} days'')\u000a      ${agentFilter}\u000a    GROUP BY tool_name\u000a    ORDER BY calls DESC\u000a    LIMIT ${limit}\u000a  `;\u000a\u000a  const res: any = await ctx.swarm.db_query({ sql });\u000a  const payload = res?.data ?? res;\u000a  const columns: string[] = payload?.columns ?? [];\u000a  const rows: any[] = (payload?.rows ?? []).map((row: any[]) =>\u000a    Object.fromEntries(columns.map((column, index) => [column, row[index]])),\u000a  );\u000a\u000a  const totalCalls = rows.reduce((sum: number, r: any) => sum + (r.calls ?? 0), 0);\u000a\u000a  return {\u000a    days,\u000a    agentId: agentId ?? "all",\u000a    totalDistinctTools: rows.length,\u000a    totalCalls,\u000a    tools: rows.map((r: any) => ({\u000a      tool: r.tool_name,\u000a      calls: r.calls,\u000a      pct: totalCalls > 0 ? Math.round((r.calls / totalCalls) * 1000) / 10 : 0,\u000a    })),\u000a  };\u000a}\u000a'),'Tool usage histogram from session_logs — top tools by call count over a time window, optionally filtered by agent.','See which MCP tools agents use most — for SDK gap analysis, optimization, or daily ops snapshots.','{"argsType":"any","resultType":"unknown","description":"Tool usage histogram from session_logs — top tools by call count."}','277c4e3c1b3743d8c3d60320bb493f691e03b95f0f819a077059d72e068528f9',1,0,1,'none',NULL,'2026-06-11T22:38:23.948Z','2026-06-11T22:38:23.948Z','{"$schema":"https://json-schema.org/draft/2020-12/schema","type":"object","properties":{"days":{"description":"Look back this many days (default 7)","type":"integer","exclusiveMinimum":0,"maximum":9007199254740991,"minimum":-9007199254740991},"agentId":{"description":"Filter by agent ID (default: all agents)","type":"string"},"limit":{"description":"Top N tools to return (default 20)","type":"integer","exclusiveMinimum":0,"maximum":9007199254740991,"minimum":-9007199254740991}},"additionalProperties":false}',NULL,NULL);
INSERT INTO scripts VALUES('82d56dac-c9d1-423c-b2ff-b1559bf24fa8','compound-insights','global',NULL,unistr('export type CatalogReportFinding = {\u000a  id: string;\u000a  severity?: string;\u000a  summary: string;\u000a  action?: string;\u000a  samples?: unknown[];\u000a};\u000a\u000aexport type CatalogReportSection = {\u000a  key: string;\u000a  label?: string;\u000a  goal: string;\u000a  findingCount?: number;\u000a  checks?: Record<string, unknown>;\u000a  findings?: CatalogReportFinding[];\u000a};\u000a\u000aexport type CatalogReport = {\u000a  title: string;\u000a  slug: string;\u000a  description: string;\u000a  generatedAt: string;\u000a  lede: string;\u000a  metrics: Array<[string, unknown]>;\u000a  sections: CatalogReportSection[];\u000a  appendix: unknown;\u000a};\u000a\u000afunction catalogReportAsText(value: unknown): string {\u000a  return typeof value === "string" ? value : value == null ? "" : JSON.stringify(value);\u000a}\u000a\u000afunction catalogReportHtmlEscape(value: unknown): string {\u000a  return catalogReportAsText(value)\u000a    .replace(/&/g, "&amp;")\u000a    .replace(/</g, "&lt;")\u000a    .replace(/>/g, "&gt;")\u000a    .replace(/"/g, "&quot;");\u000a}\u000a\u000afunction catalogReportHumanLabel(value: string): string {\u000a  return value\u000a    .replace(/([a-z0-9])([A-Z])/g, "$1 $2")\u000a    .replace(/[-_.]+/g, " ")\u000a    .replace(/\\b\\w/g, (char) => char.toUpperCase());\u000a}\u000a\u000afunction catalogReportFormatMetric(value: unknown): string {\u000a  if (typeof value === "number") return new Intl.NumberFormat("en-US").format(value);\u000a  return catalogReportAsText(value);\u000a}\u000a\u000afunction catalogReportSeverityTone(value?: string): string {\u000a  if (value === "critical") return "danger";\u000a  if (value === "high") return "warn";\u000a  if (value === "medium") return "note";\u000a  return "low";\u000a}\u000a\u000afunction catalogReportRenderSampleValue(value: unknown): string {\u000a  if (Array.isArray(value)) {\u000a    return value\u000a      .map((item) => (typeof item === "object" && item !== null ? JSON.stringify(item) : catalogReportAsText(item)))\u000a      .join(", ");\u000a  }\u000a  if (value && typeof value === "object") return JSON.stringify(value);\u000a  return catalogReportAsText(value);\u000a}\u000a\u000afunction catalogReportRenderSamples(samples?: unknown[]): string {\u000a  if (!Array.isArray(samples) || samples.length === 0) return "";\u000a  const normalized = samples.map((sampleRow) =>\u000a    sampleRow && typeof sampleRow === "object" && !Array.isArray(sampleRow)\u000a      ? (sampleRow as Record<string, unknown>)\u000a      : { value: sampleRow },\u000a  );\u000a  const columns = Array.from(\u000a    new Set(normalized.flatMap((sampleRow) => Object.keys(sampleRow).slice(0, 6))),\u000a  ).slice(0, 6);\u000a  if (columns.length === 0) return "";\u000a  const rows = normalized\u000a    .map(\u000a      (sampleRow) =>\u000a        `<tr>${columns\u000a          .map((column) => `<td>${catalogReportHtmlEscape(catalogReportRenderSampleValue(sampleRow[column]))}</td>`)\u000a          .join("")}</tr>`,\u000a    )\u000a    .join("");\u000a  return `<div class="sample-table" aria-label="Sample rows">\u000a    <table>\u000a      <thead><tr>${columns.map((column) => `<th>${catalogReportHtmlEscape(catalogReportHumanLabel(column))}</th>`).join("")}</tr></thead>\u000a      <tbody>${rows}</tbody>\u000a    </table>\u000a  </div>`;\u000a}\u000a\u000aexport function renderCatalogReportPage(report: CatalogReport): string {\u000a  const sections = report.sections\u000a    .map((section) => {\u000a      const findings = (section.findings || [])\u000a        .map(\u000a          (finding) => `<article class="finding ${catalogReportHtmlEscape(catalogReportSeverityTone(finding.severity))}">\u000a            <div class="finding-head">\u000a              <div>\u000a                <p class="finding-id">${catalogReportHtmlEscape(finding.id)}</p>\u000a                <h3>${catalogReportHtmlEscape(finding.summary)}</h3>\u000a              </div>\u000a              <span class="pill ${catalogReportHtmlEscape(catalogReportSeverityTone(finding.severity))}">${catalogReportHtmlEscape(\u000a                finding.severity || "low",\u000a              )}</span>\u000a            </div>\u000a            ${finding.action ? `<p class="action">${catalogReportHtmlEscape(finding.action)}</p>` : ""}\u000a            ${catalogReportRenderSamples(finding.samples)}\u000a          </article>`,\u000a        )\u000a        .join("");\u000a      const checks = Object.entries(section.checks || {})\u000a        .map(\u000a          ([label, value]) =>\u000a            `<div class="check"><span>${catalogReportHtmlEscape(catalogReportHumanLabel(label))}</span><strong>${catalogReportHtmlEscape(\u000a              catalogReportFormatMetric(value),\u000a            )}</strong></div>`,\u000a        )\u000a        .join("");\u000a      return `<section class="section">\u000a        <div class="section-grid">\u000a          <aside class="checks">\u000a            <p class="section-kicker">${catalogReportHtmlEscape(section.label || catalogReportHumanLabel(section.key))}</p>\u000a            <div class="check-list">${checks}</div>\u000a          </aside>\u000a          <div>\u000a            <div class="section-head">\u000a              <h2>${catalogReportHtmlEscape(section.goal)}</h2>\u000a              <span>${catalogReportHtmlEscape(catalogReportFormatMetric(section.findingCount ?? section.findings?.length ?? 0))} finding(s)</span>\u000a            </div>\u000a            <div class="findings">\u000a              ${findings || ''<p class="empty">No actionable findings in this cluster.</p>''}\u000a            </div>\u000a          </div>\u000a        </div>\u000a      </section>`;\u000a    })\u000a    .join("\\n");\u000a  return `<!doctype html>\u000a<html lang="en">\u000a<head>\u000a  <meta charset="utf-8">\u000a  <meta name="viewport" content="width=device-width, initial-scale=1">\u000a  <meta name="theme-color" content="#f5f2ea">\u000a  <title>${catalogReportHtmlEscape(report.title)}</title>\u000a  <style>\u000a    :root {\u000a      color-scheme: light;\u000a      --bg: #f5f2ea;\u000a      --panel: #ffffff;\u000a      --ink: #18181b;\u000a      --muted: #5f6368;\u000a      --line: #ded8cb;\u000a      --accent: #255c99;\u000a      --danger: #b42318;\u000a      --danger-bg: #fff1f0;\u000a      --warn: #b54708;\u000a      --warn-bg: #fff7ed;\u000a      --note: #175cd3;\u000a      --note-bg: #eff6ff;\u000a      --low: #067647;\u000a      --low-bg: #ecfdf3;\u000a      --radius: 8px;\u000a      --shadow: 0 1px 2px rgba(24, 24, 27, 0.06), 0 14px 36px rgba(24, 24, 27, 0.07);\u000a    }\u000a    * { box-sizing: border-box; }\u000a    body {\u000a      margin: 0;\u000a      background: var(--bg);\u000a      color: var(--ink);\u000a      font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;\u000a      font-size: 16px;\u000a      line-height: 1.55;\u000a    }\u000a    main {\u000a      width: min(1120px, calc(100% - 32px));\u000a      margin: 0 auto;\u000a      padding: 48px 0 72px;\u000a    }\u000a    header { margin-bottom: 28px; }\u000a    .eyebrow {\u000a      margin: 0 0 8px;\u000a      color: var(--muted);\u000a      font-size: 13px;\u000a      font-weight: 750;\u000a      letter-spacing: 0.08em;\u000a      text-transform: uppercase;\u000a    }\u000a    h1 {\u000a      margin: 0;\u000a      max-width: 860px;\u000a      font-size: clamp(2rem, 4vw, 3rem);\u000a      line-height: 1.05;\u000a      letter-spacing: 0;\u000a    }\u000a    .lede {\u000a      max-width: 780px;\u000a      margin: 16px 0 0;\u000a      color: var(--muted);\u000a      font-size: 18px;\u000a    }\u000a    .metrics {\u000a      display: grid;\u000a      grid-template-columns: repeat(4, minmax(0, 1fr));\u000a      gap: 12px;\u000a      margin: 32px 0;\u000a    }\u000a    .metric, .section, details {\u000a      background: var(--panel);\u000a      border: 1px solid var(--line);\u000a      border-radius: var(--radius);\u000a      box-shadow: var(--shadow);\u000a    }\u000a    .metric { padding: 18px; }\u000a    .metric strong {\u000a      display: block;\u000a      font-size: 32px;\u000a      line-height: 1;\u000a      font-variant-numeric: tabular-nums;\u000a    }\u000a    .metric span {\u000a      display: block;\u000a      margin-top: 8px;\u000a      color: var(--muted);\u000a      font-size: 13px;\u000a      font-weight: 650;\u000a    }\u000a    .section {\u000a      margin-top: 18px;\u000a      padding: 24px;\u000a    }\u000a    .section-grid {\u000a      display: grid;\u000a      grid-template-columns: 260px minmax(0, 1fr);\u000a      gap: 28px;\u000a    }\u000a    .section-kicker {\u000a      margin: 0 0 12px;\u000a      color: var(--accent);\u000a      font-size: 13px;\u000a      font-weight: 800;\u000a      letter-spacing: 0.08em;\u000a      text-transform: uppercase;\u000a    }\u000a    .check-list {\u000a      display: grid;\u000a      gap: 8px;\u000a    }\u000a    .check {\u000a      display: flex;\u000a      align-items: baseline;\u000a      justify-content: space-between;\u000a      gap: 12px;\u000a      padding: 10px 0;\u000a      border-bottom: 1px solid var(--line);\u000a    }\u000a    .check span {\u000a      color: var(--muted);\u000a      font-size: 13px;\u000a    }\u000a    .check strong {\u000a      font-size: 18px;\u000a      font-variant-numeric: tabular-nums;\u000a    }\u000a    .section-head {\u000a      display: flex;\u000a      align-items: start;\u000a      justify-content: space-between;\u000a      gap: 16px;\u000a      margin-bottom: 16px;\u000a    }\u000a    .section-head h2 {\u000a      max-width: 680px;\u000a      margin: 0;\u000a      font-size: 24px;\u000a      line-height: 1.2;\u000a      letter-spacing: 0;\u000a    }\u000a    .section-head > span {\u000a      flex: 0 0 auto;\u000a      color: var(--muted);\u000a      font-size: 13px;\u000a      font-weight: 700;\u000a      white-space: nowrap;\u000a    }\u000a    .findings {\u000a      display: grid;\u000a      gap: 12px;\u000a    }\u000a    .finding {\u000a      border: 1px solid var(--line);\u000a      border-left: 4px solid var(--note);\u000a      border-radius: var(--radius);\u000a      padding: 16px;\u000a      background: #fffdf8;\u000a    }\u000a    .finding.danger { border-left-color: var(--danger); }\u000a    .finding.warn { border-left-color: var(--warn); }\u000a    .finding.low { border-left-color: var(--low); }\u000a    .finding-head {\u000a      display: flex;\u000a      align-items: start;\u000a      justify-content: space-between;\u000a      gap: 16px;\u000a    }\u000a    .finding-id {\u000a      margin: 0 0 4px;\u000a      color: var(--muted);\u000a      font-family: ui-monospace, SFMono-Regular, Menlo, Consolas, monospace;\u000a      font-size: 12px;\u000a    }\u000a    h3 {\u000a      margin: 0;\u000a      font-size: 17px;\u000a      line-height: 1.3;\u000a      letter-spacing: 0;\u000a    }\u000a    .pill {\u000a      display: inline-flex;\u000a      align-items: center;\u000a      min-height: 26px;\u000a      padding: 4px 9px;\u000a      border-radius: 999px;\u000a      font-size: 12px;\u000a      font-weight: 800;\u000a      text-transform: uppercase;\u000a      white-space: nowrap;\u000a    }\u000a    .pill.danger { background: var(--danger-bg); color: var(--danger); }\u000a    .pill.warn { background: var(--warn-bg); color: var(--warn); }\u000a    .pill.note { background: var(--note-bg); color: var(--note); }\u000a    .pill.low { background: var(--low-bg); color: var(--low); }\u000a    .action {\u000a      margin: 10px 0 0;\u000a      color: var(--muted);\u000a    }\u000a    .sample-table {\u000a      margin-top: 14px;\u000a      overflow-x: auto;\u000a      border: 1px solid var(--line);\u000a      border-radius: var(--radius);\u000a      background: var(--panel);\u000a    }\u000a    table {\u000a      width: 100%;\u000a      min-width: 640px;\u000a      border-collapse: collapse;\u000a    }\u000a    th, td {\u000a      padding: 10px 12px;\u000a      border-bottom: 1px solid var(--line);\u000a      text-align: left;\u000a      vertical-align: top;\u000a    }\u000a    th {\u000a      color: var(--muted);\u000a      font-size: 12px;\u000a      font-weight: 800;\u000a      letter-spacing: 0.06em;\u000a      text-transform: uppercase;\u000a    }\u000a    td {\u000a      max-width: 360px;\u000a      color: #27272a;\u000a      font-size: 13px;\u000a      overflow-wrap: anywhere;\u000a    }\u000a    tr:last-child td { border-bottom: 0; }\u000a    .empty {\u000a      margin: 0;\u000a      color: var(--muted);\u000a    }\u000a    details {\u000a      margin-top: 24px;\u000a      padding: 18px;\u000a    }\u000a    summary {\u000a      cursor: pointer;\u000a      font-weight: 800;\u000a    }\u000a    pre {\u000a      margin: 16px 0 0;\u000a      max-height: 560px;\u000a      overflow: auto;\u000a      padding: 16px;\u000a      border-radius: var(--radius);\u000a      background: #111827;\u000a      color: #f9fafb;\u000a      font-size: 12px;\u000a      line-height: 1.45;\u000a    }\u000a    @media (max-width: 860px) {\u000a      main { width: min(100% - 24px, 1120px); padding-top: 32px; }\u000a      .metrics { grid-template-columns: repeat(2, minmax(0, 1fr)); }\u000a      .section-grid { grid-template-columns: 1fr; gap: 18px; }\u000a      .section { padding: 18px; }\u000a      .section-head { display: block; }\u000a      .section-head > span { display: block; margin-top: 8px; }\u000a    }\u000a    @media (max-width: 520px) {\u000a      .metrics { grid-template-columns: 1fr; }\u000a      .lede { font-size: 16px; }\u000a      .finding-head { display: block; }\u000a      .pill { margin-top: 10px; }\u000a    }\u000a  </style>\u000a</head>\u000a<body>\u000a  <main>\u000a    <header>\u000a      <p class="eyebrow">Generated ${catalogReportHtmlEscape(report.generatedAt)}</p>\u000a      <h1>${catalogReportHtmlEscape(report.title)}</h1>\u000a      <p class="lede">${catalogReportHtmlEscape(report.lede)}</p>\u000a    </header>\u000a    <section class="metrics" aria-label="Audit summary">\u000a      ${report.metrics\u000a        .map(\u000a          ([label, value]) =>\u000a            `<div class="metric"><strong>${catalogReportHtmlEscape(catalogReportFormatMetric(value))}</strong><span>${catalogReportHtmlEscape(\u000a              label,\u000a            )}</span></div>`,\u000a        )\u000a        .join("")}\u000a    </section>\u000a    ${sections}\u000a    <details>\u000a      <summary>Compressed JSON appendix</summary>\u000a      <pre>${catalogReportHtmlEscape(JSON.stringify(report.appendix, null, 2))}</pre>\u000a    </details>\u000a  </main>\u000a</body>\u000a</html>`;\u000a}\u000a\u000aexport async function publishCatalogReportPage(report: CatalogReport, ctx: any): Promise<any> {\u000a  const response = await ctx.swarm.page_create({\u000a    title: report.title,\u000a    slug: report.slug,\u000a    description: report.description,\u000a    contentType: "text/html",\u000a    authMode: "authed",\u000a    body: renderCatalogReportPage(report),\u000a  });\u000a  const payload = response?.data ?? response;\u000a  if (payload?.success === false) return { error: payload.error || "page_create failed" };\u000a  return {\u000a    id: payload?.id ?? payload?.page?.id ?? null,\u000a    appUrl: payload?.appUrl ?? payload?.app_url ?? null,\u000a    apiUrl: payload?.apiUrl ?? payload?.api_url ?? null,\u000a    version: payload?.version ?? payload?.page?.version ?? null,\u000a  };\u000a}\u000a\u000a\u000aimport { z } from "zod";\u000aexport const argsSchema = z.object({\u000a  days: z\u000a    .number()\u000a    .int()\u000a    .positive()\u000a    .optional()\u000a    .describe("Look back this many days (default 3)"),\u000a  includeToolUsage: z.boolean().optional().describe("Include tool usage histogram (default true)"),\u000a  includeScheduleHealth: z\u000a    .boolean()\u000a    .optional()\u000a    .describe("Include schedule health flags (default true)"),\u000a  includeMemoryHealth: z.boolean().optional().describe("Include memory health stats (default true)"),\u000a  includeScriptCandidates: z\u000a    .boolean()\u000a    .optional()\u000a    .describe("Include high-frequency tool-triplet candidates for future seed scripts (default true)"),\u000a  includeScriptUsage: z\u000a    .boolean()\u000a    .optional()\u000a    .describe("Include actual script run, creation, and edit metrics (default true)"),\u000a  includeCostAndTokens: z\u000a    .boolean()\u000a    .optional()\u000a    .describe("Include session cost and token metrics with honesty rails (default true)"),\u000a  includeByAgent: z\u000a    .boolean()\u000a    .optional()\u000a    .describe("Include per-agent task/completion/failure breakdown (default true)"),\u000a  publishPage: z.boolean().optional().describe("Publish an authed HTML page (default true)"),\u000a});\u000a\u000a/**\u000a * Failure reasons that are swarm bookkeeping, not real failures. Excluded from\u000a * failureClusters, scheduleHealth and byAgent failure counts (Lead Rule #16):\u000a * the run engine collapses redundant sibling tasks into these statuses, so\u000a * counting them produces phantom failure spikes.\u000a */\u000aconst EXCLUDED_FAIL = ["superseded_workflow_task", "cancelled"];\u000a\u000a/**\u000a * `db_query` returns positional rows (`rows: unknown[][]`) plus a `columns`\u000a * array — NOT an array of objects. Zip them back into objects so callers can\u000a * read by column name.\u000a */\u000afunction rowsToObjects(res: any): any[] {\u000a  const p = res?.data ?? res;\u000a  const cols: string[] = p?.columns ?? [];\u000a  return (p?.rows ?? []).map((r: any) =>\u000a    Array.isArray(r) ? Object.fromEntries(cols.map((c, i) => [c, r[i]])) : r,\u000a  );\u000a}\u000a\u000afunction asNumber(value: any): number {\u000a  const n = Number(value ?? 0);\u000a  return Number.isFinite(n) ? n : 0;\u000a}\u000a\u000afunction round1(value: number): number {\u000a  return Math.round(value * 10) / 10;\u000a}\u000a\u000afunction percent(part: number, total: number): number {\u000a  return total > 0 ? round1((part / total) * 100) : 0;\u000a}\u000a\u000afunction round4(value: number): number {\u000a  return Math.round(value * 10000) / 10000;\u000a}\u000a\u000afunction percentile(values: number[], p: number): number | null {\u000a  if (values.length === 0) return null;\u000a  const sorted = [...values].sort((a, b) => a - b);\u000a  const index = Math.ceil((p / 100) * sorted.length) - 1;\u000a  return sorted[Math.max(0, Math.min(sorted.length - 1, index))] ?? null;\u000a}\u000a\u000afunction extractToolName(content: string): string | null {\u000a  const match = content.match(/"type"\\s*:\\s*"tool_use"[\\s\\S]*?"name"\\s*:\\s*"([^"]+)"/);\u000a  return match?.[1] ?? null;\u000a}\u000a\u000afunction toolSlug(tool: string): string {\u000a  return tool\u000a    .replace(/^mcp__/, "")\u000a    .replace(/__/g, "-")\u000a    .replace(/_/g, "-")\u000a    .replace(/[^a-zA-Z0-9-]+/g, "-")\u000a    .replace(/^-+|-+$/g, "")\u000a    .toLowerCase();\u000a}\u000a\u000afunction decodeFloat32Blob(value: any): Float32Array | null {\u000a  if (!value) return null;\u000a  let bytes: Uint8Array | null = null;\u000a  if (value instanceof Uint8Array) bytes = value;\u000a  else if (Array.isArray(value)) bytes = Uint8Array.from(value);\u000a  else if (typeof value === "object" && Array.isArray(value.data)) bytes = Uint8Array.from(value.data);\u000a  else if (typeof value === "object") {\u000a    const keys = Object.keys(value);\u000a    if (keys.length > 0 && keys.every((key) => /^\\d+$/.test(key))) {\u000a      bytes = Uint8Array.from(Object.values(value) as number[]);\u000a    }\u000a  }\u000a  if (!bytes || bytes.byteLength < 4 || bytes.byteLength % 4 !== 0) return null;\u000a  return new Float32Array(bytes.buffer.slice(bytes.byteOffset, bytes.byteOffset + bytes.byteLength));\u000a}\u000a\u000afunction cosineSimilarity(a: Float32Array, b: Float32Array): number {\u000a  const len = Math.min(a.length, b.length);\u000a  let dot = 0;\u000a  let na = 0;\u000a  let nb = 0;\u000a  for (let i = 0; i < len; i++) {\u000a    const av = a[i] ?? 0;\u000a    const bv = b[i] ?? 0;\u000a    dot += av * bv;\u000a    na += av * av;\u000a    nb += bv * bv;\u000a  }\u000a  if (na === 0 || nb === 0) return 0;\u000a  return dot / (Math.sqrt(na) * Math.sqrt(nb));\u000a}\u000a\u000afunction summarizeScriptUsage(rows: any[], creationRows: any[], editRows: any[], toolRows: any[]) {\u000a  const terminalStatuses = new Set(["completed", "failed", "cancelled", "aborted_limit"]);\u000a  const failureStatuses = new Set(["failed", "cancelled", "aborted_limit"]);\u000a  const durations = rows\u000a    .map((r) => asNumber(r.durationMs))\u000a    .filter((duration) => duration > 0);\u000a  const byScript = new Map<\u000a    string,\u000a    {\u000a      scriptName: string;\u000a      runs: number;\u000a      completed: number;\u000a      failed: number;\u000a      successRate: number;\u000a      durationP50Ms: number | null;\u000a      durationP95Ms: number | null;\u000a      inline: number;\u000a      workflow: number;\u000a      durations: number[];\u000a    }\u000a  >();\u000a\u000a  for (const row of rows) {\u000a    const name = String(row.scriptName || "(inline source)");\u000a    const current =\u000a      byScript.get(name) ??\u000a      {\u000a        scriptName: name,\u000a        runs: 0,\u000a        completed: 0,\u000a        failed: 0,\u000a        successRate: 0,\u000a        durationP50Ms: null,\u000a        durationP95Ms: null,\u000a        inline: 0,\u000a        workflow: 0,\u000a        durations: [],\u000a      };\u000a    current.runs += 1;\u000a    if (row.kind === "inline") current.inline += 1;\u000a    if (row.kind === "workflow") current.workflow += 1;\u000a    if (row.status === "completed") current.completed += 1;\u000a    if (failureStatuses.has(String(row.status))) current.failed += 1;\u000a    const duration = asNumber(row.durationMs);\u000a    if (duration > 0) current.durations.push(duration);\u000a    byScript.set(name, current);\u000a  }\u000a\u000a  const perScript = [...byScript.values()]\u000a    .map((script) => ({\u000a      scriptName: script.scriptName,\u000a      runs: script.runs,\u000a      completed: script.completed,\u000a      failed: script.failed,\u000a      successRate: percent(script.completed, script.runs),\u000a      durationP50Ms: percentile(script.durations, 50),\u000a      durationP95Ms: percentile(script.durations, 95),\u000a      inline: script.inline,\u000a      workflow: script.workflow,\u000a    }))\u000a    .sort((a, b) => b.runs - a.runs)\u000a    .slice(0, 20);\u000a\u000a  const creationsByScope: Record<string, number> = {};\u000a  let creations = 0;\u000a  let scratchCreations = 0;\u000a  for (const row of creationRows) {\u000a    const count = asNumber(row.count);\u000a    if (asNumber(row.isScratch) === 1) {\u000a      scratchCreations += count;\u000a    } else {\u000a      creations += count;\u000a      creationsByScope[String(row.scope || "unknown")] =\u000a        (creationsByScope[String(row.scope || "unknown")] ?? 0) + count;\u000a    }\u000a  }\u000a\u000a  const editsByScope: Record<string, number> = {};\u000a  let edits = 0;\u000a  for (const row of editRows) {\u000a    const count = asNumber(row.count);\u000a    edits += count;\u000a    editsByScope[String(row.scope || "unknown")] =\u000a      (editsByScope[String(row.scope || "unknown")] ?? 0) + count;\u000a  }\u000a\u000a  return {\u000a    source: {\u000a      authoritativeRuns: "script_runs",\u000a      mcpCallSignal: "session_logs tool_use for script tools",\u000a      reconciliation:\u000a        "`script-run` via MCP calls /api/scripts/run, which records kind=''inline'' rows in script_runs; launch-script-run/workflows record kind=''workflow''. session_logs counts agent tool calls and must not be added to script_runs totals.",\u000a    },\u000a    runs: {\u000a      total: rows.length,\u000a      inline: rows.filter((r) => r.kind === "inline").length,\u000a      workflow: rows.filter((r) => r.kind === "workflow").length,\u000a      completed: rows.filter((r) => r.status === "completed").length,\u000a      failed: rows.filter((r) => failureStatuses.has(String(r.status))).length,\u000a      runningOrPaused: rows.filter((r) => !terminalStatuses.has(String(r.status))).length,\u000a      successRate: percent(\u000a        rows.filter((r) => r.status === "completed").length,\u000a        rows.length,\u000a      ),\u000a      durationP50Ms: percentile(durations, 50),\u000a      durationP95Ms: percentile(durations, 95),\u000a      perScript,\u000a    },\u000a    creations: {\u000a      totalNonScratch: creations,\u000a      scratch: scratchCreations,\u000a      byScope: creationsByScope,\u000a    },\u000a    edits: {\u000a      total: edits,\u000a      byScope: editsByScope,\u000a    },\u000a    mcpToolCalls: toolRows.map((r) => ({ tool: r.tool, calls: asNumber(r.calls) })),\u000a  };\u000a}\u000a\u000afunction summarizeCostAndTokens(rows: any[]) {\u000a  const trustedSources = new Set(["harness", "pricing-table"]);\u000a  const trustedRows = rows.filter((r) => trustedSources.has(String(r.costSource)));\u000a  const unpricedRows = rows.filter((r) => String(r.costSource) === "unpriced");\u000a  const trustedTaskRows = trustedRows.filter((r) => r.taskId);\u000a  const trustedTaskIds = new Set(trustedTaskRows.map((r) => String(r.taskId)));\u000a  const trustedTaskSpend = trustedTaskRows.reduce((sum, r) => sum + asNumber(r.totalCostUsd), 0);\u000a  const nonTaskRows = rows.filter((r) => !r.taskId);\u000a  const totalSpend = rows.reduce((sum, r) => sum + asNumber(r.totalCostUsd), 0);\u000a  const trustedSpend = trustedRows.reduce((sum, r) => sum + asNumber(r.totalCostUsd), 0);\u000a\u000a  const sumToken = (field: string) =>\u000a    rows.reduce((sum, r) => (r[field] === null || r[field] === undefined ? sum : sum + asNumber(r[field])), 0);\u000a  const unknownCount = (field: string) =>\u000a    rows.filter((r) => r[field] === null || r[field] === undefined).length;\u000a\u000a  const groupBy = (field: string) => {\u000a    const grouped = new Map<\u000a      string,\u000a      {\u000a        key: string;\u000a        rows: number;\u000a        spendUsd: number;\u000a        trustedSpendUsd: number;\u000a        unpricedRows: number;\u000a      }\u000a    >();\u000a    for (const row of rows) {\u000a      const key = String(row[field] || "unknown");\u000a      const current =\u000a        grouped.get(key) ?? {\u000a          key,\u000a          rows: 0,\u000a          spendUsd: 0,\u000a          trustedSpendUsd: 0,\u000a          unpricedRows: 0,\u000a        };\u000a      current.rows += 1;\u000a      current.spendUsd += asNumber(row.totalCostUsd);\u000a      if (trustedSources.has(String(row.costSource))) current.trustedSpendUsd += asNumber(row.totalCostUsd);\u000a      if (String(row.costSource) === "unpriced") current.unpricedRows += 1;\u000a      grouped.set(key, current);\u000a    }\u000a    return [...grouped.values()]\u000a      .map((r) => ({\u000a        ...r,\u000a        spendUsd: round4(r.spendUsd),\u000a        trustedSpendUsd: round4(r.trustedSpendUsd),\u000a      }))\u000a      .sort((a, b) => b.spendUsd - a.spendUsd);\u000a  };\u000a\u000a  return {\u000a    source: {\u000a      table: "session_costs",\u000a      providerDerivation:\u000a        "provider is derived from agents.harness_provider, then agents.provider, because session_costs does not carry a provider column",\u000a      headlineAvgCostRule:\u000a        "avgCostPerTaskUsd excludes unpriced rows and rows with null taskId; null-task sessions are reported separately",\u000a    },\u000a    rows: rows.length,\u000a    taskCountForHeadlineAvg: trustedTaskIds.size,\u000a    avgCostPerTaskUsd:\u000a      trustedTaskIds.size > 0 ? round4(trustedTaskSpend / trustedTaskIds.size) : null,\u000a    totalSpendUsd: round4(totalSpend),\u000a    trustedSpendUsd: round4(trustedSpend),\u000a    trustedRows: trustedRows.length,\u000a    trustedRowPercent: percent(trustedRows.length, rows.length),\u000a    unpricedRows: unpricedRows.length,\u000a    unpricedSpendUsd: round4(unpricedRows.reduce((sum, r) => sum + asNumber(r.totalCostUsd), 0)),\u000a    nonTaskSessionRows: nonTaskRows.length,\u000a    nonTaskSessionSpendUsd: round4(\u000a      nonTaskRows.reduce((sum, r) => sum + asNumber(r.totalCostUsd), 0),\u000a    ),\u000a    tokenTotals: {\u000a      inputTokens: sumToken("inputTokens"),\u000a      outputTokens: sumToken("outputTokens"),\u000a      cacheReadTokens: sumToken("cacheReadTokens"),\u000a      cacheWriteTokens: sumToken("cacheWriteTokens"),\u000a      reasoningOutputTokens: sumToken("reasoningOutputTokens"),\u000a      thinkingTokens: sumToken("thinkingTokens"),\u000a    },\u000a    unknownCounts: {\u000a      cacheWriteTokens: unknownCount("cacheWriteTokens"),\u000a      numTurns: unknownCount("numTurns"),\u000a    },\u000a    byModel: groupBy("model"),\u000a    byAgent: groupBy("agentName"),\u000a    byProvider: groupBy("provider"),\u000a    byCostSource: groupBy("costSource"),\u000a  };\u000a}\u000a\u000a/**\u000a * Daily compounding insights — compressed JSON for Phase 0 evolution.\u000a *\u000a * Swarm-wide by design: every section aggregates across ALL agents via direct\u000a * read-only SQL (no per-agent scoping), so a single call replaces ~25 raw tool\u000a * roundtrips. Parametric via `days` + the `include*` flags.\u000a */\u000aexport default async function compoundInsights(args: any, ctx: any) {\u000a  const parsed = argsSchema.safeParse(args || {});\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a  const days = parsed.data.days || 3;\u000a  const includeToolUsage = parsed.data.includeToolUsage !== false;\u000a  const includeScheduleHealth = parsed.data.includeScheduleHealth !== false;\u000a  const includeMemoryHealth = parsed.data.includeMemoryHealth !== false;\u000a  const includeScriptCandidates = parsed.data.includeScriptCandidates !== false;\u000a  const includeScriptUsage = parsed.data.includeScriptUsage !== false;\u000a  const includeCostAndTokens = parsed.data.includeCostAndTokens !== false;\u000a  const includeByAgent = parsed.data.includeByAgent !== false;\u000a  const publishPage = parsed.data.publishPage !== false;\u000a\u000a  // `days` is a validated positive int, so it is safe to interpolate into the\u000a  // SQLite datetime modifier. EXCLUDED_FAIL is a fixed constant list.\u000a  const w = `datetime(''now'',''-${days} days'')`;\u000a  const exclList = EXCLUDED_FAIL.map((r) => `''${r}''`).join(",");\u000a  // A "real" failure = status failed AND not one of the bookkeeping reasons.\u000a  const realFail = `t.status=''failed'' AND (t.failureReason IS NULL OR t.failureReason NOT IN (${exclList}))`;\u000a\u000a  const insights: any = { days, generatedAt: new Date().toISOString() };\u000a\u000a  // Task summary (all agents, direct SQL).\u000a  const statusRows = rowsToObjects(\u000a    await ctx.swarm.db_query({\u000a      sql: `SELECT status, count(*) as cnt FROM agent_tasks t WHERE t.createdAt > ${w} GROUP BY status`,\u000a    }),\u000a  );\u000a  const statusCounts: Record<string, number> = {};\u000a  let total = 0;\u000a  for (const r of statusRows) {\u000a    statusCounts[r.status] = r.cnt;\u000a    total += r.cnt;\u000a  }\u000a  const completed = statusCounts.completed ?? 0;\u000a  const failed = statusCounts.failed ?? 0;\u000a  insights.taskSummary = {\u000a    total,\u000a    completed,\u000a    failed,\u000a    completionRate: total > 0 ? Math.round((completed / total) * 1000) / 10 : 0,\u000a    failureRate: total > 0 ? Math.round((failed / total) * 1000) / 10 : 0,\u000a    statusCounts,\u000a  };\u000a\u000a  // Failure clusters (real failures only, normalized to a 60-char lowercased prefix).\u000a  insights.failureClusters = rowsToObjects(\u000a    await ctx.swarm.db_query({\u000a      sql: `SELECT substr(lower(t.failureReason),1,60) as reason, count(*) as count\u000a            FROM agent_tasks t\u000a            WHERE ${realFail} AND t.failureReason IS NOT NULL AND t.createdAt > ${w}\u000a            GROUP BY reason ORDER BY count DESC LIMIT 10`,\u000a    }),\u000a  );\u000a\u000a  // Schedule health (>= 2 runs, > 20% real-failure rate).\u000a  if (includeScheduleHealth) {\u000a    const sh = rowsToObjects(\u000a      await ctx.swarm.db_query({\u000a        sql: `SELECT s.name as name, s.id as id, count(t.id) as runs,\u000a                     sum(case when ${realFail} then 1 else 0 end) as failed\u000a              FROM scheduled_tasks s\u000a              JOIN agent_tasks t ON t.scheduleId = s.id\u000a              WHERE t.createdAt > ${w} AND t.status != ''cancelled''\u000a              GROUP BY s.id, s.name HAVING runs >= 2`,\u000a      }),\u000a    );\u000a    insights.scheduleHealth = sh\u000a      .map((r: any) => ({\u000a        name: r.name,\u000a        id: r.id,\u000a        runs: r.runs,\u000a        failureRate: r.runs > 0 ? Math.round((r.failed / r.runs) * 100) : 0,\u000a      }))\u000a      .filter((r: any) => r.failureRate > 20)\u000a      .sort((a: any, b: any) => b.failureRate - a.failureRate);\u000a  }\u000a\u000a  // Tool usage (top 25). Tool names live inside the `content` JSON of\u000a  // session_logs (no dedicated column), so extract the name SQL-side: the\u000a  // `''%"type":"tool_use"%''` filter excludes tool_result rows (which only carry\u000a  // `tool_use_id`), and instr/substr pull the first tool name per log line.\u000a  // Approximate: a log line with parallel tool_use blocks counts only its first.\u000a  if (includeToolUsage) {\u000a    insights.toolUsage = rowsToObjects(\u000a      await ctx.swarm.db_query({\u000a        sql: `WITH tu AS (\u000a                 SELECT substr(content, instr(content,''"type":"tool_use"'')) AS tail\u000a                 FROM session_logs\u000a                 WHERE content LIKE ''%"type":"tool_use"%'' AND createdAt > ${w}\u000a               ),\u000a               nm AS (\u000a                 SELECT substr(tail, instr(tail,''"name":"'')+8) AS rest\u000a                 FROM tu WHERE instr(tail,''"name":"'') > 0\u000a               )\u000a               SELECT substr(rest,1,instr(rest,''"'')-1) AS tool, count(*) AS calls\u000a               FROM nm GROUP BY tool ORDER BY calls DESC LIMIT 25`,\u000a      }),\u000a    ).map((r: any) => ({ tool: r.tool, calls: r.calls }));\u000a  }\u000a\u000a  // Memory health (whole store, by scope + source). Pollution markers are\u000a  // SQL-light counts plus JS-side embedding similarity where available; prod\u000a  // SQLite does not expose a scalar cosine_similarity() function.\u000a  if (includeMemoryHealth) {\u000a    const memRows = rowsToObjects(\u000a      await ctx.swarm.db_query({\u000a        sql: `SELECT scope, source, count(*) as cnt,\u000a                     sum(case when accessCount = 0 then 1 else 0 end) as zeroAccess,\u000a                     sum(case when sourceTaskId IS NOT NULL OR sourcePath IS NOT NULL then 1 else 0 end) as referenced\u000a              FROM agent_memory GROUP BY scope, source`,\u000a      }),\u000a    );\u000a    const totalMem = memRows.reduce((s: number, r: any) => s + (r.cnt ?? 0), 0);\u000a    const bySource: any = {};\u000a    for (const r of memRows) {\u000a      bySource[r.source] ??= {\u000a        total: 0,\u000a        percentOfStore: 0,\u000a        zeroAccess: 0,\u000a        zeroAccessPercent: 0,\u000a        referenced: 0,\u000a      };\u000a      bySource[r.source].total += asNumber(r.cnt);\u000a      bySource[r.source].zeroAccess += asNumber(r.zeroAccess);\u000a      bySource[r.source].referenced += asNumber(r.referenced);\u000a    }\u000a    for (const source of Object.keys(bySource)) {\u000a      bySource[source].percentOfStore = percent(bySource[source].total, totalMem);\u000a      bySource[source].zeroAccessPercent = percent(bySource[source].zeroAccess, bySource[source].total);\u000a    }\u000a\u000a    const autoSnapshotSources = ["session_summary", "task_completion"];\u000a    const autoSnapshotTotal = autoSnapshotSources.reduce(\u000a      (sum, source) => sum + (bySource[source]?.total ?? 0),\u000a      0,\u000a    );\u000a    const popularButUseless = rowsToObjects(\u000a      await ctx.swarm.db_query({\u000a        sql: `SELECT id, name, source, accessCount, alpha, beta,\u000a                     round(alpha / nullif(alpha + beta, 0), 3) as usefulness,\u000a                     substr(content, 1, 180) as preview\u000a              FROM agent_memory\u000a              WHERE source IN (''session_summary'',''task_completion'')\u000a                AND accessCount >= 5\u000a                AND alpha <= beta\u000a              ORDER BY accessCount DESC, beta DESC LIMIT 10`,\u000a      }),\u000a    ).map((r: any) => ({\u000a      id: r.id,\u000a      name: r.name,\u000a      source: r.source,\u000a      accessCount: asNumber(r.accessCount),\u000a      usefulness: Number(r.usefulness ?? 0),\u000a      preview: r.preview,\u000a    }));\u000a    const zeroAccessStaleRefRows = rowsToObjects(\u000a      await ctx.swarm.db_query({\u000a        sql: `SELECT source, count(*) as count\u000a              FROM agent_memory\u000a              WHERE accessCount = 0\u000a                AND (sourceTaskId IS NOT NULL OR sourcePath IS NOT NULL)\u000a                AND createdAt < datetime(''now'',''-${days} days'')\u000a              GROUP BY source ORDER BY count DESC`,\u000a      }),\u000a    );\u000a\u000a    const similarityRows = rowsToObjects(\u000a      await ctx.swarm.db_query({\u000a        sql: `SELECT id, name, source, accessCount, embedding\u000a              FROM agent_memory\u000a              WHERE source IN (''session_summary'',''task_completion'')\u000a                AND embedding IS NOT NULL\u000a              ORDER BY accessCount DESC LIMIT 30`,\u000a      }),\u000a    );\u000a    let strongestAutoSnapshotPair: any = null;\u000a    const vectors = similarityRows\u000a      .map((r: any) => ({ ...r, vector: decodeFloat32Blob(r.embedding) }))\u000a      .filter((r: any) => r.vector);\u000a    for (let i = 0; i < vectors.length; i++) {\u000a      for (let j = i + 1; j < vectors.length; j++) {\u000a        const similarity = cosineSimilarity(vectors[i].vector, vectors[j].vector);\u000a        if (!strongestAutoSnapshotPair || similarity > strongestAutoSnapshotPair.similarity) {\u000a          strongestAutoSnapshotPair = {\u000a            similarity: round1(similarity * 100) / 100,\u000a            a: { id: vectors[i].id, name: vectors[i].name, source: vectors[i].source },\u000a            b: { id: vectors[j].id, name: vectors[j].name, source: vectors[j].source },\u000a          };\u000a        }\u000a      }\u000a    }\u000a\u000a    insights.memoryHealth = {\u000a      total: totalMem,\u000a      byScope: memRows.reduce((m: any, r: any) => {\u000a        m[r.scope] = (m[r.scope] ?? 0) + r.cnt;\u000a        return m;\u000a      }, {}),\u000a      bySource,\u000a      pollution: {\u000a        autoSnapshotSources,\u000a        autoSnapshotTotal,\u000a        autoSnapshotPercent: percent(autoSnapshotTotal, totalMem),\u000a        popularButUselessAutoSnapshots: popularButUseless,\u000a        zeroAccessStaleRefs: {\u000a          total: zeroAccessStaleRefRows.reduce((sum: number, r: any) => sum + asNumber(r.count), 0),\u000a          bySource: zeroAccessStaleRefRows.reduce((m: any, r: any) => {\u000a            m[r.source] = asNumber(r.count);\u000a            return m;\u000a          }, {}),\u000a        },\u000a        similarityCheck: {\u000a          sqliteCosineSimilarityAvailable: false,\u000a          path: "js",\u000a          sampledAutoSnapshots: vectors.length,\u000a          strongestAutoSnapshotPair,\u000a        },\u000a      },\u000a    };\u000a  }\u000a\u000a  // Evolution/self-scripting candidates: high-frequency consecutive tool\u000a  // triplets are good prompts for a future seed script.\u000a  if (includeScriptCandidates) {\u000a    const rows = rowsToObjects(\u000a      await ctx.swarm.db_query({\u000a        sql: `WITH raw AS (\u000a                 SELECT sessionId, iteration, lineNumber, content,\u000a                        json_extract(content, ''$.tool_name'') as jsonToolName\u000a                 FROM session_logs\u000a                 WHERE createdAt > ${w}\u000a                   AND (content LIKE ''%"type":"tool_use"%'' OR json_extract(content, ''$.tool_name'') IS NOT NULL)\u000a               )\u000a               SELECT sessionId, iteration, lineNumber, jsonToolName, content\u000a               FROM raw ORDER BY sessionId, iteration, lineNumber LIMIT 100`,\u000a      }),\u000a    );\u000a    const bySession = new Map<string, string[]>();\u000a    for (const row of rows) {\u000a      const tool = row.jsonToolName || extractToolName(String(row.content ?? ""));\u000a      if (!tool) continue;\u000a      const key = String(row.sessionId ?? "unknown");\u000a      const tools = bySession.get(key) ?? [];\u000a      tools.push(tool);\u000a      bySession.set(key, tools);\u000a    }\u000a    const counts = new Map<string, { tools: string[]; count: number }>();\u000a    for (const tools of bySession.values()) {\u000a      for (let i = 0; i <= tools.length - 3; i++) {\u000a        const triplet = tools.slice(i, i + 3);\u000a        const key = triplet.join(" -> ");\u000a        const current = counts.get(key) ?? { tools: triplet, count: 0 };\u000a        current.count += 1;\u000a        counts.set(key, current);\u000a      }\u000a    }\u000a    insights.scriptCandidates = [...counts.values()]\u000a      .sort((a, b) => b.count - a.count)\u000a      .slice(0, 10)\u000a      .map((r) => ({\u000a        tools: r.tools,\u000a        count: r.count,\u000a        suggestedName: r.tools.map(toolSlug).filter(Boolean).slice(0, 3).join("-").slice(0, 80),\u000a      }));\u000a  }\u000a\u000a  // Actual script usage. Authoritative run counts come from `script_runs`;\u000a  // session_logs tool_use rows are a separate MCP-call signal for reconciliation\u000a  // and are intentionally not added to run totals.\u000a  if (includeScriptUsage) {\u000a    const runRows = rowsToObjects(\u000a      await ctx.swarm.db_query({\u000a        sql: `WITH journal_durations AS (\u000a                 SELECT runId, sum(durationMs) AS journalDurationMs\u000a                 FROM script_run_journal\u000a                 WHERE durationMs IS NOT NULL\u000a                 GROUP BY runId\u000a               )\u000a               SELECT sr.scriptName, sr.kind, sr.status, sr.startedAt, sr.finishedAt,\u000a                      COALESCE(\u000a                        jd.journalDurationMs,\u000a                        CASE\u000a                          WHEN sr.finishedAt IS NOT NULL\u000a                          THEN CAST((julianday(sr.finishedAt) - julianday(sr.startedAt)) * 86400000 AS INTEGER)\u000a                          ELSE NULL\u000a                        END\u000a                      ) AS durationMs\u000a               FROM script_runs sr\u000a               LEFT JOIN journal_durations jd ON jd.runId = sr.id\u000a               WHERE sr.startedAt > ${w}\u000a               ORDER BY sr.startedAt DESC`,\u000a      }),\u000a    );\u000a    const creationRows = rowsToObjects(\u000a      await ctx.swarm.db_query({\u000a        sql: `SELECT scope, isScratch, count(*) AS count\u000a              FROM scripts\u000a              WHERE createdAt > ${w}\u000a              GROUP BY scope, isScratch`,\u000a      }),\u000a    );\u000a    const editRows = rowsToObjects(\u000a      await ctx.swarm.db_query({\u000a        sql: `SELECT s.scope, count(*) AS count\u000a              FROM script_versions sv\u000a              JOIN scripts s ON s.id = sv.scriptId\u000a              WHERE sv.changedAt > ${w} AND sv.version > 1\u000a              GROUP BY s.scope`,\u000a      }),\u000a    );\u000a    const scriptToolRows = rowsToObjects(\u000a      await ctx.swarm.db_query({\u000a        sql: `WITH tu AS (\u000a                 SELECT substr(content, instr(content,''"type":"tool_use"'')) AS tail,\u000a                        json_extract(content, ''$.tool_name'') as jsonToolName\u000a                 FROM session_logs\u000a                 WHERE createdAt > ${w}\u000a                   AND (content LIKE ''%script-run%''\u000a                     OR content LIKE ''%launch-script-run%''\u000a                     OR content LIKE ''%get-script-run%''\u000a                     OR content LIKE ''%list-script-runs%'')\u000a               ),\u000a               nm AS (\u000a                 SELECT COALESCE(\u000a                          jsonToolName,\u000a                          CASE\u000a                            WHEN instr(tail,''"name":"'') > 0\u000a                            THEN substr(substr(tail, instr(tail,''"name":"'')+8), 1, instr(substr(tail, instr(tail,''"name":"'')+8), ''"'')-1)\u000a                            ELSE NULL\u000a                          END\u000a                        ) AS tool\u000a                 FROM tu\u000a               )\u000a               SELECT tool, count(*) AS calls\u000a               FROM nm\u000a               WHERE tool IS NOT NULL AND tool LIKE ''%script%''\u000a               GROUP BY tool\u000a               ORDER BY calls DESC`,\u000a      }),\u000a    );\u000a    insights.scriptUsage = summarizeScriptUsage(runRows, creationRows, editRows, scriptToolRows);\u000a  }\u000a\u000a  // Cost and token accounting. `costSource=''unpriced''` rows are excluded from\u000a  // the headline per-task average, and null taskId rows are reported separately.\u000a  if (includeCostAndTokens) {\u000a    const costRows = rowsToObjects(\u000a      await ctx.swarm.db_query({\u000a        sql: `SELECT sc.taskId, sc.agentId, COALESCE(a.name, sc.agentId, ''unknown'') AS agentName,\u000a                     COALESCE(a.harness_provider, a.provider, ''unknown'') AS provider,\u000a                     sc.totalCostUsd, sc.inputTokens, sc.outputTokens, sc.cacheReadTokens,\u000a                     sc.cacheWriteTokens, sc.reasoningOutputTokens, sc.thinkingTokens,\u000a                     sc.numTurns, sc.model, sc.costSource\u000a              FROM session_costs sc\u000a              LEFT JOIN agents a ON a.id = sc.agentId\u000a              WHERE sc.createdAt > ${w}`,\u000a      }),\u000a    );\u000a    insights.costAndTokens = summarizeCostAndTokens(costRows);\u000a  }\u000a\u000a  // Per-agent breakdown — covers every agent that ran a task in the window.\u000a  if (includeByAgent) {\u000a    insights.byAgent = rowsToObjects(\u000a      await ctx.swarm.db_query({\u000a        sql: `SELECT a.name as agent, count(*) as total,\u000a                     sum(case when t.status=''completed'' then 1 else 0 end) as completed,\u000a                     sum(case when ${realFail} then 1 else 0 end) as failed\u000a              FROM agent_tasks t LEFT JOIN agents a ON a.id = t.agentId\u000a              WHERE t.createdAt > ${w} AND t.agentId IS NOT NULL\u000a              GROUP BY t.agentId, a.name ORDER BY total DESC LIMIT 30`,\u000a      }),\u000a    ).map((r: any) => ({\u000a      agent: r.agent,\u000a      total: r.total,\u000a      completed: r.completed,\u000a      failed: r.failed,\u000a    }));\u000a  }\u000a\u000a  if (publishPage) {\u000a    const failureFindings = (insights.failureClusters || []).map((cluster: any) => ({\u000a      id: `failure.${String(cluster.reason || "unknown").slice(0, 48)}`,\u000a      severity: cluster.count >= 5 ? "high" : cluster.count >= 2 ? "medium" : "low",\u000a      summary: `${cluster.count} real failure(s): ${cluster.reason}`,\u000a      action: "Review the repeated failure mode and decide whether to fix, retry, or add a temporary watch item.",\u000a      samples: [cluster],\u000a    }));\u000a    const scheduleFindings = (insights.scheduleHealth || []).map((schedule: any) => ({\u000a      id: `schedule.${schedule.id}`,\u000a      severity: schedule.failureRate >= 50 ? "high" : "medium",\u000a      summary: `${schedule.name} has ${schedule.failureRate}% real-failure rate.`,\u000a      action: "Inspect recent schedule tasks and repair, retarget, or disable the schedule.",\u000a      samples: [schedule],\u000a    }));\u000a    const memoryPollution = insights.memoryHealth?.pollution;\u000a    const memoryFindings = memoryPollution?.autoSnapshotPercent\u000a      ? [\u000a          {\u000a            id: "memory.auto-snapshot-share",\u000a            severity: memoryPollution.autoSnapshotPercent >= 40 ? "high" : "medium",\u000a            summary: `Automatic snapshots are ${memoryPollution.autoSnapshotPercent}% of memory.`,\u000a            action: "Review memory gates and prune low-use automatic snapshots before adding more.",\u000a            samples: [memoryPollution],\u000a          },\u000a        ]\u000a      : [];\u000a    const scriptFindings = (insights.scriptCandidates || []).map((candidate: any) => ({\u000a      id: `script-candidate.${candidate.suggestedName || "unnamed"}`,\u000a      severity: candidate.count >= 3 ? "medium" : "low",\u000a      summary: `${candidate.count} repeated tool triplet(s): ${candidate.tools.join(" -> ")}`,\u000a      action: "Consider turning this repeated workflow into a reusable seeded script.",\u000a      samples: [candidate],\u000a    }));\u000a    const scriptUsageFindings = insights.scriptUsage\u000a      ? [\u000a          {\u000a            id: "script-usage.actual-runs",\u000a            severity: "low",\u000a            summary: `${insights.scriptUsage.runs.total} actual script run(s): ${insights.scriptUsage.runs.inline} one-off, ${insights.scriptUsage.runs.workflow} recurring/workflow.`,\u000a            action: "Use script_runs as the authoritative run count; use session_logs only as an MCP-call reconciliation signal.",\u000a            samples: [insights.scriptUsage],\u000a          },\u000a        ]\u000a      : [];\u000a    const costFindings = insights.costAndTokens\u000a      ? [\u000a          {\u000a            id: "cost-and-tokens.headline",\u000a            severity:\u000a              insights.costAndTokens.unpricedRows > 0 || insights.costAndTokens.nonTaskSessionRows > 0\u000a                ? "medium"\u000a                : "low",\u000a            summary: `$${insights.costAndTokens.totalSpendUsd} total session spend; avg task cost $${insights.costAndTokens.avgCostPerTaskUsd ?? "n/a"} over trusted task rows.`,\u000a            action: "Keep unpriced and null-task session spend separate from the headline per-task average.",\u000a            samples: [insights.costAndTokens],\u000a          },\u000a        ]\u000a      : [];\u000a\u000a    insights.page = await publishCatalogReportPage(\u000a      {\u000a        title: "Compound Insights Audit",\u000a        slug: "compound-insights",\u000a        description: "Swarm-wide daily ops snapshot for compounding and reliability review.",\u000a        generatedAt: insights.generatedAt,\u000a        lede: `Swarm-wide ${days}-day snapshot: ${insights.taskSummary.total} task(s), ${insights.taskSummary.completionRate}% completion rate, ${insights.taskSummary.failureRate}% failure rate.`,\u000a        metrics: [\u000a          ["Tasks", insights.taskSummary.total],\u000a          ["Completed", insights.taskSummary.completed],\u000a          ["Failed", insights.taskSummary.failed],\u000a          ["Failure clusters", insights.failureClusters?.length || 0],\u000a          ["Script runs", insights.scriptUsage?.runs?.total ?? 0],\u000a          ["Total spend", insights.costAndTokens?.totalSpendUsd ?? 0],\u000a        ],\u000a        sections: [\u000a          {\u000a            key: "failures",\u000a            goal: "Expose repeated real failure modes without counting bookkeeping noise.",\u000a            findingCount: failureFindings.length,\u000a            checks: insights.taskSummary,\u000a            findings: failureFindings,\u000a          },\u000a          {\u000a            key: "schedules",\u000a            goal: "Keep schedule failures visible before daily work compounds stale assumptions.",\u000a            findingCount: scheduleFindings.length,\u000a            checks: { unhealthySchedules: scheduleFindings.length },\u000a            findings: scheduleFindings,\u000a          },\u000a          {\u000a            key: "memory",\u000a            goal: "Detect memory bloat and low-use automatic snapshots.",\u000a            findingCount: memoryFindings.length,\u000a            checks: insights.memoryHealth\u000a              ? {\u000a                  total: insights.memoryHealth.total,\u000a                  autoSnapshotPercent: memoryPollution?.autoSnapshotPercent ?? 0,\u000a                  sampledAutoSnapshots:\u000a                    memoryPollution?.similarityCheck?.sampledAutoSnapshots ?? 0,\u000a                }\u000a              : {},\u000a            findings: memoryFindings,\u000a          },\u000a          {\u000a            key: "script-candidates",\u000a            goal: "Find repeated tool chains worth compressing into reusable scripts.",\u000a            findingCount: scriptFindings.length,\u000a            checks: { candidates: scriptFindings.length },\u000a            findings: scriptFindings,\u000a          },\u000a          {\u000a            key: "script-usage",\u000a            goal: "Track actual one-off and recurring script execution without double-counting MCP tool-use logs.",\u000a            findingCount: scriptUsageFindings.length,\u000a            checks: insights.scriptUsage ?? {},\u000a            findings: scriptUsageFindings,\u000a          },\u000a          {\u000a            key: "cost-and-tokens",\u000a            goal: "Track per-task cost and token consumption while separating unpriced and non-task sessions.",\u000a            findingCount: costFindings.length,\u000a            checks: insights.costAndTokens ?? {},\u000a            findings: costFindings,\u000a          },\u000a        ],\u000a        appendix: insights,\u000a      },\u000a      ctx,\u000a    );\u000a  }\u000a\u000a  return insights;\u000a}\u000a'),'All-in-one swarm-wide daily ops snapshot: task completion/failure summary, real failure clusters (excludes superseded/cancelled bookkeeping), schedule health flags, tool usage top-25, memory health/pollution stats, seed-script candidate tool triplets, and a per-agent breakdown. Aggregates across ALL agents via direct read-only SQL.','Single-call daily compounding Phase 0 helper — replaces ~25 raw tool roundtrips with one compressed JSON result covering every agent. For daily evolution, self-scripting candidates, ops reviews, or heartbeat context.','{"argsType":"any","resultType":"unknown","description":"Daily compounding insights — compressed JSON for Phase 0 evolution.\n\nSwarm-wide by design: every section aggregates across ALL agents via direct\nread-only SQL (no per-agent scoping), so a single call replaces ~25 raw tool\nroundtrips. Parametric via `days` + the `include*` flags."}','5184736e075953f14c91c6889d6299d8b29b3dbf4e99867457207e66c892bf26',1,0,1,'none',NULL,'2026-06-11T22:38:24.104Z','2026-06-11T22:38:24.104Z','{"$schema":"https://json-schema.org/draft/2020-12/schema","type":"object","properties":{"days":{"description":"Look back this many days (default 3)","type":"integer","exclusiveMinimum":0,"maximum":9007199254740991,"minimum":-9007199254740991},"includeToolUsage":{"description":"Include tool usage histogram (default true)","type":"boolean"},"includeScheduleHealth":{"description":"Include schedule health flags (default true)","type":"boolean"},"includeMemoryHealth":{"description":"Include memory health stats (default true)","type":"boolean"},"includeScriptCandidates":{"description":"Include high-frequency tool-triplet candidates for future seed scripts (default true)","type":"boolean"},"includeScriptUsage":{"description":"Include actual script run, creation, and edit metrics (default true)","type":"boolean"},"includeCostAndTokens":{"description":"Include session cost and token metrics with honesty rails (default true)","type":"boolean"},"includeByAgent":{"description":"Include per-agent task/completion/failure breakdown (default true)","type":"boolean"},"publishPage":{"description":"Publish an authed HTML page (default true)","type":"boolean"}},"additionalProperties":false}',NULL,NULL);
INSERT INTO scripts VALUES('185a38f0-a97f-493f-9bbd-e5636bc7d814','memory-eval','global',NULL,unistr('import { z } from "zod";\u000a\u000aexport const argsSchema = z.object({\u000a  days: z\u000a    .number()\u000a    .int()\u000a    .positive()\u000a    .optional()\u000a    .describe("Look back this many days for retrieval/rating data (default 30)"),\u000a  freshDays: z\u000a    .number()\u000a    .int()\u000a    .positive()\u000a    .optional()\u000a    .describe("Memories younger than this are ''fresh'' (default 14)"),\u000a  usefulnessThreshold: z\u000a    .number()\u000a    .min(0)\u000a    .max(1)\u000a    .optional()\u000a    .describe("α/(α+β) cutoff for ''useful'' (default 0.6)"),\u000a  backfillDays: z\u000a    .number()\u000a    .int()\u000a    .min(0)\u000a    .optional()\u000a    .describe("Backfill this many past daily points on first run (default 14; 0 to skip)"),\u000a  publishPage: z.boolean().optional().describe("Publish an authed HTML page (default true)"),\u000a  writeAgentFs: z.boolean().optional().describe("Write markdown report to agent-fs (default true)"),\u000a});\u000a\u000aconst KV_NS = "memory-eval";\u000aconst KV_KEY = "history";\u000a\u000atype DailyPoint = {\u000a  date: string;\u000a  axis1Score: number;\u000a  axis1Total: number;\u000a  axis1Hits: number;\u000a  axis2AvgUsefulness: number | null;\u000a  axis2Retrievals: number | null;\u000a  axis2PrefCount: number | null;\u000a  axis3FreshScore: number;\u000a  axis3TotalRetrieved: number;\u000a  axis3ExpiredPct: number;\u000a  totalMemories: number;\u000a  searchableMemories: number;\u000a  expiredMemories: number;\u000a  backfilled: boolean;\u000a};\u000a\u000afunction rowsToObjects(res: any): any[] {\u000a  const p = res?.data ?? res;\u000a  const cols: string[] = p?.columns ?? [];\u000a  return (p?.rows ?? []).map((r: any) =>\u000a    Array.isArray(r) ? Object.fromEntries(cols.map((c, i) => [c, r[i]])) : r,\u000a  );\u000a}\u000a\u000afunction pct(part: number, total: number): number {\u000a  return total > 0 ? Math.round((part / total) * 1000) / 10 : 0;\u000a}\u000a\u000afunction round2(n: number): number {\u000a  return Math.round(n * 100) / 100;\u000a}\u000a\u000afunction esc(value: unknown): string {\u000a  const s = typeof value === "string" ? value : value == null ? "" : JSON.stringify(value);\u000a  return s.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;");\u000a}\u000a\u000aasync function computeBackfillPoint(\u000a  ctx: any,\u000a  refDate: string,\u000a  days: number,\u000a  freshDays: number,\u000a  usefulnessThreshold: number,\u000a): Promise<DailyPoint> {\u000a  const w = `datetime(''${refDate}'',''-${days} days'')`;\u000a  const ref = `''${refDate}''`;\u000a  const freshW = `datetime(''${refDate}'',''-${freshDays} days'')`;\u000a\u000a  const axis1TotalRows = rowsToObjects(\u000a    await ctx.swarm.db_query({\u000a      sql: `SELECT count(*) as cnt FROM agent_tasks t\u000a            WHERE t.contextKey IS NOT NULL AND t.status = ''completed''\u000a              AND t.createdAt > ${w} AND t.createdAt <= ${ref}\u000a              AND EXISTS (\u000a                SELECT 1 FROM agent_tasks p\u000a                WHERE p.contextKey = t.contextKey AND p.id != t.id AND p.createdAt < t.createdAt\u000a              )`,\u000a    }),\u000a  );\u000a  const a1Total = Number(axis1TotalRows[0]?.cnt ?? 0);\u000a\u000a  let a1Hits = 0;\u000a  if (a1Total > 0) {\u000a    const axis1HitRows = rowsToObjects(\u000a      await ctx.swarm.db_query({\u000a        sql: `SELECT count(DISTINCT mr.taskId) as cnt FROM memory_retrieval mr\u000a              JOIN agent_memory m ON mr.memoryId = m.id\u000a              JOIN agent_tasks ct ON mr.taskId = ct.id\u000a              WHERE ct.contextKey IS NOT NULL AND ct.status = ''completed''\u000a                AND ct.createdAt > ${w} AND ct.createdAt <= ${ref}\u000a                AND m.sourceTaskId IS NOT NULL\u000a                AND m.alpha / nullif(m.alpha + m.beta, 0) > ${usefulnessThreshold}\u000a                AND EXISTS (\u000a                  SELECT 1 FROM agent_tasks p\u000a                  WHERE p.contextKey = ct.contextKey AND p.id = m.sourceTaskId AND p.createdAt < ct.createdAt\u000a                )\u000a                AND EXISTS (\u000a                  SELECT 1 FROM agent_tasks e\u000a                  WHERE e.contextKey = ct.contextKey AND e.id != ct.id AND e.createdAt < ct.createdAt\u000a                )`,\u000a      }),\u000a    );\u000a    a1Hits = Number(axis1HitRows[0]?.cnt ?? 0);\u000a  }\u000a\u000a  const axis3Rows = rowsToObjects(\u000a    await ctx.swarm.db_query({\u000a      sql: `SELECT\u000a              CASE\u000a                WHEN m.createdAt > ${freshW} THEN ''fresh''\u000a                WHEN m.expiresAt IS NOT NULL AND m.expiresAt < ${ref} THEN ''expired''\u000a                ELSE ''other''\u000a              END as bucket,\u000a              count(DISTINCT mr.memoryId) as uniqueMemories\u000a            FROM memory_retrieval mr\u000a            JOIN agent_memory m ON mr.memoryId = m.id\u000a            WHERE mr.retrievedAt > ${w} AND mr.retrievedAt <= ${ref}\u000a            GROUP BY bucket`,\u000a    }),\u000a  );\u000a\u000a  let totalRetrieved = 0;\u000a  let freshMem = 0;\u000a  let expiredMem = 0;\u000a  for (const r of axis3Rows) {\u000a    const n = Number(r.uniqueMemories ?? 0);\u000a    totalRetrieved += n;\u000a    if (r.bucket === "fresh") freshMem = n;\u000a    if (r.bucket === "expired") expiredMem = n;\u000a  }\u000a\u000a  const storeRows = rowsToObjects(\u000a    await ctx.swarm.db_query({\u000a      sql: `SELECT\u000a              count(*) as total,\u000a              sum(CASE WHEN expiresAt IS NULL OR expiresAt > ${ref} THEN 1 ELSE 0 END) as searchable,\u000a              sum(CASE WHEN expiresAt IS NOT NULL AND expiresAt <= ${ref} THEN 1 ELSE 0 END) as expired\u000a            FROM agent_memory WHERE createdAt <= ${ref}`,\u000a    }),\u000a  );\u000a  const store = storeRows[0] ?? {};\u000a\u000a  return {\u000a    date: refDate,\u000a    axis1Score: pct(a1Hits, a1Total),\u000a    axis1Total: a1Total,\u000a    axis1Hits: a1Hits,\u000a    axis2AvgUsefulness: null,\u000a    axis2Retrievals: null,\u000a    axis2PrefCount: null,\u000a    axis3FreshScore: pct(freshMem, totalRetrieved),\u000a    axis3TotalRetrieved: totalRetrieved,\u000a    axis3ExpiredPct: pct(expiredMem, totalRetrieved),\u000a    totalMemories: Number(store.total ?? 0),\u000a    searchableMemories: Number(store.searchable ?? 0),\u000a    expiredMemories: Number(store.expired ?? 0),\u000a    backfilled: true,\u000a  };\u000a}\u000a\u000afunction reportToDailyPoint(date: string, report: any): DailyPoint {\u000a  return {\u000a    date,\u000a    axis1Score: report.axis1.score,\u000a    axis1Total: report.axis1.followUpTasks,\u000a    axis1Hits: report.axis1.tasksWithUsefulCarryForward,\u000a    axis2AvgUsefulness: report.axis2.avgUsefulness,\u000a    axis2Retrievals: report.axis2.totalRetrievals,\u000a    axis2PrefCount: report.axis2.totalPreferenceMemories,\u000a    axis3FreshScore: report.axis3.freshScore,\u000a    axis3TotalRetrieved: report.axis3.totalUniqueMemoriesRetrieved,\u000a    axis3ExpiredPct: report.axis3.buckets.expired.pctOfRetrieved,\u000a    totalMemories: report.storeSnapshot.totalMemories,\u000a    searchableMemories: report.storeSnapshot.totalMemories - report.storeSnapshot.expiredMemories,\u000a    expiredMemories: report.storeSnapshot.expiredMemories,\u000a    backfilled: false,\u000a  };\u000a}\u000a\u000a/** 3-axis memory quality evaluation with over-time trend tracking and KV-backed historical backfill. */\u000aexport default async function memoryEval(args: any, ctx: any) {\u000a  const parsed = argsSchema.safeParse(args || {});\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a\u000a  const days = parsed.data.days || 30;\u000a  const freshDays = parsed.data.freshDays || 14;\u000a  const usefulnessThreshold = parsed.data.usefulnessThreshold ?? 0.6;\u000a  const backfillDays = parsed.data.backfillDays ?? 14;\u000a  const publishPage = parsed.data.publishPage !== false;\u000a  const writeAgentFs = parsed.data.writeAgentFs !== false;\u000a\u000a  const now = new Date().toISOString();\u000a  const today = now.slice(0, 10);\u000a  const report: any = { generatedAt: now, days, freshDays, usefulnessThreshold };\u000a\u000a  // ─── Axis 1: Carry-forward context ───────────────────────────────────\u000a  const w = `datetime(''now'',''-${days} days'')`;\u000a\u000a  const axis1FollowUps = rowsToObjects(\u000a    await ctx.swarm.db_query({\u000a      sql: `SELECT t.id as taskId, t.contextKey\u000a            FROM agent_tasks t\u000a            WHERE t.contextKey IS NOT NULL\u000a              AND t.status = ''completed''\u000a              AND t.createdAt > ${w}\u000a              AND EXISTS (\u000a                SELECT 1 FROM agent_tasks prior\u000a                WHERE prior.contextKey = t.contextKey\u000a                  AND prior.id != t.id\u000a                  AND prior.createdAt < t.createdAt\u000a              )`,\u000a    }),\u000a  );\u000a\u000a  let axis1HitCount = 0;\u000a  const axis1Total = axis1FollowUps.length;\u000a\u000a  if (axis1Total > 0) {\u000a    const axis1Hits = rowsToObjects(\u000a      await ctx.swarm.db_query({\u000a        sql: `SELECT DISTINCT mr.taskId\u000a              FROM memory_retrieval mr\u000a              JOIN agent_memory m ON mr.memoryId = m.id\u000a              JOIN agent_tasks current_task ON mr.taskId = current_task.id\u000a              WHERE current_task.contextKey IS NOT NULL\u000a                AND current_task.status = ''completed''\u000a                AND current_task.createdAt > ${w}\u000a                AND m.sourceTaskId IS NOT NULL\u000a                AND m.alpha / nullif(m.alpha + m.beta, 0) > ${usefulnessThreshold}\u000a                AND EXISTS (\u000a                  SELECT 1 FROM agent_tasks prior\u000a                  WHERE prior.contextKey = current_task.contextKey\u000a                    AND prior.id = m.sourceTaskId\u000a                    AND prior.createdAt < current_task.createdAt\u000a                )\u000a                AND EXISTS (\u000a                  SELECT 1 FROM agent_tasks earlier\u000a                  WHERE earlier.contextKey = current_task.contextKey\u000a                    AND earlier.id != current_task.id\u000a                    AND earlier.createdAt < current_task.createdAt\u000a                )`,\u000a      }),\u000a    );\u000a    axis1HitCount = axis1Hits.length;\u000a  }\u000a\u000a  report.axis1 = {\u000a    name: "Carry-forward context",\u000a    description:\u000a      "Fraction of contextKey-chained follow-up tasks that retrieve ≥1 useful memory from a prior task in the same chain.",\u000a    followUpTasks: axis1Total,\u000a    tasksWithUsefulCarryForward: axis1HitCount,\u000a    score: pct(axis1HitCount, axis1Total),\u000a    softTarget: 60,\u000a    unit: "%",\u000a  };\u000a\u000a  // ─── Axis 2: Follow preferences & constraints ───────────────────────\u000a\u000a  const prefMemories = rowsToObjects(\u000a    await ctx.swarm.db_query({\u000a      sql: `SELECT id, name, sourcePath, alpha, beta, accessCount,\u000a                   CASE WHEN (alpha + beta) > 0 THEN round(alpha / (alpha + beta), 4) ELSE 0.5 END as usefulness\u000a            FROM agent_memory\u000a            WHERE source = ''file_index''\u000a              AND (sourcePath LIKE ''%CLAUDE.md''\u000a                OR sourcePath LIKE ''%IDENTITY.md''\u000a                OR sourcePath LIKE ''%SOUL.md''\u000a                OR sourcePath LIKE ''%TOOLS.md'')`,\u000a    }),\u000a  );\u000a\u000a  const prefTotal = prefMemories.length;\u000a  const prefWithAccess = prefMemories.filter((m: any) => (m.accessCount ?? 0) > 0).length;\u000a  const prefUsefulnessValues = prefMemories.map((m: any) => Number(m.usefulness ?? 0.5));\u000a  const prefAvgUsefulness =\u000a    prefUsefulnessValues.length > 0\u000a      ? round2(prefUsefulnessValues.reduce((s: number, v: number) => s + v, 0) / prefUsefulnessValues.length)\u000a      : 0;\u000a  const prefTotalAccess = prefMemories.reduce((s: number, m: any) => s + (m.accessCount ?? 0), 0);\u000a\u000a  const prefRatings = rowsToObjects(\u000a    await ctx.swarm.db_query({\u000a      sql: `SELECT mr.source as raterSource, count(*) as cnt,\u000a                   round(avg(mr.signal), 4) as avgSignal\u000a            FROM memory_rating mr\u000a            JOIN agent_memory m ON mr.memoryId = m.id\u000a            WHERE m.source = ''file_index''\u000a              AND (m.sourcePath LIKE ''%CLAUDE.md''\u000a                OR m.sourcePath LIKE ''%IDENTITY.md''\u000a                OR m.sourcePath LIKE ''%SOUL.md''\u000a                OR m.sourcePath LIKE ''%TOOLS.md'')\u000a            GROUP BY mr.source`,\u000a    }),\u000a  );\u000a\u000a  const prefByPath = rowsToObjects(\u000a    await ctx.swarm.db_query({\u000a      sql: `SELECT\u000a              CASE\u000a                WHEN sourcePath LIKE ''%CLAUDE.md'' THEN ''CLAUDE.md''\u000a                WHEN sourcePath LIKE ''%IDENTITY.md'' THEN ''IDENTITY.md''\u000a                WHEN sourcePath LIKE ''%SOUL.md'' THEN ''SOUL.md''\u000a                WHEN sourcePath LIKE ''%TOOLS.md'' THEN ''TOOLS.md''\u000a                ELSE ''other''\u000a              END as fileType,\u000a              count(*) as cnt,\u000a              sum(accessCount) as totalAccess,\u000a              round(avg(CASE WHEN (alpha + beta) > 0 THEN alpha / (alpha + beta) ELSE 0.5 END), 4) as avgUsefulness\u000a            FROM agent_memory\u000a            WHERE source = ''file_index''\u000a              AND (sourcePath LIKE ''%CLAUDE.md''\u000a                OR sourcePath LIKE ''%IDENTITY.md''\u000a                OR sourcePath LIKE ''%SOUL.md''\u000a                OR sourcePath LIKE ''%TOOLS.md'')\u000a            GROUP BY fileType`,\u000a    }),\u000a  );\u000a\u000a  report.axis2 = {\u000a    name: "Follow preferences & constraints",\u000a    description:\u000a      "Retrieval rate and LlmRater scores for file_index memories from CLAUDE.md/IDENTITY.md/SOUL.md/TOOLS.md (the ''preference memories'').",\u000a    totalPreferenceMemories: prefTotal,\u000a    memoriesEverRetrieved: prefWithAccess,\u000a    retrievalRate: pct(prefWithAccess, prefTotal),\u000a    totalRetrievals: prefTotalAccess,\u000a    avgUsefulness: prefAvgUsefulness,\u000a    raterBreakdown: prefRatings.map((r: any) => ({\u000a      rater: r.raterSource,\u000a      ratings: r.cnt,\u000a      avgSignal: Number(r.avgSignal ?? 0),\u000a    })),\u000a    byFile: prefByPath.map((r: any) => ({\u000a      file: r.fileType,\u000a      memories: r.cnt,\u000a      totalAccess: r.totalAccess ?? 0,\u000a      avgUsefulness: Number(r.avgUsefulness ?? 0),\u000a    })),\u000a    softTarget: "High retrieval rate + usefulness > 0.6 on preference memories",\u000a    unit: "composite",\u000a  };\u000a\u000a  // ─── Axis 3: Stay current over time ──────────────────────────────────\u000a\u000a  const freshW = `datetime(''now'',''-${freshDays} days'')`;\u000a\u000a  const axis3Buckets = rowsToObjects(\u000a    await ctx.swarm.db_query({\u000a      sql: `SELECT\u000a              CASE\u000a                WHEN m.createdAt > ${freshW} THEN ''fresh''\u000a                WHEN m.expiresAt IS NOT NULL AND m.expiresAt < datetime(''now'') THEN ''expired''\u000a                WHEN m.accessedAt < datetime(''now'',''-${freshDays} days'') AND m.accessCount > 0 THEN ''aging''\u000a                WHEN m.accessCount = 0 AND m.createdAt < ${freshW} THEN ''stranded''\u000a                ELSE ''aging''\u000a              END as bucket,\u000a              count(DISTINCT mr.memoryId) as uniqueMemories,\u000a              count(*) as retrievals\u000a            FROM memory_retrieval mr\u000a            JOIN agent_memory m ON mr.memoryId = m.id\u000a            WHERE mr.retrievedAt > ${w}\u000a            GROUP BY bucket`,\u000a    }),\u000a  );\u000a\u000a  const bucketMap: Record<string, { uniqueMemories: number; retrievals: number }> = {};\u000a  let totalRetrievedMemories = 0;\u000a  let totalRetrievals = 0;\u000a  for (const b of axis3Buckets) {\u000a    const mem = Number(b.uniqueMemories ?? 0);\u000a    const ret = Number(b.retrievals ?? 0);\u000a    bucketMap[b.bucket] = { uniqueMemories: mem, retrievals: ret };\u000a    totalRetrievedMemories += mem;\u000a    totalRetrievals += ret;\u000a  }\u000a\u000a  const freshMem = bucketMap.fresh?.uniqueMemories ?? 0;\u000a  const freshScore = pct(freshMem, totalRetrievedMemories);\u000a\u000a  const staleRefCount = rowsToObjects(\u000a    await ctx.swarm.db_query({\u000a      sql: `SELECT count(DISTINCT mr.memoryId) as cnt\u000a            FROM memory_retrieval mr\u000a            JOIN agent_memory m ON mr.memoryId = m.id\u000a            WHERE mr.retrievedAt > ${w}\u000a              AND m.expiresAt IS NOT NULL\u000a              AND m.expiresAt < datetime(''now'')`,\u000a    }),\u000a  );\u000a\u000a  report.axis3 = {\u000a    name: "Stay current over time",\u000a    description:\u000a      "Distribution of retrieved memories across freshness buckets. Target: >80% of retrieved memories are fresh.",\u000a    window: `${days} days`,\u000a    freshDays,\u000a    totalUniqueMemoriesRetrieved: totalRetrievedMemories,\u000a    totalRetrievals,\u000a    buckets: {\u000a      fresh: {\u000a        label: `Created within last ${freshDays} days`,\u000a        uniqueMemories: freshMem,\u000a        retrievals: bucketMap.fresh?.retrievals ?? 0,\u000a        pctOfRetrieved: freshScore,\u000a      },\u000a      aging: {\u000a        label: `Older than ${freshDays} days, still active`,\u000a        uniqueMemories: bucketMap.aging?.uniqueMemories ?? 0,\u000a        retrievals: bucketMap.aging?.retrievals ?? 0,\u000a        pctOfRetrieved: pct(bucketMap.aging?.uniqueMemories ?? 0, totalRetrievedMemories),\u000a      },\u000a      stranded: {\u000a        label: "Old, never accessed",\u000a        uniqueMemories: bucketMap.stranded?.uniqueMemories ?? 0,\u000a        retrievals: bucketMap.stranded?.retrievals ?? 0,\u000a        pctOfRetrieved: pct(bucketMap.stranded?.uniqueMemories ?? 0, totalRetrievedMemories),\u000a      },\u000a      expired: {\u000a        label: "Past TTL / expired",\u000a        uniqueMemories: bucketMap.expired?.uniqueMemories ?? 0,\u000a        retrievals: bucketMap.expired?.retrievals ?? 0,\u000a        pctOfRetrieved: pct(bucketMap.expired?.uniqueMemories ?? 0, totalRetrievedMemories),\u000a      },\u000a    },\u000a    staleReferentCount: Number(staleRefCount[0]?.cnt ?? 0),\u000a    freshScore,\u000a    softTarget: 80,\u000a    unit: "%",\u000a  };\u000a\u000a  // ─── Store totals ────────────────────────────────────────────────────\u000a\u000a  const totalMemoryRows = rowsToObjects(\u000a    await ctx.swarm.db_query({\u000a      sql: `SELECT count(*) as total,\u000a                   sum(CASE WHEN accessCount > 0 THEN 1 ELSE 0 END) as accessed,\u000a                   sum(CASE WHEN expiresAt IS NOT NULL AND expiresAt < datetime(''now'') THEN 1 ELSE 0 END) as expired\u000a            FROM agent_memory`,\u000a    }),\u000a  );\u000a\u000a  const storeTotals = totalMemoryRows[0] ?? {};\u000a\u000a  report.storeSnapshot = {\u000a    totalMemories: Number(storeTotals.total ?? 0),\u000a    memoriesEverAccessed: Number(storeTotals.accessed ?? 0),\u000a    expiredMemories: Number(storeTotals.expired ?? 0),\u000a  };\u000a\u000a  // ─── History persistence (KV) ───────────────────────────────────────\u000a\u000a  let history: DailyPoint[] = [];\u000a  try {\u000a    const kvResult = await ctx.swarm.kv_get({ key: KV_KEY, namespace: KV_NS });\u000a    const payload = kvResult?.data ?? kvResult;\u000a    if (Array.isArray(payload?.value)) history = payload.value;\u000a  } catch (_e) {\u000a    // first run — no history yet\u000a  }\u000a\u000a  const todayPoint = reportToDailyPoint(today, report);\u000a\u000a  if (backfillDays > 0) {\u000a    const existingDates = new Set(history.map((p) => p.date));\u000a    const toBackfill: string[] = [];\u000a    for (let i = 1; i <= backfillDays; i++) {\u000a      const d = new Date();\u000a      d.setDate(d.getDate() - i);\u000a      const dateStr = d.toISOString().slice(0, 10);\u000a      if (!existingDates.has(dateStr)) toBackfill.push(dateStr);\u000a    }\u000a    for (const dateStr of toBackfill) {\u000a      try {\u000a        const pt = await computeBackfillPoint(ctx, dateStr, days, freshDays, usefulnessThreshold);\u000a        history.push(pt);\u000a      } catch (_e) {\u000a        // skip dates that fail\u000a      }\u000a    }\u000a  }\u000a\u000a  const idx = history.findIndex((p) => p.date === today);\u000a  if (idx >= 0) history[idx] = todayPoint;\u000a  else history.push(todayPoint);\u000a\u000a  history.sort((a, b) => a.date.localeCompare(b.date));\u000a\u000a  try {\u000a    await ctx.swarm.kv_set({ key: KV_KEY, namespace: KV_NS, value: history });\u000a  } catch (_e) {\u000a    report.kvError = "kv_set failed — history not persisted this run";\u000a  }\u000a\u000a  report.historyPoints = history.length;\u000a\u000a  // ─── Markdown report ─────────────────────────────────────────────────\u000a\u000a  const md = buildMarkdownReport(report);\u000a\u000a  if (writeAgentFs) {\u000a    try {\u000a      await ctx.swarm.agent_fs_write({\u000a        path: `docs/memory-eval-${today}.md`,\u000a        content: md,\u000a        message: `Memory eval report ${today}`,\u000a        org: "648a5f3c-35c8-4f11-8673-b89de52cd6bd",\u000a      });\u000a    } catch (_e) {\u000a      report.agentFsError = "agent_fs_write failed — report still available in page + return value";\u000a    }\u000a  }\u000a\u000a  // ─── Publish dashboard page ──────────────────────────────────────────\u000a\u000a  if (publishPage) {\u000a    const html = buildDashboardHtml(report, history);\u000a    try {\u000a      const response = await ctx.swarm.page_create({\u000a        title: "Memory Eval — 3-Axis Dashboard",\u000a        slug: "memory-eval",\u000a        description: `3-axis memory quality dashboard: carry-forward ${report.axis1.score}%, preferences usefulness ${report.axis2.avgUsefulness}, freshness ${report.axis3.freshScore}%. ${history.length} data points.`,\u000a        contentType: "text/html",\u000a        authMode: "authed",\u000a        body: html,\u000a      });\u000a      const payload = response?.data ?? response;\u000a      report.page = {\u000a        id: payload?.id ?? payload?.page?.id ?? null,\u000a        appUrl: payload?.appUrl ?? payload?.app_url ?? null,\u000a        apiUrl: payload?.apiUrl ?? payload?.api_url ?? null,\u000a        version: payload?.version ?? payload?.page?.version ?? null,\u000a      };\u000a    } catch (_e) {\u000a      report.pageError = "page_create failed";\u000a    }\u000a  }\u000a\u000a  return report;\u000a}\u000a\u000afunction buildMarkdownReport(r: any): string {\u000a  const lines: string[] = [];\u000a  const ln = (s = "") => lines.push(s);\u000a\u000a  ln(`# Memory Eval — 3-Axis Report`);\u000a  ln(`> Generated: ${r.generatedAt} · Window: ${r.days} days · History: ${r.historyPoints ?? 1} points`);\u000a  ln();\u000a  ln(`## Summary`);\u000a  ln();\u000a  ln(`| Axis | Score | Soft Target |`);\u000a  ln(`|------|-------|-------------|`);\u000a  ln(`| 1 — Carry-forward context | **${r.axis1.score}%** | ${r.axis1.softTarget}% |`);\u000a  ln(`| 2 — Preferences avg usefulness | **${r.axis2.avgUsefulness}** | >0.6 |`);\u000a  ln(`| 3 — Freshness (% fresh retrieved) | **${r.axis3.freshScore}%** | ${r.axis3.softTarget}% |`);\u000a  ln();\u000a  ln(\u000a    `**Store:** ${r.storeSnapshot.totalMemories} total memories, ${r.storeSnapshot.memoriesEverAccessed} ever accessed, ${r.storeSnapshot.expiredMemories} expired.`,\u000a  );\u000a  ln();\u000a\u000a  ln(`---`);\u000a  ln(`## Axis 1 — Carry-forward Context`);\u000a  ln();\u000a  ln(`*${r.axis1.description}*`);\u000a  ln();\u000a  ln(`- Follow-up tasks in window: **${r.axis1.followUpTasks}**`);\u000a  ln(`- Tasks with useful carry-forward: **${r.axis1.tasksWithUsefulCarryForward}**`);\u000a  ln(`- Score: **${r.axis1.score}%** (soft target: ${r.axis1.softTarget}%)`);\u000a  ln();\u000a\u000a  ln(`---`);\u000a  ln(`## Axis 2 — Follow Preferences & Constraints`);\u000a  ln();\u000a  ln(`*${r.axis2.description}*`);\u000a  ln();\u000a  ln(`- Preference memories in store: **${r.axis2.totalPreferenceMemories}**`);\u000a  ln(`- Ever retrieved: **${r.axis2.memoriesEverRetrieved}** (${r.axis2.retrievalRate}%)`);\u000a  ln(`- Total retrievals: **${r.axis2.totalRetrievals}**`);\u000a  ln(`- Avg usefulness: **${r.axis2.avgUsefulness}**`);\u000a  ln();\u000a  ln(`### By File`);\u000a  ln();\u000a  ln(`| File | Memories | Total Access | Avg Usefulness |`);\u000a  ln(`|------|----------|--------------|----------------|`);\u000a  for (const f of r.axis2.byFile) {\u000a    ln(`| ${f.file} | ${f.memories} | ${f.totalAccess} | ${round2(f.avgUsefulness)} |`);\u000a  }\u000a  ln();\u000a  if (r.axis2.raterBreakdown.length > 0) {\u000a    ln(`### Rater Breakdown`);\u000a    ln();\u000a    ln(`| Rater | Ratings | Avg Signal |`);\u000a    ln(`|-------|---------|------------|`);\u000a    for (const rb of r.axis2.raterBreakdown) {\u000a      ln(`| ${rb.rater} | ${rb.ratings} | ${round2(rb.avgSignal)} |`);\u000a    }\u000a    ln();\u000a  }\u000a\u000a  ln(`---`);\u000a  ln(`## Axis 3 — Stay Current Over Time`);\u000a  ln();\u000a  ln(`*${r.axis3.description}*`);\u000a  ln();\u000a  ln(`- Window: **${r.axis3.window}** · Fresh threshold: **${r.axis3.freshDays} days**`);\u000a  ln(`- Unique memories retrieved: **${r.axis3.totalUniqueMemoriesRetrieved}**`);\u000a  ln(`- Fresh score: **${r.axis3.freshScore}%** (soft target: ${r.axis3.softTarget}%)`);\u000a  ln(`- Stale referents (expired but still retrieved): **${r.axis3.staleReferentCount}**`);\u000a  ln();\u000a  ln(`### Freshness Buckets`);\u000a  ln();\u000a  ln(`| Bucket | Unique Memories | Retrievals | % of Retrieved |`);\u000a  ln(`|--------|-----------------|------------|----------------|`);\u000a  for (const [k, v] of Object.entries(r.axis3.buckets) as [string, any][]) {\u000a    ln(`| ${k} (${v.label}) | ${v.uniqueMemories} | ${v.retrievals} | ${v.pctOfRetrieved}% |`);\u000a  }\u000a  ln();\u000a\u000a  return lines.join("\\n");\u000a}\u000a\u000afunction buildDashboardHtml(report: any, history: DailyPoint[]): string {\u000a  const fmtNum = (v: unknown) =>\u000a    typeof v === "number" ? new Intl.NumberFormat("en-US").format(v) : String(v ?? "");\u000a  const dataJson = JSON.stringify(history);\u000a\u000a  const metricCards = [\u000a    ["Carry-forward", `${report.axis1.score}%`],\u000a    ["Pref Usefulness", report.axis2.avgUsefulness],\u000a    ["Freshness", `${report.axis3.freshScore}%`],\u000a    ["Total Memories", report.storeSnapshot.totalMemories],\u000a  ]\u000a    .map(\u000a      ([label, value]) =>\u000a        `<div class="metric"><strong>${esc(fmtNum(value))}</strong><span>${esc(label)}</span></div>`,\u000a    )\u000a    .join("");\u000a\u000a  const findingSections = buildFindingsHtml(report);\u000a\u000a  return `<!doctype html>\u000a<html lang="en">\u000a<head>\u000a  <meta charset="utf-8">\u000a  <meta name="viewport" content="width=device-width, initial-scale=1">\u000a  <meta name="theme-color" content="#f5f2ea">\u000a  <title>Memory Eval — 3-Axis Dashboard</title>\u000a  <style>\u000a    :root {\u000a      color-scheme: light;\u000a      --bg: #f5f2ea; --panel: #ffffff; --ink: #18181b; --muted: #5f6368;\u000a      --line: #ded8cb; --accent: #255c99;\u000a      --danger: #b42318; --danger-bg: #fff1f0;\u000a      --warn: #b54708; --warn-bg: #fff7ed;\u000a      --note: #175cd3; --note-bg: #eff6ff;\u000a      --low: #067647; --low-bg: #ecfdf3;\u000a      --radius: 8px;\u000a      --shadow: 0 1px 2px rgba(24,24,27,.06), 0 14px 36px rgba(24,24,27,.07);\u000a    }\u000a    * { box-sizing: border-box; }\u000a    body {\u000a      margin: 0; background: var(--bg); color: var(--ink);\u000a      font-family: Inter, ui-sans-serif, system-ui, -apple-system, sans-serif;\u000a      font-size: 16px; line-height: 1.55;\u000a    }\u000a    main { width: min(1120px, calc(100% - 32px)); margin: 0 auto; padding: 48px 0 72px; }\u000a    header { margin-bottom: 28px; }\u000a    .eyebrow {\u000a      margin: 0 0 8px; color: var(--muted); font-size: 13px; font-weight: 750;\u000a      letter-spacing: .08em; text-transform: uppercase;\u000a    }\u000a    h1 { margin: 0; max-width: 860px; font-size: clamp(2rem,4vw,3rem); line-height: 1.05; }\u000a    .lede { max-width: 780px; margin: 16px 0 0; color: var(--muted); font-size: 18px; }\u000a    .metrics {\u000a      display: grid; grid-template-columns: repeat(4, minmax(0,1fr));\u000a      gap: 12px; margin: 32px 0;\u000a    }\u000a    .metric, .section, .chart-card, details {\u000a      background: var(--panel); border: 1px solid var(--line);\u000a      border-radius: var(--radius); box-shadow: var(--shadow);\u000a    }\u000a    .metric { padding: 18px; }\u000a    .metric strong { display: block; font-size: 32px; line-height: 1; font-variant-numeric: tabular-nums; }\u000a    .metric span { display: block; margin-top: 8px; color: var(--muted); font-size: 13px; font-weight: 650; }\u000a    .chart-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 16px; margin: 24px 0; }\u000a    .chart-card { padding: 20px; }\u000a    .chart-card h2 { margin: 0 0 4px; font-size: 17px; line-height: 1.3; }\u000a    .chart-note { margin: 8px 0 0; color: var(--muted); font-size: 12px; font-style: italic; }\u000a    .chart-wrap { position: relative; height: 240px; margin-top: 12px; }\u000a    .section { margin-top: 18px; padding: 24px; }\u000a    .section-grid { display: grid; grid-template-columns: 260px minmax(0,1fr); gap: 28px; }\u000a    .section-kicker {\u000a      margin: 0 0 12px; color: var(--accent); font-size: 13px; font-weight: 800;\u000a      letter-spacing: .08em; text-transform: uppercase;\u000a    }\u000a    .check-list { display: grid; gap: 8px; }\u000a    .check {\u000a      display: flex; align-items: baseline; justify-content: space-between;\u000a      gap: 12px; padding: 10px 0; border-bottom: 1px solid var(--line);\u000a    }\u000a    .check span { color: var(--muted); font-size: 13px; }\u000a    .check strong { font-size: 18px; font-variant-numeric: tabular-nums; }\u000a    .section-head {\u000a      display: flex; align-items: start; justify-content: space-between;\u000a      gap: 16px; margin-bottom: 16px;\u000a    }\u000a    .section-head h2 { max-width: 680px; margin: 0; font-size: 24px; line-height: 1.2; }\u000a    .section-head > span { flex: 0 0 auto; color: var(--muted); font-size: 13px; font-weight: 700; white-space: nowrap; }\u000a    .findings { display: grid; gap: 12px; }\u000a    .finding {\u000a      border: 1px solid var(--line); border-left: 4px solid var(--note);\u000a      border-radius: var(--radius); padding: 16px; background: #fffdf8;\u000a    }\u000a    .finding.danger { border-left-color: var(--danger); }\u000a    .finding.warn { border-left-color: var(--warn); }\u000a    .finding.low { border-left-color: var(--low); }\u000a    .finding-head { display: flex; align-items: start; justify-content: space-between; gap: 16px; }\u000a    .finding-id { margin: 0 0 4px; color: var(--muted); font-family: ui-monospace, monospace; font-size: 12px; }\u000a    h3 { margin: 0; font-size: 17px; line-height: 1.3; }\u000a    .pill {\u000a      display: inline-flex; align-items: center; min-height: 26px; padding: 4px 9px;\u000a      border-radius: 999px; font-size: 12px; font-weight: 800; text-transform: uppercase; white-space: nowrap;\u000a    }\u000a    .pill.danger { background: var(--danger-bg); color: var(--danger); }\u000a    .pill.warn { background: var(--warn-bg); color: var(--warn); }\u000a    .pill.note { background: var(--note-bg); color: var(--note); }\u000a    .pill.low { background: var(--low-bg); color: var(--low); }\u000a    .action { margin: 10px 0 0; color: var(--muted); }\u000a    .sample-table { margin-top: 14px; overflow-x: auto; border: 1px solid var(--line); border-radius: var(--radius); background: var(--panel); }\u000a    table { width: 100%; min-width: 480px; border-collapse: collapse; }\u000a    th, td { padding: 10px 12px; border-bottom: 1px solid var(--line); text-align: left; vertical-align: top; }\u000a    th { color: var(--muted); font-size: 12px; font-weight: 800; letter-spacing: .06em; text-transform: uppercase; }\u000a    td { max-width: 360px; color: #27272a; font-size: 13px; overflow-wrap: anywhere; }\u000a    tr:last-child td { border-bottom: 0; }\u000a    details { margin-top: 24px; padding: 18px; }\u000a    summary { cursor: pointer; font-weight: 800; }\u000a    pre {\u000a      margin: 16px 0 0; max-height: 560px; overflow: auto; padding: 16px;\u000a      border-radius: var(--radius); background: #111827; color: #f9fafb;\u000a      font-size: 12px; line-height: 1.45;\u000a    }\u000a    .backfill-legend {\u000a      margin: 0 0 8px; padding: 8px 12px; background: var(--note-bg);\u000a      border-radius: var(--radius); font-size: 13px; color: var(--note);\u000a    }\u000a    @media (max-width: 860px) {\u000a      main { width: min(100% - 24px, 1120px); padding-top: 32px; }\u000a      .metrics { grid-template-columns: repeat(2, minmax(0,1fr)); }\u000a      .chart-grid { grid-template-columns: 1fr; }\u000a      .section-grid { grid-template-columns: 1fr; gap: 18px; }\u000a    }\u000a    @media (max-width: 520px) { .metrics { grid-template-columns: 1fr; } }\u000a  </style>\u000a</head>\u000a<body>\u000a  <main>\u000a    <header>\u000a      <p class="eyebrow">Generated ${esc(report.generatedAt)}</p>\u000a      <h1>Memory Eval — 3-Axis Dashboard</h1>\u000a      <p class="lede">${esc(`${report.days}-day window · Axis 1 (carry-forward): ${report.axis1.score}% · Axis 2 (preferences): ${report.axis2.avgUsefulness} · Axis 3 (freshness): ${report.axis3.freshScore}% · ${history.length} data points`)}</p>\u000a    </header>\u000a\u000a    <section class="metrics" aria-label="Current scores">${metricCards}</section>\u000a\u000a    <p class="backfill-legend">\u000a      <strong>Chart legend:</strong> Solid lines = measured data. Dashed gray = soft target.\u000a      Axes 1 &amp; 3 are backfilled from audit tables. Axis 2 (preferences) is forward-only — it queries current memory state and cannot be reconstructed historically.\u000a    </p>\u000a\u000a    <section class="chart-grid">\u000a      <div class="chart-card">\u000a        <h2>Axis 1 — Carry-forward Context (%)</h2>\u000a        <div class="chart-wrap"><canvas id="c1"></canvas></div>\u000a      </div>\u000a      <div class="chart-card">\u000a        <h2>Axis 2 — Preferences Usefulness</h2>\u000a        <div class="chart-wrap"><canvas id="c2"></canvas></div>\u000a        <p class="chart-note">Forward-only: cannot be reconstructed from historical data. Starts from first live run.</p>\u000a      </div>\u000a      <div class="chart-card">\u000a        <h2>Axis 3 — Freshness Score (%)</h2>\u000a        <div class="chart-wrap"><canvas id="c3"></canvas></div>\u000a      </div>\u000a      <div class="chart-card">\u000a        <h2>Memory Corpus</h2>\u000a        <div class="chart-wrap"><canvas id="c4"></canvas></div>\u000a      </div>\u000a    </section>\u000a\u000a    ${findingSections}\u000a\u000a    <details>\u000a      <summary>Compressed JSON appendix</summary>\u000a      <pre>${esc(JSON.stringify(report, null, 2))}</pre>\u000a    </details>\u000a  </main>\u000a\u000a  <script src="https://cdn.jsdelivr.net/npm/chart.js@4"></script>\u000a  <script>\u000a  (function() {\u000a    var H = ${dataJson};\u000a    var labels = H.map(function(p){ return p.date.slice(5); });\u000a    var fullLabels = H.map(function(p){ return p.date; });\u000a    var baseOpts = {\u000a      responsive: true, maintainAspectRatio: false,\u000a      interaction: { mode: ''index'', intersect: false },\u000a      plugins: {\u000a        legend: { position: ''bottom'', labels: { boxWidth: 12, padding: 10, font: { size: 11 } } },\u000a        tooltip: {\u000a          callbacks: {\u000a            title: function(items) { return fullLabels[items[0].dataIndex] || ''''; }\u000a          }\u000a        }\u000a      },\u000a      scales: {\u000a        x: { grid: { display: false }, ticks: { font: { size: 10 }, maxRotation: 45, autoSkip: true, maxTicksLimit: 15 } },\u000a        y: { beginAtZero: true, grid: { color: ''#ded8cb40'' }, ticks: { font: { size: 11 } } }\u000a      },\u000a      elements: { point: { radius: 3, hoverRadius: 5 }, line: { tension: 0.3, borderWidth: 2 } }\u000a    };\u000a\u000a    function targetDs(label, val, len) {\u000a      return {\u000a        label: label, data: Array(len).fill(val),\u000a        borderColor: ''#94a3b8'', borderDash: [6,4], borderWidth: 1.5,\u000a        pointRadius: 0, pointHoverRadius: 0, fill: false\u000a      };\u000a    }\u000a\u000a    new Chart(document.getElementById(''c1''), {\u000a      type: ''line'',\u000a      data: {\u000a        labels: labels,\u000a        datasets: [\u000a          { label: ''Carry-forward %'', data: H.map(function(p){return p.axis1Score;}), borderColor: ''#2563eb'', backgroundColor: ''#2563eb20'', fill: true },\u000a          targetDs(''Target 60%'', 60, H.length)\u000a        ]\u000a      },\u000a      options: Object.assign({}, baseOpts, { scales: Object.assign({}, baseOpts.scales, { y: Object.assign({}, baseOpts.scales.y, { max: 100 }) }) })\u000a    });\u000a\u000a    new Chart(document.getElementById(''c2''), {\u000a      type: ''line'',\u000a      data: {\u000a        labels: labels,\u000a        datasets: [\u000a          { label: ''Avg Usefulness'', data: H.map(function(p){return p.axis2AvgUsefulness;}), borderColor: ''#7c3aed'', backgroundColor: ''#7c3aed20'', fill: true, spanGaps: false },\u000a          targetDs(''Target 0.6'', 0.6, H.length)\u000a        ]\u000a      },\u000a      options: Object.assign({}, baseOpts, { scales: Object.assign({}, baseOpts.scales, { y: Object.assign({}, baseOpts.scales.y, { max: 1, ticks: Object.assign({}, baseOpts.scales.y.ticks, { stepSize: 0.2 }) }) }) })\u000a    });\u000a\u000a    new Chart(document.getElementById(''c3''), {\u000a      type: ''line'',\u000a      data: {\u000a        labels: labels,\u000a        datasets: [\u000a          { label: ''Freshness %'', data: H.map(function(p){return p.axis3FreshScore;}), borderColor: ''#059669'', backgroundColor: ''#05966920'', fill: true },\u000a          targetDs(''Target 80%'', 80, H.length)\u000a        ]\u000a      },\u000a      options: Object.assign({}, baseOpts, { scales: Object.assign({}, baseOpts.scales, { y: Object.assign({}, baseOpts.scales.y, { max: 100 }) }) })\u000a    });\u000a\u000a    new Chart(document.getElementById(''c4''), {\u000a      type: ''line'',\u000a      data: {\u000a        labels: labels,\u000a        datasets: [\u000a          { label: ''Total'', data: H.map(function(p){return p.totalMemories;}), borderColor: ''#2563eb'', fill: false },\u000a          { label: ''Searchable'', data: H.map(function(p){return p.searchableMemories;}), borderColor: ''#059669'', fill: false },\u000a          { label: ''Expired'', data: H.map(function(p){return p.expiredMemories;}), borderColor: ''#dc2626'', fill: false }\u000a        ]\u000a      },\u000a      options: baseOpts\u000a    });\u000a  })();\u000a  </script>\u000a</body>\u000a</html>`;\u000a}\u000a\u000afunction buildFindingsHtml(report: any): string {\u000a  const severityTone = (s?: string) =>\u000a    s === "critical" ? "danger" : s === "high" ? "warn" : s === "medium" ? "note" : "low";\u000a  const fmtMetric = (v: unknown) =>\u000a    typeof v === "number" ? new Intl.NumberFormat("en-US").format(v) : String(v ?? "");\u000a  const humanLabel = (s: string) =>\u000a    s\u000a      .replace(/([a-z0-9])([A-Z])/g, "$1 $2")\u000a      .replace(/[-_.]+/g, " ")\u000a      .replace(/\\b\\w/g, (c) => c.toUpperCase());\u000a\u000a  type Finding = { id: string; severity?: string; summary: string; action?: string; samples?: any[] };\u000a  type Section = {\u000a    key: string;\u000a    label?: string;\u000a    goal: string;\u000a    findingCount?: number;\u000a    checks?: Record<string, unknown>;\u000a    findings?: Finding[];\u000a  };\u000a\u000a  const sections: Section[] = [\u000a    {\u000a      key: "axis1-carry-forward",\u000a      label: "Axis 1",\u000a      goal: "Carry-forward context: do follow-up tasks retrieve useful memories from prior tasks in the same thread?",\u000a      findingCount: report.axis1.followUpTasks > 0 ? 1 : 0,\u000a      checks: {\u000a        followUpTasks: report.axis1.followUpTasks,\u000a        tasksWithCarryForward: report.axis1.tasksWithUsefulCarryForward,\u000a        score: `${report.axis1.score}%`,\u000a        softTarget: `${report.axis1.softTarget}%`,\u000a      },\u000a      findings:\u000a        report.axis1.followUpTasks > 0\u000a          ? [\u000a              {\u000a                id: "axis1.carry-forward-rate",\u000a                severity: report.axis1.score >= 60 ? "low" : report.axis1.score >= 30 ? "medium" : "high",\u000a                summary: `${report.axis1.score}% of ${report.axis1.followUpTasks} follow-up tasks retrieved a useful carry-forward memory (soft target: ${report.axis1.softTarget}%).`,\u000a                action:\u000a                  report.axis1.score < 60\u000a                    ? "Investigate whether memories from prior tasks in a thread are being written and embedded correctly."\u000a                    : "Score meets soft target. Monitor for regression after architecture changes.",\u000a              },\u000a            ]\u000a          : [],\u000a    },\u000a    {\u000a      key: "axis2-preferences",\u000a      label: "Axis 2",\u000a      goal: "Follow preferences & constraints: are identity/config memories retrieved and rated useful?",\u000a      findingCount: report.axis2.byFile.length,\u000a      checks: {\u000a        preferenceMemories: report.axis2.totalPreferenceMemories,\u000a        everRetrieved: `${report.axis2.retrievalRate}%`,\u000a        avgUsefulness: report.axis2.avgUsefulness,\u000a        totalRetrievals: report.axis2.totalRetrievals,\u000a      },\u000a      findings: report.axis2.byFile.map((f: any) => ({\u000a        id: `axis2.file.${f.file}`,\u000a        severity: f.avgUsefulness < 0.5 ? "medium" : "low",\u000a        summary: `${f.file}: ${f.memories} memories, ${f.totalAccess} retrievals, avg usefulness ${round2(f.avgUsefulness)}.`,\u000a        action:\u000a          f.avgUsefulness < 0.5\u000a            ? "Low usefulness suggests these memories are being retrieved but not helpful — check chunking and embedding quality."\u000a            : "Healthy retrieval pattern.",\u000a      })),\u000a    },\u000a    {\u000a      key: "axis3-freshness",\u000a      label: "Axis 3",\u000a      goal: "Stay current over time: are retrieved memories fresh, or are stale/expired memories polluting results?",\u000a      findingCount: 1,\u000a      checks: {\u000a        freshScore: `${report.axis3.freshScore}%`,\u000a        softTarget: `${report.axis3.softTarget}%`,\u000a        totalRetrieved: report.axis3.totalUniqueMemoriesRetrieved,\u000a        staleReferents: report.axis3.staleReferentCount,\u000a      },\u000a      findings: [\u000a        {\u000a          id: "axis3.freshness-distribution",\u000a          severity:\u000a            report.axis3.freshScore >= 80 ? "low" : report.axis3.freshScore >= 50 ? "medium" : "high",\u000a          summary: `${report.axis3.freshScore}% of retrieved memories are fresh (<${report.axis3.freshDays}d). Aging: ${report.axis3.buckets.aging.pctOfRetrieved}%, Stranded: ${report.axis3.buckets.stranded.pctOfRetrieved}%, Expired: ${report.axis3.buckets.expired.pctOfRetrieved}%.`,\u000a          action:\u000a            report.axis3.freshScore < 80\u000a              ? "Stale memories are diluting retrieval quality. Prioritize TTL enforcement and the Memory Curator job."\u000a              : "Freshness meets target. Continue monitoring.",\u000a          samples: Object.entries(report.axis3.buckets).map(([k, v]: [string, any]) => ({\u000a            bucket: k,\u000a            uniqueMemories: v.uniqueMemories,\u000a            retrievals: v.retrievals,\u000a            pctOfRetrieved: `${v.pctOfRetrieved}%`,\u000a          })),\u000a        },\u000a      ],\u000a    },\u000a  ];\u000a\u000a  return sections\u000a    .map((section) => {\u000a      const findings = (section.findings || [])\u000a        .map(\u000a          (f) => `<article class="finding ${esc(severityTone(f.severity))}">\u000a          <div class="finding-head">\u000a            <div>\u000a              <p class="finding-id">${esc(f.id)}</p>\u000a              <h3>${esc(f.summary)}</h3>\u000a            </div>\u000a            <span class="pill ${esc(severityTone(f.severity))}">${esc(f.severity || "low")}</span>\u000a          </div>\u000a          ${f.action ? `<p class="action">${esc(f.action)}</p>` : ""}\u000a          ${renderSamples(f.samples)}\u000a        </article>`,\u000a        )\u000a        .join("");\u000a      const checks = Object.entries(section.checks || {})\u000a        .map(\u000a          ([label, value]) =>\u000a            `<div class="check"><span>${esc(humanLabel(label))}</span><strong>${esc(fmtMetric(value))}</strong></div>`,\u000a        )\u000a        .join("");\u000a      return `<section class="section">\u000a      <div class="section-grid">\u000a        <aside class="checks">\u000a          <p class="section-kicker">${esc(section.label || humanLabel(section.key))}</p>\u000a          <div class="check-list">${checks}</div>\u000a        </aside>\u000a        <div>\u000a          <div class="section-head">\u000a            <h2>${esc(section.goal)}</h2>\u000a            <span>${esc(fmtMetric(section.findingCount ?? section.findings?.length ?? 0))} finding(s)</span>\u000a          </div>\u000a          <div class="findings">${findings || ''<p class="empty">No actionable findings.</p>''}</div>\u000a        </div>\u000a      </div>\u000a    </section>`;\u000a    })\u000a    .join("\\n");\u000a}\u000a\u000afunction renderSamples(samples?: unknown[]): string {\u000a  if (!Array.isArray(samples) || samples.length === 0) return "";\u000a  const normalized = samples.map((row) =>\u000a    row && typeof row === "object" && !Array.isArray(row) ? (row as Record<string, unknown>) : { value: row },\u000a  );\u000a  const columns = Array.from(new Set(normalized.flatMap((row) => Object.keys(row).slice(0, 6)))).slice(0, 6);\u000a  if (columns.length === 0) return "";\u000a  const renderVal = (v: unknown) =>\u000a    Array.isArray(v) ? v.map((i) => (typeof i === "object" ? JSON.stringify(i) : String(i ?? ""))).join(", ") : typeof v === "object" && v ? JSON.stringify(v) : String(v ?? "");\u000a  const rows = normalized\u000a    .map((row) => `<tr>${columns.map((c) => `<td>${esc(renderVal(row[c]))}</td>`).join("")}</tr>`)\u000a    .join("");\u000a  return `<div class="sample-table"><table>\u000a    <thead><tr>${columns.map((c) => `<th>${esc(c.replace(/([a-z0-9])([A-Z])/g, "$1 $2").replace(/[-_.]+/g, " ").replace(/\\b\\w/g, (ch) => ch.toUpperCase()))}</th>`).join("")}</tr></thead>\u000a    <tbody>${rows}</tbody>\u000a  </table></div>`;\u000a}\u000a'),'3-axis memory quality evaluation: carry-forward context (do follow-up tasks retrieve useful memories from prior tasks?), follow preferences (are CLAUDE.md/IDENTITY.md/SOUL.md/TOOLS.md memories retrieved and useful?), and stay current (what fraction of retrieved memories are fresh vs stale?). Outputs a baseline report to agent-fs + a swarm Page.','Measure memory system health across OpenAI Dreaming-inspired axes — before/after baseline for architecture changes, blog-post numbers, daily quality monitoring.','{"argsType":"any","resultType":"unknown","description":"3-axis memory quality evaluation with over-time trend tracking and KV-backed historical backfill."}','83a2338bfdde40fac6b95e68c0c0e000bb081b83c81315854786e872cc1136b8',1,0,1,'none',NULL,'2026-06-11T22:38:24.247Z','2026-06-11T22:38:24.247Z','{"$schema":"https://json-schema.org/draft/2020-12/schema","type":"object","properties":{"days":{"description":"Look back this many days for retrieval/rating data (default 30)","type":"integer","exclusiveMinimum":0,"maximum":9007199254740991,"minimum":-9007199254740991},"freshDays":{"description":"Memories younger than this are ''fresh'' (default 14)","type":"integer","exclusiveMinimum":0,"maximum":9007199254740991,"minimum":-9007199254740991},"usefulnessThreshold":{"description":"α/(α+β) cutoff for ''useful'' (default 0.6)","type":"number","minimum":0,"maximum":1},"backfillDays":{"description":"Backfill this many past daily points on first run (default 14; 0 to skip)","type":"integer","minimum":0,"maximum":9007199254740991},"publishPage":{"description":"Publish an authed HTML page (default true)","type":"boolean"},"writeAgentFs":{"description":"Write markdown report to agent-fs (default true)","type":"boolean"}},"additionalProperties":false}',NULL,NULL);
INSERT INTO scripts VALUES('166dea9e-4f94-4eb4-b02e-b51e6921dc9c','ops-catalog-audit','global',NULL,unistr('export type CatalogReportFinding = {\u000a  id: string;\u000a  severity?: string;\u000a  summary: string;\u000a  action?: string;\u000a  samples?: unknown[];\u000a};\u000a\u000aexport type CatalogReportSection = {\u000a  key: string;\u000a  label?: string;\u000a  goal: string;\u000a  findingCount?: number;\u000a  checks?: Record<string, unknown>;\u000a  findings?: CatalogReportFinding[];\u000a};\u000a\u000aexport type CatalogReport = {\u000a  title: string;\u000a  slug: string;\u000a  description: string;\u000a  generatedAt: string;\u000a  lede: string;\u000a  metrics: Array<[string, unknown]>;\u000a  sections: CatalogReportSection[];\u000a  appendix: unknown;\u000a};\u000a\u000afunction catalogReportAsText(value: unknown): string {\u000a  return typeof value === "string" ? value : value == null ? "" : JSON.stringify(value);\u000a}\u000a\u000afunction catalogReportHtmlEscape(value: unknown): string {\u000a  return catalogReportAsText(value)\u000a    .replace(/&/g, "&amp;")\u000a    .replace(/</g, "&lt;")\u000a    .replace(/>/g, "&gt;")\u000a    .replace(/"/g, "&quot;");\u000a}\u000a\u000afunction catalogReportHumanLabel(value: string): string {\u000a  return value\u000a    .replace(/([a-z0-9])([A-Z])/g, "$1 $2")\u000a    .replace(/[-_.]+/g, " ")\u000a    .replace(/\\b\\w/g, (char) => char.toUpperCase());\u000a}\u000a\u000afunction catalogReportFormatMetric(value: unknown): string {\u000a  if (typeof value === "number") return new Intl.NumberFormat("en-US").format(value);\u000a  return catalogReportAsText(value);\u000a}\u000a\u000afunction catalogReportSeverityTone(value?: string): string {\u000a  if (value === "critical") return "danger";\u000a  if (value === "high") return "warn";\u000a  if (value === "medium") return "note";\u000a  return "low";\u000a}\u000a\u000afunction catalogReportRenderSampleValue(value: unknown): string {\u000a  if (Array.isArray(value)) {\u000a    return value\u000a      .map((item) => (typeof item === "object" && item !== null ? JSON.stringify(item) : catalogReportAsText(item)))\u000a      .join(", ");\u000a  }\u000a  if (value && typeof value === "object") return JSON.stringify(value);\u000a  return catalogReportAsText(value);\u000a}\u000a\u000afunction catalogReportRenderSamples(samples?: unknown[]): string {\u000a  if (!Array.isArray(samples) || samples.length === 0) return "";\u000a  const normalized = samples.map((sampleRow) =>\u000a    sampleRow && typeof sampleRow === "object" && !Array.isArray(sampleRow)\u000a      ? (sampleRow as Record<string, unknown>)\u000a      : { value: sampleRow },\u000a  );\u000a  const columns = Array.from(\u000a    new Set(normalized.flatMap((sampleRow) => Object.keys(sampleRow).slice(0, 6))),\u000a  ).slice(0, 6);\u000a  if (columns.length === 0) return "";\u000a  const rows = normalized\u000a    .map(\u000a      (sampleRow) =>\u000a        `<tr>${columns\u000a          .map((column) => `<td>${catalogReportHtmlEscape(catalogReportRenderSampleValue(sampleRow[column]))}</td>`)\u000a          .join("")}</tr>`,\u000a    )\u000a    .join("");\u000a  return `<div class="sample-table" aria-label="Sample rows">\u000a    <table>\u000a      <thead><tr>${columns.map((column) => `<th>${catalogReportHtmlEscape(catalogReportHumanLabel(column))}</th>`).join("")}</tr></thead>\u000a      <tbody>${rows}</tbody>\u000a    </table>\u000a  </div>`;\u000a}\u000a\u000aexport function renderCatalogReportPage(report: CatalogReport): string {\u000a  const sections = report.sections\u000a    .map((section) => {\u000a      const findings = (section.findings || [])\u000a        .map(\u000a          (finding) => `<article class="finding ${catalogReportHtmlEscape(catalogReportSeverityTone(finding.severity))}">\u000a            <div class="finding-head">\u000a              <div>\u000a                <p class="finding-id">${catalogReportHtmlEscape(finding.id)}</p>\u000a                <h3>${catalogReportHtmlEscape(finding.summary)}</h3>\u000a              </div>\u000a              <span class="pill ${catalogReportHtmlEscape(catalogReportSeverityTone(finding.severity))}">${catalogReportHtmlEscape(\u000a                finding.severity || "low",\u000a              )}</span>\u000a            </div>\u000a            ${finding.action ? `<p class="action">${catalogReportHtmlEscape(finding.action)}</p>` : ""}\u000a            ${catalogReportRenderSamples(finding.samples)}\u000a          </article>`,\u000a        )\u000a        .join("");\u000a      const checks = Object.entries(section.checks || {})\u000a        .map(\u000a          ([label, value]) =>\u000a            `<div class="check"><span>${catalogReportHtmlEscape(catalogReportHumanLabel(label))}</span><strong>${catalogReportHtmlEscape(\u000a              catalogReportFormatMetric(value),\u000a            )}</strong></div>`,\u000a        )\u000a        .join("");\u000a      return `<section class="section">\u000a        <div class="section-grid">\u000a          <aside class="checks">\u000a            <p class="section-kicker">${catalogReportHtmlEscape(section.label || catalogReportHumanLabel(section.key))}</p>\u000a            <div class="check-list">${checks}</div>\u000a          </aside>\u000a          <div>\u000a            <div class="section-head">\u000a              <h2>${catalogReportHtmlEscape(section.goal)}</h2>\u000a              <span>${catalogReportHtmlEscape(catalogReportFormatMetric(section.findingCount ?? section.findings?.length ?? 0))} finding(s)</span>\u000a            </div>\u000a            <div class="findings">\u000a              ${findings || ''<p class="empty">No actionable findings in this cluster.</p>''}\u000a            </div>\u000a          </div>\u000a        </div>\u000a      </section>`;\u000a    })\u000a    .join("\\n");\u000a  return `<!doctype html>\u000a<html lang="en">\u000a<head>\u000a  <meta charset="utf-8">\u000a  <meta name="viewport" content="width=device-width, initial-scale=1">\u000a  <meta name="theme-color" content="#f5f2ea">\u000a  <title>${catalogReportHtmlEscape(report.title)}</title>\u000a  <style>\u000a    :root {\u000a      color-scheme: light;\u000a      --bg: #f5f2ea;\u000a      --panel: #ffffff;\u000a      --ink: #18181b;\u000a      --muted: #5f6368;\u000a      --line: #ded8cb;\u000a      --accent: #255c99;\u000a      --danger: #b42318;\u000a      --danger-bg: #fff1f0;\u000a      --warn: #b54708;\u000a      --warn-bg: #fff7ed;\u000a      --note: #175cd3;\u000a      --note-bg: #eff6ff;\u000a      --low: #067647;\u000a      --low-bg: #ecfdf3;\u000a      --radius: 8px;\u000a      --shadow: 0 1px 2px rgba(24, 24, 27, 0.06), 0 14px 36px rgba(24, 24, 27, 0.07);\u000a    }\u000a    * { box-sizing: border-box; }\u000a    body {\u000a      margin: 0;\u000a      background: var(--bg);\u000a      color: var(--ink);\u000a      font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;\u000a      font-size: 16px;\u000a      line-height: 1.55;\u000a    }\u000a    main {\u000a      width: min(1120px, calc(100% - 32px));\u000a      margin: 0 auto;\u000a      padding: 48px 0 72px;\u000a    }\u000a    header { margin-bottom: 28px; }\u000a    .eyebrow {\u000a      margin: 0 0 8px;\u000a      color: var(--muted);\u000a      font-size: 13px;\u000a      font-weight: 750;\u000a      letter-spacing: 0.08em;\u000a      text-transform: uppercase;\u000a    }\u000a    h1 {\u000a      margin: 0;\u000a      max-width: 860px;\u000a      font-size: clamp(2rem, 4vw, 3rem);\u000a      line-height: 1.05;\u000a      letter-spacing: 0;\u000a    }\u000a    .lede {\u000a      max-width: 780px;\u000a      margin: 16px 0 0;\u000a      color: var(--muted);\u000a      font-size: 18px;\u000a    }\u000a    .metrics {\u000a      display: grid;\u000a      grid-template-columns: repeat(4, minmax(0, 1fr));\u000a      gap: 12px;\u000a      margin: 32px 0;\u000a    }\u000a    .metric, .section, details {\u000a      background: var(--panel);\u000a      border: 1px solid var(--line);\u000a      border-radius: var(--radius);\u000a      box-shadow: var(--shadow);\u000a    }\u000a    .metric { padding: 18px; }\u000a    .metric strong {\u000a      display: block;\u000a      font-size: 32px;\u000a      line-height: 1;\u000a      font-variant-numeric: tabular-nums;\u000a    }\u000a    .metric span {\u000a      display: block;\u000a      margin-top: 8px;\u000a      color: var(--muted);\u000a      font-size: 13px;\u000a      font-weight: 650;\u000a    }\u000a    .section {\u000a      margin-top: 18px;\u000a      padding: 24px;\u000a    }\u000a    .section-grid {\u000a      display: grid;\u000a      grid-template-columns: 260px minmax(0, 1fr);\u000a      gap: 28px;\u000a    }\u000a    .section-kicker {\u000a      margin: 0 0 12px;\u000a      color: var(--accent);\u000a      font-size: 13px;\u000a      font-weight: 800;\u000a      letter-spacing: 0.08em;\u000a      text-transform: uppercase;\u000a    }\u000a    .check-list {\u000a      display: grid;\u000a      gap: 8px;\u000a    }\u000a    .check {\u000a      display: flex;\u000a      align-items: baseline;\u000a      justify-content: space-between;\u000a      gap: 12px;\u000a      padding: 10px 0;\u000a      border-bottom: 1px solid var(--line);\u000a    }\u000a    .check span {\u000a      color: var(--muted);\u000a      font-size: 13px;\u000a    }\u000a    .check strong {\u000a      font-size: 18px;\u000a      font-variant-numeric: tabular-nums;\u000a    }\u000a    .section-head {\u000a      display: flex;\u000a      align-items: start;\u000a      justify-content: space-between;\u000a      gap: 16px;\u000a      margin-bottom: 16px;\u000a    }\u000a    .section-head h2 {\u000a      max-width: 680px;\u000a      margin: 0;\u000a      font-size: 24px;\u000a      line-height: 1.2;\u000a      letter-spacing: 0;\u000a    }\u000a    .section-head > span {\u000a      flex: 0 0 auto;\u000a      color: var(--muted);\u000a      font-size: 13px;\u000a      font-weight: 700;\u000a      white-space: nowrap;\u000a    }\u000a    .findings {\u000a      display: grid;\u000a      gap: 12px;\u000a    }\u000a    .finding {\u000a      border: 1px solid var(--line);\u000a      border-left: 4px solid var(--note);\u000a      border-radius: var(--radius);\u000a      padding: 16px;\u000a      background: #fffdf8;\u000a    }\u000a    .finding.danger { border-left-color: var(--danger); }\u000a    .finding.warn { border-left-color: var(--warn); }\u000a    .finding.low { border-left-color: var(--low); }\u000a    .finding-head {\u000a      display: flex;\u000a      align-items: start;\u000a      justify-content: space-between;\u000a      gap: 16px;\u000a    }\u000a    .finding-id {\u000a      margin: 0 0 4px;\u000a      color: var(--muted);\u000a      font-family: ui-monospace, SFMono-Regular, Menlo, Consolas, monospace;\u000a      font-size: 12px;\u000a    }\u000a    h3 {\u000a      margin: 0;\u000a      font-size: 17px;\u000a      line-height: 1.3;\u000a      letter-spacing: 0;\u000a    }\u000a    .pill {\u000a      display: inline-flex;\u000a      align-items: center;\u000a      min-height: 26px;\u000a      padding: 4px 9px;\u000a      border-radius: 999px;\u000a      font-size: 12px;\u000a      font-weight: 800;\u000a      text-transform: uppercase;\u000a      white-space: nowrap;\u000a    }\u000a    .pill.danger { background: var(--danger-bg); color: var(--danger); }\u000a    .pill.warn { background: var(--warn-bg); color: var(--warn); }\u000a    .pill.note { background: var(--note-bg); color: var(--note); }\u000a    .pill.low { background: var(--low-bg); color: var(--low); }\u000a    .action {\u000a      margin: 10px 0 0;\u000a      color: var(--muted);\u000a    }\u000a    .sample-table {\u000a      margin-top: 14px;\u000a      overflow-x: auto;\u000a      border: 1px solid var(--line);\u000a      border-radius: var(--radius);\u000a      background: var(--panel);\u000a    }\u000a    table {\u000a      width: 100%;\u000a      min-width: 640px;\u000a      border-collapse: collapse;\u000a    }\u000a    th, td {\u000a      padding: 10px 12px;\u000a      border-bottom: 1px solid var(--line);\u000a      text-align: left;\u000a      vertical-align: top;\u000a    }\u000a    th {\u000a      color: var(--muted);\u000a      font-size: 12px;\u000a      font-weight: 800;\u000a      letter-spacing: 0.06em;\u000a      text-transform: uppercase;\u000a    }\u000a    td {\u000a      max-width: 360px;\u000a      color: #27272a;\u000a      font-size: 13px;\u000a      overflow-wrap: anywhere;\u000a    }\u000a    tr:last-child td { border-bottom: 0; }\u000a    .empty {\u000a      margin: 0;\u000a      color: var(--muted);\u000a    }\u000a    details {\u000a      margin-top: 24px;\u000a      padding: 18px;\u000a    }\u000a    summary {\u000a      cursor: pointer;\u000a      font-weight: 800;\u000a    }\u000a    pre {\u000a      margin: 16px 0 0;\u000a      max-height: 560px;\u000a      overflow: auto;\u000a      padding: 16px;\u000a      border-radius: var(--radius);\u000a      background: #111827;\u000a      color: #f9fafb;\u000a      font-size: 12px;\u000a      line-height: 1.45;\u000a    }\u000a    @media (max-width: 860px) {\u000a      main { width: min(100% - 24px, 1120px); padding-top: 32px; }\u000a      .metrics { grid-template-columns: repeat(2, minmax(0, 1fr)); }\u000a      .section-grid { grid-template-columns: 1fr; gap: 18px; }\u000a      .section { padding: 18px; }\u000a      .section-head { display: block; }\u000a      .section-head > span { display: block; margin-top: 8px; }\u000a    }\u000a    @media (max-width: 520px) {\u000a      .metrics { grid-template-columns: 1fr; }\u000a      .lede { font-size: 16px; }\u000a      .finding-head { display: block; }\u000a      .pill { margin-top: 10px; }\u000a    }\u000a  </style>\u000a</head>\u000a<body>\u000a  <main>\u000a    <header>\u000a      <p class="eyebrow">Generated ${catalogReportHtmlEscape(report.generatedAt)}</p>\u000a      <h1>${catalogReportHtmlEscape(report.title)}</h1>\u000a      <p class="lede">${catalogReportHtmlEscape(report.lede)}</p>\u000a    </header>\u000a    <section class="metrics" aria-label="Audit summary">\u000a      ${report.metrics\u000a        .map(\u000a          ([label, value]) =>\u000a            `<div class="metric"><strong>${catalogReportHtmlEscape(catalogReportFormatMetric(value))}</strong><span>${catalogReportHtmlEscape(\u000a              label,\u000a            )}</span></div>`,\u000a        )\u000a        .join("")}\u000a    </section>\u000a    ${sections}\u000a    <details>\u000a      <summary>Compressed JSON appendix</summary>\u000a      <pre>${catalogReportHtmlEscape(JSON.stringify(report.appendix, null, 2))}</pre>\u000a    </details>\u000a  </main>\u000a</body>\u000a</html>`;\u000a}\u000a\u000aexport async function publishCatalogReportPage(report: CatalogReport, ctx: any): Promise<any> {\u000a  const response = await ctx.swarm.page_create({\u000a    title: report.title,\u000a    slug: report.slug,\u000a    description: report.description,\u000a    contentType: "text/html",\u000a    authMode: "authed",\u000a    body: renderCatalogReportPage(report),\u000a  });\u000a  const payload = response?.data ?? response;\u000a  if (payload?.success === false) return { error: payload.error || "page_create failed" };\u000a  return {\u000a    id: payload?.id ?? payload?.page?.id ?? null,\u000a    appUrl: payload?.appUrl ?? payload?.app_url ?? null,\u000a    apiUrl: payload?.apiUrl ?? payload?.api_url ?? null,\u000a    version: payload?.version ?? payload?.page?.version ?? null,\u000a  };\u000a}\u000a\u000a\u000aimport { z } from "zod";\u000aexport const argsSchema = z.object({\u000a  nowIso: z.string().optional().describe("Audit clock override (default: current time)"),\u000a  publishPage: z.boolean().optional().describe("Publish an authed HTML page (default true)"),\u000a  includeSamples: z\u000a    .boolean()\u000a    .optional()\u000a    .describe("Include small row samples for each finding cluster (default true)"),\u000a  staleScheduleDays: z\u000a    .number()\u000a    .int()\u000a    .positive()\u000a    .optional()\u000a    .describe("Flag enabled schedules with no run for this many days (default 14)"),\u000a  tempScheduleNames: z\u000a    .array(z.string())\u000a    .optional()\u000a    .describe("Known temporary schedule name fragments that should self-lift"),\u000a});\u000a\u000aconst CODE_WORK_RE =\u000a  /\\b(git|github|gh\\b|gh-cli|docker|docker-compose|bun|npm|pnpm|yarn|tsc|eslint|lint|test|pr\\b|pull request|branch|commit|repo|worktree|typescript|javascript)\\b/i;\u000aconst CODE_AGENT_RE =\u000a  /\\b(code|coder|coding|implement|implementation|engineer|software|typescript|javascript|repo|github)\\b/i;\u000aconst NON_CODE_AGENT_RE = /\\b(content|reviewer|research|sales|gtm|support|ops|lead)\\b/i;\u000aconst SMOKE_WORKFLOW_RE =\u000a  /\\b(smoke|demo|litmus-smoke|one[- ]shot|validation|des-462-gate-validation|gsc-runtime-smoke)\\b/i;\u000aconst GATE_WORKFLOW_RE = /\\b(litmus|gate|eval|review|validation|quality|structured)\\b/i;\u000aconst STALE_URL_RE =\u000a  /\\b(localhost|127\\.0\\.0\\.1|api\\.example-swarm\\.dev|app\\.example-swarm\\.dev|example-swarm\\.dev|fly\\.dev)\\b/i;\u000aconst CONTRADICTORY_RE =\u000a  /\\b(do not|don''t|never)\\b[\\s\\S]{0,240}\\b(always|must|required)\\b|\\b(always|must|required)\\b[\\s\\S]{0,240}\\b(do not|don''t|never)\\b/i;\u000a\u000aconst CODE_REGISTRY_EVENTS =\u000a  "agentmail.email.followup agentmail.email.mapped_lead agentmail.email.mapped_worker agentmail.email.no_agent agentmail.email.unmapped common.command_suggestions.github_comment_issue common.command_suggestions.github_comment_pr common.command_suggestions.github_issue common.command_suggestions.github_pr common.command_suggestions.gitlab_issue common.command_suggestions.gitlab_mr common.delegation_instruction common.delegation_instruction.gitlab github.check_run.failed github.check_suite.failed github.comment.mentioned github.issue.assigned github.issue.labeled github.issue.mentioned github.pull_request.assigned github.pull_request.closed github.pull_request.labeled github.pull_request.mentioned github.pull_request.review_requested github.pull_request.review_submitted github.pull_request.synchronize github.workflow_run.failed gitlab.comment.mentioned gitlab.issue.assigned gitlab.merge_request.opened gitlab.pipeline.failed heartbeat.boot-triage heartbeat.checklist jira.issue.assigned jira.issue.commented jira.issue.followup kapso.message.received linear.issue.assigned linear.issue.followup linear.issue.reassigned slack.assistant.greeting slack.assistant.offline slack.assistant.suggested_prompts slack.message.thread_context system.agent.agent_fs system.agent.artifacts system.agent.code_quality system.agent.context_mode system.agent.filesystem system.agent.lead system.agent.register system.agent.role system.agent.seed_scripts system.agent.self_awareness system.agent.services system.agent.share_urls system.agent.slack system.agent.system system.agent.worker system.agent.worker.remote system.agent.worker.slack system.session.lead system.session.worker system.session.worker.pi system.session.worker.remote task.budget.refused task.requester.profile task.worker.completed task.worker.failed".split(\u000a    " ",\u000a  );\u000a\u000afunction rowsToObjects(res: any): any[] {\u000a  const p = res?.data ?? res;\u000a  const cols: string[] = p?.columns ?? [];\u000a  return (p?.rows ?? []).map((r: any) =>\u000a    Array.isArray(r) ? Object.fromEntries(cols.map((c, i) => [c, r[i]])) : r,\u000a  );\u000a}\u000a\u000aasync function query(ctx: any, sql: string, params?: unknown[]): Promise<any[]> {\u000a  try {\u000a    return rowsToObjects(await ctx.swarm.db_query({ sql, params }));\u000a  } catch (error) {\u000a    return [{ unavailable: error instanceof Error ? error.message : String(error) }];\u000a  }\u000a}\u000a\u000afunction safeJson(value: unknown, fallback: any = null): any {\u000a  if (typeof value !== "string") return value ?? fallback;\u000a  try {\u000a    return JSON.parse(value);\u000a  } catch {\u000a    return fallback;\u000a  }\u000a}\u000a\u000afunction asBool(value: unknown): boolean {\u000a  return value === true || value === 1 || value === "1";\u000a}\u000a\u000afunction asText(value: unknown): string {\u000a  return typeof value === "string" ? value : value == null ? "" : JSON.stringify(value);\u000a}\u000a\u000afunction compactText(value: unknown, max = 180): string {\u000a  return asText(value).replace(/\\s+/g, " ").trim().slice(0, max);\u000a}\u000a\u000afunction formatMetric(value: unknown): string {\u000a  if (typeof value === "number") return new Intl.NumberFormat("en-US").format(value);\u000a  return asText(value);\u000a}\u000a\u000afunction daysSince(iso: string | null | undefined, nowMs: number): number | null {\u000a  if (!iso) return null;\u000a  const t = Date.parse(iso);\u000a  if (!Number.isFinite(t)) return null;\u000a  return Math.round((nowMs - t) / 86400000);\u000a}\u000a\u000afunction severity(rank: number): "critical" | "high" | "medium" | "low" {\u000a  if (rank >= 4) return "critical";\u000a  if (rank === 3) return "high";\u000a  if (rank === 2) return "medium";\u000a  return "low";\u000a}\u000a\u000afunction sample<T>(rows: T[], includeSamples: boolean, limit = 5): T[] {\u000a  return includeSamples ? rows.slice(0, limit) : [];\u000a}\u000a\u000afunction isCodeCapable(agent: any): boolean {\u000a  if (!agent) return false;\u000a  const text = [\u000a    agent.name,\u000a    agent.role,\u000a    agent.description,\u000a    Array.isArray(agent.capabilities) ? agent.capabilities.join(" ") : agent.capabilities,\u000a  ]\u000a    .filter(Boolean)\u000a    .join(" ");\u000a  if (!CODE_AGENT_RE.test(text)) return false;\u000a  if (NON_CODE_AGENT_RE.test(text) && !/\\bpicateclas\\b/i.test(text)) return false;\u000a  return true;\u000a}\u000a\u000afunction nodeList(definition: any): any[] {\u000a  return Array.isArray(definition?.nodes) ? definition.nodes : [];\u000a}\u000a\u000afunction hasStructuredOutput(value: any): boolean {\u000a  return /"outputSchema"|"schema"|"jsonSchema"|"structured"/i.test(JSON.stringify(value ?? {}));\u000a}\u000a\u000aexport function buildReport(result: any): CatalogReport {\u000a  return {\u000a    title: "Ops Catalog Audit",\u000a    slug: "ops-catalog-audit",\u000a    description: "Clustered audit-as-code report for schedules, workflows, and prompts/templates.",\u000a    generatedAt: result.generatedAt,\u000a    lede: `A re-runnable audit of schedules, workflows, and prompt/template catalogs. It found ${formatMetric(\u000a      result.summary.findingsTotal,\u000a    )} actionable issue cluster(s), with the highest-risk items called out first inside each group.`,\u000a    metrics: [\u000a    ["Findings", result.summary.findingsTotal],\u000a    ["Schedules enabled", result.summary.schedulesEnabled],\u000a    ["Workflows enabled", result.summary.workflowsEnabled],\u000a    ["Prompt templates", result.summary.promptTemplates],\u000a    ],\u000a    sections: ["schedules", "workflows", "promptsTemplates"].map((key) => ({\u000a      key,\u000a      goal: result.goals[key].goal,\u000a      findingCount: result.goals[key].findingCount,\u000a      checks: result.goals[key].checks,\u000a      findings: result.goals[key].findings,\u000a    })),\u000a    appendix: result,\u000a  };\u000a}\u000a\u000aexport function renderPage(result: any): string {\u000a  return renderCatalogReportPage(buildReport(result));\u000a}\u000a\u000a/** Audit schedules, workflows, and prompt/template catalogs by goal, with optional authed page output. */\u000aexport default async function opsCatalogAudit(args: any, ctx: any) {\u000a  const parsed = argsSchema.safeParse(args || {});\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a\u000a  const now = parsed.data.nowIso ? new Date(parsed.data.nowIso) : new Date();\u000a  const nowMs = now.getTime();\u000a  const publishPage = parsed.data.publishPage !== false;\u000a  const includeSamples = parsed.data.includeSamples !== false;\u000a  const staleScheduleDays = parsed.data.staleScheduleDays || 14;\u000a  const tempScheduleNames = parsed.data.tempScheduleNames || [\u000a    "memory-gate-597",\u000a    "swarm-postdeploy-memory",\u000a  ];\u000a\u000a  const scheduleRows = await query(\u000a    ctx,\u000a    `SELECT s.*, a.name as targetAgentName, a.role as targetAgentRole,\u000a            a.description as targetAgentDescription, a.capabilities as targetAgentCapabilities,\u000a            a.provider as targetAgentProvider, a.harness_provider as targetAgentHarnessProvider\u000a     FROM scheduled_tasks s LEFT JOIN agents a ON a.id = s.targetAgentId\u000a     WHERE s.enabled = 1 ORDER BY s.name ASC`,\u000a  );\u000a  const schedules = scheduleRows.filter((r) => !r.unavailable);\u000a  const agentsById = new Map<string, any>();\u000a  for (const s of schedules) {\u000a    if (!s.targetAgentId) continue;\u000a    agentsById.set(s.targetAgentId, {\u000a      id: s.targetAgentId,\u000a      name: s.targetAgentName,\u000a      role: s.targetAgentRole,\u000a      description: s.targetAgentDescription,\u000a      capabilities: safeJson(s.targetAgentCapabilities, []),\u000a      provider: s.targetAgentProvider,\u000a      harnessProvider: s.targetAgentHarnessProvider,\u000a    });\u000a  }\u000a\u000a  const duplicateCronGroups = Object.values(\u000a    schedules.reduce((acc: any, s: any) => {\u000a      const cron = s.cronExpression || (s.intervalMs ? `interval:${s.intervalMs}` : "");\u000a      if (!cron) return acc;\u000a      const key = `${cron}::${s.timezone || "UTC"}`;\u000a      acc[key] ??= { key, cron, timezone: s.timezone || "UTC", schedules: [] };\u000a      acc[key].schedules.push({ id: s.id, name: s.name });\u000a      return acc;\u000a    }, {}),\u000a  ).filter((g: any) => g.schedules.length > 1);\u000a\u000a  const deadSchedules = schedules.filter((s: any) => {\u000a    const noNext = !s.nextRunAt && s.scheduleType === "recurring";\u000a    const stale = (daysSince(s.lastRunAt, nowMs) ?? 0) >= staleScheduleDays;\u000a    return noNext || stale || Number(s.consecutiveErrors || 0) > 0;\u000a  });\u000a\u000a  const tempSchedules = schedules.filter((s: any) => {\u000a    const haystack = `${s.name || ""}\\n${s.description || ""}\\n${s.taskTemplate || ""}`.toLowerCase();\u000a    const known = tempScheduleNames.some((name) => haystack.includes(name.toLowerCase()));\u000a    const dateMatches = [\u000a      ...haystack.matchAll(\u000a        /\\b(?:self[- ]lift|remove|disable|until|through|expires?)\\D{0,40}(\\d{4}-\\d{2}-\\d{2})/g,\u000a      ),\u000a    ];\u000a    const expired = dateMatches.some((m) => (m[1] ? Date.parse(m[1]) <= nowMs : false));\u000a    return known || expired;\u000a  });\u000a\u000a  const routingRisks = schedules\u000a    .filter((s: any) => CODE_WORK_RE.test(`${s.name || ""}\\n${s.tags || ""}\\n${s.taskTemplate || ""}`))\u000a    .map((s: any) => {\u000a      const target = s.targetAgentId ? agentsById.get(s.targetAgentId) : null;\u000a      const pool = !s.targetAgentId;\u000a      const opencode = target?.provider === "opencode" || target?.harnessProvider === "opencode";\u000a      const risky = pool || !isCodeCapable(target) || opencode;\u000a      return risky\u000a        ? {\u000a            id: s.id,\u000a            name: s.name,\u000a            targetAgentId: s.targetAgentId || null,\u000a            targetAgentName: target?.name || null,\u000a            reason: pool\u000a              ? "pool-targeted code work"\u000a              : opencode\u000a                ? "opencode target for code work"\u000a                : "target is not code-capable",\u000a            action: "Pin this schedule to a code-capable worker targetAgentId before it runs again.",\u000a          }\u000a        : null;\u000a    })\u000a    .filter(Boolean);\u000a\u000a  const workflowRows = await query(\u000a    ctx,\u000a    `SELECT id, name, description, enabled, definition, triggers, input, triggerSchema, createdAt, lastUpdatedAt\u000a     FROM workflows ORDER BY name ASC`,\u000a  );\u000a  const workflows = workflowRows.filter((r) => !r.unavailable);\u000a  const enabledWorkflows = workflows.filter((w: any) => asBool(w.enabled));\u000a  const smokeEnabled = enabledWorkflows\u000a    .filter((w: any) => SMOKE_WORKFLOW_RE.test(`${w.name || ""}\\n${w.description || ""}`))\u000a    .map((w: any) => ({\u000a      id: w.id,\u000a      name: w.name,\u000a      action: "Disable or delete if this was only a smoke/eval fixture.",\u000a    }));\u000a  const gateCoverageGaps = enabledWorkflows\u000a    .map((w: any) => {\u000a      const definition = safeJson(w.definition, {});\u000a      const text = `${w.name || ""}\\n${w.description || ""}\\n${JSON.stringify(definition)}`;\u000a      const structured =\u000a        hasStructuredOutput(definition) ||\u000a        hasStructuredOutput(safeJson(w.input, {})) ||\u000a        hasStructuredOutput(safeJson(w.triggerSchema, {}));\u000a      if (!GATE_WORKFLOW_RE.test(text) || structured) return null;\u000a      return {\u000a        id: w.id,\u000a        name: w.name,\u000a        nodeCount: nodeList(definition).length,\u000a        action: "Add outputSchema/schema coverage to litmus/eval/gate nodes so downstream checks are deterministic.",\u000a      };\u000a    })\u000a    .filter(Boolean);\u000a  const workflowTypeRows = enabledWorkflows.map((w: any) => {\u000a    const definition = safeJson(w.definition, {});\u000a    const nodes = nodeList(definition);\u000a    const nodeTypes = Array.from(new Set(nodes.map((n: any) => n.type).filter(Boolean))).sort();\u000a    const loadBearing =\u000a      !SMOKE_WORKFLOW_RE.test(`${w.name || ""}\\n${w.description || ""}`) && nodes.length > 1;\u000a    return {\u000a      id: w.id,\u000a      name: w.name,\u000a      nodeCount: nodes.length,\u000a      nodeTypes,\u000a      class: loadBearing ? "load-bearing" : "fixture-or-small",\u000a    };\u000a  });\u000a\u000a  const promptRows = await query(\u000a    ctx,\u000a    `SELECT id, eventType, scope, scopeId, state, body, isDefault, version, createdBy, updatedAt\u000a     FROM prompt_templates ORDER BY eventType ASC, scope ASC`,\u000a  );\u000a  const prompts = promptRows.filter((r) => !r.unavailable);\u000a  const expectedEvents = new Set(CODE_REGISTRY_EVENTS);\u000a  const defaultEvents = new Set(prompts.filter((p: any) => asBool(p.isDefault)).map((p: any) => p.eventType));\u000a  const liveEvents = new Set(prompts.map((p: any) => p.eventType));\u000a  const missingDefaultEvents = [...expectedEvents].filter((e) => !defaultEvents.has(e)).sort();\u000a  const dbOnlyEvents = [...liveEvents].filter((e) => !expectedEvents.has(e) && !e.startsWith("test.")).sort();\u000a\u000a  const bodyGroups: Record<string, any[]> = {};\u000a  for (const p of prompts) {\u000a    const key = compactText(p.body, 500);\u000a    if (!key) continue;\u000a    bodyGroups[key] ??= [];\u000a    bodyGroups[key].push({\u000a      id: p.id,\u000a      eventType: p.eventType,\u000a      scope: p.scope,\u000a      scopeId: p.scopeId,\u000a    });\u000a  }\u000a  const duplicatePromptBodies = Object.values(bodyGroups).filter((group) => group.length > 1);\u000a  const staleUrlPrompts = prompts\u000a    .filter((p: any) => STALE_URL_RE.test(p.body || ""))\u000a    .map((p: any) => ({\u000a      id: p.id,\u000a      eventType: p.eventType,\u000a      scope: p.scope,\u000a      match: (p.body.match(STALE_URL_RE) || [])[0],\u000a    }));\u000a  const contradictoryPrompts = prompts\u000a    .filter((p: any) => CONTRADICTORY_RE.test(p.body || ""))\u000a    .map((p: any) => ({ id: p.id, eventType: p.eventType, scope: p.scope }));\u000a  const skillDuplicateRows = await query(\u000a    ctx,\u000a    `SELECT name, count(*) as count,\u000a            group_concat(scope || '':'' || coalesce(ownerAgentId, ''global''), '', '') as locations\u000a     FROM skills\u000a     WHERE isEnabled = 1 AND systemDefault = 1\u000a     GROUP BY name HAVING count(*) > 1 ORDER BY count DESC, name ASC`,\u000a  );\u000a  const systemDefaultSkillDuplicates = skillDuplicateRows.filter((r) => !r.unavailable);\u000a  const skillDuplicateUnavailable = skillDuplicateRows.find((r) => r.unavailable)?.unavailable;\u000a\u000a  const findings = {\u000a    schedules: [\u000a      duplicateCronGroups.length && {\u000a        id: "schedules.duplicate-crons",\u000a        severity: severity(duplicateCronGroups.length > 2 ? 3 : 2),\u000a        summary: `${duplicateCronGroups.length} duplicate enabled cron/interval group(s).`,\u000a        action: "Confirm whether each duplicate group is intentional; consolidate or retarget redundant schedules.",\u000a        samples: sample(duplicateCronGroups, includeSamples),\u000a      },\u000a      deadSchedules.length && {\u000a        id: "schedules.dead-or-stale",\u000a        severity: severity(deadSchedules.length > 3 ? 3 : 2),\u000a        summary: `${deadSchedules.length} enabled schedule(s) look dead, stale, or erroring.`,\u000a        action: `Disable dead schedules or repair nextRunAt/cron/errors. Stale threshold: ${staleScheduleDays} days.`,\u000a        samples: sample(\u000a          deadSchedules.map((s: any) => ({\u000a            id: s.id,\u000a            name: s.name,\u000a            nextRunAt: s.nextRunAt,\u000a            lastRunAt: s.lastRunAt,\u000a            consecutiveErrors: s.consecutiveErrors,\u000a          })),\u000a          includeSamples,\u000a        ),\u000a      },\u000a      tempSchedules.length && {\u000a        id: "schedules.temporary-self-lift",\u000a        severity: "high",\u000a        summary: `${tempSchedules.length} temporary monitor schedule(s) may be past self-lift.`,\u000a        action: "Review the named temporary monitors and disable/delete the ones whose guard window has expired.",\u000a        samples: sample(\u000a          tempSchedules.map((s: any) => ({ id: s.id, name: s.name })),\u000a          includeSamples,\u000a        ),\u000a      },\u000a      routingRisks.length && {\u000a        id: "schedules.rule-13-15-routing",\u000a        severity: "critical",\u000a        summary: `${routingRisks.length} enabled code-work schedule(s) are not pinned to a code-capable worker.`,\u000a        action: "Set targetAgentId to a code-capable worker; never leave git/docker/bun/gh work on the pool.",\u000a        samples: sample(routingRisks, includeSamples),\u000a      },\u000a    ].filter(Boolean),\u000a    workflows: [\u000a      smokeEnabled.length && {\u000a        id: "workflows.enabled-fixtures",\u000a        severity: severity(smokeEnabled.length > 2 ? 3 : 2),\u000a        summary: `${smokeEnabled.length} enabled workflow(s) look like smoke/demo/one-shot fixtures.`,\u000a        action: "Disable fixture workflows unless they are explicitly load-bearing production gates.",\u000a        samples: sample(smokeEnabled, includeSamples),\u000a      },\u000a      gateCoverageGaps.length && {\u000a        id: "workflows.structured-output-gaps",\u000a        severity: "high",\u000a        summary: `${gateCoverageGaps.length} litmus/eval/gate workflow(s) lack visible structured-output schema coverage.`,\u000a        action: "Add outputSchema/schema coverage so gate outputs can be regression-checked.",\u000a        samples: sample(gateCoverageGaps, includeSamples),\u000a      },\u000a    ].filter(Boolean),\u000a    promptsTemplates: [\u000a      (missingDefaultEvents.length || dbOnlyEvents.length) && {\u000a        id: "prompts.registry-drift",\u000a        severity: severity(missingDefaultEvents.length > 0 ? 3 : 2),\u000a        summary: `${missingDefaultEvents.length} code registry event(s) missing default DB rows; ${dbOnlyEvents.length} DB event(s) absent from code registry.`,\u000a        action: "Re-seed prompt templates or remove stale DB-only templates after confirming no runtime still emits them.",\u000a        samples: sample(\u000a          [\u000a            ...missingDefaultEvents.slice(0, 5).map((eventType) => ({\u000a              kind: "missing-default",\u000a              eventType,\u000a            })),\u000a            ...dbOnlyEvents.slice(0, 5).map((eventType) => ({ kind: "db-only", eventType })),\u000a          ],\u000a          includeSamples,\u000a          10,\u000a        ),\u000a      },\u000a      duplicatePromptBodies.length && {\u000a        id: "prompts.redundant-bodies",\u000a        severity: "medium",\u000a        summary: `${duplicatePromptBodies.length} prompt body group(s) are duplicated across templates.`,\u000a        action: "Extract shared text into a template reference or remove redundant overrides.",\u000a        samples: sample(duplicatePromptBodies, includeSamples, 3),\u000a      },\u000a      staleUrlPrompts.length && {\u000a        id: "prompts.stale-urls-hosts",\u000a        severity: "high",\u000a        summary: `${staleUrlPrompts.length} prompt template(s) contain stale/local/example hosts.`,\u000a        action: "Replace hardcoded hosts with runtime env-var guidance or current public hosts.",\u000a        samples: sample(staleUrlPrompts, includeSamples),\u000a      },\u000a      contradictoryPrompts.length && {\u000a        id: "prompts.contradictory-instructions",\u000a        severity: "medium",\u000a        summary: `${contradictoryPrompts.length} prompt template(s) contain nearby must/never style conflicts worth review.`,\u000a        action: "Tighten redundant or conflicting instruction blocks so workers do not receive mixed routing guidance.",\u000a        samples: sample(contradictoryPrompts, includeSamples),\u000a      },\u000a      (systemDefaultSkillDuplicates.length || skillDuplicateUnavailable) && {\u000a        id: "prompts.system-default-skill-duplicates",\u000a        severity: systemDefaultSkillDuplicates.length ? "high" : "low",\u000a        summary: skillDuplicateUnavailable\u000a          ? `Could not query systemDefault skill duplicates: ${skillDuplicateUnavailable}`\u000a          : `${systemDefaultSkillDuplicates.length} systemDefault skill name(s) are duplicated.`,\u000a        action: "Deduplicate system-default skills so prompt skill seeding is stable and non-redundant.",\u000a        samples: sample(systemDefaultSkillDuplicates, includeSamples),\u000a      },\u000a    ].filter(Boolean),\u000a  };\u000a\u000a  const result: any = {\u000a    generatedAt: now.toISOString(),\u000a    script: "ops-catalog-audit",\u000a    summary: {\u000a      schedulesEnabled: schedules.length,\u000a      workflowsTotal: workflows.length,\u000a      workflowsEnabled: enabledWorkflows.length,\u000a      promptTemplates: prompts.length,\u000a      findingsTotal:\u000a        findings.schedules.length + findings.workflows.length + findings.promptsTemplates.length,\u000a    },\u000a    goals: {\u000a      schedules: {\u000a        goal: "Reduce schedule cost/context waste and prevent misrouted code work.",\u000a        findingCount: findings.schedules.length,\u000a        checks: {\u000a          duplicateCronGroups: duplicateCronGroups.length,\u000a          deadOrStaleSchedules: deadSchedules.length,\u000a          temporarySelfLiftSchedules: tempSchedules.length,\u000a          routingRisks: routingRisks.length,\u000a        },\u000a        findings: findings.schedules,\u000a      },\u000a      workflows: {\u000a        goal: "Separate load-bearing workflows from fixtures and enforce deterministic gate outputs.",\u000a        findingCount: findings.workflows.length,\u000a        checks: {\u000a          enabledFixtures: smokeEnabled.length,\u000a          structuredOutputGaps: gateCoverageGaps.length,\u000a          loadBearingCount: workflowTypeRows.filter((w) => w.class === "load-bearing").length,\u000a          fixtureOrSmallCount: workflowTypeRows.filter((w) => w.class === "fixture-or-small").length,\u000a        },\u000a        workflowClasses: sample(workflowTypeRows, includeSamples, 20),\u000a        findings: findings.workflows,\u000a      },\u000a      promptsTemplates: {\u000a        goal: "Keep prompt registry, runtime defaults, host guidance, and skill seed blocks aligned.",\u000a        findingCount: findings.promptsTemplates.length,\u000a        checks: {\u000a          codeRegistryEvents: CODE_REGISTRY_EVENTS.length,\u000a          dbOnlyEvents: dbOnlyEvents.length,\u000a          missingDefaultEvents: missingDefaultEvents.length,\u000a          duplicatePromptBodyGroups: duplicatePromptBodies.length,\u000a          staleUrlPrompts: staleUrlPrompts.length,\u000a          contradictoryPrompts: contradictoryPrompts.length,\u000a          systemDefaultSkillDuplicates: systemDefaultSkillDuplicates.length,\u000a        },\u000a        findings: findings.promptsTemplates,\u000a      },\u000a    },\u000a  };\u000a\u000a  if (publishPage) result.page = await publishCatalogReportPage(buildReport(result), ctx);\u000a  return result;\u000a}\u000a'),'Audit-as-code catalog check for schedules, workflows, and prompt/template drift. Clusters actionable findings by goal and can publish an authed HTML report page.','Re-run the ops inventory audit in one call: duplicate/dead schedules, code-work routing risks, enabled workflow fixtures, structured-output gate gaps, prompt registry drift, stale hosts, and systemDefault skill duplicates.','{"argsType":"any","resultType":"unknown","description":"Audit schedules, workflows, and prompt/template catalogs by goal, with optional authed page output."}','a6b5ee6dab67dfdf27e377556697fd12aaa09be60d741d9582b19bc9b8bc651b',1,0,1,'none',NULL,'2026-06-11T22:38:24.395Z','2026-06-11T22:38:24.395Z','{"$schema":"https://json-schema.org/draft/2020-12/schema","type":"object","properties":{"nowIso":{"description":"Audit clock override (default: current time)","type":"string"},"publishPage":{"description":"Publish an authed HTML page (default true)","type":"boolean"},"includeSamples":{"description":"Include small row samples for each finding cluster (default true)","type":"boolean"},"staleScheduleDays":{"description":"Flag enabled schedules with no run for this many days (default 14)","type":"integer","exclusiveMinimum":0,"maximum":9007199254740991,"minimum":-9007199254740991},"tempScheduleNames":{"description":"Known temporary schedule name fragments that should self-lift","type":"array","items":{"type":"string"}}},"additionalProperties":false}',NULL,NULL);
INSERT INTO scripts VALUES('87c25434-456a-46ab-b322-76202af8c577','boot-triage','global',NULL,unistr('import { z } from "zod";\u000a\u000aexport const argsSchema = z.object({\u000a  nowIso: z.string().optional().describe("Triage clock override (default: current time)"),\u000a  failureLookbackMinutes: z\u000a    .number()\u000a    .int()\u000a    .positive()\u000a    .optional()\u000a    .describe("Look back this many minutes for real failures (default 60)"),\u000a  stuckMinutes: z\u000a    .number()\u000a    .int()\u000a    .positive()\u000a    .optional()\u000a    .describe("Flag in-progress tasks older than this on offline agents (default 5)"),\u000a  deployWindowMinutes: z\u000a    .number()\u000a    .int()\u000a    .positive()\u000a    .optional()\u000a    .describe("Window around now for merged agent-swarm PRs (default 15)"),\u000a  repo: z\u000a    .string()\u000a    .optional()\u000a    .describe("Optional GitHub repository in ''owner/name'' form for restart/deploy PR detection"),\u000a});\u000a\u000aconst BENIGN_FAILURE_RE = /^(superseded_workflow_task|cancelled|reboot-sweep)$/i;\u000a\u000afunction rowsToObjects(res: any): any[] {\u000a  const p = res?.data ?? res;\u000a  const cols: string[] = p?.columns ?? [];\u000a  return (p?.rows ?? []).map((r: any) =>\u000a    Array.isArray(r) ? Object.fromEntries(cols.map((c, i) => [c, r[i]])) : r,\u000a  );\u000a}\u000a\u000aasync function query(ctx: any, sql: string, params?: unknown[]): Promise<any[]> {\u000a  try {\u000a    return rowsToObjects(await ctx.swarm.db_query({ sql, params }));\u000a  } catch (error) {\u000a    return [{ unavailable: error instanceof Error ? error.message : String(error) }];\u000a  }\u000a}\u000a\u000afunction taskPreview(task: unknown): string {\u000a  return String(task || "").replace(/\\s+/g, " ").trim().slice(0, 180);\u000a}\u000a\u000afunction summarizeTask(row: any): any {\u000a  return {\u000a    id: row.id,\u000a    status: row.status,\u000a    taskType: row.taskType || null,\u000a    agentId: row.agentId || null,\u000a    agentName: row.agentName || null,\u000a    scheduleId: row.scheduleId || null,\u000a    parentTaskId: row.parentTaskId || null,\u000a    failureReason: row.failureReason || null,\u000a    createdAt: row.createdAt,\u000a    lastUpdatedAt: row.lastUpdatedAt,\u000a    taskPreview: taskPreview(row.task),\u000a  };\u000a}\u000a\u000aasync function recentMergedPrs(\u000a  ctx: any,\u000a  repo: string | undefined,\u000a  nowMs: number,\u000a  windowMinutes: number,\u000a): Promise<any> {\u000a  if (!repo) return { skipped: "repo not provided" };\u000a  if (!/^[^/\\s]+\\/[^/\\s]+$/.test(repo)) return { error: "repo must be in ''owner/name'' form" };\u000a\u000a  const windowMs = windowMinutes * 60 * 1000;\u000a  try {\u000a    const response = await ctx.stdlib.fetch(\u000a      "https://api.github.com/repos/" +\u000a        repo +\u000a        "/pulls?state=closed&sort=updated&direction=desc&per_page=20",\u000a      {\u000a        headers: {\u000a          Accept: "application/vnd.github+json",\u000a          "User-Agent": "agent-swarm-boot-triage",\u000a        },\u000a      },\u000a    );\u000a    if (!response.ok) return { error: `GitHub API ${response.status}` };\u000a    const prs = (await response.json()) as any[];\u000a    return prs\u000a      .filter((pr) => pr?.merged_at)\u000a      .map((pr) => {\u000a        const mergedAtMs = Date.parse(pr.merged_at);\u000a        return {\u000a          repo,\u000a          number: pr.number,\u000a          title: pr.title,\u000a          url: pr.html_url,\u000a          mergedAt: pr.merged_at,\u000a          minutesFromRestart: Math.round((mergedAtMs - nowMs) / 60000),\u000a        };\u000a      })\u000a      .filter((pr) => Math.abs(pr.minutesFromRestart * 60000) <= windowMs);\u000a  } catch (error) {\u000a    return { error: error instanceof Error ? error.message : String(error) };\u000a  }\u000a}\u000a\u000a/** Read-only post-restart triage snapshot for the heartbeat.boot-triage prompt. */\u000aexport default async function bootTriage(args: any, ctx: any) {\u000a  const parsed = argsSchema.safeParse(args || {});\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a\u000a  const now = parsed.data.nowIso ? new Date(parsed.data.nowIso) : new Date();\u000a  const nowMs = now.getTime();\u000a  const failureLookbackMinutes = parsed.data.failureLookbackMinutes || 60;\u000a  const stuckMinutes = parsed.data.stuckMinutes || 5;\u000a  const deployWindowMinutes = parsed.data.deployWindowMinutes || 15;\u000a  const repo = parsed.data.repo;\u000a\u000a  const mergedPrs = await recentMergedPrs(ctx, repo, nowMs, deployWindowMinutes);\u000a\u000a  const recentFailureRows = await query(\u000a    ctx,\u000a    `SELECT t.id, t.task, t.status, t.taskType, t.agentId, a.name as agentName,\u000a            t.scheduleId, t.parentTaskId, t.failureReason, t.createdAt, t.lastUpdatedAt\u000a     FROM agent_tasks t\u000a     LEFT JOIN agents a ON a.id = t.agentId\u000a     WHERE t.status = ''failed''\u000a       AND datetime(t.lastUpdatedAt) >= datetime(?, ?)\u000a     ORDER BY datetime(t.lastUpdatedAt) DESC\u000a     LIMIT 50`,\u000a    [now.toISOString(), `-${failureLookbackMinutes} minutes`],\u000a  );\u000a  const recentlyFailedTasks = recentFailureRows\u000a    .filter((row) => !row.unavailable)\u000a    .filter((row) => !BENIGN_FAILURE_RE.test(String(row.failureReason || "")))\u000a    .map(summarizeTask);\u000a\u000a  const stuckOfflineRows = await query(\u000a    ctx,\u000a    `SELECT t.id, t.task, t.status, t.taskType, t.agentId, a.name as agentName,\u000a            t.scheduleId, t.parentTaskId, t.failureReason, t.createdAt, t.lastUpdatedAt\u000a     FROM agent_tasks t\u000a     JOIN agents a ON a.id = t.agentId\u000a     WHERE t.status = ''in_progress''\u000a       AND a.status = ''offline''\u000a       AND datetime(t.lastUpdatedAt) <= datetime(?, ?)\u000a     ORDER BY datetime(t.lastUpdatedAt) ASC\u000a     LIMIT 50`,\u000a    [now.toISOString(), `-${stuckMinutes} minutes`],\u000a  );\u000a  const stuckInProgressOnOfflineAgents = stuckOfflineRows\u000a    .filter((row) => !row.unavailable)\u000a    .map(summarizeTask);\u000a\u000a  const orphanRows = await query(\u000a    ctx,\u000a    `SELECT t.id, t.task, t.status, t.taskType, t.agentId, a.name as agentName,\u000a            t.scheduleId, t.parentTaskId, t.failureReason, t.createdAt, t.lastUpdatedAt\u000a     FROM agent_tasks t\u000a     JOIN agents a ON a.id = t.agentId\u000a     WHERE t.status IN (''pending'', ''offered'')\u000a       AND a.status = ''offline''\u000a     ORDER BY datetime(t.lastUpdatedAt) ASC\u000a     LIMIT 50`,\u000a  );\u000a  const orphanedPendingOrOfferedOnOfflineWorkers = orphanRows\u000a    .filter((row) => !row.unavailable)\u000a    .map(summarizeTask);\u000a\u000a  const supersededRows = await query(\u000a    ctx,\u000a    `SELECT p.id, p.task, p.status, p.taskType, p.agentId, a.name as agentName,\u000a            p.scheduleId, p.parentTaskId, p.failureReason, p.createdAt, p.lastUpdatedAt\u000a     FROM agent_tasks p\u000a     LEFT JOIN agents a ON a.id = p.agentId\u000a     WHERE p.status = ''superseded''\u000a       AND datetime(p.lastUpdatedAt) >= datetime(?, ?)\u000a       AND NOT EXISTS (\u000a         SELECT 1\u000a         FROM agent_tasks c\u000a         WHERE c.parentTaskId = p.id\u000a           AND c.taskType = ''resume''\u000a           AND c.status NOT IN (''completed'', ''failed'', ''cancelled'', ''superseded'')\u000a       )\u000a     ORDER BY datetime(p.lastUpdatedAt) DESC\u000a     LIMIT 50`,\u000a    [now.toISOString(), `-${failureLookbackMinutes} minutes`],\u000a  );\u000a  const supersededTasksMissingResumeChild = supersededRows\u000a    .filter((row) => !row.unavailable)\u000a    .map(summarizeTask);\u000a\u000a  return {\u000a    generatedAt: now.toISOString(),\u000a    windows: {\u000a      failureLookbackMinutes,\u000a      stuckMinutes,\u000a      deployWindowMinutes,\u000a    },\u000a    deployRestartDetection: {\u000a      source: repo ? "github:" + repo : null,\u000a      mergedPrsWithinWindow: Array.isArray(mergedPrs) ? mergedPrs : [],\u000a      skipped: Array.isArray(mergedPrs) ? null : mergedPrs.skipped || null,\u000a      error: Array.isArray(mergedPrs) ? null : mergedPrs.error,\u000a    },\u000a    recentlyFailedTasks,\u000a    stuckInProgressOnOfflineAgents,\u000a    orphanedPendingOrOfferedOnOfflineWorkers,\u000a    supersededTasksMissingResumeChild,\u000a    summary: {\u000a      mergedPrsWithinWindow: Array.isArray(mergedPrs) ? mergedPrs.length : 0,\u000a      recentlyFailedTasks: recentlyFailedTasks.length,\u000a      stuckInProgressOnOfflineAgents: stuckInProgressOnOfflineAgents.length,\u000a      orphanedPendingOrOfferedOnOfflineWorkers: orphanedPendingOrOfferedOnOfflineWorkers.length,\u000a      supersededTasksMissingResumeChild: supersededTasksMissingResumeChild.length,\u000a    },\u000a  };\u000a}\u000a'),'Post-restart heartbeat triage snapshot: deploy restart PR context, recent real failures, stuck offline-agent work, orphaned tasks, and superseded tasks missing resume children.','Run immediately after a swarm restart to gather deterministic boot triage data in one read-only call before the Lead decides what to retry, cancel, or escalate.','{"argsType":"any","resultType":"unknown","description":"Read-only post-restart triage snapshot for the heartbeat.boot-triage prompt."}','c5da2e8f9c5283051bafbdb9e367e115cc259d6754c08f63adbd66fef48a15db',1,0,1,'none',NULL,'2026-06-11T22:38:24.519Z','2026-06-11T22:38:24.519Z','{"$schema":"https://json-schema.org/draft/2020-12/schema","type":"object","properties":{"nowIso":{"description":"Triage clock override (default: current time)","type":"string"},"failureLookbackMinutes":{"description":"Look back this many minutes for real failures (default 60)","type":"integer","exclusiveMinimum":0,"maximum":9007199254740991,"minimum":-9007199254740991},"stuckMinutes":{"description":"Flag in-progress tasks older than this on offline agents (default 5)","type":"integer","exclusiveMinimum":0,"maximum":9007199254740991,"minimum":-9007199254740991},"deployWindowMinutes":{"description":"Window around now for merged agent-swarm PRs (default 15)","type":"integer","exclusiveMinimum":0,"maximum":9007199254740991,"minimum":-9007199254740991},"repo":{"description":"Optional GitHub repository in ''owner/name'' form for restart/deploy PR detection","type":"string"}},"additionalProperties":false}',NULL,NULL);
INSERT INTO script_versions VALUES('6ea455b7-a4a0-4a01-b1d8-3c0aa310a1f1','5a903cc9-8d9d-490c-8178-a1507e5c01a9',1,unistr('import { z } from "zod";\u000a\u000aexport const argsSchema = z.object({\u000a  repo: z.string().describe("Repository in ''owner/name'' form, e.g. ''owner/name''"),\u000a  number: z.number().int().positive().describe("Pull request number"),\u000a  token: z\u000a    .string()\u000a    .optional()\u000a    .describe("GitHub token override; falls back to the GITHUB_TOKEN swarm config"),\u000a});\u000a\u000aasync function resolveSecret(ctx: any, key: string, override: unknown): Promise<string | null> {\u000a  if (typeof override === "string" && override.length > 0) return override;\u000a  try {\u000a    const base = ctx.stdlib.Redacted.value(ctx.swarm.config.mcpBaseUrl).replace(/\\/+$/, "");\u000a    const apiKey = ctx.stdlib.Redacted.value(ctx.swarm.config.apiKey);\u000a    const res: any = await ctx.stdlib.fetchJson(\u000a      base + "/api/config/resolved?includeSecrets=true",\u000a      { headers: { Authorization: "Bearer " + apiKey } },\u000a    );\u000a    const configs: any = res && Array.isArray(res.configs) ? res.configs : [];\u000a    for (const c of configs) {\u000a      if (c && c.key === key && typeof c.value === "string" && c.value.length > 0) {\u000a        return c.value;\u000a      }\u000a    }\u000a  } catch {\u000a    // Best-effort: a missing config row just means we proceed unauthenticated.\u000a  }\u000a  return null;\u000a}\u000a\u000a/** One-call GitHub PR snapshot: state, draft, mergeable, CI checks and review tallies. */\u000aexport default async function ghPrSnapshot(args: any, ctx: any) {\u000a  const parsed = argsSchema.safeParse(args);\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a  const { repo, number } = parsed.data;\u000a  if (!/^[^/\\s]+\\/[^/\\s]+$/.test(repo)) {\u000a    return { error: "repo must be in ''owner/name'' form" };\u000a  }\u000a\u000a  const token = await resolveSecret(ctx, "GITHUB_TOKEN", parsed.data.token);\u000a  const headers: any = {\u000a    Accept: "application/vnd.github+json",\u000a    "User-Agent": "agent-swarm-scripts",\u000a  };\u000a  if (token) headers.Authorization = "Bearer " + token;\u000a\u000a  const api = "https://api.github.com/repos/" + repo;\u000a  const pr: any = await ctx.stdlib.fetchJson(api + "/pulls/" + number, { headers });\u000a  if (!pr || typeof pr.number !== "number") {\u000a    const why = pr && pr.message ? pr.message : "not found or not accessible";\u000a    return { error: "PR " + repo + "#" + number + ": " + why };\u000a  }\u000a\u000a  const checks = { passed: 0, failed: 0, pending: 0 };\u000a  const sha = pr.head && pr.head.sha ? pr.head.sha : null;\u000a  if (sha) {\u000a    const runs: any = await ctx.stdlib.fetchJson(api + "/commits/" + sha + "/check-runs", {\u000a      headers,\u000a    });\u000a    const list: any = runs && Array.isArray(runs.check_runs) ? runs.check_runs : [];\u000a    for (const run of list) {\u000a      if (run.status !== "completed") checks.pending++;\u000a      else if (run.conclusion === "success") checks.passed++;\u000a      else if (\u000a        run.conclusion === "failure" ||\u000a        run.conclusion === "timed_out" ||\u000a        run.conclusion === "cancelled" ||\u000a        run.conclusion === "action_required"\u000a      ) {\u000a        checks.failed++;\u000a      }\u000a    }\u000a  }\u000a\u000a  const reviewsRaw: any = await ctx.stdlib.fetchJson(api + "/pulls/" + number + "/reviews", {\u000a    headers,\u000a  });\u000a  const reviewList: any = Array.isArray(reviewsRaw) ? reviewsRaw : [];\u000a  const latestByUser: any = {};\u000a  for (const r of reviewList) {\u000a    const user = r && r.user && r.user.login ? r.user.login : "unknown";\u000a    if (r.state === "APPROVED" || r.state === "CHANGES_REQUESTED") {\u000a      latestByUser[user] = r.state;\u000a    }\u000a  }\u000a  const reviews = { approved: 0, changesRequested: 0, pending: 0 };\u000a  for (const user of Object.keys(latestByUser)) {\u000a    if (latestByUser[user] === "APPROVED") reviews.approved++;\u000a    else reviews.changesRequested++;\u000a  }\u000a  reviews.pending = Array.isArray(pr.requested_reviewers) ? pr.requested_reviewers.length : 0;\u000a\u000a  return {\u000a    title: pr.title,\u000a    state: pr.merged_at ? "merged" : pr.state,\u000a    draft: Boolean(pr.draft),\u000a    mergeable: pr.mergeable,\u000a    checks,\u000a    reviews,\u000a    url: pr.html_url,\u000a  };\u000a}\u000a'),'One-call GitHub pull request snapshot: title, state, draft, mergeable, CI check tallies (passed/failed/pending) and review tallies (approved/changes-requested/pending).','Triage a GitHub PR''s status in a single call instead of running several gh pr view / gh pr checks / gh api invocations.','{"argsType":"any","resultType":"unknown","description":"One-call GitHub PR snapshot: state, draft, mergeable, CI checks and review tallies."}','023ffb9c44b5ff4f2d85addfdb1d098224a8ac12dbaa9ed7cc3f7a3770a085b4',NULL,'2026-06-11T22:38:22.200Z','Seeded from the built-in scripts catalog (src/be/seed-scripts)',NULL,NULL);
INSERT INTO script_versions VALUES('3f868817-8326-4ed0-a43e-03a3e150d7f3','52ce70b3-ab75-4eda-99ff-cd88c43598d6',1,unistr('import { z } from "zod";\u000a\u000aexport const argsSchema = z.object({\u000a  url: z.string().describe("Absolute http(s) URL of the page to extract"),\u000a  maxChars: z\u000a    .number()\u000a    .int()\u000a    .positive()\u000a    .optional()\u000a    .describe("Truncate extracted text to this many characters (default 20000)"),\u000a});\u000a\u000aconst ENTITIES: any = {\u000a  "&amp;": "&",\u000a  "&lt;": "<",\u000a  "&gt;": ">",\u000a  "&quot;": ''"'',\u000a  "&#39;": "''",\u000a  "&apos;": "''",\u000a  "&nbsp;": " ",\u000a};\u000a\u000afunction decodeEntities(input: string): string {\u000a  let out = input.replace(/&(amp|lt|gt|quot|#39|apos|nbsp);/g, (m: string) => ENTITIES[m] || m);\u000a  out = out.replace(/&#(\\d+);/g, (_m: string, code: string) =>\u000a    String.fromCodePoint(Number.parseInt(code, 10)),\u000a  );\u000a  out = out.replace(/&#x([0-9a-fA-F]+);/g, (_m: string, code: string) =>\u000a    String.fromCodePoint(Number.parseInt(code, 16)),\u000a  );\u000a  return out;\u000a}\u000a\u000a/** Fetch a web page and return readable article text with nav/ads/boilerplate stripped. */\u000aexport default async function fetchReadable(args: any, ctx: any) {\u000a  const parsed = argsSchema.safeParse(args);\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a  const { url } = parsed.data;\u000a  if (!/^https?:\\/\\//i.test(url)) return { error: "url must be an absolute http(s) URL" };\u000a  const maxChars = parsed.data.maxChars || 20000;\u000a\u000a  const html: any = await ctx.stdlib.fetchJson(url, {\u000a    headers: { "User-Agent": "agent-swarm-scripts", Accept: "text/html,*/*" },\u000a  });\u000a  const raw = typeof html === "string" ? html : JSON.stringify(html);\u000a\u000a  const titleMatch = raw.match(/<title[^>]*>([\\s\\S]*?)<\\/title>/i);\u000a  const ogMatch = raw.match(\u000a    /<meta[^>]+property=["'']og:title["''][^>]+content=["'']([^"'']+)["'']/i,\u000a  );\u000a  const title = decodeEntities((ogMatch?.[1] ?? titleMatch?.[1] ?? "").trim());\u000a\u000a  let body = raw;\u000a  // Drop non-content regions entirely (tag + inner content).\u000a  body = body.replace(\u000a    /<(script|style|noscript|nav|header|footer|aside|svg|template|form|iframe)\\b[^>]*>[\\s\\S]*?<\\/\\1>/gi,\u000a    " ",\u000a  );\u000a  body = body.replace(/<!--[\\s\\S]*?-->/g, " ");\u000a  // Keep block boundaries as newlines so paragraphs survive.\u000a  body = body.replace(/<\\/(p|div|section|article|li|h[1-6]|br|tr)>/gi, "\\n");\u000a  body = body.replace(/<br\\s*\\/?>/gi, "\\n");\u000a  // Strip all remaining tags.\u000a  body = body.replace(/<[^>]+>/g, " ");\u000a  body = decodeEntities(body);\u000a  body = body\u000a    .split("\\n")\u000a    .map((line: string) => line.replace(/[ \\t\\f\\v ]+/g, " ").trim())\u000a    .filter((line: string) => line.length > 0)\u000a    .join("\\n");\u000a  body = body.replace(/\\n{3,}/g, "\\n\\n");\u000a\u000a  const truncated = body.length > maxChars;\u000a  if (truncated) body = body.slice(0, maxChars);\u000a\u000a  return { title, text: body, url, length: body.length, truncated };\u000a}\u000a'),'Fetch a web page and extract clean readable article text — strips scripts, styles, nav, headers, footers, ads and HTML tags, and decodes entities.','Read the actual content of a URL without wading through raw HTML; readable-article / reader-mode extraction.','{"argsType":"any","resultType":"unknown","description":"Fetch a web page and return readable article text with nav/ads/boilerplate stripped."}','fc50aa7e13c71c36cd6af15e101b6ab380f978d56f80d581dffbacd0756f39b1',NULL,'2026-06-11T22:38:22.346Z','Seeded from the built-in scripts catalog (src/be/seed-scripts)',NULL,NULL);
INSERT INTO script_versions VALUES('f4737422-bb2d-4eb3-a1db-3fcc930adcb1','4cf0e0fa-f341-4ebd-aaee-921965e8a2c8',1,unistr('import { z } from "zod";\u000a\u000aexport const argsSchema = z.object({\u000a  data: z.unknown().describe("Any JSON value to query (object, array, or scalar)"),\u000a  query: z\u000a    .string()\u000a    .describe(\u000a      "jq-style path: dot fields, [n] index, [] iterate, | pipe, and keys/values/length/type",\u000a    ),\u000a});\u000a\u000afunction getProp(value: any, key: string): any {\u000a  if (value == null) return undefined;\u000a  if (typeof value !== "object") return undefined;\u000a  return value[key];\u000a}\u000a\u000afunction applyToken(stream: any[], token: string): any[] {\u000a  const next: any[] = [];\u000a  for (const value of stream) {\u000a    if (token === "[]") {\u000a      if (Array.isArray(value)) {\u000a        for (const item of value) next.push(item);\u000a      } else if (value && typeof value === "object") {\u000a        for (const k of Object.keys(value)) next.push(value[k]);\u000a      }\u000a      continue;\u000a    }\u000a    const idx = token.match(/^\\[(-?\\d+)\\]$/);\u000a    if (idx) {\u000a      let i = Number.parseInt(idx[1] as string, 10);\u000a      if (Array.isArray(value) && i < 0) i += value.length;\u000a      next.push(Array.isArray(value) ? value[i] : undefined);\u000a      continue;\u000a    }\u000a    const quoted = token.match(/^\\["([^"]*)"\\]$/);\u000a    if (quoted) {\u000a      next.push(getProp(value, quoted[1] as string));\u000a      continue;\u000a    }\u000a    const field = token.match(/^\\.([a-zA-Z_$][\\w$]*)$/);\u000a    if (field) {\u000a      next.push(getProp(value, field[1] as string));\u000a      continue;\u000a    }\u000a    if (token === "." || token === "") {\u000a      next.push(value);\u000a      continue;\u000a    }\u000a    throw "unrecognized path token: " + token;\u000a  }\u000a  return next;\u000a}\u000a\u000afunction applyFunction(stream: any[], name: string): any[] {\u000a  return stream.map((value: any) => {\u000a    if (name === "length") {\u000a      if (Array.isArray(value) || typeof value === "string") return value.length;\u000a      if (value && typeof value === "object") return Object.keys(value).length;\u000a      return 0;\u000a    }\u000a    if (name === "keys") {\u000a      return value && typeof value === "object" ? Object.keys(value) : [];\u000a    }\u000a    if (name === "values") {\u000a      if (Array.isArray(value)) return value;\u000a      return value && typeof value === "object" ? Object.values(value) : [];\u000a    }\u000a    if (name === "type") {\u000a      if (value === null) return "null";\u000a      if (Array.isArray(value)) return "array";\u000a      return typeof value;\u000a    }\u000a    throw "unknown function: " + name;\u000a  });\u000a}\u000a\u000afunction applyStage(stream: any[], stage: string): any[] {\u000a  const trimmed = stage.trim();\u000a  if (/^(keys|values|length|type)$/.test(trimmed)) {\u000a    return applyFunction(stream, trimmed);\u000a  }\u000a  let rest = trimmed;\u000a  let current = stream;\u000a  if (rest === "." || rest === "") return current;\u000a  while (rest.length > 0) {\u000a    const m = rest.match(/^(\\[\\]|\\[-?\\d+\\]|\\["[^"]*"\\]|\\.[a-zA-Z_$][\\w$]*|\\.)/);\u000a    if (!m) throw "could not parse path near: " + rest;\u000a    const token = m[1] as string;\u000a    current = applyToken(current, token);\u000a    rest = rest.slice(token.length);\u000a  }\u000a  return current;\u000a}\u000a\u000a/** Run a jq-style path/filter query over a JSON value — replaces curl|jq pipelines. */\u000aexport default async function jsonQuery(args: any, _ctx: any) {\u000a  const parsed = argsSchema.safeParse(args);\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a  const { query } = parsed.data;\u000a\u000a  let data: any = parsed.data.data;\u000a  if (typeof data === "string") {\u000a    const t = data.trim();\u000a    if (t.startsWith("{") || t.startsWith("[")) {\u000a      try {\u000a        data = JSON.parse(t);\u000a      } catch {\u000a        // Leave as a plain string if it is not valid JSON.\u000a      }\u000a    }\u000a  }\u000a\u000a  try {\u000a    let stream: any[] = [data];\u000a    for (const stage of query.split("|")) {\u000a      stream = applyStage(stream, stage);\u000a    }\u000a    const result = stream.length === 1 ? stream[0] : stream;\u000a    return { result, matches: stream.length };\u000a  } catch (err) {\u000a    return { error: typeof err === "string" ? err : "query failed" };\u000a  }\u000a}\u000a'),'Run a jq-style path/filter query over any JSON value: dot fields, [n] indexing, [] iteration, | pipes, and keys/values/length/type functions.','Extract a value from a JSON blob without shelling out to a curl | jq pipeline.','{"argsType":"any","resultType":"unknown","description":"Run a jq-style path/filter query over a JSON value — replaces curl|jq pipelines."}','88f200ba0d090c85112465316655d2a5869263def915bb9b0b2808d98dbb49b4',NULL,'2026-06-11T22:38:22.490Z','Seeded from the built-in scripts catalog (src/be/seed-scripts)',NULL,NULL);
INSERT INTO script_versions VALUES('cb913cef-544b-421c-b625-4c6cf2a5588e','19e282df-8147-4338-99e9-085e2a1152c7',1,unistr('import { z } from "zod";\u000a\u000aexport const argsSchema = z.object({\u000a  items: z.array(z.unknown()).describe("Array of objects to aggregate"),\u000a  by: z.string().describe("Field name (dotted paths allowed) to group by"),\u000a  sum: z\u000a    .string()\u000a    .optional()\u000a    .describe("Optional numeric field name to sum within each group"),\u000a  limit: z\u000a    .number()\u000a    .int()\u000a    .positive()\u000a    .optional()\u000a    .describe("Return only the top N groups by count (default: all)"),\u000a});\u000a\u000afunction dig(obj: any, path: string): any {\u000a  let cur = obj;\u000a  for (const part of path.split(".")) {\u000a    if (cur == null || typeof cur !== "object") return undefined;\u000a    cur = cur[part];\u000a  }\u000a  return cur;\u000a}\u000a\u000afunction keyOf(value: any): string {\u000a  if (value === undefined) return "(undefined)";\u000a  if (value === null) return "(null)";\u000a  if (typeof value === "object") return JSON.stringify(value);\u000a  return String(value);\u000a}\u000a\u000a/** Group an array of objects by a field, returning per-group count and optional sum. */\u000aexport default async function groupCount(args: any, _ctx: any) {\u000a  const parsed = argsSchema.safeParse(args);\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a  const { items, by } = parsed.data;\u000a  const sumField = parsed.data.sum;\u000a\u000a  const groups: any = {};\u000a  let totalSum = 0;\u000a  for (const item of items) {\u000a    const key = keyOf(dig(item, by));\u000a    if (!groups[key]) groups[key] = { key, count: 0, sum: 0 };\u000a    groups[key].count++;\u000a    if (sumField) {\u000a      const raw = dig(item, sumField);\u000a      const num = typeof raw === "number" ? raw : Number(raw);\u000a      if (!Number.isNaN(num)) {\u000a        groups[key].sum += num;\u000a        totalSum += num;\u000a      }\u000a    }\u000a  }\u000a\u000a  let rows: any[] = Object.keys(groups).map((k: string) => {\u000a    const g = groups[k];\u000a    return sumField ? { key: g.key, count: g.count, sum: g.sum } : { key: g.key, count: g.count };\u000a  });\u000a  rows.sort((a: any, b: any) => b.count - a.count);\u000a  if (parsed.data.limit) rows = rows.slice(0, parsed.data.limit);\u000a\u000a  return {\u000a    groups: rows,\u000a    groupCount: rows.length,\u000a    total: items.length,\u000a    totalSum: sumField ? totalSum : undefined,\u000a  };\u000a}\u000a'),'Group an array of objects by a field (dotted paths supported), returning per-group counts sorted by frequency plus an optional numeric sum.','Aggregate or tally records — counts and sums by category — without writing ad-hoc reduce code.','{"argsType":"any","resultType":"unknown","description":"Group an array of objects by a field, returning per-group count and optional sum."}','428efdd1d1886b26a31ea3f29ed623b0a087da2615b8e55ef1cfc1f659a59c4e',NULL,'2026-06-11T22:38:22.628Z','Seeded from the built-in scripts catalog (src/be/seed-scripts)',NULL,NULL);
INSERT INTO script_versions VALUES('62667533-68bb-4945-b88e-5937a544f4b6','acfd7980-2422-496b-9085-3297d18753c2',1,unistr('import { z } from "zod";\u000a\u000aexport const argsSchema = z.object({\u000a  expr: z\u000a    .string()\u000a    .describe("Natural date expression: yesterday, last week, Thursday, 7d ago, 2026-01-01"),\u000a  now: z\u000a    .string()\u000a    .optional()\u000a    .describe("ISO timestamp to resolve relative to (default: current time)"),\u000a});\u000a\u000aconst DAY = 86400000;\u000aconst WEEKDAYS = ["sunday", "monday", "tuesday", "wednesday", "thursday", "friday", "saturday"];\u000aconst UNIT_MS: any = {\u000a  hour: 3600000,\u000a  hours: 3600000,\u000a  h: 3600000,\u000a  day: DAY,\u000a  days: DAY,\u000a  d: DAY,\u000a  week: 7 * DAY,\u000a  weeks: 7 * DAY,\u000a  w: 7 * DAY,\u000a};\u000a\u000afunction ymd(d: Date): string {\u000a  return d.toISOString().slice(0, 10);\u000a}\u000a\u000afunction startOfDay(d: Date): Date {\u000a  return new Date(Date.UTC(d.getUTCFullYear(), d.getUTCMonth(), d.getUTCDate()));\u000a}\u000a\u000afunction single(d: Date): any {\u000a  return { iso: d.toISOString(), date: ymd(d) };\u000a}\u000a\u000afunction range(start: Date, end: Date): any {\u000a  return { start: start.toISOString(), end: end.toISOString() };\u000a}\u000a\u000a/** Resolve a natural date expression to an ISO date or a {start,end} range. */\u000aexport default async function dateResolve(args: any, _ctx: any) {\u000a  const parsed = argsSchema.safeParse(args);\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a\u000a  const nowMs = parsed.data.now ? Date.parse(parsed.data.now) : Date.now();\u000a  if (Number.isNaN(nowMs)) return { error: "invalid ''now'' timestamp" };\u000a  const now = new Date(nowMs);\u000a  const today = startOfDay(now);\u000a  const expr = parsed.data.expr.trim().toLowerCase();\u000a\u000a  if (expr === "now") return single(now);\u000a  if (expr === "today") return single(today);\u000a  if (expr === "yesterday") return single(new Date(today.getTime() - DAY));\u000a  if (expr === "tomorrow") return single(new Date(today.getTime() + DAY));\u000a\u000a  if (/^\\d{4}-\\d{2}-\\d{2}/.test(expr)) {\u000a    const ms = Date.parse(parsed.data.expr.trim());\u000a    if (Number.isNaN(ms)) return { error: "unparseable ISO date" };\u000a    return single(new Date(ms));\u000a  }\u000a\u000a  // "N <unit> ago" / "in N <unit>" / "Nd ago"\u000a  const rel = expr.match(/^(?:in\\s+)?(\\d+)\\s*([a-z]+)\\s*(ago)?$/);\u000a  if (rel) {\u000a    const amount = Number.parseInt(rel[1] as string, 10);\u000a    const unitMs = UNIT_MS[rel[2] as string];\u000a    if (unitMs) {\u000a      const dir = rel[3] === "ago" ? -1 : 1;\u000a      return single(new Date(now.getTime() + dir * amount * unitMs));\u000a    }\u000a  }\u000a\u000a  // Weekday name → most recent occurrence on or before today.\u000a  const wd = WEEKDAYS.indexOf(expr);\u000a  if (wd >= 0) {\u000a    let back = today.getUTCDay() - wd;\u000a    if (back < 0) back += 7;\u000a    return single(new Date(today.getTime() - back * DAY));\u000a  }\u000a\u000a  // Week ranges (weeks start Monday).\u000a  const weekMatch = expr.match(/^(last|this|next)\\s+week$/);\u000a  if (weekMatch) {\u000a    const offset = today.getUTCDay() === 0 ? 6 : today.getUTCDay() - 1;\u000a    const monday = new Date(today.getTime() - offset * DAY);\u000a    const shift = weekMatch[1] === "last" ? -7 : weekMatch[1] === "next" ? 7 : 0;\u000a    const start = new Date(monday.getTime() + shift * DAY);\u000a    return range(start, new Date(start.getTime() + 7 * DAY));\u000a  }\u000a\u000a  // Month ranges.\u000a  const monthMatch = expr.match(/^(last|this|next)\\s+month$/);\u000a  if (monthMatch) {\u000a    const delta = monthMatch[1] === "last" ? -1 : monthMatch[1] === "next" ? 1 : 0;\u000a    const start = new Date(Date.UTC(today.getUTCFullYear(), today.getUTCMonth() + delta, 1));\u000a    const end = new Date(Date.UTC(today.getUTCFullYear(), today.getUTCMonth() + delta + 1, 1));\u000a    return range(start, end);\u000a  }\u000a\u000a  return { error: "could not resolve expression: " + parsed.data.expr };\u000a}\u000a'),'Resolve a natural-language date expression (yesterday, last week, Thursday, 7d ago, an ISO date) into an ISO timestamp or a {start,end} range.','Turn fuzzy human date phrases into concrete timestamps for filtering, querying or scheduling.','{"argsType":"any","resultType":"unknown","description":"Resolve a natural date expression to an ISO date or a {start,end} range."}','1b998fc4be3a734d1901e72561fbc2fe0ac111b963495de6de5073464e7a90fb',NULL,'2026-06-11T22:38:22.771Z','Seeded from the built-in scripts catalog (src/be/seed-scripts)',NULL,NULL);
INSERT INTO script_versions VALUES('a359bdd4-4d6f-4d72-ae56-5fefca2956ae','43cca088-38f5-4d7e-977a-10f4d7696cea',1,unistr('import { z } from "zod";\u000a\u000aexport const argsSchema = z.object({\u000a  a: z.string().describe("Original / left-hand text"),\u000a  b: z.string().describe("Updated / right-hand text"),\u000a  context: z\u000a    .number()\u000a    .int()\u000a    .nonnegative()\u000a    .optional()\u000a    .describe("Lines of unchanged context to keep around each change (default 3)"),\u000a});\u000a\u000aconst MAX_LINES = 5000;\u000a\u000afunction lcsOps(a: string[], b: string[]): any[] {\u000a  const n = a.length;\u000a  const m = b.length;\u000a  const dp: any[] = [];\u000a  for (let i = 0; i <= n; i++) dp.push(new Array(m + 1).fill(0));\u000a  for (let i = n - 1; i >= 0; i--) {\u000a    for (let j = m - 1; j >= 0; j--) {\u000a      dp[i][j] = a[i] === b[j] ? dp[i + 1][j + 1] + 1 : Math.max(dp[i + 1][j], dp[i][j + 1]);\u000a    }\u000a  }\u000a  const ops: any[] = [];\u000a  let i = 0;\u000a  let j = 0;\u000a  while (i < n && j < m) {\u000a    if (a[i] === b[j]) {\u000a      ops.push({ type: "eq", text: a[i] });\u000a      i++;\u000a      j++;\u000a    } else if (dp[i + 1][j] >= dp[i][j + 1]) {\u000a      ops.push({ type: "del", text: a[i] });\u000a      i++;\u000a    } else {\u000a      ops.push({ type: "ins", text: b[j] });\u000a      j++;\u000a    }\u000a  }\u000a  while (i < n) {\u000a    ops.push({ type: "del", text: a[i] });\u000a    i++;\u000a  }\u000a  while (j < m) {\u000a    ops.push({ type: "ins", text: b[j] });\u000a    j++;\u000a  }\u000a  return ops;\u000a}\u000a\u000a/** Compare two strings line-by-line and return a unified-diff summary. */\u000aexport default async function textDiff(args: any, _ctx: any) {\u000a  const parsed = argsSchema.safeParse(args);\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a  const ctxLines = parsed.data.context == null ? 3 : parsed.data.context;\u000a\u000a  const aLines = parsed.data.a.split("\\n");\u000a  const bLines = parsed.data.b.split("\\n");\u000a  if (aLines.length > MAX_LINES || bLines.length > MAX_LINES) {\u000a    return { error: "input too large: max " + MAX_LINES + " lines per side" };\u000a  }\u000a\u000a  const ops = lcsOps(aLines, bLines);\u000a  let added = 0;\u000a  let removed = 0;\u000a  let unchanged = 0;\u000a  for (const op of ops) {\u000a    if (op.type === "ins") added++;\u000a    else if (op.type === "del") removed++;\u000a    else unchanged++;\u000a  }\u000a\u000a  if (added === 0 && removed === 0) {\u000a    return { added, removed, unchanged, identical: true, diff: "" };\u000a  }\u000a\u000a  // Keep only context lines around runs of changes.\u000a  const keep: boolean[] = ops.map(() => false);\u000a  for (let k = 0; k < ops.length; k++) {\u000a    if (ops[k].type !== "eq") {\u000a      for (let w = Math.max(0, k - ctxLines); w <= Math.min(ops.length - 1, k + ctxLines); w++) {\u000a        keep[w] = true;\u000a      }\u000a    }\u000a  }\u000a  const lines: string[] = [];\u000a  let lastKept = false;\u000a  for (let k = 0; k < ops.length; k++) {\u000a    if (!keep[k]) {\u000a      lastKept = false;\u000a      continue;\u000a    }\u000a    if (!lastKept && lines.length > 0) lines.push("@@");\u000a    const op = ops[k];\u000a    const prefix = op.type === "ins" ? "+" : op.type === "del" ? "-" : " ";\u000a    lines.push(prefix + op.text);\u000a    lastKept = true;\u000a  }\u000a\u000a  return { added, removed, unchanged, identical: false, diff: lines.join("\\n") };\u000a}\u000a'),'Compare two strings line-by-line with an LCS diff and return a unified-diff summary plus added/removed/unchanged counts.','See exactly what changed between two versions of a text, config or document.','{"argsType":"any","resultType":"unknown","description":"Compare two strings line-by-line and return a unified-diff summary."}','5757420b2624fe414711b7127930247aaa937bfd415d7e0308e9ed4b11238b5a',NULL,'2026-06-11T22:38:22.906Z','Seeded from the built-in scripts catalog (src/be/seed-scripts)',NULL,NULL);
INSERT INTO script_versions VALUES('4291247a-175d-406b-b752-e5c429195f7e','72d3122e-4c96-489f-9787-baac5b3f5dc0',1,unistr('export type CatalogReportFinding = {\u000a  id: string;\u000a  severity?: string;\u000a  summary: string;\u000a  action?: string;\u000a  samples?: unknown[];\u000a};\u000a\u000aexport type CatalogReportSection = {\u000a  key: string;\u000a  label?: string;\u000a  goal: string;\u000a  findingCount?: number;\u000a  checks?: Record<string, unknown>;\u000a  findings?: CatalogReportFinding[];\u000a};\u000a\u000aexport type CatalogReport = {\u000a  title: string;\u000a  slug: string;\u000a  description: string;\u000a  generatedAt: string;\u000a  lede: string;\u000a  metrics: Array<[string, unknown]>;\u000a  sections: CatalogReportSection[];\u000a  appendix: unknown;\u000a};\u000a\u000afunction catalogReportAsText(value: unknown): string {\u000a  return typeof value === "string" ? value : value == null ? "" : JSON.stringify(value);\u000a}\u000a\u000afunction catalogReportHtmlEscape(value: unknown): string {\u000a  return catalogReportAsText(value)\u000a    .replace(/&/g, "&amp;")\u000a    .replace(/</g, "&lt;")\u000a    .replace(/>/g, "&gt;")\u000a    .replace(/"/g, "&quot;");\u000a}\u000a\u000afunction catalogReportHumanLabel(value: string): string {\u000a  return value\u000a    .replace(/([a-z0-9])([A-Z])/g, "$1 $2")\u000a    .replace(/[-_.]+/g, " ")\u000a    .replace(/\\b\\w/g, (char) => char.toUpperCase());\u000a}\u000a\u000afunction catalogReportFormatMetric(value: unknown): string {\u000a  if (typeof value === "number") return new Intl.NumberFormat("en-US").format(value);\u000a  return catalogReportAsText(value);\u000a}\u000a\u000afunction catalogReportSeverityTone(value?: string): string {\u000a  if (value === "critical") return "danger";\u000a  if (value === "high") return "warn";\u000a  if (value === "medium") return "note";\u000a  return "low";\u000a}\u000a\u000afunction catalogReportRenderSampleValue(value: unknown): string {\u000a  if (Array.isArray(value)) {\u000a    return value\u000a      .map((item) => (typeof item === "object" && item !== null ? JSON.stringify(item) : catalogReportAsText(item)))\u000a      .join(", ");\u000a  }\u000a  if (value && typeof value === "object") return JSON.stringify(value);\u000a  return catalogReportAsText(value);\u000a}\u000a\u000afunction catalogReportRenderSamples(samples?: unknown[]): string {\u000a  if (!Array.isArray(samples) || samples.length === 0) return "";\u000a  const normalized = samples.map((sampleRow) =>\u000a    sampleRow && typeof sampleRow === "object" && !Array.isArray(sampleRow)\u000a      ? (sampleRow as Record<string, unknown>)\u000a      : { value: sampleRow },\u000a  );\u000a  const columns = Array.from(\u000a    new Set(normalized.flatMap((sampleRow) => Object.keys(sampleRow).slice(0, 6))),\u000a  ).slice(0, 6);\u000a  if (columns.length === 0) return "";\u000a  const rows = normalized\u000a    .map(\u000a      (sampleRow) =>\u000a        `<tr>${columns\u000a          .map((column) => `<td>${catalogReportHtmlEscape(catalogReportRenderSampleValue(sampleRow[column]))}</td>`)\u000a          .join("")}</tr>`,\u000a    )\u000a    .join("");\u000a  return `<div class="sample-table" aria-label="Sample rows">\u000a    <table>\u000a      <thead><tr>${columns.map((column) => `<th>${catalogReportHtmlEscape(catalogReportHumanLabel(column))}</th>`).join("")}</tr></thead>\u000a      <tbody>${rows}</tbody>\u000a    </table>\u000a  </div>`;\u000a}\u000a\u000aexport function renderCatalogReportPage(report: CatalogReport): string {\u000a  const sections = report.sections\u000a    .map((section) => {\u000a      const findings = (section.findings || [])\u000a        .map(\u000a          (finding) => `<article class="finding ${catalogReportHtmlEscape(catalogReportSeverityTone(finding.severity))}">\u000a            <div class="finding-head">\u000a              <div>\u000a                <p class="finding-id">${catalogReportHtmlEscape(finding.id)}</p>\u000a                <h3>${catalogReportHtmlEscape(finding.summary)}</h3>\u000a              </div>\u000a              <span class="pill ${catalogReportHtmlEscape(catalogReportSeverityTone(finding.severity))}">${catalogReportHtmlEscape(\u000a                finding.severity || "low",\u000a              )}</span>\u000a            </div>\u000a            ${finding.action ? `<p class="action">${catalogReportHtmlEscape(finding.action)}</p>` : ""}\u000a            ${catalogReportRenderSamples(finding.samples)}\u000a          </article>`,\u000a        )\u000a        .join("");\u000a      const checks = Object.entries(section.checks || {})\u000a        .map(\u000a          ([label, value]) =>\u000a            `<div class="check"><span>${catalogReportHtmlEscape(catalogReportHumanLabel(label))}</span><strong>${catalogReportHtmlEscape(\u000a              catalogReportFormatMetric(value),\u000a            )}</strong></div>`,\u000a        )\u000a        .join("");\u000a      return `<section class="section">\u000a        <div class="section-grid">\u000a          <aside class="checks">\u000a            <p class="section-kicker">${catalogReportHtmlEscape(section.label || catalogReportHumanLabel(section.key))}</p>\u000a            <div class="check-list">${checks}</div>\u000a          </aside>\u000a          <div>\u000a            <div class="section-head">\u000a              <h2>${catalogReportHtmlEscape(section.goal)}</h2>\u000a              <span>${catalogReportHtmlEscape(catalogReportFormatMetric(section.findingCount ?? section.findings?.length ?? 0))} finding(s)</span>\u000a            </div>\u000a            <div class="findings">\u000a              ${findings || ''<p class="empty">No actionable findings in this cluster.</p>''}\u000a            </div>\u000a          </div>\u000a        </div>\u000a      </section>`;\u000a    })\u000a    .join("\\n");\u000a  return `<!doctype html>\u000a<html lang="en">\u000a<head>\u000a  <meta charset="utf-8">\u000a  <meta name="viewport" content="width=device-width, initial-scale=1">\u000a  <meta name="theme-color" content="#f5f2ea">\u000a  <title>${catalogReportHtmlEscape(report.title)}</title>\u000a  <style>\u000a    :root {\u000a      color-scheme: light;\u000a      --bg: #f5f2ea;\u000a      --panel: #ffffff;\u000a      --ink: #18181b;\u000a      --muted: #5f6368;\u000a      --line: #ded8cb;\u000a      --accent: #255c99;\u000a      --danger: #b42318;\u000a      --danger-bg: #fff1f0;\u000a      --warn: #b54708;\u000a      --warn-bg: #fff7ed;\u000a      --note: #175cd3;\u000a      --note-bg: #eff6ff;\u000a      --low: #067647;\u000a      --low-bg: #ecfdf3;\u000a      --radius: 8px;\u000a      --shadow: 0 1px 2px rgba(24, 24, 27, 0.06), 0 14px 36px rgba(24, 24, 27, 0.07);\u000a    }\u000a    * { box-sizing: border-box; }\u000a    body {\u000a      margin: 0;\u000a      background: var(--bg);\u000a      color: var(--ink);\u000a      font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;\u000a      font-size: 16px;\u000a      line-height: 1.55;\u000a    }\u000a    main {\u000a      width: min(1120px, calc(100% - 32px));\u000a      margin: 0 auto;\u000a      padding: 48px 0 72px;\u000a    }\u000a    header { margin-bottom: 28px; }\u000a    .eyebrow {\u000a      margin: 0 0 8px;\u000a      color: var(--muted);\u000a      font-size: 13px;\u000a      font-weight: 750;\u000a      letter-spacing: 0.08em;\u000a      text-transform: uppercase;\u000a    }\u000a    h1 {\u000a      margin: 0;\u000a      max-width: 860px;\u000a      font-size: clamp(2rem, 4vw, 3rem);\u000a      line-height: 1.05;\u000a      letter-spacing: 0;\u000a    }\u000a    .lede {\u000a      max-width: 780px;\u000a      margin: 16px 0 0;\u000a      color: var(--muted);\u000a      font-size: 18px;\u000a    }\u000a    .metrics {\u000a      display: grid;\u000a      grid-template-columns: repeat(4, minmax(0, 1fr));\u000a      gap: 12px;\u000a      margin: 32px 0;\u000a    }\u000a    .metric, .section, details {\u000a      background: var(--panel);\u000a      border: 1px solid var(--line);\u000a      border-radius: var(--radius);\u000a      box-shadow: var(--shadow);\u000a    }\u000a    .metric { padding: 18px; }\u000a    .metric strong {\u000a      display: block;\u000a      font-size: 32px;\u000a      line-height: 1;\u000a      font-variant-numeric: tabular-nums;\u000a    }\u000a    .metric span {\u000a      display: block;\u000a      margin-top: 8px;\u000a      color: var(--muted);\u000a      font-size: 13px;\u000a      font-weight: 650;\u000a    }\u000a    .section {\u000a      margin-top: 18px;\u000a      padding: 24px;\u000a    }\u000a    .section-grid {\u000a      display: grid;\u000a      grid-template-columns: 260px minmax(0, 1fr);\u000a      gap: 28px;\u000a    }\u000a    .section-kicker {\u000a      margin: 0 0 12px;\u000a      color: var(--accent);\u000a      font-size: 13px;\u000a      font-weight: 800;\u000a      letter-spacing: 0.08em;\u000a      text-transform: uppercase;\u000a    }\u000a    .check-list {\u000a      display: grid;\u000a      gap: 8px;\u000a    }\u000a    .check {\u000a      display: flex;\u000a      align-items: baseline;\u000a      justify-content: space-between;\u000a      gap: 12px;\u000a      padding: 10px 0;\u000a      border-bottom: 1px solid var(--line);\u000a    }\u000a    .check span {\u000a      color: var(--muted);\u000a      font-size: 13px;\u000a    }\u000a    .check strong {\u000a      font-size: 18px;\u000a      font-variant-numeric: tabular-nums;\u000a    }\u000a    .section-head {\u000a      display: flex;\u000a      align-items: start;\u000a      justify-content: space-between;\u000a      gap: 16px;\u000a      margin-bottom: 16px;\u000a    }\u000a    .section-head h2 {\u000a      max-width: 680px;\u000a      margin: 0;\u000a      font-size: 24px;\u000a      line-height: 1.2;\u000a      letter-spacing: 0;\u000a    }\u000a    .section-head > span {\u000a      flex: 0 0 auto;\u000a      color: var(--muted);\u000a      font-size: 13px;\u000a      font-weight: 700;\u000a      white-space: nowrap;\u000a    }\u000a    .findings {\u000a      display: grid;\u000a      gap: 12px;\u000a    }\u000a    .finding {\u000a      border: 1px solid var(--line);\u000a      border-left: 4px solid var(--note);\u000a      border-radius: var(--radius);\u000a      padding: 16px;\u000a      background: #fffdf8;\u000a    }\u000a    .finding.danger { border-left-color: var(--danger); }\u000a    .finding.warn { border-left-color: var(--warn); }\u000a    .finding.low { border-left-color: var(--low); }\u000a    .finding-head {\u000a      display: flex;\u000a      align-items: start;\u000a      justify-content: space-between;\u000a      gap: 16px;\u000a    }\u000a    .finding-id {\u000a      margin: 0 0 4px;\u000a      color: var(--muted);\u000a      font-family: ui-monospace, SFMono-Regular, Menlo, Consolas, monospace;\u000a      font-size: 12px;\u000a    }\u000a    h3 {\u000a      margin: 0;\u000a      font-size: 17px;\u000a      line-height: 1.3;\u000a      letter-spacing: 0;\u000a    }\u000a    .pill {\u000a      display: inline-flex;\u000a      align-items: center;\u000a      min-height: 26px;\u000a      padding: 4px 9px;\u000a      border-radius: 999px;\u000a      font-size: 12px;\u000a      font-weight: 800;\u000a      text-transform: uppercase;\u000a      white-space: nowrap;\u000a    }\u000a    .pill.danger { background: var(--danger-bg); color: var(--danger); }\u000a    .pill.warn { background: var(--warn-bg); color: var(--warn); }\u000a    .pill.note { background: var(--note-bg); color: var(--note); }\u000a    .pill.low { background: var(--low-bg); color: var(--low); }\u000a    .action {\u000a      margin: 10px 0 0;\u000a      color: var(--muted);\u000a    }\u000a    .sample-table {\u000a      margin-top: 14px;\u000a      overflow-x: auto;\u000a      border: 1px solid var(--line);\u000a      border-radius: var(--radius);\u000a      background: var(--panel);\u000a    }\u000a    table {\u000a      width: 100%;\u000a      min-width: 640px;\u000a      border-collapse: collapse;\u000a    }\u000a    th, td {\u000a      padding: 10px 12px;\u000a      border-bottom: 1px solid var(--line);\u000a      text-align: left;\u000a      vertical-align: top;\u000a    }\u000a    th {\u000a      color: var(--muted);\u000a      font-size: 12px;\u000a      font-weight: 800;\u000a      letter-spacing: 0.06em;\u000a      text-transform: uppercase;\u000a    }\u000a    td {\u000a      max-width: 360px;\u000a      color: #27272a;\u000a      font-size: 13px;\u000a      overflow-wrap: anywhere;\u000a    }\u000a    tr:last-child td { border-bottom: 0; }\u000a    .empty {\u000a      margin: 0;\u000a      color: var(--muted);\u000a    }\u000a    details {\u000a      margin-top: 24px;\u000a      padding: 18px;\u000a    }\u000a    summary {\u000a      cursor: pointer;\u000a      font-weight: 800;\u000a    }\u000a    pre {\u000a      margin: 16px 0 0;\u000a      max-height: 560px;\u000a      overflow: auto;\u000a      padding: 16px;\u000a      border-radius: var(--radius);\u000a      background: #111827;\u000a      color: #f9fafb;\u000a      font-size: 12px;\u000a      line-height: 1.45;\u000a    }\u000a    @media (max-width: 860px) {\u000a      main { width: min(100% - 24px, 1120px); padding-top: 32px; }\u000a      .metrics { grid-template-columns: repeat(2, minmax(0, 1fr)); }\u000a      .section-grid { grid-template-columns: 1fr; gap: 18px; }\u000a      .section { padding: 18px; }\u000a      .section-head { display: block; }\u000a      .section-head > span { display: block; margin-top: 8px; }\u000a    }\u000a    @media (max-width: 520px) {\u000a      .metrics { grid-template-columns: 1fr; }\u000a      .lede { font-size: 16px; }\u000a      .finding-head { display: block; }\u000a      .pill { margin-top: 10px; }\u000a    }\u000a  </style>\u000a</head>\u000a<body>\u000a  <main>\u000a    <header>\u000a      <p class="eyebrow">Generated ${catalogReportHtmlEscape(report.generatedAt)}</p>\u000a      <h1>${catalogReportHtmlEscape(report.title)}</h1>\u000a      <p class="lede">${catalogReportHtmlEscape(report.lede)}</p>\u000a    </header>\u000a    <section class="metrics" aria-label="Audit summary">\u000a      ${report.metrics\u000a        .map(\u000a          ([label, value]) =>\u000a            `<div class="metric"><strong>${catalogReportHtmlEscape(catalogReportFormatMetric(value))}</strong><span>${catalogReportHtmlEscape(\u000a              label,\u000a            )}</span></div>`,\u000a        )\u000a        .join("")}\u000a    </section>\u000a    ${sections}\u000a    <details>\u000a      <summary>Compressed JSON appendix</summary>\u000a      <pre>${catalogReportHtmlEscape(JSON.stringify(report.appendix, null, 2))}</pre>\u000a    </details>\u000a  </main>\u000a</body>\u000a</html>`;\u000a}\u000a\u000aexport async function publishCatalogReportPage(report: CatalogReport, ctx: any): Promise<any> {\u000a  const response = await ctx.swarm.page_create({\u000a    title: report.title,\u000a    slug: report.slug,\u000a    description: report.description,\u000a    contentType: "text/html",\u000a    authMode: "authed",\u000a    body: renderCatalogReportPage(report),\u000a  });\u000a  const payload = response?.data ?? response;\u000a  if (payload?.success === false) return { error: payload.error || "page_create failed" };\u000a  return {\u000a    id: payload?.id ?? payload?.page?.id ?? null,\u000a    appUrl: payload?.appUrl ?? payload?.app_url ?? null,\u000a    apiUrl: payload?.apiUrl ?? payload?.api_url ?? null,\u000a    version: payload?.version ?? payload?.page?.version ?? null,\u000a  };\u000a}\u000a\u000a\u000aimport { z } from "zod";\u000aexport const argsSchema = z.object({\u000a  days: z\u000a    .number()\u000a    .int()\u000a    .positive()\u000a    .optional()\u000a    .describe("Look back this many days for failed tasks (default 7)"),\u000a  groupBy: z\u000a    .enum(["reason", "agent", "schedule"])\u000a    .optional()\u000a    .describe("Cluster failures by failure reason, agent, or schedule (default reason)"),\u000a  limit: z\u000a    .number()\u000a    .int()\u000a    .positive()\u000a    .optional()\u000a    .describe("Max failed tasks to scan (default 500)"),\u000a  publishPage: z.boolean().optional().describe("Publish an authed HTML page (default true)"),\u000a});\u000a\u000aconst REASON_PATTERNS: any[] = [\u000a  { key: "sigterm/killed", re: /sigterm|sigkill|killed|143|137/i },\u000a  { key: "timeout", re: /time?d?\\s*out|timeout|deadline/i },\u000a  { key: "context-window", re: /context (window|limit|saturat)|peakcontext|compact/i },\u000a  { key: "not-found", re: /not found|404|missing|no such/i },\u000a  { key: "auth/credentials", re: /unauthorized|401|403|credential|token|forbidden/i },\u000a  { key: "ci/checks-failed", re: /ci|check.?s? fail|lint|tsc|test.?s? fail/i },\u000a  { key: "network", re: /network|econn|fetch failed|socket|dns|502|503|504/i },\u000a  { key: "cancelled", re: /cancel|aborted/i },\u000a];\u000a\u000afunction reasonCluster(reason: string): string {\u000a  const r = (reason || "").trim();\u000a  if (!r) return "(no reason given)";\u000a  for (const p of REASON_PATTERNS) {\u000a    if (p.re.test(r)) return p.key;\u000a  }\u000a  return r.toLowerCase().slice(0, 48);\u000a}\u000a\u000a/** Cluster recently failed swarm tasks by reason, agent, or schedule. */\u000aexport default async function taskFailureAudit(args: any, ctx: any) {\u000a  const parsed = argsSchema.safeParse(args);\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a  const days = parsed.data.days || 7;\u000a  const groupBy = parsed.data.groupBy || "reason";\u000a  const limit = parsed.data.limit || 500;\u000a  const publishPage = parsed.data.publishPage !== false;\u000a\u000a  const since = new Date(Date.now() - days * 86400000).toISOString();\u000a  const res: any = await ctx.swarm.task_list({\u000a    status: "failed",\u000a    createdAfter: since,\u000a    limit,\u000a  });\u000a  if (res && res.success === false) {\u000a    return { error: "task_list failed with status " + res.status };\u000a  }\u000a  const payload: any = res && res.data ? res.data : res;\u000a  const tasks: any = payload && Array.isArray(payload.tasks) ? payload.tasks : [];\u000a\u000a  const groups: any = {};\u000a  for (const t of tasks) {\u000a    let key: string;\u000a    if (groupBy === "agent") key = t.agentId || "(unassigned)";\u000a    else if (groupBy === "schedule") key = t.scheduleId || "(not scheduled)";\u000a    else key = reasonCluster(t.failureReason || "");\u000a    if (!groups[key]) groups[key] = { key, count: 0, taskIds: [], sampleReason: "" };\u000a    groups[key].count++;\u000a    if (groups[key].taskIds.length < 5) groups[key].taskIds.push(t.id);\u000a    if (!groups[key].sampleReason && t.failureReason) {\u000a      groups[key].sampleReason = String(t.failureReason).slice(0, 200);\u000a    }\u000a  }\u000a\u000a  const rows: any[] = Object.keys(groups)\u000a    .map((k: string) => groups[k])\u000a    .sort((a: any, b: any) => b.count - a.count);\u000a\u000a  const result: any = {\u000a    days,\u000a    groupBy,\u000a    totalFailed: tasks.length,\u000a    clusterCount: rows.length,\u000a    groups: rows,\u000a  };\u000a\u000a  if (publishPage) {\u000a    result.page = await publishCatalogReportPage(\u000a      {\u000a        title: "Task Failure Audit",\u000a        slug: "task-failure-audit",\u000a        description: "Clustered audit of recently failed swarm tasks.",\u000a        generatedAt: new Date().toISOString(),\u000a        lede: `Clustered ${tasks.length} failed task(s) over ${days} day(s) by ${groupBy}.`,\u000a        metrics: [\u000a          ["Failed tasks", tasks.length],\u000a          ["Clusters", rows.length],\u000a          ["Days", days],\u000a          ["Limit", limit],\u000a        ],\u000a        sections: [\u000a          {\u000a            key: "failure-clusters",\u000a            goal: "Surface repeated failure modes before they become operational drift.",\u000a            findingCount: rows.length,\u000a            checks: { totalFailed: tasks.length, clusterCount: rows.length, groupBy },\u000a            findings: rows.map((group: any) => ({\u000a              id: `failure.${group.key}`,\u000a              severity: group.count >= 5 ? "high" : group.count >= 2 ? "medium" : "low",\u000a              summary: `${group.count} failed task(s) in ${group.key}.`,\u000a              action: "Inspect the sample task IDs and decide whether this needs a fix, retry, or HEARTBEAT watch item.",\u000a              samples: [\u000a                {\u000a                  key: group.key,\u000a                  count: group.count,\u000a                  taskIds: group.taskIds,\u000a                  sampleReason: group.sampleReason,\u000a                },\u000a              ],\u000a            })),\u000a          },\u000a        ],\u000a        appendix: result,\u000a      },\u000a      ctx,\u000a    );\u000a  }\u000a\u000a  return result;\u000a}\u000a'),'Scan recently failed swarm tasks and cluster them by failure reason, agent or schedule to surface recurring problems.','Find patterns in swarm task failures — which agent, schedule or error keeps breaking — for a reliability review.','{"argsType":"any","resultType":"unknown","description":"Cluster recently failed swarm tasks by reason, agent, or schedule."}','519728190085f68c0e43cdacebdf998e581dacb782a604a24be0d3c39ccf4ad0',NULL,'2026-06-11T22:38:23.047Z','Seeded from the built-in scripts catalog (src/be/seed-scripts)',NULL,NULL);
INSERT INTO script_versions VALUES('137f4f38-01d4-413a-81d4-0c5f25029d96','fcf1bed5-7b3c-4de3-8f26-e46b50bee551',1,unistr('import { z } from "zod";\u000a\u000aexport const argsSchema = z.object({\u000a  text: z.string().describe("Candidate memory text to check for near-duplicates"),\u000a  threshold: z\u000a    .number()\u000a    .min(0)\u000a    .max(1)\u000a    .optional()\u000a    .describe("Minimum cosine similarity to count as a duplicate (default 0.85)"),\u000a  limit: z\u000a    .number()\u000a    .int()\u000a    .positive()\u000a    .optional()\u000a    .describe("Max existing memories to compare against (default 10)"),\u000a});\u000a\u000a/** Semantic-search existing memories and flag near-duplicates before you save a new one. */\u000aexport default async function memoryDedupCheck(args: any, ctx: any) {\u000a  const parsed = argsSchema.safeParse(args);\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a  const text = parsed.data.text.trim();\u000a  if (!text) return { error: "text must not be empty" };\u000a  const threshold = parsed.data.threshold == null ? 0.85 : parsed.data.threshold;\u000a  const limit = parsed.data.limit || 10;\u000a\u000a  const res: any = await ctx.swarm.memory_search({ query: text, scope: "all", limit });\u000a  if (res && res.success === false) {\u000a    return { error: "memory_search failed with status " + res.status };\u000a  }\u000a  const payload: any = res && res.data ? res.data : res;\u000a  const results: any = payload && Array.isArray(payload.results) ? payload.results : [];\u000a\u000a  const duplicates: any[] = [];\u000a  for (const r of results) {\u000a    const score = typeof r.similarity === "number" ? r.similarity : 0;\u000a    if (score >= threshold) {\u000a      duplicates.push({\u000a        id: r.id,\u000a        name: r.name,\u000a        similarity: Math.round(score * 1000) / 1000,\u000a        scope: r.scope,\u000a        source: r.source,\u000a        preview: typeof r.content === "string" ? r.content.slice(0, 200) : "",\u000a      });\u000a    }\u000a  }\u000a  duplicates.sort((a: any, b: any) => b.similarity - a.similarity);\u000a\u000a  return {\u000a    isDuplicate: duplicates.length > 0,\u000a    duplicateCount: duplicates.length,\u000a    threshold,\u000a    comparedAgainst: results.length,\u000a    topSimilarity: results.length > 0 && typeof results[0].similarity === "number"\u000a      ? Math.round(results[0].similarity * 1000) / 1000\u000a      : 0,\u000a    duplicates,\u000a  };\u000a}\u000a'),'Semantic-search existing swarm memories for near-duplicates of a candidate text and report matches above a similarity threshold.','Avoid writing a redundant memory — check whether something equivalent is already stored before saving.','{"argsType":"any","resultType":"unknown","description":"Semantic-search existing memories and flag near-duplicates before you save a new one."}','e86cdf31958ae2d11319a60f7530fef52e010edf316bc62afa868ea68b58ce5f',NULL,'2026-06-11T22:38:23.174Z','Seeded from the built-in scripts catalog (src/be/seed-scripts)',NULL,NULL);
INSERT INTO script_versions VALUES('68cddbed-c4e5-4253-a330-d6c3300298ac','a66c75b2-ec9d-41aa-b508-0586252cdbbd',1,unistr('import { z } from "zod";\u000a\u000aexport const argsSchema = z.object({\u000a  key: z.string().describe("Linear issue identifier, e.g. ''DES-123''"),\u000a  token: z\u000a    .string()\u000a    .optional()\u000a    .describe("Linear API key override; falls back to the LINEAR_API_KEY swarm config"),\u000a});\u000a\u000aasync function resolveSecret(ctx: any, key: string, override: unknown): Promise<string | null> {\u000a  if (typeof override === "string" && override.length > 0) return override;\u000a  try {\u000a    const base = ctx.stdlib.Redacted.value(ctx.swarm.config.mcpBaseUrl).replace(/\\/+$/, "");\u000a    const apiKey = ctx.stdlib.Redacted.value(ctx.swarm.config.apiKey);\u000a    const res: any = await ctx.stdlib.fetchJson(\u000a      base + "/api/config/resolved?includeSecrets=true",\u000a      { headers: { Authorization: "Bearer " + apiKey } },\u000a    );\u000a    const configs: any = res && Array.isArray(res.configs) ? res.configs : [];\u000a    for (const c of configs) {\u000a      if (c && c.key === key && typeof c.value === "string" && c.value.length > 0) {\u000a        return c.value;\u000a      }\u000a    }\u000a  } catch {\u000a    // Best-effort.\u000a  }\u000a  return null;\u000a}\u000a\u000a/** Fetch a Linear issue (title, status, assignee, comments) by its DES-123 identifier. */\u000aexport default async function linearIssue(args: any, ctx: any) {\u000a  const parsed = argsSchema.safeParse(args);\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a  const key = parsed.data.key.trim().toUpperCase();\u000a  const m = key.match(/^([A-Z][A-Z0-9]*)-(\\d+)$/);\u000a  if (!m) return { error: "key must look like ''DES-123''" };\u000a  const teamKey = m[1] as string;\u000a  const number = Number.parseInt(m[2] as string, 10);\u000a\u000a  const token = await resolveSecret(ctx, "LINEAR_API_KEY", parsed.data.token);\u000a  if (!token) {\u000a    return {\u000a      error: "no Linear API key available",\u000a      hint: "set the LINEAR_API_KEY swarm config or pass a ''token'' arg",\u000a    };\u000a  }\u000a\u000a  const query = `query {\u000a    issues(filter: { team: { key: { eq: "${teamKey}" } }, number: { eq: ${number} } }, first: 1) {\u000a      nodes {\u000a        identifier\u000a        title\u000a        url\u000a        priorityLabel\u000a        state { name type }\u000a        assignee { name displayName }\u000a        comments(first: 50) {\u000a          nodes { body createdAt user { name displayName } }\u000a        }\u000a      }\u000a    }\u000a  }`;\u000a\u000a  const res: any = await ctx.stdlib.fetchJson("https://api.linear.app/graphql", {\u000a    method: "POST",\u000a    headers: { "Content-Type": "application/json", Authorization: token },\u000a    body: JSON.stringify({ query }),\u000a  });\u000a  if (res && res.errors && res.errors.length > 0) {\u000a    return { error: "Linear API error: " + (res.errors[0].message || "unknown") };\u000a  }\u000a  const nodes: any =\u000a    res && res.data && res.data.issues && Array.isArray(res.data.issues.nodes)\u000a      ? res.data.issues.nodes\u000a      : [];\u000a  if (nodes.length === 0) return { error: "issue " + key + " not found" };\u000a\u000a  const issue: any = nodes[0];\u000a  const assignee = issue.assignee\u000a    ? issue.assignee.displayName || issue.assignee.name || null\u000a    : null;\u000a  const comments: any[] = (\u000a    issue.comments && Array.isArray(issue.comments.nodes) ? issue.comments.nodes : []\u000a  ).map((c: any) => ({\u000a    body: c.body,\u000a    author: c.user ? c.user.displayName || c.user.name : "unknown",\u000a    createdAt: c.createdAt,\u000a  }));\u000a\u000a  return {\u000a    key: issue.identifier,\u000a    title: issue.title,\u000a    status: issue.state ? issue.state.name : "unknown",\u000a    statusType: issue.state ? issue.state.type : null,\u000a    priority: issue.priorityLabel || null,\u000a    assignee,\u000a    url: issue.url,\u000a    commentCount: comments.length,\u000a    comments,\u000a  };\u000a}\u000a'),'Fetch a Linear issue by its identifier (e.g. DES-123): title, status, priority, assignee and comments.','Pull Linear ticket context into a task without leaving the swarm or opening a browser.','{"argsType":"any","resultType":"unknown","description":"Fetch a Linear issue (title, status, assignee, comments) by its DES-123 identifier."}','11bb732c6165e6f46c502b5f3c89ef17ef2d8f3226f6b1325483af85bdf1eebb',NULL,'2026-06-11T22:38:23.300Z','Seeded from the built-in scripts catalog (src/be/seed-scripts)',NULL,NULL);
INSERT INTO script_versions VALUES('b516140b-6c7a-4ce0-998e-38057f6a8eaf','ff9b7185-e466-4885-82df-49827905d6de',1,unistr('import { z } from "zod";\u000a\u000aexport const argsSchema = z.object({\u000a  channelId: z.string().describe("Slack channel ID, e.g. ''C0AR967K0KZ''"),\u000a  threadTs: z.string().describe("Thread timestamp (ts) of the root message"),\u000a  token: z\u000a    .string()\u000a    .optional()\u000a    .describe("Slack bot token override; falls back to the SLACK_BOT_TOKEN swarm config"),\u000a});\u000a\u000aasync function resolveSecret(ctx: any, key: string, override: unknown): Promise<string | null> {\u000a  if (typeof override === "string" && override.length > 0) return override;\u000a  try {\u000a    const base = ctx.stdlib.Redacted.value(ctx.swarm.config.mcpBaseUrl).replace(/\\/+$/, "");\u000a    const apiKey = ctx.stdlib.Redacted.value(ctx.swarm.config.apiKey);\u000a    const res: any = await ctx.stdlib.fetchJson(\u000a      base + "/api/config/resolved?includeSecrets=true",\u000a      { headers: { Authorization: "Bearer " + apiKey } },\u000a    );\u000a    const configs: any = res && Array.isArray(res.configs) ? res.configs : [];\u000a    for (const c of configs) {\u000a      if (c && c.key === key && typeof c.value === "string" && c.value.length > 0) {\u000a        return c.value;\u000a      }\u000a    }\u000a  } catch {\u000a    // Best-effort.\u000a  }\u000a  return null;\u000a}\u000a\u000afunction tsToIso(ts: string): string {\u000a  const seconds = Number.parseFloat(ts);\u000a  return Number.isNaN(seconds) ? ts : new Date(seconds * 1000).toISOString();\u000a}\u000a\u000a/** Flatten a Slack thread into a readable, chronological transcript. */\u000aexport default async function slackThreadFlatten(args: any, ctx: any) {\u000a  const parsed = argsSchema.safeParse(args);\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a  const { channelId, threadTs } = parsed.data;\u000a\u000a  const token = await resolveSecret(ctx, "SLACK_BOT_TOKEN", parsed.data.token);\u000a  if (!token) {\u000a    return {\u000a      error: "no Slack bot token available",\u000a      hint: "set the SLACK_BOT_TOKEN swarm config or pass a ''token'' arg",\u000a    };\u000a  }\u000a\u000a  const url =\u000a    "https://slack.com/api/conversations.replies?channel=" +\u000a    encodeURIComponent(channelId) +\u000a    "&ts=" +\u000a    encodeURIComponent(threadTs) +\u000a    "&limit=1000";\u000a  const res: any = await ctx.stdlib.fetchJson(url, {\u000a    headers: { Authorization: "Bearer " + token },\u000a  });\u000a  if (!res || res.ok !== true) {\u000a    return { error: "Slack API error: " + (res && res.error ? res.error : "unknown") };\u000a  }\u000a\u000a  const raw: any = Array.isArray(res.messages) ? res.messages : [];\u000a  const messages: any[] = raw.map((m: any) => ({\u000a    author: m.username || m.user || m.bot_id || "unknown",\u000a    text: typeof m.text === "string" ? m.text : "",\u000a    ts: m.ts,\u000a    at: m.ts ? tsToIso(m.ts) : null,\u000a  }));\u000a  messages.sort((a: any, b: any) => Number.parseFloat(a.ts || "0") - Number.parseFloat(b.ts || "0"));\u000a\u000a  const transcript = messages\u000a    .map((m: any) => "[" + (m.at || m.ts) + "] " + m.author + ": " + m.text)\u000a    .join("\\n");\u000a\u000a  return {\u000a    channelId,\u000a    threadTs,\u000a    messageCount: messages.length,\u000a    hasMore: Boolean(res.has_more),\u000a    transcript,\u000a    messages,\u000a  };\u000a}\u000a'),'Fetch a Slack thread by channel + thread timestamp and flatten it into a readable chronological transcript.','Turn a Slack thread into plain text for summarizing or as task context.','{"argsType":"any","resultType":"unknown","description":"Flatten a Slack thread into a readable, chronological transcript."}','f3cefa176e7d39c0c7fb5e26d059089d5bdf1b9fa12b249188d86fb52482b7a2',NULL,'2026-06-11T22:38:23.424Z','Seeded from the built-in scripts catalog (src/be/seed-scripts)',NULL,NULL);
INSERT INTO script_versions VALUES('c95a5c3d-7f57-4fea-9c65-bfd2429c1af7','972543be-a0f9-434a-b5d0-7945b0dcf021',1,unistr('import { z } from "zod";\u000a\u000aexport const argsSchema = z.object({\u000a  queries: z\u000a    .array(z.string())\u000a    .min(1)\u000a    .describe("One or more search queries to fan out against the memory store"),\u000a  scope: z\u000a    .enum(["all", "agent", "swarm"])\u000a    .optional()\u000a    .describe("Memory scope filter (default all)"),\u000a  limit: z\u000a    .number()\u000a    .int()\u000a    .positive()\u000a    .optional()\u000a    .describe("Max results per query (default 10)"),\u000a  dedupThreshold: z\u000a    .number()\u000a    .optional()\u000a    .describe("Similarity threshold for dedup — memories above this are merged (default 0.92)"),\u000a});\u000a\u000a/** Multi-query fan-out memory recall with dedup and composite reranking. */\u000aexport default async function smartRecall(args: any, ctx: any) {\u000a  const parsed = argsSchema.safeParse(args);\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a  const { queries, scope = "all", limit = 10, dedupThreshold = 0.92 } = parsed.data;\u000a\u000a  const allResults: any[] = [];\u000a  for (const q of queries) {\u000a    const res: any = await ctx.swarm.memory_search({ query: q, limit, scope });\u000a    const payload = res?.data ?? res;\u000a    const results = payload?.results ?? [];\u000a    for (const r of results) {\u000a      allResults.push({ ...r, querySource: q });\u000a    }\u000a  }\u000a\u000a  // Dedup by ID, keeping best similarity per memory\u000a  const seen = new Map<string, any>();\u000a  const hitCounts = new Map<string, number>();\u000a  for (const r of allResults) {\u000a    hitCounts.set(r.id, (hitCounts.get(r.id) ?? 0) + 1);\u000a    const existing = seen.get(r.id);\u000a    if (!existing || r.similarity > existing.similarity) {\u000a      seen.set(r.id, r);\u000a    }\u000a  }\u000a\u000a  // Composite rerank: bestSimilarity + 0.05 * hitCount\u000a  const deduped = Array.from(seen.values()).map((r) => ({\u000a    ...r,\u000a    hits: hitCounts.get(r.id) ?? 1,\u000a    compositeScore: r.similarity + 0.05 * (hitCounts.get(r.id) ?? 1),\u000a  }));\u000a  deduped.sort((a: any, b: any) => b.compositeScore - a.compositeScore);\u000a\u000a  return {\u000a    queriesRun: queries.length,\u000a    totalCandidates: allResults.length,\u000a    uniqueMemories: deduped.length,\u000a    memories: deduped.slice(0, limit * 2),\u000a  };\u000a}\u000a'),'Multi-query fan-out memory search with dedup and composite reranking (bestSimilarity + 0.05 * hitCount). Returns unique memories across all queries.','Recall relevant memories using multiple search angles — better coverage than a single query. Use for task onboarding, context gathering, or before writing new memories.','{"argsType":"any","resultType":"unknown","description":"Multi-query fan-out memory recall with dedup and composite reranking."}','dcd3679c8573998b71c3da0a1fe3d033f638740566352250ae8af81ce47cf960',NULL,'2026-06-11T22:38:23.549Z','Seeded from the built-in scripts catalog (src/be/seed-scripts)',NULL,NULL);
INSERT INTO script_versions VALUES('2a73701c-ddbc-4cf3-b7d9-a65610ce6253','3898797c-96df-4f19-90a7-a5f2ac203eed',1,unistr('import { z } from "zod";\u000a\u000aexport const argsSchema = z.object({\u000a  taskId: z.string().describe("Task ID to fetch details for"),\u000a  queries: z\u000a    .array(z.string())\u000a    .min(1)\u000a    .describe("Search queries from the task description — 2-4 recommended"),\u000a  scope: z\u000a    .enum(["all", "agent", "swarm"])\u000a    .optional()\u000a    .describe("Memory scope filter (default all)"),\u000a  memoryLimit: z\u000a    .number()\u000a    .int()\u000a    .positive()\u000a    .optional()\u000a    .describe("Max memories per query before dedup (default 8)"),\u000a});\u000a\u000afunction slimTask(task: any) {\u000a  if (!task || typeof task !== "object") return null;\u000a  return {\u000a    id: task.id,\u000a    status: task.status,\u000a    description: task.task,\u000a    dependsOn: task.dependsOn,\u000a    slackChannelId: task.slackChannelId,\u000a    slackThreadTs: task.slackThreadTs,\u000a    createdAt: task.createdAt,\u000a    finishedAt: task.finishedAt,\u000a    agentId: task.agentId,\u000a    output: task.output,\u000a    failureReason: task.failureReason,\u000a  };\u000a}\u000a\u000a/** Fetch slim task details plus deduped multi-query memories for task onboarding. */\u000aexport default async function taskContextGathering(args: any, ctx: any) {\u000a  const parsed = argsSchema.safeParse(args);\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a  const { taskId, queries, scope = "all", memoryLimit = 8 } = parsed.data;\u000a\u000a  const taskRes: any = await ctx.swarm.task_get({ taskId });\u000a  const taskPayload = taskRes?.data ?? taskRes;\u000a  if (taskPayload?.success === false) {\u000a    return { error: taskPayload.message ?? "task_get failed", taskId };\u000a  }\u000a\u000a  const allResults: any[] = [];\u000a  for (const query of queries) {\u000a    const res: any = await ctx.swarm.memory_search({ query, scope, limit: memoryLimit });\u000a    const payload = res?.data ?? res;\u000a    const results = payload?.results ?? [];\u000a    for (const memory of results) {\u000a      allResults.push({ ...memory, querySource: query });\u000a    }\u000a  }\u000a\u000a  const byId = new Map<string, any>();\u000a  const hitCounts = new Map<string, number>();\u000a  for (const memory of allResults) {\u000a    const id = typeof memory.id === "string" ? memory.id : JSON.stringify(memory);\u000a    hitCounts.set(id, (hitCounts.get(id) ?? 0) + 1);\u000a    const existing = byId.get(id);\u000a    const similarity = typeof memory.similarity === "number" ? memory.similarity : 0;\u000a    const existingSimilarity =\u000a      existing && typeof existing.similarity === "number" ? existing.similarity : -Infinity;\u000a    if (!existing || similarity > existingSimilarity) byId.set(id, memory);\u000a  }\u000a\u000a  const memories = Array.from(byId.entries()).map(([id, memory]) => {\u000a    const hits = hitCounts.get(id) ?? 1;\u000a    const similarity = typeof memory.similarity === "number" ? memory.similarity : 0;\u000a    return {\u000a      ...memory,\u000a      hits,\u000a      compositeScore: similarity + 0.05 * hits,\u000a    };\u000a  });\u000a  memories.sort((a: any, b: any) => b.compositeScore - a.compositeScore);\u000a\u000a  return {\u000a    task: slimTask(taskPayload?.task),\u000a    requestedBy: taskPayload?.requestedBy,\u000a    attachments: taskPayload?.attachments ?? [],\u000a    queriesRun: queries.length,\u000a    totalCandidates: allResults.length,\u000a    uniqueMemories: memories.length,\u000a    memories: memories.slice(0, memoryLimit * 2),\u000a  };\u000a}\u000a'),'Get task details and recall relevant memories in one call — returns a slimmed task projection plus deduped and reranked memories from multi-query fan-out.','Task onboarding: one call instead of task_get plus multiple memory_search calls. Pass the task description split into 2-4 natural-language queries.','{"argsType":"any","resultType":"unknown","description":"Fetch slim task details plus deduped multi-query memories for task onboarding."}','a613b00f65e74479f011aceb6674fa1bcb5892e267fd3d70a72a6ca11c6c4bcb',NULL,'2026-06-11T22:38:23.680Z','Seeded from the built-in scripts catalog (src/be/seed-scripts)',NULL,NULL);
INSERT INTO script_versions VALUES('72b1f0b3-c220-47ca-9bd9-7ba3aae68c51','b2d83689-526a-423e-a45f-f4fb48fd2e2a',1,unistr('export type CatalogReportFinding = {\u000a  id: string;\u000a  severity?: string;\u000a  summary: string;\u000a  action?: string;\u000a  samples?: unknown[];\u000a};\u000a\u000aexport type CatalogReportSection = {\u000a  key: string;\u000a  label?: string;\u000a  goal: string;\u000a  findingCount?: number;\u000a  checks?: Record<string, unknown>;\u000a  findings?: CatalogReportFinding[];\u000a};\u000a\u000aexport type CatalogReport = {\u000a  title: string;\u000a  slug: string;\u000a  description: string;\u000a  generatedAt: string;\u000a  lede: string;\u000a  metrics: Array<[string, unknown]>;\u000a  sections: CatalogReportSection[];\u000a  appendix: unknown;\u000a};\u000a\u000afunction catalogReportAsText(value: unknown): string {\u000a  return typeof value === "string" ? value : value == null ? "" : JSON.stringify(value);\u000a}\u000a\u000afunction catalogReportHtmlEscape(value: unknown): string {\u000a  return catalogReportAsText(value)\u000a    .replace(/&/g, "&amp;")\u000a    .replace(/</g, "&lt;")\u000a    .replace(/>/g, "&gt;")\u000a    .replace(/"/g, "&quot;");\u000a}\u000a\u000afunction catalogReportHumanLabel(value: string): string {\u000a  return value\u000a    .replace(/([a-z0-9])([A-Z])/g, "$1 $2")\u000a    .replace(/[-_.]+/g, " ")\u000a    .replace(/\\b\\w/g, (char) => char.toUpperCase());\u000a}\u000a\u000afunction catalogReportFormatMetric(value: unknown): string {\u000a  if (typeof value === "number") return new Intl.NumberFormat("en-US").format(value);\u000a  return catalogReportAsText(value);\u000a}\u000a\u000afunction catalogReportSeverityTone(value?: string): string {\u000a  if (value === "critical") return "danger";\u000a  if (value === "high") return "warn";\u000a  if (value === "medium") return "note";\u000a  return "low";\u000a}\u000a\u000afunction catalogReportRenderSampleValue(value: unknown): string {\u000a  if (Array.isArray(value)) {\u000a    return value\u000a      .map((item) => (typeof item === "object" && item !== null ? JSON.stringify(item) : catalogReportAsText(item)))\u000a      .join(", ");\u000a  }\u000a  if (value && typeof value === "object") return JSON.stringify(value);\u000a  return catalogReportAsText(value);\u000a}\u000a\u000afunction catalogReportRenderSamples(samples?: unknown[]): string {\u000a  if (!Array.isArray(samples) || samples.length === 0) return "";\u000a  const normalized = samples.map((sampleRow) =>\u000a    sampleRow && typeof sampleRow === "object" && !Array.isArray(sampleRow)\u000a      ? (sampleRow as Record<string, unknown>)\u000a      : { value: sampleRow },\u000a  );\u000a  const columns = Array.from(\u000a    new Set(normalized.flatMap((sampleRow) => Object.keys(sampleRow).slice(0, 6))),\u000a  ).slice(0, 6);\u000a  if (columns.length === 0) return "";\u000a  const rows = normalized\u000a    .map(\u000a      (sampleRow) =>\u000a        `<tr>${columns\u000a          .map((column) => `<td>${catalogReportHtmlEscape(catalogReportRenderSampleValue(sampleRow[column]))}</td>`)\u000a          .join("")}</tr>`,\u000a    )\u000a    .join("");\u000a  return `<div class="sample-table" aria-label="Sample rows">\u000a    <table>\u000a      <thead><tr>${columns.map((column) => `<th>${catalogReportHtmlEscape(catalogReportHumanLabel(column))}</th>`).join("")}</tr></thead>\u000a      <tbody>${rows}</tbody>\u000a    </table>\u000a  </div>`;\u000a}\u000a\u000aexport function renderCatalogReportPage(report: CatalogReport): string {\u000a  const sections = report.sections\u000a    .map((section) => {\u000a      const findings = (section.findings || [])\u000a        .map(\u000a          (finding) => `<article class="finding ${catalogReportHtmlEscape(catalogReportSeverityTone(finding.severity))}">\u000a            <div class="finding-head">\u000a              <div>\u000a                <p class="finding-id">${catalogReportHtmlEscape(finding.id)}</p>\u000a                <h3>${catalogReportHtmlEscape(finding.summary)}</h3>\u000a              </div>\u000a              <span class="pill ${catalogReportHtmlEscape(catalogReportSeverityTone(finding.severity))}">${catalogReportHtmlEscape(\u000a                finding.severity || "low",\u000a              )}</span>\u000a            </div>\u000a            ${finding.action ? `<p class="action">${catalogReportHtmlEscape(finding.action)}</p>` : ""}\u000a            ${catalogReportRenderSamples(finding.samples)}\u000a          </article>`,\u000a        )\u000a        .join("");\u000a      const checks = Object.entries(section.checks || {})\u000a        .map(\u000a          ([label, value]) =>\u000a            `<div class="check"><span>${catalogReportHtmlEscape(catalogReportHumanLabel(label))}</span><strong>${catalogReportHtmlEscape(\u000a              catalogReportFormatMetric(value),\u000a            )}</strong></div>`,\u000a        )\u000a        .join("");\u000a      return `<section class="section">\u000a        <div class="section-grid">\u000a          <aside class="checks">\u000a            <p class="section-kicker">${catalogReportHtmlEscape(section.label || catalogReportHumanLabel(section.key))}</p>\u000a            <div class="check-list">${checks}</div>\u000a          </aside>\u000a          <div>\u000a            <div class="section-head">\u000a              <h2>${catalogReportHtmlEscape(section.goal)}</h2>\u000a              <span>${catalogReportHtmlEscape(catalogReportFormatMetric(section.findingCount ?? section.findings?.length ?? 0))} finding(s)</span>\u000a            </div>\u000a            <div class="findings">\u000a              ${findings || ''<p class="empty">No actionable findings in this cluster.</p>''}\u000a            </div>\u000a          </div>\u000a        </div>\u000a      </section>`;\u000a    })\u000a    .join("\\n");\u000a  return `<!doctype html>\u000a<html lang="en">\u000a<head>\u000a  <meta charset="utf-8">\u000a  <meta name="viewport" content="width=device-width, initial-scale=1">\u000a  <meta name="theme-color" content="#f5f2ea">\u000a  <title>${catalogReportHtmlEscape(report.title)}</title>\u000a  <style>\u000a    :root {\u000a      color-scheme: light;\u000a      --bg: #f5f2ea;\u000a      --panel: #ffffff;\u000a      --ink: #18181b;\u000a      --muted: #5f6368;\u000a      --line: #ded8cb;\u000a      --accent: #255c99;\u000a      --danger: #b42318;\u000a      --danger-bg: #fff1f0;\u000a      --warn: #b54708;\u000a      --warn-bg: #fff7ed;\u000a      --note: #175cd3;\u000a      --note-bg: #eff6ff;\u000a      --low: #067647;\u000a      --low-bg: #ecfdf3;\u000a      --radius: 8px;\u000a      --shadow: 0 1px 2px rgba(24, 24, 27, 0.06), 0 14px 36px rgba(24, 24, 27, 0.07);\u000a    }\u000a    * { box-sizing: border-box; }\u000a    body {\u000a      margin: 0;\u000a      background: var(--bg);\u000a      color: var(--ink);\u000a      font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;\u000a      font-size: 16px;\u000a      line-height: 1.55;\u000a    }\u000a    main {\u000a      width: min(1120px, calc(100% - 32px));\u000a      margin: 0 auto;\u000a      padding: 48px 0 72px;\u000a    }\u000a    header { margin-bottom: 28px; }\u000a    .eyebrow {\u000a      margin: 0 0 8px;\u000a      color: var(--muted);\u000a      font-size: 13px;\u000a      font-weight: 750;\u000a      letter-spacing: 0.08em;\u000a      text-transform: uppercase;\u000a    }\u000a    h1 {\u000a      margin: 0;\u000a      max-width: 860px;\u000a      font-size: clamp(2rem, 4vw, 3rem);\u000a      line-height: 1.05;\u000a      letter-spacing: 0;\u000a    }\u000a    .lede {\u000a      max-width: 780px;\u000a      margin: 16px 0 0;\u000a      color: var(--muted);\u000a      font-size: 18px;\u000a    }\u000a    .metrics {\u000a      display: grid;\u000a      grid-template-columns: repeat(4, minmax(0, 1fr));\u000a      gap: 12px;\u000a      margin: 32px 0;\u000a    }\u000a    .metric, .section, details {\u000a      background: var(--panel);\u000a      border: 1px solid var(--line);\u000a      border-radius: var(--radius);\u000a      box-shadow: var(--shadow);\u000a    }\u000a    .metric { padding: 18px; }\u000a    .metric strong {\u000a      display: block;\u000a      font-size: 32px;\u000a      line-height: 1;\u000a      font-variant-numeric: tabular-nums;\u000a    }\u000a    .metric span {\u000a      display: block;\u000a      margin-top: 8px;\u000a      color: var(--muted);\u000a      font-size: 13px;\u000a      font-weight: 650;\u000a    }\u000a    .section {\u000a      margin-top: 18px;\u000a      padding: 24px;\u000a    }\u000a    .section-grid {\u000a      display: grid;\u000a      grid-template-columns: 260px minmax(0, 1fr);\u000a      gap: 28px;\u000a    }\u000a    .section-kicker {\u000a      margin: 0 0 12px;\u000a      color: var(--accent);\u000a      font-size: 13px;\u000a      font-weight: 800;\u000a      letter-spacing: 0.08em;\u000a      text-transform: uppercase;\u000a    }\u000a    .check-list {\u000a      display: grid;\u000a      gap: 8px;\u000a    }\u000a    .check {\u000a      display: flex;\u000a      align-items: baseline;\u000a      justify-content: space-between;\u000a      gap: 12px;\u000a      padding: 10px 0;\u000a      border-bottom: 1px solid var(--line);\u000a    }\u000a    .check span {\u000a      color: var(--muted);\u000a      font-size: 13px;\u000a    }\u000a    .check strong {\u000a      font-size: 18px;\u000a      font-variant-numeric: tabular-nums;\u000a    }\u000a    .section-head {\u000a      display: flex;\u000a      align-items: start;\u000a      justify-content: space-between;\u000a      gap: 16px;\u000a      margin-bottom: 16px;\u000a    }\u000a    .section-head h2 {\u000a      max-width: 680px;\u000a      margin: 0;\u000a      font-size: 24px;\u000a      line-height: 1.2;\u000a      letter-spacing: 0;\u000a    }\u000a    .section-head > span {\u000a      flex: 0 0 auto;\u000a      color: var(--muted);\u000a      font-size: 13px;\u000a      font-weight: 700;\u000a      white-space: nowrap;\u000a    }\u000a    .findings {\u000a      display: grid;\u000a      gap: 12px;\u000a    }\u000a    .finding {\u000a      border: 1px solid var(--line);\u000a      border-left: 4px solid var(--note);\u000a      border-radius: var(--radius);\u000a      padding: 16px;\u000a      background: #fffdf8;\u000a    }\u000a    .finding.danger { border-left-color: var(--danger); }\u000a    .finding.warn { border-left-color: var(--warn); }\u000a    .finding.low { border-left-color: var(--low); }\u000a    .finding-head {\u000a      display: flex;\u000a      align-items: start;\u000a      justify-content: space-between;\u000a      gap: 16px;\u000a    }\u000a    .finding-id {\u000a      margin: 0 0 4px;\u000a      color: var(--muted);\u000a      font-family: ui-monospace, SFMono-Regular, Menlo, Consolas, monospace;\u000a      font-size: 12px;\u000a    }\u000a    h3 {\u000a      margin: 0;\u000a      font-size: 17px;\u000a      line-height: 1.3;\u000a      letter-spacing: 0;\u000a    }\u000a    .pill {\u000a      display: inline-flex;\u000a      align-items: center;\u000a      min-height: 26px;\u000a      padding: 4px 9px;\u000a      border-radius: 999px;\u000a      font-size: 12px;\u000a      font-weight: 800;\u000a      text-transform: uppercase;\u000a      white-space: nowrap;\u000a    }\u000a    .pill.danger { background: var(--danger-bg); color: var(--danger); }\u000a    .pill.warn { background: var(--warn-bg); color: var(--warn); }\u000a    .pill.note { background: var(--note-bg); color: var(--note); }\u000a    .pill.low { background: var(--low-bg); color: var(--low); }\u000a    .action {\u000a      margin: 10px 0 0;\u000a      color: var(--muted);\u000a    }\u000a    .sample-table {\u000a      margin-top: 14px;\u000a      overflow-x: auto;\u000a      border: 1px solid var(--line);\u000a      border-radius: var(--radius);\u000a      background: var(--panel);\u000a    }\u000a    table {\u000a      width: 100%;\u000a      min-width: 640px;\u000a      border-collapse: collapse;\u000a    }\u000a    th, td {\u000a      padding: 10px 12px;\u000a      border-bottom: 1px solid var(--line);\u000a      text-align: left;\u000a      vertical-align: top;\u000a    }\u000a    th {\u000a      color: var(--muted);\u000a      font-size: 12px;\u000a      font-weight: 800;\u000a      letter-spacing: 0.06em;\u000a      text-transform: uppercase;\u000a    }\u000a    td {\u000a      max-width: 360px;\u000a      color: #27272a;\u000a      font-size: 13px;\u000a      overflow-wrap: anywhere;\u000a    }\u000a    tr:last-child td { border-bottom: 0; }\u000a    .empty {\u000a      margin: 0;\u000a      color: var(--muted);\u000a    }\u000a    details {\u000a      margin-top: 24px;\u000a      padding: 18px;\u000a    }\u000a    summary {\u000a      cursor: pointer;\u000a      font-weight: 800;\u000a    }\u000a    pre {\u000a      margin: 16px 0 0;\u000a      max-height: 560px;\u000a      overflow: auto;\u000a      padding: 16px;\u000a      border-radius: var(--radius);\u000a      background: #111827;\u000a      color: #f9fafb;\u000a      font-size: 12px;\u000a      line-height: 1.45;\u000a    }\u000a    @media (max-width: 860px) {\u000a      main { width: min(100% - 24px, 1120px); padding-top: 32px; }\u000a      .metrics { grid-template-columns: repeat(2, minmax(0, 1fr)); }\u000a      .section-grid { grid-template-columns: 1fr; gap: 18px; }\u000a      .section { padding: 18px; }\u000a      .section-head { display: block; }\u000a      .section-head > span { display: block; margin-top: 8px; }\u000a    }\u000a    @media (max-width: 520px) {\u000a      .metrics { grid-template-columns: 1fr; }\u000a      .lede { font-size: 16px; }\u000a      .finding-head { display: block; }\u000a      .pill { margin-top: 10px; }\u000a    }\u000a  </style>\u000a</head>\u000a<body>\u000a  <main>\u000a    <header>\u000a      <p class="eyebrow">Generated ${catalogReportHtmlEscape(report.generatedAt)}</p>\u000a      <h1>${catalogReportHtmlEscape(report.title)}</h1>\u000a      <p class="lede">${catalogReportHtmlEscape(report.lede)}</p>\u000a    </header>\u000a    <section class="metrics" aria-label="Audit summary">\u000a      ${report.metrics\u000a        .map(\u000a          ([label, value]) =>\u000a            `<div class="metric"><strong>${catalogReportHtmlEscape(catalogReportFormatMetric(value))}</strong><span>${catalogReportHtmlEscape(\u000a              label,\u000a            )}</span></div>`,\u000a        )\u000a        .join("")}\u000a    </section>\u000a    ${sections}\u000a    <details>\u000a      <summary>Compressed JSON appendix</summary>\u000a      <pre>${catalogReportHtmlEscape(JSON.stringify(report.appendix, null, 2))}</pre>\u000a    </details>\u000a  </main>\u000a</body>\u000a</html>`;\u000a}\u000a\u000aexport async function publishCatalogReportPage(report: CatalogReport, ctx: any): Promise<any> {\u000a  const response = await ctx.swarm.page_create({\u000a    title: report.title,\u000a    slug: report.slug,\u000a    description: report.description,\u000a    contentType: "text/html",\u000a    authMode: "authed",\u000a    body: renderCatalogReportPage(report),\u000a  });\u000a  const payload = response?.data ?? response;\u000a  if (payload?.success === false) return { error: payload.error || "page_create failed" };\u000a  return {\u000a    id: payload?.id ?? payload?.page?.id ?? null,\u000a    appUrl: payload?.appUrl ?? payload?.app_url ?? null,\u000a    apiUrl: payload?.apiUrl ?? payload?.api_url ?? null,\u000a    version: payload?.version ?? payload?.page?.version ?? null,\u000a  };\u000a}\u000a\u000a\u000aimport { z } from "zod";\u000aexport const argsSchema = z.object({\u000a  days: z\u000a    .number()\u000a    .int()\u000a    .positive()\u000a    .optional()\u000a    .describe("Look back this many days (default 7)"),\u000a  failureThreshold: z\u000a    .number()\u000a    .optional()\u000a    .describe("Flag schedules with failure rate above this (0-1, default 0.2)"),\u000a  publishPage: z.boolean().optional().describe("Publish an authed HTML page (default true)"),\u000a});\u000a\u000a/** Per-schedule health check: failure rates and flagging unhealthy schedules. */\u000aexport default async function scheduleHealth(args: any, ctx: any) {\u000a  const parsed = argsSchema.safeParse(args);\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a  const days = parsed.data.days || 7;\u000a  const threshold = parsed.data.failureThreshold ?? 0.2;\u000a  const publishPage = parsed.data.publishPage !== false;\u000a  const since = new Date(Date.now() - days * 86400000).toISOString();\u000a\u000a  // Get schedules\u000a  const schedRes: any = await ctx.swarm.schedule_list({});\u000a  const schedPayload = schedRes?.data ?? schedRes;\u000a  const schedules: any[] = schedPayload?.schedules ?? [];\u000a\u000a  if (!schedules.length) {\u000a    const result: any = { days, threshold, totalSchedules: 0, flaggedCount: 0, schedules: [], flagged: [] };\u000a    if (publishPage) {\u000a      result.page = await publishCatalogReportPage(\u000a        {\u000a          title: "Schedule Health Audit",\u000a          slug: "schedule-health",\u000a          description: "Per-schedule failure rate audit.",\u000a          generatedAt: new Date().toISOString(),\u000a          lede: "No schedules were returned for the selected window.",\u000a          metrics: [\u000a            ["Schedules", 0],\u000a            ["Flagged", 0],\u000a            ["Days", days],\u000a            ["Threshold", threshold],\u000a          ],\u000a          sections: [\u000a            {\u000a              key: "schedule-health",\u000a              goal: "Keep recurring schedules healthy and visible.",\u000a              findingCount: 0,\u000a              checks: { schedules: 0, flagged: 0 },\u000a              findings: [],\u000a            },\u000a          ],\u000a          appendix: result,\u000a        },\u000a        ctx,\u000a      );\u000a    }\u000a    return result;\u000a  }\u000a\u000a  // Get recent tasks to correlate with schedules\u000a  const taskRes: any = await ctx.swarm.task_list({ createdAfter: since, limit: 2000 });\u000a  const taskPayload = taskRes?.data ?? taskRes;\u000a  const tasks: any[] = taskPayload?.tasks ?? [];\u000a\u000a  // Group by scheduleId\u000a  const bySchedule = new Map<string, { total: number; failed: number; completed: number }>();\u000a  for (const t of tasks) {\u000a    if (!t.scheduleId) continue;\u000a    const entry = bySchedule.get(t.scheduleId) ?? { total: 0, failed: 0, completed: 0 };\u000a    entry.total++;\u000a    if (t.status === "failed") entry.failed++;\u000a    if (t.status === "completed") entry.completed++;\u000a    bySchedule.set(t.scheduleId, entry);\u000a  }\u000a\u000a  const results = schedules.map((s: any) => {\u000a    const stats = bySchedule.get(s.id) ?? { total: 0, failed: 0, completed: 0 };\u000a    const failureRate = stats.total > 0 ? stats.failed / stats.total : 0;\u000a    return {\u000a      id: s.id,\u000a      name: s.name,\u000a      enabled: s.enabled,\u000a      targetAgentId: s.targetAgentId,\u000a      runs: stats.total,\u000a      failed: stats.failed,\u000a      completed: stats.completed,\u000a      failureRate: Math.round(failureRate * 1000) / 1000,\u000a      flagged: stats.total >= 3 && failureRate > threshold,\u000a    };\u000a  });\u000a\u000a  const flagged = results.filter((r: any) => r.flagged);\u000a\u000a  const result: any = {\u000a    days,\u000a    threshold,\u000a    totalSchedules: schedules.length,\u000a    flaggedCount: flagged.length,\u000a    schedules: results.sort((a: any, b: any) => b.failureRate - a.failureRate),\u000a    flagged,\u000a  };\u000a\u000a  if (publishPage) {\u000a    result.page = await publishCatalogReportPage(\u000a      {\u000a        title: "Schedule Health Audit",\u000a        slug: "schedule-health",\u000a        description: "Per-schedule failure rate audit.",\u000a        generatedAt: new Date().toISOString(),\u000a        lede: `Checked ${schedules.length} schedule(s) over ${days} day(s); ${flagged.length} exceeded the configured failure threshold.`,\u000a        metrics: [\u000a          ["Schedules", schedules.length],\u000a          ["Flagged", flagged.length],\u000a          ["Days", days],\u000a          ["Threshold", threshold],\u000a        ],\u000a        sections: [\u000a          {\u000a            key: "schedule-health",\u000a            goal: "Keep recurring schedules healthy and visible.",\u000a            findingCount: flagged.length,\u000a            checks: {\u000a              totalSchedules: schedules.length,\u000a              flaggedSchedules: flagged.length,\u000a              threshold,\u000a              scannedTasks: tasks.length,\u000a            },\u000a            findings: flagged.map((schedule: any) => ({\u000a              id: `schedule.${schedule.id}`,\u000a              severity: schedule.failureRate >= 0.5 ? "high" : "medium",\u000a              summary: `${schedule.name} failed ${schedule.failed}/${schedule.runs} recent run(s).`,\u000a              action: "Review the latest failed tasks and disable, repair, or retarget this schedule.",\u000a              samples: [schedule],\u000a            })),\u000a          },\u000a        ],\u000a        appendix: result,\u000a      },\u000a      ctx,\u000a    );\u000a  }\u000a\u000a  return result;\u000a}\u000a'),'Per-schedule failure rate check over recent tasks — flags schedules with failure rates above a configurable threshold.','Find unhealthy schedules that keep failing — for daily compounding, reliability reviews, or ops triage.','{"argsType":"any","resultType":"unknown","description":"Per-schedule health check: failure rates and flagging unhealthy schedules."}','69c68d5bc828d20cddcde57ff69f30965549bb3b136b315295fb760beab6fffe',NULL,'2026-06-11T22:38:23.825Z','Seeded from the built-in scripts catalog (src/be/seed-scripts)',NULL,NULL);
INSERT INTO script_versions VALUES('8ad6c6d2-0570-406b-9d21-d075715a463b','bb3189d0-d123-4443-8f1c-f07ff75a292f',1,unistr('import { z } from "zod";\u000a\u000aexport const argsSchema = z.object({\u000a  days: z\u000a    .number()\u000a    .int()\u000a    .positive()\u000a    .optional()\u000a    .describe("Look back this many days (default 7)"),\u000a  agentId: z.string().optional().describe("Filter by agent ID (default: all agents)"),\u000a  limit: z\u000a    .number()\u000a    .int()\u000a    .positive()\u000a    .optional()\u000a    .describe("Top N tools to return (default 20)"),\u000a});\u000a\u000a/** Tool usage histogram from session_logs — top tools by call count. */\u000aexport default async function toolUsage(args: any, ctx: any) {\u000a  const parsed = argsSchema.safeParse(args);\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a  const days = parsed.data.days || 7;\u000a  const limit = parsed.data.limit || 20;\u000a  const agentId = parsed.data.agentId;\u000a\u000a  const agentFilter = agentId ? `AND agent_id = ''${agentId}''` : "";\u000a  const sql = `\u000a    SELECT tool_name, count(*) as calls\u000a    FROM session_logs\u000a    WHERE tool_name IS NOT NULL\u000a      AND created_at > datetime(''now'', ''-${days} days'')\u000a      ${agentFilter}\u000a    GROUP BY tool_name\u000a    ORDER BY calls DESC\u000a    LIMIT ${limit}\u000a  `;\u000a\u000a  const res: any = await ctx.swarm.db_query({ sql });\u000a  const payload = res?.data ?? res;\u000a  const columns: string[] = payload?.columns ?? [];\u000a  const rows: any[] = (payload?.rows ?? []).map((row: any[]) =>\u000a    Object.fromEntries(columns.map((column, index) => [column, row[index]])),\u000a  );\u000a\u000a  const totalCalls = rows.reduce((sum: number, r: any) => sum + (r.calls ?? 0), 0);\u000a\u000a  return {\u000a    days,\u000a    agentId: agentId ?? "all",\u000a    totalDistinctTools: rows.length,\u000a    totalCalls,\u000a    tools: rows.map((r: any) => ({\u000a      tool: r.tool_name,\u000a      calls: r.calls,\u000a      pct: totalCalls > 0 ? Math.round((r.calls / totalCalls) * 1000) / 10 : 0,\u000a    })),\u000a  };\u000a}\u000a'),'Tool usage histogram from session_logs — top tools by call count over a time window, optionally filtered by agent.','See which MCP tools agents use most — for SDK gap analysis, optimization, or daily ops snapshots.','{"argsType":"any","resultType":"unknown","description":"Tool usage histogram from session_logs — top tools by call count."}','277c4e3c1b3743d8c3d60320bb493f691e03b95f0f819a077059d72e068528f9',NULL,'2026-06-11T22:38:23.948Z','Seeded from the built-in scripts catalog (src/be/seed-scripts)',NULL,NULL);
INSERT INTO script_versions VALUES('3287aca9-765f-40b9-a7f3-04198e0b1c1f','82d56dac-c9d1-423c-b2ff-b1559bf24fa8',1,unistr('export type CatalogReportFinding = {\u000a  id: string;\u000a  severity?: string;\u000a  summary: string;\u000a  action?: string;\u000a  samples?: unknown[];\u000a};\u000a\u000aexport type CatalogReportSection = {\u000a  key: string;\u000a  label?: string;\u000a  goal: string;\u000a  findingCount?: number;\u000a  checks?: Record<string, unknown>;\u000a  findings?: CatalogReportFinding[];\u000a};\u000a\u000aexport type CatalogReport = {\u000a  title: string;\u000a  slug: string;\u000a  description: string;\u000a  generatedAt: string;\u000a  lede: string;\u000a  metrics: Array<[string, unknown]>;\u000a  sections: CatalogReportSection[];\u000a  appendix: unknown;\u000a};\u000a\u000afunction catalogReportAsText(value: unknown): string {\u000a  return typeof value === "string" ? value : value == null ? "" : JSON.stringify(value);\u000a}\u000a\u000afunction catalogReportHtmlEscape(value: unknown): string {\u000a  return catalogReportAsText(value)\u000a    .replace(/&/g, "&amp;")\u000a    .replace(/</g, "&lt;")\u000a    .replace(/>/g, "&gt;")\u000a    .replace(/"/g, "&quot;");\u000a}\u000a\u000afunction catalogReportHumanLabel(value: string): string {\u000a  return value\u000a    .replace(/([a-z0-9])([A-Z])/g, "$1 $2")\u000a    .replace(/[-_.]+/g, " ")\u000a    .replace(/\\b\\w/g, (char) => char.toUpperCase());\u000a}\u000a\u000afunction catalogReportFormatMetric(value: unknown): string {\u000a  if (typeof value === "number") return new Intl.NumberFormat("en-US").format(value);\u000a  return catalogReportAsText(value);\u000a}\u000a\u000afunction catalogReportSeverityTone(value?: string): string {\u000a  if (value === "critical") return "danger";\u000a  if (value === "high") return "warn";\u000a  if (value === "medium") return "note";\u000a  return "low";\u000a}\u000a\u000afunction catalogReportRenderSampleValue(value: unknown): string {\u000a  if (Array.isArray(value)) {\u000a    return value\u000a      .map((item) => (typeof item === "object" && item !== null ? JSON.stringify(item) : catalogReportAsText(item)))\u000a      .join(", ");\u000a  }\u000a  if (value && typeof value === "object") return JSON.stringify(value);\u000a  return catalogReportAsText(value);\u000a}\u000a\u000afunction catalogReportRenderSamples(samples?: unknown[]): string {\u000a  if (!Array.isArray(samples) || samples.length === 0) return "";\u000a  const normalized = samples.map((sampleRow) =>\u000a    sampleRow && typeof sampleRow === "object" && !Array.isArray(sampleRow)\u000a      ? (sampleRow as Record<string, unknown>)\u000a      : { value: sampleRow },\u000a  );\u000a  const columns = Array.from(\u000a    new Set(normalized.flatMap((sampleRow) => Object.keys(sampleRow).slice(0, 6))),\u000a  ).slice(0, 6);\u000a  if (columns.length === 0) return "";\u000a  const rows = normalized\u000a    .map(\u000a      (sampleRow) =>\u000a        `<tr>${columns\u000a          .map((column) => `<td>${catalogReportHtmlEscape(catalogReportRenderSampleValue(sampleRow[column]))}</td>`)\u000a          .join("")}</tr>`,\u000a    )\u000a    .join("");\u000a  return `<div class="sample-table" aria-label="Sample rows">\u000a    <table>\u000a      <thead><tr>${columns.map((column) => `<th>${catalogReportHtmlEscape(catalogReportHumanLabel(column))}</th>`).join("")}</tr></thead>\u000a      <tbody>${rows}</tbody>\u000a    </table>\u000a  </div>`;\u000a}\u000a\u000aexport function renderCatalogReportPage(report: CatalogReport): string {\u000a  const sections = report.sections\u000a    .map((section) => {\u000a      const findings = (section.findings || [])\u000a        .map(\u000a          (finding) => `<article class="finding ${catalogReportHtmlEscape(catalogReportSeverityTone(finding.severity))}">\u000a            <div class="finding-head">\u000a              <div>\u000a                <p class="finding-id">${catalogReportHtmlEscape(finding.id)}</p>\u000a                <h3>${catalogReportHtmlEscape(finding.summary)}</h3>\u000a              </div>\u000a              <span class="pill ${catalogReportHtmlEscape(catalogReportSeverityTone(finding.severity))}">${catalogReportHtmlEscape(\u000a                finding.severity || "low",\u000a              )}</span>\u000a            </div>\u000a            ${finding.action ? `<p class="action">${catalogReportHtmlEscape(finding.action)}</p>` : ""}\u000a            ${catalogReportRenderSamples(finding.samples)}\u000a          </article>`,\u000a        )\u000a        .join("");\u000a      const checks = Object.entries(section.checks || {})\u000a        .map(\u000a          ([label, value]) =>\u000a            `<div class="check"><span>${catalogReportHtmlEscape(catalogReportHumanLabel(label))}</span><strong>${catalogReportHtmlEscape(\u000a              catalogReportFormatMetric(value),\u000a            )}</strong></div>`,\u000a        )\u000a        .join("");\u000a      return `<section class="section">\u000a        <div class="section-grid">\u000a          <aside class="checks">\u000a            <p class="section-kicker">${catalogReportHtmlEscape(section.label || catalogReportHumanLabel(section.key))}</p>\u000a            <div class="check-list">${checks}</div>\u000a          </aside>\u000a          <div>\u000a            <div class="section-head">\u000a              <h2>${catalogReportHtmlEscape(section.goal)}</h2>\u000a              <span>${catalogReportHtmlEscape(catalogReportFormatMetric(section.findingCount ?? section.findings?.length ?? 0))} finding(s)</span>\u000a            </div>\u000a            <div class="findings">\u000a              ${findings || ''<p class="empty">No actionable findings in this cluster.</p>''}\u000a            </div>\u000a          </div>\u000a        </div>\u000a      </section>`;\u000a    })\u000a    .join("\\n");\u000a  return `<!doctype html>\u000a<html lang="en">\u000a<head>\u000a  <meta charset="utf-8">\u000a  <meta name="viewport" content="width=device-width, initial-scale=1">\u000a  <meta name="theme-color" content="#f5f2ea">\u000a  <title>${catalogReportHtmlEscape(report.title)}</title>\u000a  <style>\u000a    :root {\u000a      color-scheme: light;\u000a      --bg: #f5f2ea;\u000a      --panel: #ffffff;\u000a      --ink: #18181b;\u000a      --muted: #5f6368;\u000a      --line: #ded8cb;\u000a      --accent: #255c99;\u000a      --danger: #b42318;\u000a      --danger-bg: #fff1f0;\u000a      --warn: #b54708;\u000a      --warn-bg: #fff7ed;\u000a      --note: #175cd3;\u000a      --note-bg: #eff6ff;\u000a      --low: #067647;\u000a      --low-bg: #ecfdf3;\u000a      --radius: 8px;\u000a      --shadow: 0 1px 2px rgba(24, 24, 27, 0.06), 0 14px 36px rgba(24, 24, 27, 0.07);\u000a    }\u000a    * { box-sizing: border-box; }\u000a    body {\u000a      margin: 0;\u000a      background: var(--bg);\u000a      color: var(--ink);\u000a      font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;\u000a      font-size: 16px;\u000a      line-height: 1.55;\u000a    }\u000a    main {\u000a      width: min(1120px, calc(100% - 32px));\u000a      margin: 0 auto;\u000a      padding: 48px 0 72px;\u000a    }\u000a    header { margin-bottom: 28px; }\u000a    .eyebrow {\u000a      margin: 0 0 8px;\u000a      color: var(--muted);\u000a      font-size: 13px;\u000a      font-weight: 750;\u000a      letter-spacing: 0.08em;\u000a      text-transform: uppercase;\u000a    }\u000a    h1 {\u000a      margin: 0;\u000a      max-width: 860px;\u000a      font-size: clamp(2rem, 4vw, 3rem);\u000a      line-height: 1.05;\u000a      letter-spacing: 0;\u000a    }\u000a    .lede {\u000a      max-width: 780px;\u000a      margin: 16px 0 0;\u000a      color: var(--muted);\u000a      font-size: 18px;\u000a    }\u000a    .metrics {\u000a      display: grid;\u000a      grid-template-columns: repeat(4, minmax(0, 1fr));\u000a      gap: 12px;\u000a      margin: 32px 0;\u000a    }\u000a    .metric, .section, details {\u000a      background: var(--panel);\u000a      border: 1px solid var(--line);\u000a      border-radius: var(--radius);\u000a      box-shadow: var(--shadow);\u000a    }\u000a    .metric { padding: 18px; }\u000a    .metric strong {\u000a      display: block;\u000a      font-size: 32px;\u000a      line-height: 1;\u000a      font-variant-numeric: tabular-nums;\u000a    }\u000a    .metric span {\u000a      display: block;\u000a      margin-top: 8px;\u000a      color: var(--muted);\u000a      font-size: 13px;\u000a      font-weight: 650;\u000a    }\u000a    .section {\u000a      margin-top: 18px;\u000a      padding: 24px;\u000a    }\u000a    .section-grid {\u000a      display: grid;\u000a      grid-template-columns: 260px minmax(0, 1fr);\u000a      gap: 28px;\u000a    }\u000a    .section-kicker {\u000a      margin: 0 0 12px;\u000a      color: var(--accent);\u000a      font-size: 13px;\u000a      font-weight: 800;\u000a      letter-spacing: 0.08em;\u000a      text-transform: uppercase;\u000a    }\u000a    .check-list {\u000a      display: grid;\u000a      gap: 8px;\u000a    }\u000a    .check {\u000a      display: flex;\u000a      align-items: baseline;\u000a      justify-content: space-between;\u000a      gap: 12px;\u000a      padding: 10px 0;\u000a      border-bottom: 1px solid var(--line);\u000a    }\u000a    .check span {\u000a      color: var(--muted);\u000a      font-size: 13px;\u000a    }\u000a    .check strong {\u000a      font-size: 18px;\u000a      font-variant-numeric: tabular-nums;\u000a    }\u000a    .section-head {\u000a      display: flex;\u000a      align-items: start;\u000a      justify-content: space-between;\u000a      gap: 16px;\u000a      margin-bottom: 16px;\u000a    }\u000a    .section-head h2 {\u000a      max-width: 680px;\u000a      margin: 0;\u000a      font-size: 24px;\u000a      line-height: 1.2;\u000a      letter-spacing: 0;\u000a    }\u000a    .section-head > span {\u000a      flex: 0 0 auto;\u000a      color: var(--muted);\u000a      font-size: 13px;\u000a      font-weight: 700;\u000a      white-space: nowrap;\u000a    }\u000a    .findings {\u000a      display: grid;\u000a      gap: 12px;\u000a    }\u000a    .finding {\u000a      border: 1px solid var(--line);\u000a      border-left: 4px solid var(--note);\u000a      border-radius: var(--radius);\u000a      padding: 16px;\u000a      background: #fffdf8;\u000a    }\u000a    .finding.danger { border-left-color: var(--danger); }\u000a    .finding.warn { border-left-color: var(--warn); }\u000a    .finding.low { border-left-color: var(--low); }\u000a    .finding-head {\u000a      display: flex;\u000a      align-items: start;\u000a      justify-content: space-between;\u000a      gap: 16px;\u000a    }\u000a    .finding-id {\u000a      margin: 0 0 4px;\u000a      color: var(--muted);\u000a      font-family: ui-monospace, SFMono-Regular, Menlo, Consolas, monospace;\u000a      font-size: 12px;\u000a    }\u000a    h3 {\u000a      margin: 0;\u000a      font-size: 17px;\u000a      line-height: 1.3;\u000a      letter-spacing: 0;\u000a    }\u000a    .pill {\u000a      display: inline-flex;\u000a      align-items: center;\u000a      min-height: 26px;\u000a      padding: 4px 9px;\u000a      border-radius: 999px;\u000a      font-size: 12px;\u000a      font-weight: 800;\u000a      text-transform: uppercase;\u000a      white-space: nowrap;\u000a    }\u000a    .pill.danger { background: var(--danger-bg); color: var(--danger); }\u000a    .pill.warn { background: var(--warn-bg); color: var(--warn); }\u000a    .pill.note { background: var(--note-bg); color: var(--note); }\u000a    .pill.low { background: var(--low-bg); color: var(--low); }\u000a    .action {\u000a      margin: 10px 0 0;\u000a      color: var(--muted);\u000a    }\u000a    .sample-table {\u000a      margin-top: 14px;\u000a      overflow-x: auto;\u000a      border: 1px solid var(--line);\u000a      border-radius: var(--radius);\u000a      background: var(--panel);\u000a    }\u000a    table {\u000a      width: 100%;\u000a      min-width: 640px;\u000a      border-collapse: collapse;\u000a    }\u000a    th, td {\u000a      padding: 10px 12px;\u000a      border-bottom: 1px solid var(--line);\u000a      text-align: left;\u000a      vertical-align: top;\u000a    }\u000a    th {\u000a      color: var(--muted);\u000a      font-size: 12px;\u000a      font-weight: 800;\u000a      letter-spacing: 0.06em;\u000a      text-transform: uppercase;\u000a    }\u000a    td {\u000a      max-width: 360px;\u000a      color: #27272a;\u000a      font-size: 13px;\u000a      overflow-wrap: anywhere;\u000a    }\u000a    tr:last-child td { border-bottom: 0; }\u000a    .empty {\u000a      margin: 0;\u000a      color: var(--muted);\u000a    }\u000a    details {\u000a      margin-top: 24px;\u000a      padding: 18px;\u000a    }\u000a    summary {\u000a      cursor: pointer;\u000a      font-weight: 800;\u000a    }\u000a    pre {\u000a      margin: 16px 0 0;\u000a      max-height: 560px;\u000a      overflow: auto;\u000a      padding: 16px;\u000a      border-radius: var(--radius);\u000a      background: #111827;\u000a      color: #f9fafb;\u000a      font-size: 12px;\u000a      line-height: 1.45;\u000a    }\u000a    @media (max-width: 860px) {\u000a      main { width: min(100% - 24px, 1120px); padding-top: 32px; }\u000a      .metrics { grid-template-columns: repeat(2, minmax(0, 1fr)); }\u000a      .section-grid { grid-template-columns: 1fr; gap: 18px; }\u000a      .section { padding: 18px; }\u000a      .section-head { display: block; }\u000a      .section-head > span { display: block; margin-top: 8px; }\u000a    }\u000a    @media (max-width: 520px) {\u000a      .metrics { grid-template-columns: 1fr; }\u000a      .lede { font-size: 16px; }\u000a      .finding-head { display: block; }\u000a      .pill { margin-top: 10px; }\u000a    }\u000a  </style>\u000a</head>\u000a<body>\u000a  <main>\u000a    <header>\u000a      <p class="eyebrow">Generated ${catalogReportHtmlEscape(report.generatedAt)}</p>\u000a      <h1>${catalogReportHtmlEscape(report.title)}</h1>\u000a      <p class="lede">${catalogReportHtmlEscape(report.lede)}</p>\u000a    </header>\u000a    <section class="metrics" aria-label="Audit summary">\u000a      ${report.metrics\u000a        .map(\u000a          ([label, value]) =>\u000a            `<div class="metric"><strong>${catalogReportHtmlEscape(catalogReportFormatMetric(value))}</strong><span>${catalogReportHtmlEscape(\u000a              label,\u000a            )}</span></div>`,\u000a        )\u000a        .join("")}\u000a    </section>\u000a    ${sections}\u000a    <details>\u000a      <summary>Compressed JSON appendix</summary>\u000a      <pre>${catalogReportHtmlEscape(JSON.stringify(report.appendix, null, 2))}</pre>\u000a    </details>\u000a  </main>\u000a</body>\u000a</html>`;\u000a}\u000a\u000aexport async function publishCatalogReportPage(report: CatalogReport, ctx: any): Promise<any> {\u000a  const response = await ctx.swarm.page_create({\u000a    title: report.title,\u000a    slug: report.slug,\u000a    description: report.description,\u000a    contentType: "text/html",\u000a    authMode: "authed",\u000a    body: renderCatalogReportPage(report),\u000a  });\u000a  const payload = response?.data ?? response;\u000a  if (payload?.success === false) return { error: payload.error || "page_create failed" };\u000a  return {\u000a    id: payload?.id ?? payload?.page?.id ?? null,\u000a    appUrl: payload?.appUrl ?? payload?.app_url ?? null,\u000a    apiUrl: payload?.apiUrl ?? payload?.api_url ?? null,\u000a    version: payload?.version ?? payload?.page?.version ?? null,\u000a  };\u000a}\u000a\u000a\u000aimport { z } from "zod";\u000aexport const argsSchema = z.object({\u000a  days: z\u000a    .number()\u000a    .int()\u000a    .positive()\u000a    .optional()\u000a    .describe("Look back this many days (default 3)"),\u000a  includeToolUsage: z.boolean().optional().describe("Include tool usage histogram (default true)"),\u000a  includeScheduleHealth: z\u000a    .boolean()\u000a    .optional()\u000a    .describe("Include schedule health flags (default true)"),\u000a  includeMemoryHealth: z.boolean().optional().describe("Include memory health stats (default true)"),\u000a  includeScriptCandidates: z\u000a    .boolean()\u000a    .optional()\u000a    .describe("Include high-frequency tool-triplet candidates for future seed scripts (default true)"),\u000a  includeScriptUsage: z\u000a    .boolean()\u000a    .optional()\u000a    .describe("Include actual script run, creation, and edit metrics (default true)"),\u000a  includeCostAndTokens: z\u000a    .boolean()\u000a    .optional()\u000a    .describe("Include session cost and token metrics with honesty rails (default true)"),\u000a  includeByAgent: z\u000a    .boolean()\u000a    .optional()\u000a    .describe("Include per-agent task/completion/failure breakdown (default true)"),\u000a  publishPage: z.boolean().optional().describe("Publish an authed HTML page (default true)"),\u000a});\u000a\u000a/**\u000a * Failure reasons that are swarm bookkeeping, not real failures. Excluded from\u000a * failureClusters, scheduleHealth and byAgent failure counts (Lead Rule #16):\u000a * the run engine collapses redundant sibling tasks into these statuses, so\u000a * counting them produces phantom failure spikes.\u000a */\u000aconst EXCLUDED_FAIL = ["superseded_workflow_task", "cancelled"];\u000a\u000a/**\u000a * `db_query` returns positional rows (`rows: unknown[][]`) plus a `columns`\u000a * array — NOT an array of objects. Zip them back into objects so callers can\u000a * read by column name.\u000a */\u000afunction rowsToObjects(res: any): any[] {\u000a  const p = res?.data ?? res;\u000a  const cols: string[] = p?.columns ?? [];\u000a  return (p?.rows ?? []).map((r: any) =>\u000a    Array.isArray(r) ? Object.fromEntries(cols.map((c, i) => [c, r[i]])) : r,\u000a  );\u000a}\u000a\u000afunction asNumber(value: any): number {\u000a  const n = Number(value ?? 0);\u000a  return Number.isFinite(n) ? n : 0;\u000a}\u000a\u000afunction round1(value: number): number {\u000a  return Math.round(value * 10) / 10;\u000a}\u000a\u000afunction percent(part: number, total: number): number {\u000a  return total > 0 ? round1((part / total) * 100) : 0;\u000a}\u000a\u000afunction round4(value: number): number {\u000a  return Math.round(value * 10000) / 10000;\u000a}\u000a\u000afunction percentile(values: number[], p: number): number | null {\u000a  if (values.length === 0) return null;\u000a  const sorted = [...values].sort((a, b) => a - b);\u000a  const index = Math.ceil((p / 100) * sorted.length) - 1;\u000a  return sorted[Math.max(0, Math.min(sorted.length - 1, index))] ?? null;\u000a}\u000a\u000afunction extractToolName(content: string): string | null {\u000a  const match = content.match(/"type"\\s*:\\s*"tool_use"[\\s\\S]*?"name"\\s*:\\s*"([^"]+)"/);\u000a  return match?.[1] ?? null;\u000a}\u000a\u000afunction toolSlug(tool: string): string {\u000a  return tool\u000a    .replace(/^mcp__/, "")\u000a    .replace(/__/g, "-")\u000a    .replace(/_/g, "-")\u000a    .replace(/[^a-zA-Z0-9-]+/g, "-")\u000a    .replace(/^-+|-+$/g, "")\u000a    .toLowerCase();\u000a}\u000a\u000afunction decodeFloat32Blob(value: any): Float32Array | null {\u000a  if (!value) return null;\u000a  let bytes: Uint8Array | null = null;\u000a  if (value instanceof Uint8Array) bytes = value;\u000a  else if (Array.isArray(value)) bytes = Uint8Array.from(value);\u000a  else if (typeof value === "object" && Array.isArray(value.data)) bytes = Uint8Array.from(value.data);\u000a  else if (typeof value === "object") {\u000a    const keys = Object.keys(value);\u000a    if (keys.length > 0 && keys.every((key) => /^\\d+$/.test(key))) {\u000a      bytes = Uint8Array.from(Object.values(value) as number[]);\u000a    }\u000a  }\u000a  if (!bytes || bytes.byteLength < 4 || bytes.byteLength % 4 !== 0) return null;\u000a  return new Float32Array(bytes.buffer.slice(bytes.byteOffset, bytes.byteOffset + bytes.byteLength));\u000a}\u000a\u000afunction cosineSimilarity(a: Float32Array, b: Float32Array): number {\u000a  const len = Math.min(a.length, b.length);\u000a  let dot = 0;\u000a  let na = 0;\u000a  let nb = 0;\u000a  for (let i = 0; i < len; i++) {\u000a    const av = a[i] ?? 0;\u000a    const bv = b[i] ?? 0;\u000a    dot += av * bv;\u000a    na += av * av;\u000a    nb += bv * bv;\u000a  }\u000a  if (na === 0 || nb === 0) return 0;\u000a  return dot / (Math.sqrt(na) * Math.sqrt(nb));\u000a}\u000a\u000afunction summarizeScriptUsage(rows: any[], creationRows: any[], editRows: any[], toolRows: any[]) {\u000a  const terminalStatuses = new Set(["completed", "failed", "cancelled", "aborted_limit"]);\u000a  const failureStatuses = new Set(["failed", "cancelled", "aborted_limit"]);\u000a  const durations = rows\u000a    .map((r) => asNumber(r.durationMs))\u000a    .filter((duration) => duration > 0);\u000a  const byScript = new Map<\u000a    string,\u000a    {\u000a      scriptName: string;\u000a      runs: number;\u000a      completed: number;\u000a      failed: number;\u000a      successRate: number;\u000a      durationP50Ms: number | null;\u000a      durationP95Ms: number | null;\u000a      inline: number;\u000a      workflow: number;\u000a      durations: number[];\u000a    }\u000a  >();\u000a\u000a  for (const row of rows) {\u000a    const name = String(row.scriptName || "(inline source)");\u000a    const current =\u000a      byScript.get(name) ??\u000a      {\u000a        scriptName: name,\u000a        runs: 0,\u000a        completed: 0,\u000a        failed: 0,\u000a        successRate: 0,\u000a        durationP50Ms: null,\u000a        durationP95Ms: null,\u000a        inline: 0,\u000a        workflow: 0,\u000a        durations: [],\u000a      };\u000a    current.runs += 1;\u000a    if (row.kind === "inline") current.inline += 1;\u000a    if (row.kind === "workflow") current.workflow += 1;\u000a    if (row.status === "completed") current.completed += 1;\u000a    if (failureStatuses.has(String(row.status))) current.failed += 1;\u000a    const duration = asNumber(row.durationMs);\u000a    if (duration > 0) current.durations.push(duration);\u000a    byScript.set(name, current);\u000a  }\u000a\u000a  const perScript = [...byScript.values()]\u000a    .map((script) => ({\u000a      scriptName: script.scriptName,\u000a      runs: script.runs,\u000a      completed: script.completed,\u000a      failed: script.failed,\u000a      successRate: percent(script.completed, script.runs),\u000a      durationP50Ms: percentile(script.durations, 50),\u000a      durationP95Ms: percentile(script.durations, 95),\u000a      inline: script.inline,\u000a      workflow: script.workflow,\u000a    }))\u000a    .sort((a, b) => b.runs - a.runs)\u000a    .slice(0, 20);\u000a\u000a  const creationsByScope: Record<string, number> = {};\u000a  let creations = 0;\u000a  let scratchCreations = 0;\u000a  for (const row of creationRows) {\u000a    const count = asNumber(row.count);\u000a    if (asNumber(row.isScratch) === 1) {\u000a      scratchCreations += count;\u000a    } else {\u000a      creations += count;\u000a      creationsByScope[String(row.scope || "unknown")] =\u000a        (creationsByScope[String(row.scope || "unknown")] ?? 0) + count;\u000a    }\u000a  }\u000a\u000a  const editsByScope: Record<string, number> = {};\u000a  let edits = 0;\u000a  for (const row of editRows) {\u000a    const count = asNumber(row.count);\u000a    edits += count;\u000a    editsByScope[String(row.scope || "unknown")] =\u000a      (editsByScope[String(row.scope || "unknown")] ?? 0) + count;\u000a  }\u000a\u000a  return {\u000a    source: {\u000a      authoritativeRuns: "script_runs",\u000a      mcpCallSignal: "session_logs tool_use for script tools",\u000a      reconciliation:\u000a        "`script-run` via MCP calls /api/scripts/run, which records kind=''inline'' rows in script_runs; launch-script-run/workflows record kind=''workflow''. session_logs counts agent tool calls and must not be added to script_runs totals.",\u000a    },\u000a    runs: {\u000a      total: rows.length,\u000a      inline: rows.filter((r) => r.kind === "inline").length,\u000a      workflow: rows.filter((r) => r.kind === "workflow").length,\u000a      completed: rows.filter((r) => r.status === "completed").length,\u000a      failed: rows.filter((r) => failureStatuses.has(String(r.status))).length,\u000a      runningOrPaused: rows.filter((r) => !terminalStatuses.has(String(r.status))).length,\u000a      successRate: percent(\u000a        rows.filter((r) => r.status === "completed").length,\u000a        rows.length,\u000a      ),\u000a      durationP50Ms: percentile(durations, 50),\u000a      durationP95Ms: percentile(durations, 95),\u000a      perScript,\u000a    },\u000a    creations: {\u000a      totalNonScratch: creations,\u000a      scratch: scratchCreations,\u000a      byScope: creationsByScope,\u000a    },\u000a    edits: {\u000a      total: edits,\u000a      byScope: editsByScope,\u000a    },\u000a    mcpToolCalls: toolRows.map((r) => ({ tool: r.tool, calls: asNumber(r.calls) })),\u000a  };\u000a}\u000a\u000afunction summarizeCostAndTokens(rows: any[]) {\u000a  const trustedSources = new Set(["harness", "pricing-table"]);\u000a  const trustedRows = rows.filter((r) => trustedSources.has(String(r.costSource)));\u000a  const unpricedRows = rows.filter((r) => String(r.costSource) === "unpriced");\u000a  const trustedTaskRows = trustedRows.filter((r) => r.taskId);\u000a  const trustedTaskIds = new Set(trustedTaskRows.map((r) => String(r.taskId)));\u000a  const trustedTaskSpend = trustedTaskRows.reduce((sum, r) => sum + asNumber(r.totalCostUsd), 0);\u000a  const nonTaskRows = rows.filter((r) => !r.taskId);\u000a  const totalSpend = rows.reduce((sum, r) => sum + asNumber(r.totalCostUsd), 0);\u000a  const trustedSpend = trustedRows.reduce((sum, r) => sum + asNumber(r.totalCostUsd), 0);\u000a\u000a  const sumToken = (field: string) =>\u000a    rows.reduce((sum, r) => (r[field] === null || r[field] === undefined ? sum : sum + asNumber(r[field])), 0);\u000a  const unknownCount = (field: string) =>\u000a    rows.filter((r) => r[field] === null || r[field] === undefined).length;\u000a\u000a  const groupBy = (field: string) => {\u000a    const grouped = new Map<\u000a      string,\u000a      {\u000a        key: string;\u000a        rows: number;\u000a        spendUsd: number;\u000a        trustedSpendUsd: number;\u000a        unpricedRows: number;\u000a      }\u000a    >();\u000a    for (const row of rows) {\u000a      const key = String(row[field] || "unknown");\u000a      const current =\u000a        grouped.get(key) ?? {\u000a          key,\u000a          rows: 0,\u000a          spendUsd: 0,\u000a          trustedSpendUsd: 0,\u000a          unpricedRows: 0,\u000a        };\u000a      current.rows += 1;\u000a      current.spendUsd += asNumber(row.totalCostUsd);\u000a      if (trustedSources.has(String(row.costSource))) current.trustedSpendUsd += asNumber(row.totalCostUsd);\u000a      if (String(row.costSource) === "unpriced") current.unpricedRows += 1;\u000a      grouped.set(key, current);\u000a    }\u000a    return [...grouped.values()]\u000a      .map((r) => ({\u000a        ...r,\u000a        spendUsd: round4(r.spendUsd),\u000a        trustedSpendUsd: round4(r.trustedSpendUsd),\u000a      }))\u000a      .sort((a, b) => b.spendUsd - a.spendUsd);\u000a  };\u000a\u000a  return {\u000a    source: {\u000a      table: "session_costs",\u000a      providerDerivation:\u000a        "provider is derived from agents.harness_provider, then agents.provider, because session_costs does not carry a provider column",\u000a      headlineAvgCostRule:\u000a        "avgCostPerTaskUsd excludes unpriced rows and rows with null taskId; null-task sessions are reported separately",\u000a    },\u000a    rows: rows.length,\u000a    taskCountForHeadlineAvg: trustedTaskIds.size,\u000a    avgCostPerTaskUsd:\u000a      trustedTaskIds.size > 0 ? round4(trustedTaskSpend / trustedTaskIds.size) : null,\u000a    totalSpendUsd: round4(totalSpend),\u000a    trustedSpendUsd: round4(trustedSpend),\u000a    trustedRows: trustedRows.length,\u000a    trustedRowPercent: percent(trustedRows.length, rows.length),\u000a    unpricedRows: unpricedRows.length,\u000a    unpricedSpendUsd: round4(unpricedRows.reduce((sum, r) => sum + asNumber(r.totalCostUsd), 0)),\u000a    nonTaskSessionRows: nonTaskRows.length,\u000a    nonTaskSessionSpendUsd: round4(\u000a      nonTaskRows.reduce((sum, r) => sum + asNumber(r.totalCostUsd), 0),\u000a    ),\u000a    tokenTotals: {\u000a      inputTokens: sumToken("inputTokens"),\u000a      outputTokens: sumToken("outputTokens"),\u000a      cacheReadTokens: sumToken("cacheReadTokens"),\u000a      cacheWriteTokens: sumToken("cacheWriteTokens"),\u000a      reasoningOutputTokens: sumToken("reasoningOutputTokens"),\u000a      thinkingTokens: sumToken("thinkingTokens"),\u000a    },\u000a    unknownCounts: {\u000a      cacheWriteTokens: unknownCount("cacheWriteTokens"),\u000a      numTurns: unknownCount("numTurns"),\u000a    },\u000a    byModel: groupBy("model"),\u000a    byAgent: groupBy("agentName"),\u000a    byProvider: groupBy("provider"),\u000a    byCostSource: groupBy("costSource"),\u000a  };\u000a}\u000a\u000a/**\u000a * Daily compounding insights — compressed JSON for Phase 0 evolution.\u000a *\u000a * Swarm-wide by design: every section aggregates across ALL agents via direct\u000a * read-only SQL (no per-agent scoping), so a single call replaces ~25 raw tool\u000a * roundtrips. Parametric via `days` + the `include*` flags.\u000a */\u000aexport default async function compoundInsights(args: any, ctx: any) {\u000a  const parsed = argsSchema.safeParse(args || {});\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a  const days = parsed.data.days || 3;\u000a  const includeToolUsage = parsed.data.includeToolUsage !== false;\u000a  const includeScheduleHealth = parsed.data.includeScheduleHealth !== false;\u000a  const includeMemoryHealth = parsed.data.includeMemoryHealth !== false;\u000a  const includeScriptCandidates = parsed.data.includeScriptCandidates !== false;\u000a  const includeScriptUsage = parsed.data.includeScriptUsage !== false;\u000a  const includeCostAndTokens = parsed.data.includeCostAndTokens !== false;\u000a  const includeByAgent = parsed.data.includeByAgent !== false;\u000a  const publishPage = parsed.data.publishPage !== false;\u000a\u000a  // `days` is a validated positive int, so it is safe to interpolate into the\u000a  // SQLite datetime modifier. EXCLUDED_FAIL is a fixed constant list.\u000a  const w = `datetime(''now'',''-${days} days'')`;\u000a  const exclList = EXCLUDED_FAIL.map((r) => `''${r}''`).join(",");\u000a  // A "real" failure = status failed AND not one of the bookkeeping reasons.\u000a  const realFail = `t.status=''failed'' AND (t.failureReason IS NULL OR t.failureReason NOT IN (${exclList}))`;\u000a\u000a  const insights: any = { days, generatedAt: new Date().toISOString() };\u000a\u000a  // Task summary (all agents, direct SQL).\u000a  const statusRows = rowsToObjects(\u000a    await ctx.swarm.db_query({\u000a      sql: `SELECT status, count(*) as cnt FROM agent_tasks t WHERE t.createdAt > ${w} GROUP BY status`,\u000a    }),\u000a  );\u000a  const statusCounts: Record<string, number> = {};\u000a  let total = 0;\u000a  for (const r of statusRows) {\u000a    statusCounts[r.status] = r.cnt;\u000a    total += r.cnt;\u000a  }\u000a  const completed = statusCounts.completed ?? 0;\u000a  const failed = statusCounts.failed ?? 0;\u000a  insights.taskSummary = {\u000a    total,\u000a    completed,\u000a    failed,\u000a    completionRate: total > 0 ? Math.round((completed / total) * 1000) / 10 : 0,\u000a    failureRate: total > 0 ? Math.round((failed / total) * 1000) / 10 : 0,\u000a    statusCounts,\u000a  };\u000a\u000a  // Failure clusters (real failures only, normalized to a 60-char lowercased prefix).\u000a  insights.failureClusters = rowsToObjects(\u000a    await ctx.swarm.db_query({\u000a      sql: `SELECT substr(lower(t.failureReason),1,60) as reason, count(*) as count\u000a            FROM agent_tasks t\u000a            WHERE ${realFail} AND t.failureReason IS NOT NULL AND t.createdAt > ${w}\u000a            GROUP BY reason ORDER BY count DESC LIMIT 10`,\u000a    }),\u000a  );\u000a\u000a  // Schedule health (>= 2 runs, > 20% real-failure rate).\u000a  if (includeScheduleHealth) {\u000a    const sh = rowsToObjects(\u000a      await ctx.swarm.db_query({\u000a        sql: `SELECT s.name as name, s.id as id, count(t.id) as runs,\u000a                     sum(case when ${realFail} then 1 else 0 end) as failed\u000a              FROM scheduled_tasks s\u000a              JOIN agent_tasks t ON t.scheduleId = s.id\u000a              WHERE t.createdAt > ${w} AND t.status != ''cancelled''\u000a              GROUP BY s.id, s.name HAVING runs >= 2`,\u000a      }),\u000a    );\u000a    insights.scheduleHealth = sh\u000a      .map((r: any) => ({\u000a        name: r.name,\u000a        id: r.id,\u000a        runs: r.runs,\u000a        failureRate: r.runs > 0 ? Math.round((r.failed / r.runs) * 100) : 0,\u000a      }))\u000a      .filter((r: any) => r.failureRate > 20)\u000a      .sort((a: any, b: any) => b.failureRate - a.failureRate);\u000a  }\u000a\u000a  // Tool usage (top 25). Tool names live inside the `content` JSON of\u000a  // session_logs (no dedicated column), so extract the name SQL-side: the\u000a  // `''%"type":"tool_use"%''` filter excludes tool_result rows (which only carry\u000a  // `tool_use_id`), and instr/substr pull the first tool name per log line.\u000a  // Approximate: a log line with parallel tool_use blocks counts only its first.\u000a  if (includeToolUsage) {\u000a    insights.toolUsage = rowsToObjects(\u000a      await ctx.swarm.db_query({\u000a        sql: `WITH tu AS (\u000a                 SELECT substr(content, instr(content,''"type":"tool_use"'')) AS tail\u000a                 FROM session_logs\u000a                 WHERE content LIKE ''%"type":"tool_use"%'' AND createdAt > ${w}\u000a               ),\u000a               nm AS (\u000a                 SELECT substr(tail, instr(tail,''"name":"'')+8) AS rest\u000a                 FROM tu WHERE instr(tail,''"name":"'') > 0\u000a               )\u000a               SELECT substr(rest,1,instr(rest,''"'')-1) AS tool, count(*) AS calls\u000a               FROM nm GROUP BY tool ORDER BY calls DESC LIMIT 25`,\u000a      }),\u000a    ).map((r: any) => ({ tool: r.tool, calls: r.calls }));\u000a  }\u000a\u000a  // Memory health (whole store, by scope + source). Pollution markers are\u000a  // SQL-light counts plus JS-side embedding similarity where available; prod\u000a  // SQLite does not expose a scalar cosine_similarity() function.\u000a  if (includeMemoryHealth) {\u000a    const memRows = rowsToObjects(\u000a      await ctx.swarm.db_query({\u000a        sql: `SELECT scope, source, count(*) as cnt,\u000a                     sum(case when accessCount = 0 then 1 else 0 end) as zeroAccess,\u000a                     sum(case when sourceTaskId IS NOT NULL OR sourcePath IS NOT NULL then 1 else 0 end) as referenced\u000a              FROM agent_memory GROUP BY scope, source`,\u000a      }),\u000a    );\u000a    const totalMem = memRows.reduce((s: number, r: any) => s + (r.cnt ?? 0), 0);\u000a    const bySource: any = {};\u000a    for (const r of memRows) {\u000a      bySource[r.source] ??= {\u000a        total: 0,\u000a        percentOfStore: 0,\u000a        zeroAccess: 0,\u000a        zeroAccessPercent: 0,\u000a        referenced: 0,\u000a      };\u000a      bySource[r.source].total += asNumber(r.cnt);\u000a      bySource[r.source].zeroAccess += asNumber(r.zeroAccess);\u000a      bySource[r.source].referenced += asNumber(r.referenced);\u000a    }\u000a    for (const source of Object.keys(bySource)) {\u000a      bySource[source].percentOfStore = percent(bySource[source].total, totalMem);\u000a      bySource[source].zeroAccessPercent = percent(bySource[source].zeroAccess, bySource[source].total);\u000a    }\u000a\u000a    const autoSnapshotSources = ["session_summary", "task_completion"];\u000a    const autoSnapshotTotal = autoSnapshotSources.reduce(\u000a      (sum, source) => sum + (bySource[source]?.total ?? 0),\u000a      0,\u000a    );\u000a    const popularButUseless = rowsToObjects(\u000a      await ctx.swarm.db_query({\u000a        sql: `SELECT id, name, source, accessCount, alpha, beta,\u000a                     round(alpha / nullif(alpha + beta, 0), 3) as usefulness,\u000a                     substr(content, 1, 180) as preview\u000a              FROM agent_memory\u000a              WHERE source IN (''session_summary'',''task_completion'')\u000a                AND accessCount >= 5\u000a                AND alpha <= beta\u000a              ORDER BY accessCount DESC, beta DESC LIMIT 10`,\u000a      }),\u000a    ).map((r: any) => ({\u000a      id: r.id,\u000a      name: r.name,\u000a      source: r.source,\u000a      accessCount: asNumber(r.accessCount),\u000a      usefulness: Number(r.usefulness ?? 0),\u000a      preview: r.preview,\u000a    }));\u000a    const zeroAccessStaleRefRows = rowsToObjects(\u000a      await ctx.swarm.db_query({\u000a        sql: `SELECT source, count(*) as count\u000a              FROM agent_memory\u000a              WHERE accessCount = 0\u000a                AND (sourceTaskId IS NOT NULL OR sourcePath IS NOT NULL)\u000a                AND createdAt < datetime(''now'',''-${days} days'')\u000a              GROUP BY source ORDER BY count DESC`,\u000a      }),\u000a    );\u000a\u000a    const similarityRows = rowsToObjects(\u000a      await ctx.swarm.db_query({\u000a        sql: `SELECT id, name, source, accessCount, embedding\u000a              FROM agent_memory\u000a              WHERE source IN (''session_summary'',''task_completion'')\u000a                AND embedding IS NOT NULL\u000a              ORDER BY accessCount DESC LIMIT 30`,\u000a      }),\u000a    );\u000a    let strongestAutoSnapshotPair: any = null;\u000a    const vectors = similarityRows\u000a      .map((r: any) => ({ ...r, vector: decodeFloat32Blob(r.embedding) }))\u000a      .filter((r: any) => r.vector);\u000a    for (let i = 0; i < vectors.length; i++) {\u000a      for (let j = i + 1; j < vectors.length; j++) {\u000a        const similarity = cosineSimilarity(vectors[i].vector, vectors[j].vector);\u000a        if (!strongestAutoSnapshotPair || similarity > strongestAutoSnapshotPair.similarity) {\u000a          strongestAutoSnapshotPair = {\u000a            similarity: round1(similarity * 100) / 100,\u000a            a: { id: vectors[i].id, name: vectors[i].name, source: vectors[i].source },\u000a            b: { id: vectors[j].id, name: vectors[j].name, source: vectors[j].source },\u000a          };\u000a        }\u000a      }\u000a    }\u000a\u000a    insights.memoryHealth = {\u000a      total: totalMem,\u000a      byScope: memRows.reduce((m: any, r: any) => {\u000a        m[r.scope] = (m[r.scope] ?? 0) + r.cnt;\u000a        return m;\u000a      }, {}),\u000a      bySource,\u000a      pollution: {\u000a        autoSnapshotSources,\u000a        autoSnapshotTotal,\u000a        autoSnapshotPercent: percent(autoSnapshotTotal, totalMem),\u000a        popularButUselessAutoSnapshots: popularButUseless,\u000a        zeroAccessStaleRefs: {\u000a          total: zeroAccessStaleRefRows.reduce((sum: number, r: any) => sum + asNumber(r.count), 0),\u000a          bySource: zeroAccessStaleRefRows.reduce((m: any, r: any) => {\u000a            m[r.source] = asNumber(r.count);\u000a            return m;\u000a          }, {}),\u000a        },\u000a        similarityCheck: {\u000a          sqliteCosineSimilarityAvailable: false,\u000a          path: "js",\u000a          sampledAutoSnapshots: vectors.length,\u000a          strongestAutoSnapshotPair,\u000a        },\u000a      },\u000a    };\u000a  }\u000a\u000a  // Evolution/self-scripting candidates: high-frequency consecutive tool\u000a  // triplets are good prompts for a future seed script.\u000a  if (includeScriptCandidates) {\u000a    const rows = rowsToObjects(\u000a      await ctx.swarm.db_query({\u000a        sql: `WITH raw AS (\u000a                 SELECT sessionId, iteration, lineNumber, content,\u000a                        json_extract(content, ''$.tool_name'') as jsonToolName\u000a                 FROM session_logs\u000a                 WHERE createdAt > ${w}\u000a                   AND (content LIKE ''%"type":"tool_use"%'' OR json_extract(content, ''$.tool_name'') IS NOT NULL)\u000a               )\u000a               SELECT sessionId, iteration, lineNumber, jsonToolName, content\u000a               FROM raw ORDER BY sessionId, iteration, lineNumber LIMIT 100`,\u000a      }),\u000a    );\u000a    const bySession = new Map<string, string[]>();\u000a    for (const row of rows) {\u000a      const tool = row.jsonToolName || extractToolName(String(row.content ?? ""));\u000a      if (!tool) continue;\u000a      const key = String(row.sessionId ?? "unknown");\u000a      const tools = bySession.get(key) ?? [];\u000a      tools.push(tool);\u000a      bySession.set(key, tools);\u000a    }\u000a    const counts = new Map<string, { tools: string[]; count: number }>();\u000a    for (const tools of bySession.values()) {\u000a      for (let i = 0; i <= tools.length - 3; i++) {\u000a        const triplet = tools.slice(i, i + 3);\u000a        const key = triplet.join(" -> ");\u000a        const current = counts.get(key) ?? { tools: triplet, count: 0 };\u000a        current.count += 1;\u000a        counts.set(key, current);\u000a      }\u000a    }\u000a    insights.scriptCandidates = [...counts.values()]\u000a      .sort((a, b) => b.count - a.count)\u000a      .slice(0, 10)\u000a      .map((r) => ({\u000a        tools: r.tools,\u000a        count: r.count,\u000a        suggestedName: r.tools.map(toolSlug).filter(Boolean).slice(0, 3).join("-").slice(0, 80),\u000a      }));\u000a  }\u000a\u000a  // Actual script usage. Authoritative run counts come from `script_runs`;\u000a  // session_logs tool_use rows are a separate MCP-call signal for reconciliation\u000a  // and are intentionally not added to run totals.\u000a  if (includeScriptUsage) {\u000a    const runRows = rowsToObjects(\u000a      await ctx.swarm.db_query({\u000a        sql: `WITH journal_durations AS (\u000a                 SELECT runId, sum(durationMs) AS journalDurationMs\u000a                 FROM script_run_journal\u000a                 WHERE durationMs IS NOT NULL\u000a                 GROUP BY runId\u000a               )\u000a               SELECT sr.scriptName, sr.kind, sr.status, sr.startedAt, sr.finishedAt,\u000a                      COALESCE(\u000a                        jd.journalDurationMs,\u000a                        CASE\u000a                          WHEN sr.finishedAt IS NOT NULL\u000a                          THEN CAST((julianday(sr.finishedAt) - julianday(sr.startedAt)) * 86400000 AS INTEGER)\u000a                          ELSE NULL\u000a                        END\u000a                      ) AS durationMs\u000a               FROM script_runs sr\u000a               LEFT JOIN journal_durations jd ON jd.runId = sr.id\u000a               WHERE sr.startedAt > ${w}\u000a               ORDER BY sr.startedAt DESC`,\u000a      }),\u000a    );\u000a    const creationRows = rowsToObjects(\u000a      await ctx.swarm.db_query({\u000a        sql: `SELECT scope, isScratch, count(*) AS count\u000a              FROM scripts\u000a              WHERE createdAt > ${w}\u000a              GROUP BY scope, isScratch`,\u000a      }),\u000a    );\u000a    const editRows = rowsToObjects(\u000a      await ctx.swarm.db_query({\u000a        sql: `SELECT s.scope, count(*) AS count\u000a              FROM script_versions sv\u000a              JOIN scripts s ON s.id = sv.scriptId\u000a              WHERE sv.changedAt > ${w} AND sv.version > 1\u000a              GROUP BY s.scope`,\u000a      }),\u000a    );\u000a    const scriptToolRows = rowsToObjects(\u000a      await ctx.swarm.db_query({\u000a        sql: `WITH tu AS (\u000a                 SELECT substr(content, instr(content,''"type":"tool_use"'')) AS tail,\u000a                        json_extract(content, ''$.tool_name'') as jsonToolName\u000a                 FROM session_logs\u000a                 WHERE createdAt > ${w}\u000a                   AND (content LIKE ''%script-run%''\u000a                     OR content LIKE ''%launch-script-run%''\u000a                     OR content LIKE ''%get-script-run%''\u000a                     OR content LIKE ''%list-script-runs%'')\u000a               ),\u000a               nm AS (\u000a                 SELECT COALESCE(\u000a                          jsonToolName,\u000a                          CASE\u000a                            WHEN instr(tail,''"name":"'') > 0\u000a                            THEN substr(substr(tail, instr(tail,''"name":"'')+8), 1, instr(substr(tail, instr(tail,''"name":"'')+8), ''"'')-1)\u000a                            ELSE NULL\u000a                          END\u000a                        ) AS tool\u000a                 FROM tu\u000a               )\u000a               SELECT tool, count(*) AS calls\u000a               FROM nm\u000a               WHERE tool IS NOT NULL AND tool LIKE ''%script%''\u000a               GROUP BY tool\u000a               ORDER BY calls DESC`,\u000a      }),\u000a    );\u000a    insights.scriptUsage = summarizeScriptUsage(runRows, creationRows, editRows, scriptToolRows);\u000a  }\u000a\u000a  // Cost and token accounting. `costSource=''unpriced''` rows are excluded from\u000a  // the headline per-task average, and null taskId rows are reported separately.\u000a  if (includeCostAndTokens) {\u000a    const costRows = rowsToObjects(\u000a      await ctx.swarm.db_query({\u000a        sql: `SELECT sc.taskId, sc.agentId, COALESCE(a.name, sc.agentId, ''unknown'') AS agentName,\u000a                     COALESCE(a.harness_provider, a.provider, ''unknown'') AS provider,\u000a                     sc.totalCostUsd, sc.inputTokens, sc.outputTokens, sc.cacheReadTokens,\u000a                     sc.cacheWriteTokens, sc.reasoningOutputTokens, sc.thinkingTokens,\u000a                     sc.numTurns, sc.model, sc.costSource\u000a              FROM session_costs sc\u000a              LEFT JOIN agents a ON a.id = sc.agentId\u000a              WHERE sc.createdAt > ${w}`,\u000a      }),\u000a    );\u000a    insights.costAndTokens = summarizeCostAndTokens(costRows);\u000a  }\u000a\u000a  // Per-agent breakdown — covers every agent that ran a task in the window.\u000a  if (includeByAgent) {\u000a    insights.byAgent = rowsToObjects(\u000a      await ctx.swarm.db_query({\u000a        sql: `SELECT a.name as agent, count(*) as total,\u000a                     sum(case when t.status=''completed'' then 1 else 0 end) as completed,\u000a                     sum(case when ${realFail} then 1 else 0 end) as failed\u000a              FROM agent_tasks t LEFT JOIN agents a ON a.id = t.agentId\u000a              WHERE t.createdAt > ${w} AND t.agentId IS NOT NULL\u000a              GROUP BY t.agentId, a.name ORDER BY total DESC LIMIT 30`,\u000a      }),\u000a    ).map((r: any) => ({\u000a      agent: r.agent,\u000a      total: r.total,\u000a      completed: r.completed,\u000a      failed: r.failed,\u000a    }));\u000a  }\u000a\u000a  if (publishPage) {\u000a    const failureFindings = (insights.failureClusters || []).map((cluster: any) => ({\u000a      id: `failure.${String(cluster.reason || "unknown").slice(0, 48)}`,\u000a      severity: cluster.count >= 5 ? "high" : cluster.count >= 2 ? "medium" : "low",\u000a      summary: `${cluster.count} real failure(s): ${cluster.reason}`,\u000a      action: "Review the repeated failure mode and decide whether to fix, retry, or add a temporary watch item.",\u000a      samples: [cluster],\u000a    }));\u000a    const scheduleFindings = (insights.scheduleHealth || []).map((schedule: any) => ({\u000a      id: `schedule.${schedule.id}`,\u000a      severity: schedule.failureRate >= 50 ? "high" : "medium",\u000a      summary: `${schedule.name} has ${schedule.failureRate}% real-failure rate.`,\u000a      action: "Inspect recent schedule tasks and repair, retarget, or disable the schedule.",\u000a      samples: [schedule],\u000a    }));\u000a    const memoryPollution = insights.memoryHealth?.pollution;\u000a    const memoryFindings = memoryPollution?.autoSnapshotPercent\u000a      ? [\u000a          {\u000a            id: "memory.auto-snapshot-share",\u000a            severity: memoryPollution.autoSnapshotPercent >= 40 ? "high" : "medium",\u000a            summary: `Automatic snapshots are ${memoryPollution.autoSnapshotPercent}% of memory.`,\u000a            action: "Review memory gates and prune low-use automatic snapshots before adding more.",\u000a            samples: [memoryPollution],\u000a          },\u000a        ]\u000a      : [];\u000a    const scriptFindings = (insights.scriptCandidates || []).map((candidate: any) => ({\u000a      id: `script-candidate.${candidate.suggestedName || "unnamed"}`,\u000a      severity: candidate.count >= 3 ? "medium" : "low",\u000a      summary: `${candidate.count} repeated tool triplet(s): ${candidate.tools.join(" -> ")}`,\u000a      action: "Consider turning this repeated workflow into a reusable seeded script.",\u000a      samples: [candidate],\u000a    }));\u000a    const scriptUsageFindings = insights.scriptUsage\u000a      ? [\u000a          {\u000a            id: "script-usage.actual-runs",\u000a            severity: "low",\u000a            summary: `${insights.scriptUsage.runs.total} actual script run(s): ${insights.scriptUsage.runs.inline} one-off, ${insights.scriptUsage.runs.workflow} recurring/workflow.`,\u000a            action: "Use script_runs as the authoritative run count; use session_logs only as an MCP-call reconciliation signal.",\u000a            samples: [insights.scriptUsage],\u000a          },\u000a        ]\u000a      : [];\u000a    const costFindings = insights.costAndTokens\u000a      ? [\u000a          {\u000a            id: "cost-and-tokens.headline",\u000a            severity:\u000a              insights.costAndTokens.unpricedRows > 0 || insights.costAndTokens.nonTaskSessionRows > 0\u000a                ? "medium"\u000a                : "low",\u000a            summary: `$${insights.costAndTokens.totalSpendUsd} total session spend; avg task cost $${insights.costAndTokens.avgCostPerTaskUsd ?? "n/a"} over trusted task rows.`,\u000a            action: "Keep unpriced and null-task session spend separate from the headline per-task average.",\u000a            samples: [insights.costAndTokens],\u000a          },\u000a        ]\u000a      : [];\u000a\u000a    insights.page = await publishCatalogReportPage(\u000a      {\u000a        title: "Compound Insights Audit",\u000a        slug: "compound-insights",\u000a        description: "Swarm-wide daily ops snapshot for compounding and reliability review.",\u000a        generatedAt: insights.generatedAt,\u000a        lede: `Swarm-wide ${days}-day snapshot: ${insights.taskSummary.total} task(s), ${insights.taskSummary.completionRate}% completion rate, ${insights.taskSummary.failureRate}% failure rate.`,\u000a        metrics: [\u000a          ["Tasks", insights.taskSummary.total],\u000a          ["Completed", insights.taskSummary.completed],\u000a          ["Failed", insights.taskSummary.failed],\u000a          ["Failure clusters", insights.failureClusters?.length || 0],\u000a          ["Script runs", insights.scriptUsage?.runs?.total ?? 0],\u000a          ["Total spend", insights.costAndTokens?.totalSpendUsd ?? 0],\u000a        ],\u000a        sections: [\u000a          {\u000a            key: "failures",\u000a            goal: "Expose repeated real failure modes without counting bookkeeping noise.",\u000a            findingCount: failureFindings.length,\u000a            checks: insights.taskSummary,\u000a            findings: failureFindings,\u000a          },\u000a          {\u000a            key: "schedules",\u000a            goal: "Keep schedule failures visible before daily work compounds stale assumptions.",\u000a            findingCount: scheduleFindings.length,\u000a            checks: { unhealthySchedules: scheduleFindings.length },\u000a            findings: scheduleFindings,\u000a          },\u000a          {\u000a            key: "memory",\u000a            goal: "Detect memory bloat and low-use automatic snapshots.",\u000a            findingCount: memoryFindings.length,\u000a            checks: insights.memoryHealth\u000a              ? {\u000a                  total: insights.memoryHealth.total,\u000a                  autoSnapshotPercent: memoryPollution?.autoSnapshotPercent ?? 0,\u000a                  sampledAutoSnapshots:\u000a                    memoryPollution?.similarityCheck?.sampledAutoSnapshots ?? 0,\u000a                }\u000a              : {},\u000a            findings: memoryFindings,\u000a          },\u000a          {\u000a            key: "script-candidates",\u000a            goal: "Find repeated tool chains worth compressing into reusable scripts.",\u000a            findingCount: scriptFindings.length,\u000a            checks: { candidates: scriptFindings.length },\u000a            findings: scriptFindings,\u000a          },\u000a          {\u000a            key: "script-usage",\u000a            goal: "Track actual one-off and recurring script execution without double-counting MCP tool-use logs.",\u000a            findingCount: scriptUsageFindings.length,\u000a            checks: insights.scriptUsage ?? {},\u000a            findings: scriptUsageFindings,\u000a          },\u000a          {\u000a            key: "cost-and-tokens",\u000a            goal: "Track per-task cost and token consumption while separating unpriced and non-task sessions.",\u000a            findingCount: costFindings.length,\u000a            checks: insights.costAndTokens ?? {},\u000a            findings: costFindings,\u000a          },\u000a        ],\u000a        appendix: insights,\u000a      },\u000a      ctx,\u000a    );\u000a  }\u000a\u000a  return insights;\u000a}\u000a'),'All-in-one swarm-wide daily ops snapshot: task completion/failure summary, real failure clusters (excludes superseded/cancelled bookkeeping), schedule health flags, tool usage top-25, memory health/pollution stats, seed-script candidate tool triplets, and a per-agent breakdown. Aggregates across ALL agents via direct read-only SQL.','Single-call daily compounding Phase 0 helper — replaces ~25 raw tool roundtrips with one compressed JSON result covering every agent. For daily evolution, self-scripting candidates, ops reviews, or heartbeat context.','{"argsType":"any","resultType":"unknown","description":"Daily compounding insights — compressed JSON for Phase 0 evolution.\n\nSwarm-wide by design: every section aggregates across ALL agents via direct\nread-only SQL (no per-agent scoping), so a single call replaces ~25 raw tool\nroundtrips. Parametric via `days` + the `include*` flags."}','5184736e075953f14c91c6889d6299d8b29b3dbf4e99867457207e66c892bf26',NULL,'2026-06-11T22:38:24.104Z','Seeded from the built-in scripts catalog (src/be/seed-scripts)',NULL,NULL);
INSERT INTO script_versions VALUES('4024f51d-0783-4550-adf4-f04f09b8dffb','185a38f0-a97f-493f-9bbd-e5636bc7d814',1,unistr('import { z } from "zod";\u000a\u000aexport const argsSchema = z.object({\u000a  days: z\u000a    .number()\u000a    .int()\u000a    .positive()\u000a    .optional()\u000a    .describe("Look back this many days for retrieval/rating data (default 30)"),\u000a  freshDays: z\u000a    .number()\u000a    .int()\u000a    .positive()\u000a    .optional()\u000a    .describe("Memories younger than this are ''fresh'' (default 14)"),\u000a  usefulnessThreshold: z\u000a    .number()\u000a    .min(0)\u000a    .max(1)\u000a    .optional()\u000a    .describe("α/(α+β) cutoff for ''useful'' (default 0.6)"),\u000a  backfillDays: z\u000a    .number()\u000a    .int()\u000a    .min(0)\u000a    .optional()\u000a    .describe("Backfill this many past daily points on first run (default 14; 0 to skip)"),\u000a  publishPage: z.boolean().optional().describe("Publish an authed HTML page (default true)"),\u000a  writeAgentFs: z.boolean().optional().describe("Write markdown report to agent-fs (default true)"),\u000a});\u000a\u000aconst KV_NS = "memory-eval";\u000aconst KV_KEY = "history";\u000a\u000atype DailyPoint = {\u000a  date: string;\u000a  axis1Score: number;\u000a  axis1Total: number;\u000a  axis1Hits: number;\u000a  axis2AvgUsefulness: number | null;\u000a  axis2Retrievals: number | null;\u000a  axis2PrefCount: number | null;\u000a  axis3FreshScore: number;\u000a  axis3TotalRetrieved: number;\u000a  axis3ExpiredPct: number;\u000a  totalMemories: number;\u000a  searchableMemories: number;\u000a  expiredMemories: number;\u000a  backfilled: boolean;\u000a};\u000a\u000afunction rowsToObjects(res: any): any[] {\u000a  const p = res?.data ?? res;\u000a  const cols: string[] = p?.columns ?? [];\u000a  return (p?.rows ?? []).map((r: any) =>\u000a    Array.isArray(r) ? Object.fromEntries(cols.map((c, i) => [c, r[i]])) : r,\u000a  );\u000a}\u000a\u000afunction pct(part: number, total: number): number {\u000a  return total > 0 ? Math.round((part / total) * 1000) / 10 : 0;\u000a}\u000a\u000afunction round2(n: number): number {\u000a  return Math.round(n * 100) / 100;\u000a}\u000a\u000afunction esc(value: unknown): string {\u000a  const s = typeof value === "string" ? value : value == null ? "" : JSON.stringify(value);\u000a  return s.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;");\u000a}\u000a\u000aasync function computeBackfillPoint(\u000a  ctx: any,\u000a  refDate: string,\u000a  days: number,\u000a  freshDays: number,\u000a  usefulnessThreshold: number,\u000a): Promise<DailyPoint> {\u000a  const w = `datetime(''${refDate}'',''-${days} days'')`;\u000a  const ref = `''${refDate}''`;\u000a  const freshW = `datetime(''${refDate}'',''-${freshDays} days'')`;\u000a\u000a  const axis1TotalRows = rowsToObjects(\u000a    await ctx.swarm.db_query({\u000a      sql: `SELECT count(*) as cnt FROM agent_tasks t\u000a            WHERE t.contextKey IS NOT NULL AND t.status = ''completed''\u000a              AND t.createdAt > ${w} AND t.createdAt <= ${ref}\u000a              AND EXISTS (\u000a                SELECT 1 FROM agent_tasks p\u000a                WHERE p.contextKey = t.contextKey AND p.id != t.id AND p.createdAt < t.createdAt\u000a              )`,\u000a    }),\u000a  );\u000a  const a1Total = Number(axis1TotalRows[0]?.cnt ?? 0);\u000a\u000a  let a1Hits = 0;\u000a  if (a1Total > 0) {\u000a    const axis1HitRows = rowsToObjects(\u000a      await ctx.swarm.db_query({\u000a        sql: `SELECT count(DISTINCT mr.taskId) as cnt FROM memory_retrieval mr\u000a              JOIN agent_memory m ON mr.memoryId = m.id\u000a              JOIN agent_tasks ct ON mr.taskId = ct.id\u000a              WHERE ct.contextKey IS NOT NULL AND ct.status = ''completed''\u000a                AND ct.createdAt > ${w} AND ct.createdAt <= ${ref}\u000a                AND m.sourceTaskId IS NOT NULL\u000a                AND m.alpha / nullif(m.alpha + m.beta, 0) > ${usefulnessThreshold}\u000a                AND EXISTS (\u000a                  SELECT 1 FROM agent_tasks p\u000a                  WHERE p.contextKey = ct.contextKey AND p.id = m.sourceTaskId AND p.createdAt < ct.createdAt\u000a                )\u000a                AND EXISTS (\u000a                  SELECT 1 FROM agent_tasks e\u000a                  WHERE e.contextKey = ct.contextKey AND e.id != ct.id AND e.createdAt < ct.createdAt\u000a                )`,\u000a      }),\u000a    );\u000a    a1Hits = Number(axis1HitRows[0]?.cnt ?? 0);\u000a  }\u000a\u000a  const axis3Rows = rowsToObjects(\u000a    await ctx.swarm.db_query({\u000a      sql: `SELECT\u000a              CASE\u000a                WHEN m.createdAt > ${freshW} THEN ''fresh''\u000a                WHEN m.expiresAt IS NOT NULL AND m.expiresAt < ${ref} THEN ''expired''\u000a                ELSE ''other''\u000a              END as bucket,\u000a              count(DISTINCT mr.memoryId) as uniqueMemories\u000a            FROM memory_retrieval mr\u000a            JOIN agent_memory m ON mr.memoryId = m.id\u000a            WHERE mr.retrievedAt > ${w} AND mr.retrievedAt <= ${ref}\u000a            GROUP BY bucket`,\u000a    }),\u000a  );\u000a\u000a  let totalRetrieved = 0;\u000a  let freshMem = 0;\u000a  let expiredMem = 0;\u000a  for (const r of axis3Rows) {\u000a    const n = Number(r.uniqueMemories ?? 0);\u000a    totalRetrieved += n;\u000a    if (r.bucket === "fresh") freshMem = n;\u000a    if (r.bucket === "expired") expiredMem = n;\u000a  }\u000a\u000a  const storeRows = rowsToObjects(\u000a    await ctx.swarm.db_query({\u000a      sql: `SELECT\u000a              count(*) as total,\u000a              sum(CASE WHEN expiresAt IS NULL OR expiresAt > ${ref} THEN 1 ELSE 0 END) as searchable,\u000a              sum(CASE WHEN expiresAt IS NOT NULL AND expiresAt <= ${ref} THEN 1 ELSE 0 END) as expired\u000a            FROM agent_memory WHERE createdAt <= ${ref}`,\u000a    }),\u000a  );\u000a  const store = storeRows[0] ?? {};\u000a\u000a  return {\u000a    date: refDate,\u000a    axis1Score: pct(a1Hits, a1Total),\u000a    axis1Total: a1Total,\u000a    axis1Hits: a1Hits,\u000a    axis2AvgUsefulness: null,\u000a    axis2Retrievals: null,\u000a    axis2PrefCount: null,\u000a    axis3FreshScore: pct(freshMem, totalRetrieved),\u000a    axis3TotalRetrieved: totalRetrieved,\u000a    axis3ExpiredPct: pct(expiredMem, totalRetrieved),\u000a    totalMemories: Number(store.total ?? 0),\u000a    searchableMemories: Number(store.searchable ?? 0),\u000a    expiredMemories: Number(store.expired ?? 0),\u000a    backfilled: true,\u000a  };\u000a}\u000a\u000afunction reportToDailyPoint(date: string, report: any): DailyPoint {\u000a  return {\u000a    date,\u000a    axis1Score: report.axis1.score,\u000a    axis1Total: report.axis1.followUpTasks,\u000a    axis1Hits: report.axis1.tasksWithUsefulCarryForward,\u000a    axis2AvgUsefulness: report.axis2.avgUsefulness,\u000a    axis2Retrievals: report.axis2.totalRetrievals,\u000a    axis2PrefCount: report.axis2.totalPreferenceMemories,\u000a    axis3FreshScore: report.axis3.freshScore,\u000a    axis3TotalRetrieved: report.axis3.totalUniqueMemoriesRetrieved,\u000a    axis3ExpiredPct: report.axis3.buckets.expired.pctOfRetrieved,\u000a    totalMemories: report.storeSnapshot.totalMemories,\u000a    searchableMemories: report.storeSnapshot.totalMemories - report.storeSnapshot.expiredMemories,\u000a    expiredMemories: report.storeSnapshot.expiredMemories,\u000a    backfilled: false,\u000a  };\u000a}\u000a\u000a/** 3-axis memory quality evaluation with over-time trend tracking and KV-backed historical backfill. */\u000aexport default async function memoryEval(args: any, ctx: any) {\u000a  const parsed = argsSchema.safeParse(args || {});\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a\u000a  const days = parsed.data.days || 30;\u000a  const freshDays = parsed.data.freshDays || 14;\u000a  const usefulnessThreshold = parsed.data.usefulnessThreshold ?? 0.6;\u000a  const backfillDays = parsed.data.backfillDays ?? 14;\u000a  const publishPage = parsed.data.publishPage !== false;\u000a  const writeAgentFs = parsed.data.writeAgentFs !== false;\u000a\u000a  const now = new Date().toISOString();\u000a  const today = now.slice(0, 10);\u000a  const report: any = { generatedAt: now, days, freshDays, usefulnessThreshold };\u000a\u000a  // ─── Axis 1: Carry-forward context ───────────────────────────────────\u000a  const w = `datetime(''now'',''-${days} days'')`;\u000a\u000a  const axis1FollowUps = rowsToObjects(\u000a    await ctx.swarm.db_query({\u000a      sql: `SELECT t.id as taskId, t.contextKey\u000a            FROM agent_tasks t\u000a            WHERE t.contextKey IS NOT NULL\u000a              AND t.status = ''completed''\u000a              AND t.createdAt > ${w}\u000a              AND EXISTS (\u000a                SELECT 1 FROM agent_tasks prior\u000a                WHERE prior.contextKey = t.contextKey\u000a                  AND prior.id != t.id\u000a                  AND prior.createdAt < t.createdAt\u000a              )`,\u000a    }),\u000a  );\u000a\u000a  let axis1HitCount = 0;\u000a  const axis1Total = axis1FollowUps.length;\u000a\u000a  if (axis1Total > 0) {\u000a    const axis1Hits = rowsToObjects(\u000a      await ctx.swarm.db_query({\u000a        sql: `SELECT DISTINCT mr.taskId\u000a              FROM memory_retrieval mr\u000a              JOIN agent_memory m ON mr.memoryId = m.id\u000a              JOIN agent_tasks current_task ON mr.taskId = current_task.id\u000a              WHERE current_task.contextKey IS NOT NULL\u000a                AND current_task.status = ''completed''\u000a                AND current_task.createdAt > ${w}\u000a                AND m.sourceTaskId IS NOT NULL\u000a                AND m.alpha / nullif(m.alpha + m.beta, 0) > ${usefulnessThreshold}\u000a                AND EXISTS (\u000a                  SELECT 1 FROM agent_tasks prior\u000a                  WHERE prior.contextKey = current_task.contextKey\u000a                    AND prior.id = m.sourceTaskId\u000a                    AND prior.createdAt < current_task.createdAt\u000a                )\u000a                AND EXISTS (\u000a                  SELECT 1 FROM agent_tasks earlier\u000a                  WHERE earlier.contextKey = current_task.contextKey\u000a                    AND earlier.id != current_task.id\u000a                    AND earlier.createdAt < current_task.createdAt\u000a                )`,\u000a      }),\u000a    );\u000a    axis1HitCount = axis1Hits.length;\u000a  }\u000a\u000a  report.axis1 = {\u000a    name: "Carry-forward context",\u000a    description:\u000a      "Fraction of contextKey-chained follow-up tasks that retrieve ≥1 useful memory from a prior task in the same chain.",\u000a    followUpTasks: axis1Total,\u000a    tasksWithUsefulCarryForward: axis1HitCount,\u000a    score: pct(axis1HitCount, axis1Total),\u000a    softTarget: 60,\u000a    unit: "%",\u000a  };\u000a\u000a  // ─── Axis 2: Follow preferences & constraints ───────────────────────\u000a\u000a  const prefMemories = rowsToObjects(\u000a    await ctx.swarm.db_query({\u000a      sql: `SELECT id, name, sourcePath, alpha, beta, accessCount,\u000a                   CASE WHEN (alpha + beta) > 0 THEN round(alpha / (alpha + beta), 4) ELSE 0.5 END as usefulness\u000a            FROM agent_memory\u000a            WHERE source = ''file_index''\u000a              AND (sourcePath LIKE ''%CLAUDE.md''\u000a                OR sourcePath LIKE ''%IDENTITY.md''\u000a                OR sourcePath LIKE ''%SOUL.md''\u000a                OR sourcePath LIKE ''%TOOLS.md'')`,\u000a    }),\u000a  );\u000a\u000a  const prefTotal = prefMemories.length;\u000a  const prefWithAccess = prefMemories.filter((m: any) => (m.accessCount ?? 0) > 0).length;\u000a  const prefUsefulnessValues = prefMemories.map((m: any) => Number(m.usefulness ?? 0.5));\u000a  const prefAvgUsefulness =\u000a    prefUsefulnessValues.length > 0\u000a      ? round2(prefUsefulnessValues.reduce((s: number, v: number) => s + v, 0) / prefUsefulnessValues.length)\u000a      : 0;\u000a  const prefTotalAccess = prefMemories.reduce((s: number, m: any) => s + (m.accessCount ?? 0), 0);\u000a\u000a  const prefRatings = rowsToObjects(\u000a    await ctx.swarm.db_query({\u000a      sql: `SELECT mr.source as raterSource, count(*) as cnt,\u000a                   round(avg(mr.signal), 4) as avgSignal\u000a            FROM memory_rating mr\u000a            JOIN agent_memory m ON mr.memoryId = m.id\u000a            WHERE m.source = ''file_index''\u000a              AND (m.sourcePath LIKE ''%CLAUDE.md''\u000a                OR m.sourcePath LIKE ''%IDENTITY.md''\u000a                OR m.sourcePath LIKE ''%SOUL.md''\u000a                OR m.sourcePath LIKE ''%TOOLS.md'')\u000a            GROUP BY mr.source`,\u000a    }),\u000a  );\u000a\u000a  const prefByPath = rowsToObjects(\u000a    await ctx.swarm.db_query({\u000a      sql: `SELECT\u000a              CASE\u000a                WHEN sourcePath LIKE ''%CLAUDE.md'' THEN ''CLAUDE.md''\u000a                WHEN sourcePath LIKE ''%IDENTITY.md'' THEN ''IDENTITY.md''\u000a                WHEN sourcePath LIKE ''%SOUL.md'' THEN ''SOUL.md''\u000a                WHEN sourcePath LIKE ''%TOOLS.md'' THEN ''TOOLS.md''\u000a                ELSE ''other''\u000a              END as fileType,\u000a              count(*) as cnt,\u000a              sum(accessCount) as totalAccess,\u000a              round(avg(CASE WHEN (alpha + beta) > 0 THEN alpha / (alpha + beta) ELSE 0.5 END), 4) as avgUsefulness\u000a            FROM agent_memory\u000a            WHERE source = ''file_index''\u000a              AND (sourcePath LIKE ''%CLAUDE.md''\u000a                OR sourcePath LIKE ''%IDENTITY.md''\u000a                OR sourcePath LIKE ''%SOUL.md''\u000a                OR sourcePath LIKE ''%TOOLS.md'')\u000a            GROUP BY fileType`,\u000a    }),\u000a  );\u000a\u000a  report.axis2 = {\u000a    name: "Follow preferences & constraints",\u000a    description:\u000a      "Retrieval rate and LlmRater scores for file_index memories from CLAUDE.md/IDENTITY.md/SOUL.md/TOOLS.md (the ''preference memories'').",\u000a    totalPreferenceMemories: prefTotal,\u000a    memoriesEverRetrieved: prefWithAccess,\u000a    retrievalRate: pct(prefWithAccess, prefTotal),\u000a    totalRetrievals: prefTotalAccess,\u000a    avgUsefulness: prefAvgUsefulness,\u000a    raterBreakdown: prefRatings.map((r: any) => ({\u000a      rater: r.raterSource,\u000a      ratings: r.cnt,\u000a      avgSignal: Number(r.avgSignal ?? 0),\u000a    })),\u000a    byFile: prefByPath.map((r: any) => ({\u000a      file: r.fileType,\u000a      memories: r.cnt,\u000a      totalAccess: r.totalAccess ?? 0,\u000a      avgUsefulness: Number(r.avgUsefulness ?? 0),\u000a    })),\u000a    softTarget: "High retrieval rate + usefulness > 0.6 on preference memories",\u000a    unit: "composite",\u000a  };\u000a\u000a  // ─── Axis 3: Stay current over time ──────────────────────────────────\u000a\u000a  const freshW = `datetime(''now'',''-${freshDays} days'')`;\u000a\u000a  const axis3Buckets = rowsToObjects(\u000a    await ctx.swarm.db_query({\u000a      sql: `SELECT\u000a              CASE\u000a                WHEN m.createdAt > ${freshW} THEN ''fresh''\u000a                WHEN m.expiresAt IS NOT NULL AND m.expiresAt < datetime(''now'') THEN ''expired''\u000a                WHEN m.accessedAt < datetime(''now'',''-${freshDays} days'') AND m.accessCount > 0 THEN ''aging''\u000a                WHEN m.accessCount = 0 AND m.createdAt < ${freshW} THEN ''stranded''\u000a                ELSE ''aging''\u000a              END as bucket,\u000a              count(DISTINCT mr.memoryId) as uniqueMemories,\u000a              count(*) as retrievals\u000a            FROM memory_retrieval mr\u000a            JOIN agent_memory m ON mr.memoryId = m.id\u000a            WHERE mr.retrievedAt > ${w}\u000a            GROUP BY bucket`,\u000a    }),\u000a  );\u000a\u000a  const bucketMap: Record<string, { uniqueMemories: number; retrievals: number }> = {};\u000a  let totalRetrievedMemories = 0;\u000a  let totalRetrievals = 0;\u000a  for (const b of axis3Buckets) {\u000a    const mem = Number(b.uniqueMemories ?? 0);\u000a    const ret = Number(b.retrievals ?? 0);\u000a    bucketMap[b.bucket] = { uniqueMemories: mem, retrievals: ret };\u000a    totalRetrievedMemories += mem;\u000a    totalRetrievals += ret;\u000a  }\u000a\u000a  const freshMem = bucketMap.fresh?.uniqueMemories ?? 0;\u000a  const freshScore = pct(freshMem, totalRetrievedMemories);\u000a\u000a  const staleRefCount = rowsToObjects(\u000a    await ctx.swarm.db_query({\u000a      sql: `SELECT count(DISTINCT mr.memoryId) as cnt\u000a            FROM memory_retrieval mr\u000a            JOIN agent_memory m ON mr.memoryId = m.id\u000a            WHERE mr.retrievedAt > ${w}\u000a              AND m.expiresAt IS NOT NULL\u000a              AND m.expiresAt < datetime(''now'')`,\u000a    }),\u000a  );\u000a\u000a  report.axis3 = {\u000a    name: "Stay current over time",\u000a    description:\u000a      "Distribution of retrieved memories across freshness buckets. Target: >80% of retrieved memories are fresh.",\u000a    window: `${days} days`,\u000a    freshDays,\u000a    totalUniqueMemoriesRetrieved: totalRetrievedMemories,\u000a    totalRetrievals,\u000a    buckets: {\u000a      fresh: {\u000a        label: `Created within last ${freshDays} days`,\u000a        uniqueMemories: freshMem,\u000a        retrievals: bucketMap.fresh?.retrievals ?? 0,\u000a        pctOfRetrieved: freshScore,\u000a      },\u000a      aging: {\u000a        label: `Older than ${freshDays} days, still active`,\u000a        uniqueMemories: bucketMap.aging?.uniqueMemories ?? 0,\u000a        retrievals: bucketMap.aging?.retrievals ?? 0,\u000a        pctOfRetrieved: pct(bucketMap.aging?.uniqueMemories ?? 0, totalRetrievedMemories),\u000a      },\u000a      stranded: {\u000a        label: "Old, never accessed",\u000a        uniqueMemories: bucketMap.stranded?.uniqueMemories ?? 0,\u000a        retrievals: bucketMap.stranded?.retrievals ?? 0,\u000a        pctOfRetrieved: pct(bucketMap.stranded?.uniqueMemories ?? 0, totalRetrievedMemories),\u000a      },\u000a      expired: {\u000a        label: "Past TTL / expired",\u000a        uniqueMemories: bucketMap.expired?.uniqueMemories ?? 0,\u000a        retrievals: bucketMap.expired?.retrievals ?? 0,\u000a        pctOfRetrieved: pct(bucketMap.expired?.uniqueMemories ?? 0, totalRetrievedMemories),\u000a      },\u000a    },\u000a    staleReferentCount: Number(staleRefCount[0]?.cnt ?? 0),\u000a    freshScore,\u000a    softTarget: 80,\u000a    unit: "%",\u000a  };\u000a\u000a  // ─── Store totals ────────────────────────────────────────────────────\u000a\u000a  const totalMemoryRows = rowsToObjects(\u000a    await ctx.swarm.db_query({\u000a      sql: `SELECT count(*) as total,\u000a                   sum(CASE WHEN accessCount > 0 THEN 1 ELSE 0 END) as accessed,\u000a                   sum(CASE WHEN expiresAt IS NOT NULL AND expiresAt < datetime(''now'') THEN 1 ELSE 0 END) as expired\u000a            FROM agent_memory`,\u000a    }),\u000a  );\u000a\u000a  const storeTotals = totalMemoryRows[0] ?? {};\u000a\u000a  report.storeSnapshot = {\u000a    totalMemories: Number(storeTotals.total ?? 0),\u000a    memoriesEverAccessed: Number(storeTotals.accessed ?? 0),\u000a    expiredMemories: Number(storeTotals.expired ?? 0),\u000a  };\u000a\u000a  // ─── History persistence (KV) ───────────────────────────────────────\u000a\u000a  let history: DailyPoint[] = [];\u000a  try {\u000a    const kvResult = await ctx.swarm.kv_get({ key: KV_KEY, namespace: KV_NS });\u000a    const payload = kvResult?.data ?? kvResult;\u000a    if (Array.isArray(payload?.value)) history = payload.value;\u000a  } catch (_e) {\u000a    // first run — no history yet\u000a  }\u000a\u000a  const todayPoint = reportToDailyPoint(today, report);\u000a\u000a  if (backfillDays > 0) {\u000a    const existingDates = new Set(history.map((p) => p.date));\u000a    const toBackfill: string[] = [];\u000a    for (let i = 1; i <= backfillDays; i++) {\u000a      const d = new Date();\u000a      d.setDate(d.getDate() - i);\u000a      const dateStr = d.toISOString().slice(0, 10);\u000a      if (!existingDates.has(dateStr)) toBackfill.push(dateStr);\u000a    }\u000a    for (const dateStr of toBackfill) {\u000a      try {\u000a        const pt = await computeBackfillPoint(ctx, dateStr, days, freshDays, usefulnessThreshold);\u000a        history.push(pt);\u000a      } catch (_e) {\u000a        // skip dates that fail\u000a      }\u000a    }\u000a  }\u000a\u000a  const idx = history.findIndex((p) => p.date === today);\u000a  if (idx >= 0) history[idx] = todayPoint;\u000a  else history.push(todayPoint);\u000a\u000a  history.sort((a, b) => a.date.localeCompare(b.date));\u000a\u000a  try {\u000a    await ctx.swarm.kv_set({ key: KV_KEY, namespace: KV_NS, value: history });\u000a  } catch (_e) {\u000a    report.kvError = "kv_set failed — history not persisted this run";\u000a  }\u000a\u000a  report.historyPoints = history.length;\u000a\u000a  // ─── Markdown report ─────────────────────────────────────────────────\u000a\u000a  const md = buildMarkdownReport(report);\u000a\u000a  if (writeAgentFs) {\u000a    try {\u000a      await ctx.swarm.agent_fs_write({\u000a        path: `docs/memory-eval-${today}.md`,\u000a        content: md,\u000a        message: `Memory eval report ${today}`,\u000a        org: "648a5f3c-35c8-4f11-8673-b89de52cd6bd",\u000a      });\u000a    } catch (_e) {\u000a      report.agentFsError = "agent_fs_write failed — report still available in page + return value";\u000a    }\u000a  }\u000a\u000a  // ─── Publish dashboard page ──────────────────────────────────────────\u000a\u000a  if (publishPage) {\u000a    const html = buildDashboardHtml(report, history);\u000a    try {\u000a      const response = await ctx.swarm.page_create({\u000a        title: "Memory Eval — 3-Axis Dashboard",\u000a        slug: "memory-eval",\u000a        description: `3-axis memory quality dashboard: carry-forward ${report.axis1.score}%, preferences usefulness ${report.axis2.avgUsefulness}, freshness ${report.axis3.freshScore}%. ${history.length} data points.`,\u000a        contentType: "text/html",\u000a        authMode: "authed",\u000a        body: html,\u000a      });\u000a      const payload = response?.data ?? response;\u000a      report.page = {\u000a        id: payload?.id ?? payload?.page?.id ?? null,\u000a        appUrl: payload?.appUrl ?? payload?.app_url ?? null,\u000a        apiUrl: payload?.apiUrl ?? payload?.api_url ?? null,\u000a        version: payload?.version ?? payload?.page?.version ?? null,\u000a      };\u000a    } catch (_e) {\u000a      report.pageError = "page_create failed";\u000a    }\u000a  }\u000a\u000a  return report;\u000a}\u000a\u000afunction buildMarkdownReport(r: any): string {\u000a  const lines: string[] = [];\u000a  const ln = (s = "") => lines.push(s);\u000a\u000a  ln(`# Memory Eval — 3-Axis Report`);\u000a  ln(`> Generated: ${r.generatedAt} · Window: ${r.days} days · History: ${r.historyPoints ?? 1} points`);\u000a  ln();\u000a  ln(`## Summary`);\u000a  ln();\u000a  ln(`| Axis | Score | Soft Target |`);\u000a  ln(`|------|-------|-------------|`);\u000a  ln(`| 1 — Carry-forward context | **${r.axis1.score}%** | ${r.axis1.softTarget}% |`);\u000a  ln(`| 2 — Preferences avg usefulness | **${r.axis2.avgUsefulness}** | >0.6 |`);\u000a  ln(`| 3 — Freshness (% fresh retrieved) | **${r.axis3.freshScore}%** | ${r.axis3.softTarget}% |`);\u000a  ln();\u000a  ln(\u000a    `**Store:** ${r.storeSnapshot.totalMemories} total memories, ${r.storeSnapshot.memoriesEverAccessed} ever accessed, ${r.storeSnapshot.expiredMemories} expired.`,\u000a  );\u000a  ln();\u000a\u000a  ln(`---`);\u000a  ln(`## Axis 1 — Carry-forward Context`);\u000a  ln();\u000a  ln(`*${r.axis1.description}*`);\u000a  ln();\u000a  ln(`- Follow-up tasks in window: **${r.axis1.followUpTasks}**`);\u000a  ln(`- Tasks with useful carry-forward: **${r.axis1.tasksWithUsefulCarryForward}**`);\u000a  ln(`- Score: **${r.axis1.score}%** (soft target: ${r.axis1.softTarget}%)`);\u000a  ln();\u000a\u000a  ln(`---`);\u000a  ln(`## Axis 2 — Follow Preferences & Constraints`);\u000a  ln();\u000a  ln(`*${r.axis2.description}*`);\u000a  ln();\u000a  ln(`- Preference memories in store: **${r.axis2.totalPreferenceMemories}**`);\u000a  ln(`- Ever retrieved: **${r.axis2.memoriesEverRetrieved}** (${r.axis2.retrievalRate}%)`);\u000a  ln(`- Total retrievals: **${r.axis2.totalRetrievals}**`);\u000a  ln(`- Avg usefulness: **${r.axis2.avgUsefulness}**`);\u000a  ln();\u000a  ln(`### By File`);\u000a  ln();\u000a  ln(`| File | Memories | Total Access | Avg Usefulness |`);\u000a  ln(`|------|----------|--------------|----------------|`);\u000a  for (const f of r.axis2.byFile) {\u000a    ln(`| ${f.file} | ${f.memories} | ${f.totalAccess} | ${round2(f.avgUsefulness)} |`);\u000a  }\u000a  ln();\u000a  if (r.axis2.raterBreakdown.length > 0) {\u000a    ln(`### Rater Breakdown`);\u000a    ln();\u000a    ln(`| Rater | Ratings | Avg Signal |`);\u000a    ln(`|-------|---------|------------|`);\u000a    for (const rb of r.axis2.raterBreakdown) {\u000a      ln(`| ${rb.rater} | ${rb.ratings} | ${round2(rb.avgSignal)} |`);\u000a    }\u000a    ln();\u000a  }\u000a\u000a  ln(`---`);\u000a  ln(`## Axis 3 — Stay Current Over Time`);\u000a  ln();\u000a  ln(`*${r.axis3.description}*`);\u000a  ln();\u000a  ln(`- Window: **${r.axis3.window}** · Fresh threshold: **${r.axis3.freshDays} days**`);\u000a  ln(`- Unique memories retrieved: **${r.axis3.totalUniqueMemoriesRetrieved}**`);\u000a  ln(`- Fresh score: **${r.axis3.freshScore}%** (soft target: ${r.axis3.softTarget}%)`);\u000a  ln(`- Stale referents (expired but still retrieved): **${r.axis3.staleReferentCount}**`);\u000a  ln();\u000a  ln(`### Freshness Buckets`);\u000a  ln();\u000a  ln(`| Bucket | Unique Memories | Retrievals | % of Retrieved |`);\u000a  ln(`|--------|-----------------|------------|----------------|`);\u000a  for (const [k, v] of Object.entries(r.axis3.buckets) as [string, any][]) {\u000a    ln(`| ${k} (${v.label}) | ${v.uniqueMemories} | ${v.retrievals} | ${v.pctOfRetrieved}% |`);\u000a  }\u000a  ln();\u000a\u000a  return lines.join("\\n");\u000a}\u000a\u000afunction buildDashboardHtml(report: any, history: DailyPoint[]): string {\u000a  const fmtNum = (v: unknown) =>\u000a    typeof v === "number" ? new Intl.NumberFormat("en-US").format(v) : String(v ?? "");\u000a  const dataJson = JSON.stringify(history);\u000a\u000a  const metricCards = [\u000a    ["Carry-forward", `${report.axis1.score}%`],\u000a    ["Pref Usefulness", report.axis2.avgUsefulness],\u000a    ["Freshness", `${report.axis3.freshScore}%`],\u000a    ["Total Memories", report.storeSnapshot.totalMemories],\u000a  ]\u000a    .map(\u000a      ([label, value]) =>\u000a        `<div class="metric"><strong>${esc(fmtNum(value))}</strong><span>${esc(label)}</span></div>`,\u000a    )\u000a    .join("");\u000a\u000a  const findingSections = buildFindingsHtml(report);\u000a\u000a  return `<!doctype html>\u000a<html lang="en">\u000a<head>\u000a  <meta charset="utf-8">\u000a  <meta name="viewport" content="width=device-width, initial-scale=1">\u000a  <meta name="theme-color" content="#f5f2ea">\u000a  <title>Memory Eval — 3-Axis Dashboard</title>\u000a  <style>\u000a    :root {\u000a      color-scheme: light;\u000a      --bg: #f5f2ea; --panel: #ffffff; --ink: #18181b; --muted: #5f6368;\u000a      --line: #ded8cb; --accent: #255c99;\u000a      --danger: #b42318; --danger-bg: #fff1f0;\u000a      --warn: #b54708; --warn-bg: #fff7ed;\u000a      --note: #175cd3; --note-bg: #eff6ff;\u000a      --low: #067647; --low-bg: #ecfdf3;\u000a      --radius: 8px;\u000a      --shadow: 0 1px 2px rgba(24,24,27,.06), 0 14px 36px rgba(24,24,27,.07);\u000a    }\u000a    * { box-sizing: border-box; }\u000a    body {\u000a      margin: 0; background: var(--bg); color: var(--ink);\u000a      font-family: Inter, ui-sans-serif, system-ui, -apple-system, sans-serif;\u000a      font-size: 16px; line-height: 1.55;\u000a    }\u000a    main { width: min(1120px, calc(100% - 32px)); margin: 0 auto; padding: 48px 0 72px; }\u000a    header { margin-bottom: 28px; }\u000a    .eyebrow {\u000a      margin: 0 0 8px; color: var(--muted); font-size: 13px; font-weight: 750;\u000a      letter-spacing: .08em; text-transform: uppercase;\u000a    }\u000a    h1 { margin: 0; max-width: 860px; font-size: clamp(2rem,4vw,3rem); line-height: 1.05; }\u000a    .lede { max-width: 780px; margin: 16px 0 0; color: var(--muted); font-size: 18px; }\u000a    .metrics {\u000a      display: grid; grid-template-columns: repeat(4, minmax(0,1fr));\u000a      gap: 12px; margin: 32px 0;\u000a    }\u000a    .metric, .section, .chart-card, details {\u000a      background: var(--panel); border: 1px solid var(--line);\u000a      border-radius: var(--radius); box-shadow: var(--shadow);\u000a    }\u000a    .metric { padding: 18px; }\u000a    .metric strong { display: block; font-size: 32px; line-height: 1; font-variant-numeric: tabular-nums; }\u000a    .metric span { display: block; margin-top: 8px; color: var(--muted); font-size: 13px; font-weight: 650; }\u000a    .chart-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 16px; margin: 24px 0; }\u000a    .chart-card { padding: 20px; }\u000a    .chart-card h2 { margin: 0 0 4px; font-size: 17px; line-height: 1.3; }\u000a    .chart-note { margin: 8px 0 0; color: var(--muted); font-size: 12px; font-style: italic; }\u000a    .chart-wrap { position: relative; height: 240px; margin-top: 12px; }\u000a    .section { margin-top: 18px; padding: 24px; }\u000a    .section-grid { display: grid; grid-template-columns: 260px minmax(0,1fr); gap: 28px; }\u000a    .section-kicker {\u000a      margin: 0 0 12px; color: var(--accent); font-size: 13px; font-weight: 800;\u000a      letter-spacing: .08em; text-transform: uppercase;\u000a    }\u000a    .check-list { display: grid; gap: 8px; }\u000a    .check {\u000a      display: flex; align-items: baseline; justify-content: space-between;\u000a      gap: 12px; padding: 10px 0; border-bottom: 1px solid var(--line);\u000a    }\u000a    .check span { color: var(--muted); font-size: 13px; }\u000a    .check strong { font-size: 18px; font-variant-numeric: tabular-nums; }\u000a    .section-head {\u000a      display: flex; align-items: start; justify-content: space-between;\u000a      gap: 16px; margin-bottom: 16px;\u000a    }\u000a    .section-head h2 { max-width: 680px; margin: 0; font-size: 24px; line-height: 1.2; }\u000a    .section-head > span { flex: 0 0 auto; color: var(--muted); font-size: 13px; font-weight: 700; white-space: nowrap; }\u000a    .findings { display: grid; gap: 12px; }\u000a    .finding {\u000a      border: 1px solid var(--line); border-left: 4px solid var(--note);\u000a      border-radius: var(--radius); padding: 16px; background: #fffdf8;\u000a    }\u000a    .finding.danger { border-left-color: var(--danger); }\u000a    .finding.warn { border-left-color: var(--warn); }\u000a    .finding.low { border-left-color: var(--low); }\u000a    .finding-head { display: flex; align-items: start; justify-content: space-between; gap: 16px; }\u000a    .finding-id { margin: 0 0 4px; color: var(--muted); font-family: ui-monospace, monospace; font-size: 12px; }\u000a    h3 { margin: 0; font-size: 17px; line-height: 1.3; }\u000a    .pill {\u000a      display: inline-flex; align-items: center; min-height: 26px; padding: 4px 9px;\u000a      border-radius: 999px; font-size: 12px; font-weight: 800; text-transform: uppercase; white-space: nowrap;\u000a    }\u000a    .pill.danger { background: var(--danger-bg); color: var(--danger); }\u000a    .pill.warn { background: var(--warn-bg); color: var(--warn); }\u000a    .pill.note { background: var(--note-bg); color: var(--note); }\u000a    .pill.low { background: var(--low-bg); color: var(--low); }\u000a    .action { margin: 10px 0 0; color: var(--muted); }\u000a    .sample-table { margin-top: 14px; overflow-x: auto; border: 1px solid var(--line); border-radius: var(--radius); background: var(--panel); }\u000a    table { width: 100%; min-width: 480px; border-collapse: collapse; }\u000a    th, td { padding: 10px 12px; border-bottom: 1px solid var(--line); text-align: left; vertical-align: top; }\u000a    th { color: var(--muted); font-size: 12px; font-weight: 800; letter-spacing: .06em; text-transform: uppercase; }\u000a    td { max-width: 360px; color: #27272a; font-size: 13px; overflow-wrap: anywhere; }\u000a    tr:last-child td { border-bottom: 0; }\u000a    details { margin-top: 24px; padding: 18px; }\u000a    summary { cursor: pointer; font-weight: 800; }\u000a    pre {\u000a      margin: 16px 0 0; max-height: 560px; overflow: auto; padding: 16px;\u000a      border-radius: var(--radius); background: #111827; color: #f9fafb;\u000a      font-size: 12px; line-height: 1.45;\u000a    }\u000a    .backfill-legend {\u000a      margin: 0 0 8px; padding: 8px 12px; background: var(--note-bg);\u000a      border-radius: var(--radius); font-size: 13px; color: var(--note);\u000a    }\u000a    @media (max-width: 860px) {\u000a      main { width: min(100% - 24px, 1120px); padding-top: 32px; }\u000a      .metrics { grid-template-columns: repeat(2, minmax(0,1fr)); }\u000a      .chart-grid { grid-template-columns: 1fr; }\u000a      .section-grid { grid-template-columns: 1fr; gap: 18px; }\u000a    }\u000a    @media (max-width: 520px) { .metrics { grid-template-columns: 1fr; } }\u000a  </style>\u000a</head>\u000a<body>\u000a  <main>\u000a    <header>\u000a      <p class="eyebrow">Generated ${esc(report.generatedAt)}</p>\u000a      <h1>Memory Eval — 3-Axis Dashboard</h1>\u000a      <p class="lede">${esc(`${report.days}-day window · Axis 1 (carry-forward): ${report.axis1.score}% · Axis 2 (preferences): ${report.axis2.avgUsefulness} · Axis 3 (freshness): ${report.axis3.freshScore}% · ${history.length} data points`)}</p>\u000a    </header>\u000a\u000a    <section class="metrics" aria-label="Current scores">${metricCards}</section>\u000a\u000a    <p class="backfill-legend">\u000a      <strong>Chart legend:</strong> Solid lines = measured data. Dashed gray = soft target.\u000a      Axes 1 &amp; 3 are backfilled from audit tables. Axis 2 (preferences) is forward-only — it queries current memory state and cannot be reconstructed historically.\u000a    </p>\u000a\u000a    <section class="chart-grid">\u000a      <div class="chart-card">\u000a        <h2>Axis 1 — Carry-forward Context (%)</h2>\u000a        <div class="chart-wrap"><canvas id="c1"></canvas></div>\u000a      </div>\u000a      <div class="chart-card">\u000a        <h2>Axis 2 — Preferences Usefulness</h2>\u000a        <div class="chart-wrap"><canvas id="c2"></canvas></div>\u000a        <p class="chart-note">Forward-only: cannot be reconstructed from historical data. Starts from first live run.</p>\u000a      </div>\u000a      <div class="chart-card">\u000a        <h2>Axis 3 — Freshness Score (%)</h2>\u000a        <div class="chart-wrap"><canvas id="c3"></canvas></div>\u000a      </div>\u000a      <div class="chart-card">\u000a        <h2>Memory Corpus</h2>\u000a        <div class="chart-wrap"><canvas id="c4"></canvas></div>\u000a      </div>\u000a    </section>\u000a\u000a    ${findingSections}\u000a\u000a    <details>\u000a      <summary>Compressed JSON appendix</summary>\u000a      <pre>${esc(JSON.stringify(report, null, 2))}</pre>\u000a    </details>\u000a  </main>\u000a\u000a  <script src="https://cdn.jsdelivr.net/npm/chart.js@4"></script>\u000a  <script>\u000a  (function() {\u000a    var H = ${dataJson};\u000a    var labels = H.map(function(p){ return p.date.slice(5); });\u000a    var fullLabels = H.map(function(p){ return p.date; });\u000a    var baseOpts = {\u000a      responsive: true, maintainAspectRatio: false,\u000a      interaction: { mode: ''index'', intersect: false },\u000a      plugins: {\u000a        legend: { position: ''bottom'', labels: { boxWidth: 12, padding: 10, font: { size: 11 } } },\u000a        tooltip: {\u000a          callbacks: {\u000a            title: function(items) { return fullLabels[items[0].dataIndex] || ''''; }\u000a          }\u000a        }\u000a      },\u000a      scales: {\u000a        x: { grid: { display: false }, ticks: { font: { size: 10 }, maxRotation: 45, autoSkip: true, maxTicksLimit: 15 } },\u000a        y: { beginAtZero: true, grid: { color: ''#ded8cb40'' }, ticks: { font: { size: 11 } } }\u000a      },\u000a      elements: { point: { radius: 3, hoverRadius: 5 }, line: { tension: 0.3, borderWidth: 2 } }\u000a    };\u000a\u000a    function targetDs(label, val, len) {\u000a      return {\u000a        label: label, data: Array(len).fill(val),\u000a        borderColor: ''#94a3b8'', borderDash: [6,4], borderWidth: 1.5,\u000a        pointRadius: 0, pointHoverRadius: 0, fill: false\u000a      };\u000a    }\u000a\u000a    new Chart(document.getElementById(''c1''), {\u000a      type: ''line'',\u000a      data: {\u000a        labels: labels,\u000a        datasets: [\u000a          { label: ''Carry-forward %'', data: H.map(function(p){return p.axis1Score;}), borderColor: ''#2563eb'', backgroundColor: ''#2563eb20'', fill: true },\u000a          targetDs(''Target 60%'', 60, H.length)\u000a        ]\u000a      },\u000a      options: Object.assign({}, baseOpts, { scales: Object.assign({}, baseOpts.scales, { y: Object.assign({}, baseOpts.scales.y, { max: 100 }) }) })\u000a    });\u000a\u000a    new Chart(document.getElementById(''c2''), {\u000a      type: ''line'',\u000a      data: {\u000a        labels: labels,\u000a        datasets: [\u000a          { label: ''Avg Usefulness'', data: H.map(function(p){return p.axis2AvgUsefulness;}), borderColor: ''#7c3aed'', backgroundColor: ''#7c3aed20'', fill: true, spanGaps: false },\u000a          targetDs(''Target 0.6'', 0.6, H.length)\u000a        ]\u000a      },\u000a      options: Object.assign({}, baseOpts, { scales: Object.assign({}, baseOpts.scales, { y: Object.assign({}, baseOpts.scales.y, { max: 1, ticks: Object.assign({}, baseOpts.scales.y.ticks, { stepSize: 0.2 }) }) }) })\u000a    });\u000a\u000a    new Chart(document.getElementById(''c3''), {\u000a      type: ''line'',\u000a      data: {\u000a        labels: labels,\u000a        datasets: [\u000a          { label: ''Freshness %'', data: H.map(function(p){return p.axis3FreshScore;}), borderColor: ''#059669'', backgroundColor: ''#05966920'', fill: true },\u000a          targetDs(''Target 80%'', 80, H.length)\u000a        ]\u000a      },\u000a      options: Object.assign({}, baseOpts, { scales: Object.assign({}, baseOpts.scales, { y: Object.assign({}, baseOpts.scales.y, { max: 100 }) }) })\u000a    });\u000a\u000a    new Chart(document.getElementById(''c4''), {\u000a      type: ''line'',\u000a      data: {\u000a        labels: labels,\u000a        datasets: [\u000a          { label: ''Total'', data: H.map(function(p){return p.totalMemories;}), borderColor: ''#2563eb'', fill: false },\u000a          { label: ''Searchable'', data: H.map(function(p){return p.searchableMemories;}), borderColor: ''#059669'', fill: false },\u000a          { label: ''Expired'', data: H.map(function(p){return p.expiredMemories;}), borderColor: ''#dc2626'', fill: false }\u000a        ]\u000a      },\u000a      options: baseOpts\u000a    });\u000a  })();\u000a  </script>\u000a</body>\u000a</html>`;\u000a}\u000a\u000afunction buildFindingsHtml(report: any): string {\u000a  const severityTone = (s?: string) =>\u000a    s === "critical" ? "danger" : s === "high" ? "warn" : s === "medium" ? "note" : "low";\u000a  const fmtMetric = (v: unknown) =>\u000a    typeof v === "number" ? new Intl.NumberFormat("en-US").format(v) : String(v ?? "");\u000a  const humanLabel = (s: string) =>\u000a    s\u000a      .replace(/([a-z0-9])([A-Z])/g, "$1 $2")\u000a      .replace(/[-_.]+/g, " ")\u000a      .replace(/\\b\\w/g, (c) => c.toUpperCase());\u000a\u000a  type Finding = { id: string; severity?: string; summary: string; action?: string; samples?: any[] };\u000a  type Section = {\u000a    key: string;\u000a    label?: string;\u000a    goal: string;\u000a    findingCount?: number;\u000a    checks?: Record<string, unknown>;\u000a    findings?: Finding[];\u000a  };\u000a\u000a  const sections: Section[] = [\u000a    {\u000a      key: "axis1-carry-forward",\u000a      label: "Axis 1",\u000a      goal: "Carry-forward context: do follow-up tasks retrieve useful memories from prior tasks in the same thread?",\u000a      findingCount: report.axis1.followUpTasks > 0 ? 1 : 0,\u000a      checks: {\u000a        followUpTasks: report.axis1.followUpTasks,\u000a        tasksWithCarryForward: report.axis1.tasksWithUsefulCarryForward,\u000a        score: `${report.axis1.score}%`,\u000a        softTarget: `${report.axis1.softTarget}%`,\u000a      },\u000a      findings:\u000a        report.axis1.followUpTasks > 0\u000a          ? [\u000a              {\u000a                id: "axis1.carry-forward-rate",\u000a                severity: report.axis1.score >= 60 ? "low" : report.axis1.score >= 30 ? "medium" : "high",\u000a                summary: `${report.axis1.score}% of ${report.axis1.followUpTasks} follow-up tasks retrieved a useful carry-forward memory (soft target: ${report.axis1.softTarget}%).`,\u000a                action:\u000a                  report.axis1.score < 60\u000a                    ? "Investigate whether memories from prior tasks in a thread are being written and embedded correctly."\u000a                    : "Score meets soft target. Monitor for regression after architecture changes.",\u000a              },\u000a            ]\u000a          : [],\u000a    },\u000a    {\u000a      key: "axis2-preferences",\u000a      label: "Axis 2",\u000a      goal: "Follow preferences & constraints: are identity/config memories retrieved and rated useful?",\u000a      findingCount: report.axis2.byFile.length,\u000a      checks: {\u000a        preferenceMemories: report.axis2.totalPreferenceMemories,\u000a        everRetrieved: `${report.axis2.retrievalRate}%`,\u000a        avgUsefulness: report.axis2.avgUsefulness,\u000a        totalRetrievals: report.axis2.totalRetrievals,\u000a      },\u000a      findings: report.axis2.byFile.map((f: any) => ({\u000a        id: `axis2.file.${f.file}`,\u000a        severity: f.avgUsefulness < 0.5 ? "medium" : "low",\u000a        summary: `${f.file}: ${f.memories} memories, ${f.totalAccess} retrievals, avg usefulness ${round2(f.avgUsefulness)}.`,\u000a        action:\u000a          f.avgUsefulness < 0.5\u000a            ? "Low usefulness suggests these memories are being retrieved but not helpful — check chunking and embedding quality."\u000a            : "Healthy retrieval pattern.",\u000a      })),\u000a    },\u000a    {\u000a      key: "axis3-freshness",\u000a      label: "Axis 3",\u000a      goal: "Stay current over time: are retrieved memories fresh, or are stale/expired memories polluting results?",\u000a      findingCount: 1,\u000a      checks: {\u000a        freshScore: `${report.axis3.freshScore}%`,\u000a        softTarget: `${report.axis3.softTarget}%`,\u000a        totalRetrieved: report.axis3.totalUniqueMemoriesRetrieved,\u000a        staleReferents: report.axis3.staleReferentCount,\u000a      },\u000a      findings: [\u000a        {\u000a          id: "axis3.freshness-distribution",\u000a          severity:\u000a            report.axis3.freshScore >= 80 ? "low" : report.axis3.freshScore >= 50 ? "medium" : "high",\u000a          summary: `${report.axis3.freshScore}% of retrieved memories are fresh (<${report.axis3.freshDays}d). Aging: ${report.axis3.buckets.aging.pctOfRetrieved}%, Stranded: ${report.axis3.buckets.stranded.pctOfRetrieved}%, Expired: ${report.axis3.buckets.expired.pctOfRetrieved}%.`,\u000a          action:\u000a            report.axis3.freshScore < 80\u000a              ? "Stale memories are diluting retrieval quality. Prioritize TTL enforcement and the Memory Curator job."\u000a              : "Freshness meets target. Continue monitoring.",\u000a          samples: Object.entries(report.axis3.buckets).map(([k, v]: [string, any]) => ({\u000a            bucket: k,\u000a            uniqueMemories: v.uniqueMemories,\u000a            retrievals: v.retrievals,\u000a            pctOfRetrieved: `${v.pctOfRetrieved}%`,\u000a          })),\u000a        },\u000a      ],\u000a    },\u000a  ];\u000a\u000a  return sections\u000a    .map((section) => {\u000a      const findings = (section.findings || [])\u000a        .map(\u000a          (f) => `<article class="finding ${esc(severityTone(f.severity))}">\u000a          <div class="finding-head">\u000a            <div>\u000a              <p class="finding-id">${esc(f.id)}</p>\u000a              <h3>${esc(f.summary)}</h3>\u000a            </div>\u000a            <span class="pill ${esc(severityTone(f.severity))}">${esc(f.severity || "low")}</span>\u000a          </div>\u000a          ${f.action ? `<p class="action">${esc(f.action)}</p>` : ""}\u000a          ${renderSamples(f.samples)}\u000a        </article>`,\u000a        )\u000a        .join("");\u000a      const checks = Object.entries(section.checks || {})\u000a        .map(\u000a          ([label, value]) =>\u000a            `<div class="check"><span>${esc(humanLabel(label))}</span><strong>${esc(fmtMetric(value))}</strong></div>`,\u000a        )\u000a        .join("");\u000a      return `<section class="section">\u000a      <div class="section-grid">\u000a        <aside class="checks">\u000a          <p class="section-kicker">${esc(section.label || humanLabel(section.key))}</p>\u000a          <div class="check-list">${checks}</div>\u000a        </aside>\u000a        <div>\u000a          <div class="section-head">\u000a            <h2>${esc(section.goal)}</h2>\u000a            <span>${esc(fmtMetric(section.findingCount ?? section.findings?.length ?? 0))} finding(s)</span>\u000a          </div>\u000a          <div class="findings">${findings || ''<p class="empty">No actionable findings.</p>''}</div>\u000a        </div>\u000a      </div>\u000a    </section>`;\u000a    })\u000a    .join("\\n");\u000a}\u000a\u000afunction renderSamples(samples?: unknown[]): string {\u000a  if (!Array.isArray(samples) || samples.length === 0) return "";\u000a  const normalized = samples.map((row) =>\u000a    row && typeof row === "object" && !Array.isArray(row) ? (row as Record<string, unknown>) : { value: row },\u000a  );\u000a  const columns = Array.from(new Set(normalized.flatMap((row) => Object.keys(row).slice(0, 6)))).slice(0, 6);\u000a  if (columns.length === 0) return "";\u000a  const renderVal = (v: unknown) =>\u000a    Array.isArray(v) ? v.map((i) => (typeof i === "object" ? JSON.stringify(i) : String(i ?? ""))).join(", ") : typeof v === "object" && v ? JSON.stringify(v) : String(v ?? "");\u000a  const rows = normalized\u000a    .map((row) => `<tr>${columns.map((c) => `<td>${esc(renderVal(row[c]))}</td>`).join("")}</tr>`)\u000a    .join("");\u000a  return `<div class="sample-table"><table>\u000a    <thead><tr>${columns.map((c) => `<th>${esc(c.replace(/([a-z0-9])([A-Z])/g, "$1 $2").replace(/[-_.]+/g, " ").replace(/\\b\\w/g, (ch) => ch.toUpperCase()))}</th>`).join("")}</tr></thead>\u000a    <tbody>${rows}</tbody>\u000a  </table></div>`;\u000a}\u000a'),'3-axis memory quality evaluation: carry-forward context (do follow-up tasks retrieve useful memories from prior tasks?), follow preferences (are CLAUDE.md/IDENTITY.md/SOUL.md/TOOLS.md memories retrieved and useful?), and stay current (what fraction of retrieved memories are fresh vs stale?). Outputs a baseline report to agent-fs + a swarm Page.','Measure memory system health across OpenAI Dreaming-inspired axes — before/after baseline for architecture changes, blog-post numbers, daily quality monitoring.','{"argsType":"any","resultType":"unknown","description":"3-axis memory quality evaluation with over-time trend tracking and KV-backed historical backfill."}','83a2338bfdde40fac6b95e68c0c0e000bb081b83c81315854786e872cc1136b8',NULL,'2026-06-11T22:38:24.248Z','Seeded from the built-in scripts catalog (src/be/seed-scripts)',NULL,NULL);
INSERT INTO script_versions VALUES('904e7d9a-8b26-404f-98e7-fe701566ac66','166dea9e-4f94-4eb4-b02e-b51e6921dc9c',1,unistr('export type CatalogReportFinding = {\u000a  id: string;\u000a  severity?: string;\u000a  summary: string;\u000a  action?: string;\u000a  samples?: unknown[];\u000a};\u000a\u000aexport type CatalogReportSection = {\u000a  key: string;\u000a  label?: string;\u000a  goal: string;\u000a  findingCount?: number;\u000a  checks?: Record<string, unknown>;\u000a  findings?: CatalogReportFinding[];\u000a};\u000a\u000aexport type CatalogReport = {\u000a  title: string;\u000a  slug: string;\u000a  description: string;\u000a  generatedAt: string;\u000a  lede: string;\u000a  metrics: Array<[string, unknown]>;\u000a  sections: CatalogReportSection[];\u000a  appendix: unknown;\u000a};\u000a\u000afunction catalogReportAsText(value: unknown): string {\u000a  return typeof value === "string" ? value : value == null ? "" : JSON.stringify(value);\u000a}\u000a\u000afunction catalogReportHtmlEscape(value: unknown): string {\u000a  return catalogReportAsText(value)\u000a    .replace(/&/g, "&amp;")\u000a    .replace(/</g, "&lt;")\u000a    .replace(/>/g, "&gt;")\u000a    .replace(/"/g, "&quot;");\u000a}\u000a\u000afunction catalogReportHumanLabel(value: string): string {\u000a  return value\u000a    .replace(/([a-z0-9])([A-Z])/g, "$1 $2")\u000a    .replace(/[-_.]+/g, " ")\u000a    .replace(/\\b\\w/g, (char) => char.toUpperCase());\u000a}\u000a\u000afunction catalogReportFormatMetric(value: unknown): string {\u000a  if (typeof value === "number") return new Intl.NumberFormat("en-US").format(value);\u000a  return catalogReportAsText(value);\u000a}\u000a\u000afunction catalogReportSeverityTone(value?: string): string {\u000a  if (value === "critical") return "danger";\u000a  if (value === "high") return "warn";\u000a  if (value === "medium") return "note";\u000a  return "low";\u000a}\u000a\u000afunction catalogReportRenderSampleValue(value: unknown): string {\u000a  if (Array.isArray(value)) {\u000a    return value\u000a      .map((item) => (typeof item === "object" && item !== null ? JSON.stringify(item) : catalogReportAsText(item)))\u000a      .join(", ");\u000a  }\u000a  if (value && typeof value === "object") return JSON.stringify(value);\u000a  return catalogReportAsText(value);\u000a}\u000a\u000afunction catalogReportRenderSamples(samples?: unknown[]): string {\u000a  if (!Array.isArray(samples) || samples.length === 0) return "";\u000a  const normalized = samples.map((sampleRow) =>\u000a    sampleRow && typeof sampleRow === "object" && !Array.isArray(sampleRow)\u000a      ? (sampleRow as Record<string, unknown>)\u000a      : { value: sampleRow },\u000a  );\u000a  const columns = Array.from(\u000a    new Set(normalized.flatMap((sampleRow) => Object.keys(sampleRow).slice(0, 6))),\u000a  ).slice(0, 6);\u000a  if (columns.length === 0) return "";\u000a  const rows = normalized\u000a    .map(\u000a      (sampleRow) =>\u000a        `<tr>${columns\u000a          .map((column) => `<td>${catalogReportHtmlEscape(catalogReportRenderSampleValue(sampleRow[column]))}</td>`)\u000a          .join("")}</tr>`,\u000a    )\u000a    .join("");\u000a  return `<div class="sample-table" aria-label="Sample rows">\u000a    <table>\u000a      <thead><tr>${columns.map((column) => `<th>${catalogReportHtmlEscape(catalogReportHumanLabel(column))}</th>`).join("")}</tr></thead>\u000a      <tbody>${rows}</tbody>\u000a    </table>\u000a  </div>`;\u000a}\u000a\u000aexport function renderCatalogReportPage(report: CatalogReport): string {\u000a  const sections = report.sections\u000a    .map((section) => {\u000a      const findings = (section.findings || [])\u000a        .map(\u000a          (finding) => `<article class="finding ${catalogReportHtmlEscape(catalogReportSeverityTone(finding.severity))}">\u000a            <div class="finding-head">\u000a              <div>\u000a                <p class="finding-id">${catalogReportHtmlEscape(finding.id)}</p>\u000a                <h3>${catalogReportHtmlEscape(finding.summary)}</h3>\u000a              </div>\u000a              <span class="pill ${catalogReportHtmlEscape(catalogReportSeverityTone(finding.severity))}">${catalogReportHtmlEscape(\u000a                finding.severity || "low",\u000a              )}</span>\u000a            </div>\u000a            ${finding.action ? `<p class="action">${catalogReportHtmlEscape(finding.action)}</p>` : ""}\u000a            ${catalogReportRenderSamples(finding.samples)}\u000a          </article>`,\u000a        )\u000a        .join("");\u000a      const checks = Object.entries(section.checks || {})\u000a        .map(\u000a          ([label, value]) =>\u000a            `<div class="check"><span>${catalogReportHtmlEscape(catalogReportHumanLabel(label))}</span><strong>${catalogReportHtmlEscape(\u000a              catalogReportFormatMetric(value),\u000a            )}</strong></div>`,\u000a        )\u000a        .join("");\u000a      return `<section class="section">\u000a        <div class="section-grid">\u000a          <aside class="checks">\u000a            <p class="section-kicker">${catalogReportHtmlEscape(section.label || catalogReportHumanLabel(section.key))}</p>\u000a            <div class="check-list">${checks}</div>\u000a          </aside>\u000a          <div>\u000a            <div class="section-head">\u000a              <h2>${catalogReportHtmlEscape(section.goal)}</h2>\u000a              <span>${catalogReportHtmlEscape(catalogReportFormatMetric(section.findingCount ?? section.findings?.length ?? 0))} finding(s)</span>\u000a            </div>\u000a            <div class="findings">\u000a              ${findings || ''<p class="empty">No actionable findings in this cluster.</p>''}\u000a            </div>\u000a          </div>\u000a        </div>\u000a      </section>`;\u000a    })\u000a    .join("\\n");\u000a  return `<!doctype html>\u000a<html lang="en">\u000a<head>\u000a  <meta charset="utf-8">\u000a  <meta name="viewport" content="width=device-width, initial-scale=1">\u000a  <meta name="theme-color" content="#f5f2ea">\u000a  <title>${catalogReportHtmlEscape(report.title)}</title>\u000a  <style>\u000a    :root {\u000a      color-scheme: light;\u000a      --bg: #f5f2ea;\u000a      --panel: #ffffff;\u000a      --ink: #18181b;\u000a      --muted: #5f6368;\u000a      --line: #ded8cb;\u000a      --accent: #255c99;\u000a      --danger: #b42318;\u000a      --danger-bg: #fff1f0;\u000a      --warn: #b54708;\u000a      --warn-bg: #fff7ed;\u000a      --note: #175cd3;\u000a      --note-bg: #eff6ff;\u000a      --low: #067647;\u000a      --low-bg: #ecfdf3;\u000a      --radius: 8px;\u000a      --shadow: 0 1px 2px rgba(24, 24, 27, 0.06), 0 14px 36px rgba(24, 24, 27, 0.07);\u000a    }\u000a    * { box-sizing: border-box; }\u000a    body {\u000a      margin: 0;\u000a      background: var(--bg);\u000a      color: var(--ink);\u000a      font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;\u000a      font-size: 16px;\u000a      line-height: 1.55;\u000a    }\u000a    main {\u000a      width: min(1120px, calc(100% - 32px));\u000a      margin: 0 auto;\u000a      padding: 48px 0 72px;\u000a    }\u000a    header { margin-bottom: 28px; }\u000a    .eyebrow {\u000a      margin: 0 0 8px;\u000a      color: var(--muted);\u000a      font-size: 13px;\u000a      font-weight: 750;\u000a      letter-spacing: 0.08em;\u000a      text-transform: uppercase;\u000a    }\u000a    h1 {\u000a      margin: 0;\u000a      max-width: 860px;\u000a      font-size: clamp(2rem, 4vw, 3rem);\u000a      line-height: 1.05;\u000a      letter-spacing: 0;\u000a    }\u000a    .lede {\u000a      max-width: 780px;\u000a      margin: 16px 0 0;\u000a      color: var(--muted);\u000a      font-size: 18px;\u000a    }\u000a    .metrics {\u000a      display: grid;\u000a      grid-template-columns: repeat(4, minmax(0, 1fr));\u000a      gap: 12px;\u000a      margin: 32px 0;\u000a    }\u000a    .metric, .section, details {\u000a      background: var(--panel);\u000a      border: 1px solid var(--line);\u000a      border-radius: var(--radius);\u000a      box-shadow: var(--shadow);\u000a    }\u000a    .metric { padding: 18px; }\u000a    .metric strong {\u000a      display: block;\u000a      font-size: 32px;\u000a      line-height: 1;\u000a      font-variant-numeric: tabular-nums;\u000a    }\u000a    .metric span {\u000a      display: block;\u000a      margin-top: 8px;\u000a      color: var(--muted);\u000a      font-size: 13px;\u000a      font-weight: 650;\u000a    }\u000a    .section {\u000a      margin-top: 18px;\u000a      padding: 24px;\u000a    }\u000a    .section-grid {\u000a      display: grid;\u000a      grid-template-columns: 260px minmax(0, 1fr);\u000a      gap: 28px;\u000a    }\u000a    .section-kicker {\u000a      margin: 0 0 12px;\u000a      color: var(--accent);\u000a      font-size: 13px;\u000a      font-weight: 800;\u000a      letter-spacing: 0.08em;\u000a      text-transform: uppercase;\u000a    }\u000a    .check-list {\u000a      display: grid;\u000a      gap: 8px;\u000a    }\u000a    .check {\u000a      display: flex;\u000a      align-items: baseline;\u000a      justify-content: space-between;\u000a      gap: 12px;\u000a      padding: 10px 0;\u000a      border-bottom: 1px solid var(--line);\u000a    }\u000a    .check span {\u000a      color: var(--muted);\u000a      font-size: 13px;\u000a    }\u000a    .check strong {\u000a      font-size: 18px;\u000a      font-variant-numeric: tabular-nums;\u000a    }\u000a    .section-head {\u000a      display: flex;\u000a      align-items: start;\u000a      justify-content: space-between;\u000a      gap: 16px;\u000a      margin-bottom: 16px;\u000a    }\u000a    .section-head h2 {\u000a      max-width: 680px;\u000a      margin: 0;\u000a      font-size: 24px;\u000a      line-height: 1.2;\u000a      letter-spacing: 0;\u000a    }\u000a    .section-head > span {\u000a      flex: 0 0 auto;\u000a      color: var(--muted);\u000a      font-size: 13px;\u000a      font-weight: 700;\u000a      white-space: nowrap;\u000a    }\u000a    .findings {\u000a      display: grid;\u000a      gap: 12px;\u000a    }\u000a    .finding {\u000a      border: 1px solid var(--line);\u000a      border-left: 4px solid var(--note);\u000a      border-radius: var(--radius);\u000a      padding: 16px;\u000a      background: #fffdf8;\u000a    }\u000a    .finding.danger { border-left-color: var(--danger); }\u000a    .finding.warn { border-left-color: var(--warn); }\u000a    .finding.low { border-left-color: var(--low); }\u000a    .finding-head {\u000a      display: flex;\u000a      align-items: start;\u000a      justify-content: space-between;\u000a      gap: 16px;\u000a    }\u000a    .finding-id {\u000a      margin: 0 0 4px;\u000a      color: var(--muted);\u000a      font-family: ui-monospace, SFMono-Regular, Menlo, Consolas, monospace;\u000a      font-size: 12px;\u000a    }\u000a    h3 {\u000a      margin: 0;\u000a      font-size: 17px;\u000a      line-height: 1.3;\u000a      letter-spacing: 0;\u000a    }\u000a    .pill {\u000a      display: inline-flex;\u000a      align-items: center;\u000a      min-height: 26px;\u000a      padding: 4px 9px;\u000a      border-radius: 999px;\u000a      font-size: 12px;\u000a      font-weight: 800;\u000a      text-transform: uppercase;\u000a      white-space: nowrap;\u000a    }\u000a    .pill.danger { background: var(--danger-bg); color: var(--danger); }\u000a    .pill.warn { background: var(--warn-bg); color: var(--warn); }\u000a    .pill.note { background: var(--note-bg); color: var(--note); }\u000a    .pill.low { background: var(--low-bg); color: var(--low); }\u000a    .action {\u000a      margin: 10px 0 0;\u000a      color: var(--muted);\u000a    }\u000a    .sample-table {\u000a      margin-top: 14px;\u000a      overflow-x: auto;\u000a      border: 1px solid var(--line);\u000a      border-radius: var(--radius);\u000a      background: var(--panel);\u000a    }\u000a    table {\u000a      width: 100%;\u000a      min-width: 640px;\u000a      border-collapse: collapse;\u000a    }\u000a    th, td {\u000a      padding: 10px 12px;\u000a      border-bottom: 1px solid var(--line);\u000a      text-align: left;\u000a      vertical-align: top;\u000a    }\u000a    th {\u000a      color: var(--muted);\u000a      font-size: 12px;\u000a      font-weight: 800;\u000a      letter-spacing: 0.06em;\u000a      text-transform: uppercase;\u000a    }\u000a    td {\u000a      max-width: 360px;\u000a      color: #27272a;\u000a      font-size: 13px;\u000a      overflow-wrap: anywhere;\u000a    }\u000a    tr:last-child td { border-bottom: 0; }\u000a    .empty {\u000a      margin: 0;\u000a      color: var(--muted);\u000a    }\u000a    details {\u000a      margin-top: 24px;\u000a      padding: 18px;\u000a    }\u000a    summary {\u000a      cursor: pointer;\u000a      font-weight: 800;\u000a    }\u000a    pre {\u000a      margin: 16px 0 0;\u000a      max-height: 560px;\u000a      overflow: auto;\u000a      padding: 16px;\u000a      border-radius: var(--radius);\u000a      background: #111827;\u000a      color: #f9fafb;\u000a      font-size: 12px;\u000a      line-height: 1.45;\u000a    }\u000a    @media (max-width: 860px) {\u000a      main { width: min(100% - 24px, 1120px); padding-top: 32px; }\u000a      .metrics { grid-template-columns: repeat(2, minmax(0, 1fr)); }\u000a      .section-grid { grid-template-columns: 1fr; gap: 18px; }\u000a      .section { padding: 18px; }\u000a      .section-head { display: block; }\u000a      .section-head > span { display: block; margin-top: 8px; }\u000a    }\u000a    @media (max-width: 520px) {\u000a      .metrics { grid-template-columns: 1fr; }\u000a      .lede { font-size: 16px; }\u000a      .finding-head { display: block; }\u000a      .pill { margin-top: 10px; }\u000a    }\u000a  </style>\u000a</head>\u000a<body>\u000a  <main>\u000a    <header>\u000a      <p class="eyebrow">Generated ${catalogReportHtmlEscape(report.generatedAt)}</p>\u000a      <h1>${catalogReportHtmlEscape(report.title)}</h1>\u000a      <p class="lede">${catalogReportHtmlEscape(report.lede)}</p>\u000a    </header>\u000a    <section class="metrics" aria-label="Audit summary">\u000a      ${report.metrics\u000a        .map(\u000a          ([label, value]) =>\u000a            `<div class="metric"><strong>${catalogReportHtmlEscape(catalogReportFormatMetric(value))}</strong><span>${catalogReportHtmlEscape(\u000a              label,\u000a            )}</span></div>`,\u000a        )\u000a        .join("")}\u000a    </section>\u000a    ${sections}\u000a    <details>\u000a      <summary>Compressed JSON appendix</summary>\u000a      <pre>${catalogReportHtmlEscape(JSON.stringify(report.appendix, null, 2))}</pre>\u000a    </details>\u000a  </main>\u000a</body>\u000a</html>`;\u000a}\u000a\u000aexport async function publishCatalogReportPage(report: CatalogReport, ctx: any): Promise<any> {\u000a  const response = await ctx.swarm.page_create({\u000a    title: report.title,\u000a    slug: report.slug,\u000a    description: report.description,\u000a    contentType: "text/html",\u000a    authMode: "authed",\u000a    body: renderCatalogReportPage(report),\u000a  });\u000a  const payload = response?.data ?? response;\u000a  if (payload?.success === false) return { error: payload.error || "page_create failed" };\u000a  return {\u000a    id: payload?.id ?? payload?.page?.id ?? null,\u000a    appUrl: payload?.appUrl ?? payload?.app_url ?? null,\u000a    apiUrl: payload?.apiUrl ?? payload?.api_url ?? null,\u000a    version: payload?.version ?? payload?.page?.version ?? null,\u000a  };\u000a}\u000a\u000a\u000aimport { z } from "zod";\u000aexport const argsSchema = z.object({\u000a  nowIso: z.string().optional().describe("Audit clock override (default: current time)"),\u000a  publishPage: z.boolean().optional().describe("Publish an authed HTML page (default true)"),\u000a  includeSamples: z\u000a    .boolean()\u000a    .optional()\u000a    .describe("Include small row samples for each finding cluster (default true)"),\u000a  staleScheduleDays: z\u000a    .number()\u000a    .int()\u000a    .positive()\u000a    .optional()\u000a    .describe("Flag enabled schedules with no run for this many days (default 14)"),\u000a  tempScheduleNames: z\u000a    .array(z.string())\u000a    .optional()\u000a    .describe("Known temporary schedule name fragments that should self-lift"),\u000a});\u000a\u000aconst CODE_WORK_RE =\u000a  /\\b(git|github|gh\\b|gh-cli|docker|docker-compose|bun|npm|pnpm|yarn|tsc|eslint|lint|test|pr\\b|pull request|branch|commit|repo|worktree|typescript|javascript)\\b/i;\u000aconst CODE_AGENT_RE =\u000a  /\\b(code|coder|coding|implement|implementation|engineer|software|typescript|javascript|repo|github)\\b/i;\u000aconst NON_CODE_AGENT_RE = /\\b(content|reviewer|research|sales|gtm|support|ops|lead)\\b/i;\u000aconst SMOKE_WORKFLOW_RE =\u000a  /\\b(smoke|demo|litmus-smoke|one[- ]shot|validation|des-462-gate-validation|gsc-runtime-smoke)\\b/i;\u000aconst GATE_WORKFLOW_RE = /\\b(litmus|gate|eval|review|validation|quality|structured)\\b/i;\u000aconst STALE_URL_RE =\u000a  /\\b(localhost|127\\.0\\.0\\.1|api\\.example-swarm\\.dev|app\\.example-swarm\\.dev|example-swarm\\.dev|fly\\.dev)\\b/i;\u000aconst CONTRADICTORY_RE =\u000a  /\\b(do not|don''t|never)\\b[\\s\\S]{0,240}\\b(always|must|required)\\b|\\b(always|must|required)\\b[\\s\\S]{0,240}\\b(do not|don''t|never)\\b/i;\u000a\u000aconst CODE_REGISTRY_EVENTS =\u000a  "agentmail.email.followup agentmail.email.mapped_lead agentmail.email.mapped_worker agentmail.email.no_agent agentmail.email.unmapped common.command_suggestions.github_comment_issue common.command_suggestions.github_comment_pr common.command_suggestions.github_issue common.command_suggestions.github_pr common.command_suggestions.gitlab_issue common.command_suggestions.gitlab_mr common.delegation_instruction common.delegation_instruction.gitlab github.check_run.failed github.check_suite.failed github.comment.mentioned github.issue.assigned github.issue.labeled github.issue.mentioned github.pull_request.assigned github.pull_request.closed github.pull_request.labeled github.pull_request.mentioned github.pull_request.review_requested github.pull_request.review_submitted github.pull_request.synchronize github.workflow_run.failed gitlab.comment.mentioned gitlab.issue.assigned gitlab.merge_request.opened gitlab.pipeline.failed heartbeat.boot-triage heartbeat.checklist jira.issue.assigned jira.issue.commented jira.issue.followup kapso.message.received linear.issue.assigned linear.issue.followup linear.issue.reassigned slack.assistant.greeting slack.assistant.offline slack.assistant.suggested_prompts slack.message.thread_context system.agent.agent_fs system.agent.artifacts system.agent.code_quality system.agent.context_mode system.agent.filesystem system.agent.lead system.agent.register system.agent.role system.agent.seed_scripts system.agent.self_awareness system.agent.services system.agent.share_urls system.agent.slack system.agent.system system.agent.worker system.agent.worker.remote system.agent.worker.slack system.session.lead system.session.worker system.session.worker.pi system.session.worker.remote task.budget.refused task.requester.profile task.worker.completed task.worker.failed".split(\u000a    " ",\u000a  );\u000a\u000afunction rowsToObjects(res: any): any[] {\u000a  const p = res?.data ?? res;\u000a  const cols: string[] = p?.columns ?? [];\u000a  return (p?.rows ?? []).map((r: any) =>\u000a    Array.isArray(r) ? Object.fromEntries(cols.map((c, i) => [c, r[i]])) : r,\u000a  );\u000a}\u000a\u000aasync function query(ctx: any, sql: string, params?: unknown[]): Promise<any[]> {\u000a  try {\u000a    return rowsToObjects(await ctx.swarm.db_query({ sql, params }));\u000a  } catch (error) {\u000a    return [{ unavailable: error instanceof Error ? error.message : String(error) }];\u000a  }\u000a}\u000a\u000afunction safeJson(value: unknown, fallback: any = null): any {\u000a  if (typeof value !== "string") return value ?? fallback;\u000a  try {\u000a    return JSON.parse(value);\u000a  } catch {\u000a    return fallback;\u000a  }\u000a}\u000a\u000afunction asBool(value: unknown): boolean {\u000a  return value === true || value === 1 || value === "1";\u000a}\u000a\u000afunction asText(value: unknown): string {\u000a  return typeof value === "string" ? value : value == null ? "" : JSON.stringify(value);\u000a}\u000a\u000afunction compactText(value: unknown, max = 180): string {\u000a  return asText(value).replace(/\\s+/g, " ").trim().slice(0, max);\u000a}\u000a\u000afunction formatMetric(value: unknown): string {\u000a  if (typeof value === "number") return new Intl.NumberFormat("en-US").format(value);\u000a  return asText(value);\u000a}\u000a\u000afunction daysSince(iso: string | null | undefined, nowMs: number): number | null {\u000a  if (!iso) return null;\u000a  const t = Date.parse(iso);\u000a  if (!Number.isFinite(t)) return null;\u000a  return Math.round((nowMs - t) / 86400000);\u000a}\u000a\u000afunction severity(rank: number): "critical" | "high" | "medium" | "low" {\u000a  if (rank >= 4) return "critical";\u000a  if (rank === 3) return "high";\u000a  if (rank === 2) return "medium";\u000a  return "low";\u000a}\u000a\u000afunction sample<T>(rows: T[], includeSamples: boolean, limit = 5): T[] {\u000a  return includeSamples ? rows.slice(0, limit) : [];\u000a}\u000a\u000afunction isCodeCapable(agent: any): boolean {\u000a  if (!agent) return false;\u000a  const text = [\u000a    agent.name,\u000a    agent.role,\u000a    agent.description,\u000a    Array.isArray(agent.capabilities) ? agent.capabilities.join(" ") : agent.capabilities,\u000a  ]\u000a    .filter(Boolean)\u000a    .join(" ");\u000a  if (!CODE_AGENT_RE.test(text)) return false;\u000a  if (NON_CODE_AGENT_RE.test(text) && !/\\bpicateclas\\b/i.test(text)) return false;\u000a  return true;\u000a}\u000a\u000afunction nodeList(definition: any): any[] {\u000a  return Array.isArray(definition?.nodes) ? definition.nodes : [];\u000a}\u000a\u000afunction hasStructuredOutput(value: any): boolean {\u000a  return /"outputSchema"|"schema"|"jsonSchema"|"structured"/i.test(JSON.stringify(value ?? {}));\u000a}\u000a\u000aexport function buildReport(result: any): CatalogReport {\u000a  return {\u000a    title: "Ops Catalog Audit",\u000a    slug: "ops-catalog-audit",\u000a    description: "Clustered audit-as-code report for schedules, workflows, and prompts/templates.",\u000a    generatedAt: result.generatedAt,\u000a    lede: `A re-runnable audit of schedules, workflows, and prompt/template catalogs. It found ${formatMetric(\u000a      result.summary.findingsTotal,\u000a    )} actionable issue cluster(s), with the highest-risk items called out first inside each group.`,\u000a    metrics: [\u000a    ["Findings", result.summary.findingsTotal],\u000a    ["Schedules enabled", result.summary.schedulesEnabled],\u000a    ["Workflows enabled", result.summary.workflowsEnabled],\u000a    ["Prompt templates", result.summary.promptTemplates],\u000a    ],\u000a    sections: ["schedules", "workflows", "promptsTemplates"].map((key) => ({\u000a      key,\u000a      goal: result.goals[key].goal,\u000a      findingCount: result.goals[key].findingCount,\u000a      checks: result.goals[key].checks,\u000a      findings: result.goals[key].findings,\u000a    })),\u000a    appendix: result,\u000a  };\u000a}\u000a\u000aexport function renderPage(result: any): string {\u000a  return renderCatalogReportPage(buildReport(result));\u000a}\u000a\u000a/** Audit schedules, workflows, and prompt/template catalogs by goal, with optional authed page output. */\u000aexport default async function opsCatalogAudit(args: any, ctx: any) {\u000a  const parsed = argsSchema.safeParse(args || {});\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a\u000a  const now = parsed.data.nowIso ? new Date(parsed.data.nowIso) : new Date();\u000a  const nowMs = now.getTime();\u000a  const publishPage = parsed.data.publishPage !== false;\u000a  const includeSamples = parsed.data.includeSamples !== false;\u000a  const staleScheduleDays = parsed.data.staleScheduleDays || 14;\u000a  const tempScheduleNames = parsed.data.tempScheduleNames || [\u000a    "memory-gate-597",\u000a    "swarm-postdeploy-memory",\u000a  ];\u000a\u000a  const scheduleRows = await query(\u000a    ctx,\u000a    `SELECT s.*, a.name as targetAgentName, a.role as targetAgentRole,\u000a            a.description as targetAgentDescription, a.capabilities as targetAgentCapabilities,\u000a            a.provider as targetAgentProvider, a.harness_provider as targetAgentHarnessProvider\u000a     FROM scheduled_tasks s LEFT JOIN agents a ON a.id = s.targetAgentId\u000a     WHERE s.enabled = 1 ORDER BY s.name ASC`,\u000a  );\u000a  const schedules = scheduleRows.filter((r) => !r.unavailable);\u000a  const agentsById = new Map<string, any>();\u000a  for (const s of schedules) {\u000a    if (!s.targetAgentId) continue;\u000a    agentsById.set(s.targetAgentId, {\u000a      id: s.targetAgentId,\u000a      name: s.targetAgentName,\u000a      role: s.targetAgentRole,\u000a      description: s.targetAgentDescription,\u000a      capabilities: safeJson(s.targetAgentCapabilities, []),\u000a      provider: s.targetAgentProvider,\u000a      harnessProvider: s.targetAgentHarnessProvider,\u000a    });\u000a  }\u000a\u000a  const duplicateCronGroups = Object.values(\u000a    schedules.reduce((acc: any, s: any) => {\u000a      const cron = s.cronExpression || (s.intervalMs ? `interval:${s.intervalMs}` : "");\u000a      if (!cron) return acc;\u000a      const key = `${cron}::${s.timezone || "UTC"}`;\u000a      acc[key] ??= { key, cron, timezone: s.timezone || "UTC", schedules: [] };\u000a      acc[key].schedules.push({ id: s.id, name: s.name });\u000a      return acc;\u000a    }, {}),\u000a  ).filter((g: any) => g.schedules.length > 1);\u000a\u000a  const deadSchedules = schedules.filter((s: any) => {\u000a    const noNext = !s.nextRunAt && s.scheduleType === "recurring";\u000a    const stale = (daysSince(s.lastRunAt, nowMs) ?? 0) >= staleScheduleDays;\u000a    return noNext || stale || Number(s.consecutiveErrors || 0) > 0;\u000a  });\u000a\u000a  const tempSchedules = schedules.filter((s: any) => {\u000a    const haystack = `${s.name || ""}\\n${s.description || ""}\\n${s.taskTemplate || ""}`.toLowerCase();\u000a    const known = tempScheduleNames.some((name) => haystack.includes(name.toLowerCase()));\u000a    const dateMatches = [\u000a      ...haystack.matchAll(\u000a        /\\b(?:self[- ]lift|remove|disable|until|through|expires?)\\D{0,40}(\\d{4}-\\d{2}-\\d{2})/g,\u000a      ),\u000a    ];\u000a    const expired = dateMatches.some((m) => (m[1] ? Date.parse(m[1]) <= nowMs : false));\u000a    return known || expired;\u000a  });\u000a\u000a  const routingRisks = schedules\u000a    .filter((s: any) => CODE_WORK_RE.test(`${s.name || ""}\\n${s.tags || ""}\\n${s.taskTemplate || ""}`))\u000a    .map((s: any) => {\u000a      const target = s.targetAgentId ? agentsById.get(s.targetAgentId) : null;\u000a      const pool = !s.targetAgentId;\u000a      const opencode = target?.provider === "opencode" || target?.harnessProvider === "opencode";\u000a      const risky = pool || !isCodeCapable(target) || opencode;\u000a      return risky\u000a        ? {\u000a            id: s.id,\u000a            name: s.name,\u000a            targetAgentId: s.targetAgentId || null,\u000a            targetAgentName: target?.name || null,\u000a            reason: pool\u000a              ? "pool-targeted code work"\u000a              : opencode\u000a                ? "opencode target for code work"\u000a                : "target is not code-capable",\u000a            action: "Pin this schedule to a code-capable worker targetAgentId before it runs again.",\u000a          }\u000a        : null;\u000a    })\u000a    .filter(Boolean);\u000a\u000a  const workflowRows = await query(\u000a    ctx,\u000a    `SELECT id, name, description, enabled, definition, triggers, input, triggerSchema, createdAt, lastUpdatedAt\u000a     FROM workflows ORDER BY name ASC`,\u000a  );\u000a  const workflows = workflowRows.filter((r) => !r.unavailable);\u000a  const enabledWorkflows = workflows.filter((w: any) => asBool(w.enabled));\u000a  const smokeEnabled = enabledWorkflows\u000a    .filter((w: any) => SMOKE_WORKFLOW_RE.test(`${w.name || ""}\\n${w.description || ""}`))\u000a    .map((w: any) => ({\u000a      id: w.id,\u000a      name: w.name,\u000a      action: "Disable or delete if this was only a smoke/eval fixture.",\u000a    }));\u000a  const gateCoverageGaps = enabledWorkflows\u000a    .map((w: any) => {\u000a      const definition = safeJson(w.definition, {});\u000a      const text = `${w.name || ""}\\n${w.description || ""}\\n${JSON.stringify(definition)}`;\u000a      const structured =\u000a        hasStructuredOutput(definition) ||\u000a        hasStructuredOutput(safeJson(w.input, {})) ||\u000a        hasStructuredOutput(safeJson(w.triggerSchema, {}));\u000a      if (!GATE_WORKFLOW_RE.test(text) || structured) return null;\u000a      return {\u000a        id: w.id,\u000a        name: w.name,\u000a        nodeCount: nodeList(definition).length,\u000a        action: "Add outputSchema/schema coverage to litmus/eval/gate nodes so downstream checks are deterministic.",\u000a      };\u000a    })\u000a    .filter(Boolean);\u000a  const workflowTypeRows = enabledWorkflows.map((w: any) => {\u000a    const definition = safeJson(w.definition, {});\u000a    const nodes = nodeList(definition);\u000a    const nodeTypes = Array.from(new Set(nodes.map((n: any) => n.type).filter(Boolean))).sort();\u000a    const loadBearing =\u000a      !SMOKE_WORKFLOW_RE.test(`${w.name || ""}\\n${w.description || ""}`) && nodes.length > 1;\u000a    return {\u000a      id: w.id,\u000a      name: w.name,\u000a      nodeCount: nodes.length,\u000a      nodeTypes,\u000a      class: loadBearing ? "load-bearing" : "fixture-or-small",\u000a    };\u000a  });\u000a\u000a  const promptRows = await query(\u000a    ctx,\u000a    `SELECT id, eventType, scope, scopeId, state, body, isDefault, version, createdBy, updatedAt\u000a     FROM prompt_templates ORDER BY eventType ASC, scope ASC`,\u000a  );\u000a  const prompts = promptRows.filter((r) => !r.unavailable);\u000a  const expectedEvents = new Set(CODE_REGISTRY_EVENTS);\u000a  const defaultEvents = new Set(prompts.filter((p: any) => asBool(p.isDefault)).map((p: any) => p.eventType));\u000a  const liveEvents = new Set(prompts.map((p: any) => p.eventType));\u000a  const missingDefaultEvents = [...expectedEvents].filter((e) => !defaultEvents.has(e)).sort();\u000a  const dbOnlyEvents = [...liveEvents].filter((e) => !expectedEvents.has(e) && !e.startsWith("test.")).sort();\u000a\u000a  const bodyGroups: Record<string, any[]> = {};\u000a  for (const p of prompts) {\u000a    const key = compactText(p.body, 500);\u000a    if (!key) continue;\u000a    bodyGroups[key] ??= [];\u000a    bodyGroups[key].push({\u000a      id: p.id,\u000a      eventType: p.eventType,\u000a      scope: p.scope,\u000a      scopeId: p.scopeId,\u000a    });\u000a  }\u000a  const duplicatePromptBodies = Object.values(bodyGroups).filter((group) => group.length > 1);\u000a  const staleUrlPrompts = prompts\u000a    .filter((p: any) => STALE_URL_RE.test(p.body || ""))\u000a    .map((p: any) => ({\u000a      id: p.id,\u000a      eventType: p.eventType,\u000a      scope: p.scope,\u000a      match: (p.body.match(STALE_URL_RE) || [])[0],\u000a    }));\u000a  const contradictoryPrompts = prompts\u000a    .filter((p: any) => CONTRADICTORY_RE.test(p.body || ""))\u000a    .map((p: any) => ({ id: p.id, eventType: p.eventType, scope: p.scope }));\u000a  const skillDuplicateRows = await query(\u000a    ctx,\u000a    `SELECT name, count(*) as count,\u000a            group_concat(scope || '':'' || coalesce(ownerAgentId, ''global''), '', '') as locations\u000a     FROM skills\u000a     WHERE isEnabled = 1 AND systemDefault = 1\u000a     GROUP BY name HAVING count(*) > 1 ORDER BY count DESC, name ASC`,\u000a  );\u000a  const systemDefaultSkillDuplicates = skillDuplicateRows.filter((r) => !r.unavailable);\u000a  const skillDuplicateUnavailable = skillDuplicateRows.find((r) => r.unavailable)?.unavailable;\u000a\u000a  const findings = {\u000a    schedules: [\u000a      duplicateCronGroups.length && {\u000a        id: "schedules.duplicate-crons",\u000a        severity: severity(duplicateCronGroups.length > 2 ? 3 : 2),\u000a        summary: `${duplicateCronGroups.length} duplicate enabled cron/interval group(s).`,\u000a        action: "Confirm whether each duplicate group is intentional; consolidate or retarget redundant schedules.",\u000a        samples: sample(duplicateCronGroups, includeSamples),\u000a      },\u000a      deadSchedules.length && {\u000a        id: "schedules.dead-or-stale",\u000a        severity: severity(deadSchedules.length > 3 ? 3 : 2),\u000a        summary: `${deadSchedules.length} enabled schedule(s) look dead, stale, or erroring.`,\u000a        action: `Disable dead schedules or repair nextRunAt/cron/errors. Stale threshold: ${staleScheduleDays} days.`,\u000a        samples: sample(\u000a          deadSchedules.map((s: any) => ({\u000a            id: s.id,\u000a            name: s.name,\u000a            nextRunAt: s.nextRunAt,\u000a            lastRunAt: s.lastRunAt,\u000a            consecutiveErrors: s.consecutiveErrors,\u000a          })),\u000a          includeSamples,\u000a        ),\u000a      },\u000a      tempSchedules.length && {\u000a        id: "schedules.temporary-self-lift",\u000a        severity: "high",\u000a        summary: `${tempSchedules.length} temporary monitor schedule(s) may be past self-lift.`,\u000a        action: "Review the named temporary monitors and disable/delete the ones whose guard window has expired.",\u000a        samples: sample(\u000a          tempSchedules.map((s: any) => ({ id: s.id, name: s.name })),\u000a          includeSamples,\u000a        ),\u000a      },\u000a      routingRisks.length && {\u000a        id: "schedules.rule-13-15-routing",\u000a        severity: "critical",\u000a        summary: `${routingRisks.length} enabled code-work schedule(s) are not pinned to a code-capable worker.`,\u000a        action: "Set targetAgentId to a code-capable worker; never leave git/docker/bun/gh work on the pool.",\u000a        samples: sample(routingRisks, includeSamples),\u000a      },\u000a    ].filter(Boolean),\u000a    workflows: [\u000a      smokeEnabled.length && {\u000a        id: "workflows.enabled-fixtures",\u000a        severity: severity(smokeEnabled.length > 2 ? 3 : 2),\u000a        summary: `${smokeEnabled.length} enabled workflow(s) look like smoke/demo/one-shot fixtures.`,\u000a        action: "Disable fixture workflows unless they are explicitly load-bearing production gates.",\u000a        samples: sample(smokeEnabled, includeSamples),\u000a      },\u000a      gateCoverageGaps.length && {\u000a        id: "workflows.structured-output-gaps",\u000a        severity: "high",\u000a        summary: `${gateCoverageGaps.length} litmus/eval/gate workflow(s) lack visible structured-output schema coverage.`,\u000a        action: "Add outputSchema/schema coverage so gate outputs can be regression-checked.",\u000a        samples: sample(gateCoverageGaps, includeSamples),\u000a      },\u000a    ].filter(Boolean),\u000a    promptsTemplates: [\u000a      (missingDefaultEvents.length || dbOnlyEvents.length) && {\u000a        id: "prompts.registry-drift",\u000a        severity: severity(missingDefaultEvents.length > 0 ? 3 : 2),\u000a        summary: `${missingDefaultEvents.length} code registry event(s) missing default DB rows; ${dbOnlyEvents.length} DB event(s) absent from code registry.`,\u000a        action: "Re-seed prompt templates or remove stale DB-only templates after confirming no runtime still emits them.",\u000a        samples: sample(\u000a          [\u000a            ...missingDefaultEvents.slice(0, 5).map((eventType) => ({\u000a              kind: "missing-default",\u000a              eventType,\u000a            })),\u000a            ...dbOnlyEvents.slice(0, 5).map((eventType) => ({ kind: "db-only", eventType })),\u000a          ],\u000a          includeSamples,\u000a          10,\u000a        ),\u000a      },\u000a      duplicatePromptBodies.length && {\u000a        id: "prompts.redundant-bodies",\u000a        severity: "medium",\u000a        summary: `${duplicatePromptBodies.length} prompt body group(s) are duplicated across templates.`,\u000a        action: "Extract shared text into a template reference or remove redundant overrides.",\u000a        samples: sample(duplicatePromptBodies, includeSamples, 3),\u000a      },\u000a      staleUrlPrompts.length && {\u000a        id: "prompts.stale-urls-hosts",\u000a        severity: "high",\u000a        summary: `${staleUrlPrompts.length} prompt template(s) contain stale/local/example hosts.`,\u000a        action: "Replace hardcoded hosts with runtime env-var guidance or current public hosts.",\u000a        samples: sample(staleUrlPrompts, includeSamples),\u000a      },\u000a      contradictoryPrompts.length && {\u000a        id: "prompts.contradictory-instructions",\u000a        severity: "medium",\u000a        summary: `${contradictoryPrompts.length} prompt template(s) contain nearby must/never style conflicts worth review.`,\u000a        action: "Tighten redundant or conflicting instruction blocks so workers do not receive mixed routing guidance.",\u000a        samples: sample(contradictoryPrompts, includeSamples),\u000a      },\u000a      (systemDefaultSkillDuplicates.length || skillDuplicateUnavailable) && {\u000a        id: "prompts.system-default-skill-duplicates",\u000a        severity: systemDefaultSkillDuplicates.length ? "high" : "low",\u000a        summary: skillDuplicateUnavailable\u000a          ? `Could not query systemDefault skill duplicates: ${skillDuplicateUnavailable}`\u000a          : `${systemDefaultSkillDuplicates.length} systemDefault skill name(s) are duplicated.`,\u000a        action: "Deduplicate system-default skills so prompt skill seeding is stable and non-redundant.",\u000a        samples: sample(systemDefaultSkillDuplicates, includeSamples),\u000a      },\u000a    ].filter(Boolean),\u000a  };\u000a\u000a  const result: any = {\u000a    generatedAt: now.toISOString(),\u000a    script: "ops-catalog-audit",\u000a    summary: {\u000a      schedulesEnabled: schedules.length,\u000a      workflowsTotal: workflows.length,\u000a      workflowsEnabled: enabledWorkflows.length,\u000a      promptTemplates: prompts.length,\u000a      findingsTotal:\u000a        findings.schedules.length + findings.workflows.length + findings.promptsTemplates.length,\u000a    },\u000a    goals: {\u000a      schedules: {\u000a        goal: "Reduce schedule cost/context waste and prevent misrouted code work.",\u000a        findingCount: findings.schedules.length,\u000a        checks: {\u000a          duplicateCronGroups: duplicateCronGroups.length,\u000a          deadOrStaleSchedules: deadSchedules.length,\u000a          temporarySelfLiftSchedules: tempSchedules.length,\u000a          routingRisks: routingRisks.length,\u000a        },\u000a        findings: findings.schedules,\u000a      },\u000a      workflows: {\u000a        goal: "Separate load-bearing workflows from fixtures and enforce deterministic gate outputs.",\u000a        findingCount: findings.workflows.length,\u000a        checks: {\u000a          enabledFixtures: smokeEnabled.length,\u000a          structuredOutputGaps: gateCoverageGaps.length,\u000a          loadBearingCount: workflowTypeRows.filter((w) => w.class === "load-bearing").length,\u000a          fixtureOrSmallCount: workflowTypeRows.filter((w) => w.class === "fixture-or-small").length,\u000a        },\u000a        workflowClasses: sample(workflowTypeRows, includeSamples, 20),\u000a        findings: findings.workflows,\u000a      },\u000a      promptsTemplates: {\u000a        goal: "Keep prompt registry, runtime defaults, host guidance, and skill seed blocks aligned.",\u000a        findingCount: findings.promptsTemplates.length,\u000a        checks: {\u000a          codeRegistryEvents: CODE_REGISTRY_EVENTS.length,\u000a          dbOnlyEvents: dbOnlyEvents.length,\u000a          missingDefaultEvents: missingDefaultEvents.length,\u000a          duplicatePromptBodyGroups: duplicatePromptBodies.length,\u000a          staleUrlPrompts: staleUrlPrompts.length,\u000a          contradictoryPrompts: contradictoryPrompts.length,\u000a          systemDefaultSkillDuplicates: systemDefaultSkillDuplicates.length,\u000a        },\u000a        findings: findings.promptsTemplates,\u000a      },\u000a    },\u000a  };\u000a\u000a  if (publishPage) result.page = await publishCatalogReportPage(buildReport(result), ctx);\u000a  return result;\u000a}\u000a'),'Audit-as-code catalog check for schedules, workflows, and prompt/template drift. Clusters actionable findings by goal and can publish an authed HTML report page.','Re-run the ops inventory audit in one call: duplicate/dead schedules, code-work routing risks, enabled workflow fixtures, structured-output gate gaps, prompt registry drift, stale hosts, and systemDefault skill duplicates.','{"argsType":"any","resultType":"unknown","description":"Audit schedules, workflows, and prompt/template catalogs by goal, with optional authed page output."}','a6b5ee6dab67dfdf27e377556697fd12aaa09be60d741d9582b19bc9b8bc651b',NULL,'2026-06-11T22:38:24.395Z','Seeded from the built-in scripts catalog (src/be/seed-scripts)',NULL,NULL);
INSERT INTO script_versions VALUES('e120eadb-6f58-4e4e-ade9-486589ff0e8d','87c25434-456a-46ab-b322-76202af8c577',1,unistr('import { z } from "zod";\u000a\u000aexport const argsSchema = z.object({\u000a  nowIso: z.string().optional().describe("Triage clock override (default: current time)"),\u000a  failureLookbackMinutes: z\u000a    .number()\u000a    .int()\u000a    .positive()\u000a    .optional()\u000a    .describe("Look back this many minutes for real failures (default 60)"),\u000a  stuckMinutes: z\u000a    .number()\u000a    .int()\u000a    .positive()\u000a    .optional()\u000a    .describe("Flag in-progress tasks older than this on offline agents (default 5)"),\u000a  deployWindowMinutes: z\u000a    .number()\u000a    .int()\u000a    .positive()\u000a    .optional()\u000a    .describe("Window around now for merged agent-swarm PRs (default 15)"),\u000a  repo: z\u000a    .string()\u000a    .optional()\u000a    .describe("Optional GitHub repository in ''owner/name'' form for restart/deploy PR detection"),\u000a});\u000a\u000aconst BENIGN_FAILURE_RE = /^(superseded_workflow_task|cancelled|reboot-sweep)$/i;\u000a\u000afunction rowsToObjects(res: any): any[] {\u000a  const p = res?.data ?? res;\u000a  const cols: string[] = p?.columns ?? [];\u000a  return (p?.rows ?? []).map((r: any) =>\u000a    Array.isArray(r) ? Object.fromEntries(cols.map((c, i) => [c, r[i]])) : r,\u000a  );\u000a}\u000a\u000aasync function query(ctx: any, sql: string, params?: unknown[]): Promise<any[]> {\u000a  try {\u000a    return rowsToObjects(await ctx.swarm.db_query({ sql, params }));\u000a  } catch (error) {\u000a    return [{ unavailable: error instanceof Error ? error.message : String(error) }];\u000a  }\u000a}\u000a\u000afunction taskPreview(task: unknown): string {\u000a  return String(task || "").replace(/\\s+/g, " ").trim().slice(0, 180);\u000a}\u000a\u000afunction summarizeTask(row: any): any {\u000a  return {\u000a    id: row.id,\u000a    status: row.status,\u000a    taskType: row.taskType || null,\u000a    agentId: row.agentId || null,\u000a    agentName: row.agentName || null,\u000a    scheduleId: row.scheduleId || null,\u000a    parentTaskId: row.parentTaskId || null,\u000a    failureReason: row.failureReason || null,\u000a    createdAt: row.createdAt,\u000a    lastUpdatedAt: row.lastUpdatedAt,\u000a    taskPreview: taskPreview(row.task),\u000a  };\u000a}\u000a\u000aasync function recentMergedPrs(\u000a  ctx: any,\u000a  repo: string | undefined,\u000a  nowMs: number,\u000a  windowMinutes: number,\u000a): Promise<any> {\u000a  if (!repo) return { skipped: "repo not provided" };\u000a  if (!/^[^/\\s]+\\/[^/\\s]+$/.test(repo)) return { error: "repo must be in ''owner/name'' form" };\u000a\u000a  const windowMs = windowMinutes * 60 * 1000;\u000a  try {\u000a    const response = await ctx.stdlib.fetch(\u000a      "https://api.github.com/repos/" +\u000a        repo +\u000a        "/pulls?state=closed&sort=updated&direction=desc&per_page=20",\u000a      {\u000a        headers: {\u000a          Accept: "application/vnd.github+json",\u000a          "User-Agent": "agent-swarm-boot-triage",\u000a        },\u000a      },\u000a    );\u000a    if (!response.ok) return { error: `GitHub API ${response.status}` };\u000a    const prs = (await response.json()) as any[];\u000a    return prs\u000a      .filter((pr) => pr?.merged_at)\u000a      .map((pr) => {\u000a        const mergedAtMs = Date.parse(pr.merged_at);\u000a        return {\u000a          repo,\u000a          number: pr.number,\u000a          title: pr.title,\u000a          url: pr.html_url,\u000a          mergedAt: pr.merged_at,\u000a          minutesFromRestart: Math.round((mergedAtMs - nowMs) / 60000),\u000a        };\u000a      })\u000a      .filter((pr) => Math.abs(pr.minutesFromRestart * 60000) <= windowMs);\u000a  } catch (error) {\u000a    return { error: error instanceof Error ? error.message : String(error) };\u000a  }\u000a}\u000a\u000a/** Read-only post-restart triage snapshot for the heartbeat.boot-triage prompt. */\u000aexport default async function bootTriage(args: any, ctx: any) {\u000a  const parsed = argsSchema.safeParse(args || {});\u000a  if (!parsed.success) return { error: "invalid args: " + parsed.error.message };\u000a\u000a  const now = parsed.data.nowIso ? new Date(parsed.data.nowIso) : new Date();\u000a  const nowMs = now.getTime();\u000a  const failureLookbackMinutes = parsed.data.failureLookbackMinutes || 60;\u000a  const stuckMinutes = parsed.data.stuckMinutes || 5;\u000a  const deployWindowMinutes = parsed.data.deployWindowMinutes || 15;\u000a  const repo = parsed.data.repo;\u000a\u000a  const mergedPrs = await recentMergedPrs(ctx, repo, nowMs, deployWindowMinutes);\u000a\u000a  const recentFailureRows = await query(\u000a    ctx,\u000a    `SELECT t.id, t.task, t.status, t.taskType, t.agentId, a.name as agentName,\u000a            t.scheduleId, t.parentTaskId, t.failureReason, t.createdAt, t.lastUpdatedAt\u000a     FROM agent_tasks t\u000a     LEFT JOIN agents a ON a.id = t.agentId\u000a     WHERE t.status = ''failed''\u000a       AND datetime(t.lastUpdatedAt) >= datetime(?, ?)\u000a     ORDER BY datetime(t.lastUpdatedAt) DESC\u000a     LIMIT 50`,\u000a    [now.toISOString(), `-${failureLookbackMinutes} minutes`],\u000a  );\u000a  const recentlyFailedTasks = recentFailureRows\u000a    .filter((row) => !row.unavailable)\u000a    .filter((row) => !BENIGN_FAILURE_RE.test(String(row.failureReason || "")))\u000a    .map(summarizeTask);\u000a\u000a  const stuckOfflineRows = await query(\u000a    ctx,\u000a    `SELECT t.id, t.task, t.status, t.taskType, t.agentId, a.name as agentName,\u000a            t.scheduleId, t.parentTaskId, t.failureReason, t.createdAt, t.lastUpdatedAt\u000a     FROM agent_tasks t\u000a     JOIN agents a ON a.id = t.agentId\u000a     WHERE t.status = ''in_progress''\u000a       AND a.status = ''offline''\u000a       AND datetime(t.lastUpdatedAt) <= datetime(?, ?)\u000a     ORDER BY datetime(t.lastUpdatedAt) ASC\u000a     LIMIT 50`,\u000a    [now.toISOString(), `-${stuckMinutes} minutes`],\u000a  );\u000a  const stuckInProgressOnOfflineAgents = stuckOfflineRows\u000a    .filter((row) => !row.unavailable)\u000a    .map(summarizeTask);\u000a\u000a  const orphanRows = await query(\u000a    ctx,\u000a    `SELECT t.id, t.task, t.status, t.taskType, t.agentId, a.name as agentName,\u000a            t.scheduleId, t.parentTaskId, t.failureReason, t.createdAt, t.lastUpdatedAt\u000a     FROM agent_tasks t\u000a     JOIN agents a ON a.id = t.agentId\u000a     WHERE t.status IN (''pending'', ''offered'')\u000a       AND a.status = ''offline''\u000a     ORDER BY datetime(t.lastUpdatedAt) ASC\u000a     LIMIT 50`,\u000a  );\u000a  const orphanedPendingOrOfferedOnOfflineWorkers = orphanRows\u000a    .filter((row) => !row.unavailable)\u000a    .map(summarizeTask);\u000a\u000a  const supersededRows = await query(\u000a    ctx,\u000a    `SELECT p.id, p.task, p.status, p.taskType, p.agentId, a.name as agentName,\u000a            p.scheduleId, p.parentTaskId, p.failureReason, p.createdAt, p.lastUpdatedAt\u000a     FROM agent_tasks p\u000a     LEFT JOIN agents a ON a.id = p.agentId\u000a     WHERE p.status = ''superseded''\u000a       AND datetime(p.lastUpdatedAt) >= datetime(?, ?)\u000a       AND NOT EXISTS (\u000a         SELECT 1\u000a         FROM agent_tasks c\u000a         WHERE c.parentTaskId = p.id\u000a           AND c.taskType = ''resume''\u000a           AND c.status NOT IN (''completed'', ''failed'', ''cancelled'', ''superseded'')\u000a       )\u000a     ORDER BY datetime(p.lastUpdatedAt) DESC\u000a     LIMIT 50`,\u000a    [now.toISOString(), `-${failureLookbackMinutes} minutes`],\u000a  );\u000a  const supersededTasksMissingResumeChild = supersededRows\u000a    .filter((row) => !row.unavailable)\u000a    .map(summarizeTask);\u000a\u000a  return {\u000a    generatedAt: now.toISOString(),\u000a    windows: {\u000a      failureLookbackMinutes,\u000a      stuckMinutes,\u000a      deployWindowMinutes,\u000a    },\u000a    deployRestartDetection: {\u000a      source: repo ? "github:" + repo : null,\u000a      mergedPrsWithinWindow: Array.isArray(mergedPrs) ? mergedPrs : [],\u000a      skipped: Array.isArray(mergedPrs) ? null : mergedPrs.skipped || null,\u000a      error: Array.isArray(mergedPrs) ? null : mergedPrs.error,\u000a    },\u000a    recentlyFailedTasks,\u000a    stuckInProgressOnOfflineAgents,\u000a    orphanedPendingOrOfferedOnOfflineWorkers,\u000a    supersededTasksMissingResumeChild,\u000a    summary: {\u000a      mergedPrsWithinWindow: Array.isArray(mergedPrs) ? mergedPrs.length : 0,\u000a      recentlyFailedTasks: recentlyFailedTasks.length,\u000a      stuckInProgressOnOfflineAgents: stuckInProgressOnOfflineAgents.length,\u000a      orphanedPendingOrOfferedOnOfflineWorkers: orphanedPendingOrOfferedOnOfflineWorkers.length,\u000a      supersededTasksMissingResumeChild: supersededTasksMissingResumeChild.length,\u000a    },\u000a  };\u000a}\u000a'),'Post-restart heartbeat triage snapshot: deploy restart PR context, recent real failures, stuck offline-agent work, orphaned tasks, and superseded tasks missing resume children.','Run immediately after a swarm restart to gather deterministic boot triage data in one read-only call before the Lead decides what to retry, cancel, or escalate.','{"argsType":"any","resultType":"unknown","description":"Read-only post-restart triage snapshot for the heartbeat.boot-triage prompt."}','c5da2e8f9c5283051bafbdb9e367e115cc259d6754c08f63adbd66fef48a15db',NULL,'2026-06-11T22:38:24.520Z','Seeded from the built-in scripts catalog (src/be/seed-scripts)',NULL,NULL);
INSERT INTO script_embeddings VALUES('5a903cc9-8d9d-490c-8178-a1507e5c01a9',X'','openai/text-embedding-3-small',unistr('One-call GitHub pull request snapshot: title, state, draft, mergeable, CI check tallies (passed/failed/pending) and review tallies (approved/changes-requested/pending).\u000aTriage a GitHub PR''s status in a single call instead of running several gh pr view / gh pr checks / gh api invocations.\u000a{"argsType":"any","resultType":"unknown","description":"One-call GitHub PR snapshot: state, draft, mergeable, CI checks and review tallies."}'),'2026-06-11T22:38:24.863Z');
INSERT INTO script_embeddings VALUES('52ce70b3-ab75-4eda-99ff-cd88c43598d6',X'','openai/text-embedding-3-small',unistr('Fetch a web page and extract clean readable article text — strips scripts, styles, nav, headers, footers, ads and HTML tags, and decodes entities.\u000aRead the actual content of a URL without wading through raw HTML; readable-article / reader-mode extraction.\u000a{"argsType":"any","resultType":"unknown","description":"Fetch a web page and return readable article text with nav/ads/boilerplate stripped."}'),'2026-06-11T22:38:25.032Z');
INSERT INTO script_embeddings VALUES('4cf0e0fa-f341-4ebd-aaee-921965e8a2c8',X'','openai/text-embedding-3-small',unistr('Run a jq-style path/filter query over any JSON value: dot fields, [n] indexing, [] iteration, | pipes, and keys/values/length/type functions.\u000aExtract a value from a JSON blob without shelling out to a curl | jq pipeline.\u000a{"argsType":"any","resultType":"unknown","description":"Run a jq-style path/filter query over a JSON value — replaces curl|jq pipelines."}'),'2026-06-11T22:38:25.587Z');
INSERT INTO script_embeddings VALUES('19e282df-8147-4338-99e9-085e2a1152c7',X'','openai/text-embedding-3-small',unistr('Group an array of objects by a field (dotted paths supported), returning per-group counts sorted by frequency plus an optional numeric sum.\u000aAggregate or tally records — counts and sums by category — without writing ad-hoc reduce code.\u000a{"argsType":"any","resultType":"unknown","description":"Group an array of objects by a field, returning per-group count and optional sum."}'),'2026-06-11T22:38:25.728Z');
INSERT INTO script_embeddings VALUES('acfd7980-2422-496b-9085-3297d18753c2',X'','openai/text-embedding-3-small',unistr('Resolve a natural-language date expression (yesterday, last week, Thursday, 7d ago, an ISO date) into an ISO timestamp or a {start,end} range.\u000aTurn fuzzy human date phrases into concrete timestamps for filtering, querying or scheduling.\u000a{"argsType":"any","resultType":"unknown","description":"Resolve a natural date expression to an ISO date or a {start,end} range."}'),'2026-06-11T22:38:25.970Z');
INSERT INTO script_embeddings VALUES('43cca088-38f5-4d7e-977a-10f4d7696cea',X'','openai/text-embedding-3-small',unistr('Compare two strings line-by-line with an LCS diff and return a unified-diff summary plus added/removed/unchanged counts.\u000aSee exactly what changed between two versions of a text, config or document.\u000a{"argsType":"any","resultType":"unknown","description":"Compare two strings line-by-line and return a unified-diff summary."}'),'2026-06-11T22:38:26.122Z');
INSERT INTO script_embeddings VALUES('72d3122e-4c96-489f-9787-baac5b3f5dc0',X'','openai/text-embedding-3-small',unistr('Scan recently failed swarm tasks and cluster them by failure reason, agent or schedule to surface recurring problems.\u000aFind patterns in swarm task failures — which agent, schedule or error keeps breaking — for a reliability review.\u000a{"argsType":"any","resultType":"unknown","description":"Cluster recently failed swarm tasks by reason, agent, or schedule."}'),'2026-06-11T22:38:26.252Z');
INSERT INTO script_embeddings VALUES('fcf1bed5-7b3c-4de3-8f26-e46b50bee551',X'','openai/text-embedding-3-small',unistr('Semantic-search existing swarm memories for near-duplicates of a candidate text and report matches above a similarity threshold.\u000aAvoid writing a redundant memory — check whether something equivalent is already stored before saving.\u000a{"argsType":"any","resultType":"unknown","description":"Semantic-search existing memories and flag near-duplicates before you save a new one."}'),'2026-06-11T22:38:26.502Z');
INSERT INTO script_embeddings VALUES('ff9b7185-e466-4885-82df-49827905d6de',X'','openai/text-embedding-3-small',unistr('Fetch a Slack thread by channel + thread timestamp and flatten it into a readable chronological transcript.\u000aTurn a Slack thread into plain text for summarizing or as task context.\u000a{"argsType":"any","resultType":"unknown","description":"Flatten a Slack thread into a readable, chronological transcript."}'),'2026-06-11T22:38:26.735Z');
INSERT INTO script_embeddings VALUES('972543be-a0f9-434a-b5d0-7945b0dcf021',X'','openai/text-embedding-3-small',unistr('Multi-query fan-out memory search with dedup and composite reranking (bestSimilarity + 0.05 * hitCount). Returns unique memories across all queries.\u000aRecall relevant memories using multiple search angles — better coverage than a single query. Use for task onboarding, context gathering, or before writing new memories.\u000a{"argsType":"any","resultType":"unknown","description":"Multi-query fan-out memory recall with dedup and composite reranking."}'),'2026-06-11T22:38:26.894Z');
INSERT INTO script_embeddings VALUES('3898797c-96df-4f19-90a7-a5f2ac203eed',X'','openai/text-embedding-3-small',unistr('Get task details and recall relevant memories in one call — returns a slimmed task projection plus deduped and reranked memories from multi-query fan-out.\u000aTask onboarding: one call instead of task_get plus multiple memory_search calls. Pass the task description split into 2-4 natural-language queries.\u000a{"argsType":"any","resultType":"unknown","description":"Fetch slim task details plus deduped multi-query memories for task onboarding."}'),'2026-06-11T22:38:27.042Z');
INSERT INTO script_embeddings VALUES('b2d83689-526a-423e-a45f-f4fb48fd2e2a',X'','openai/text-embedding-3-small',unistr('Per-schedule failure rate check over recent tasks — flags schedules with failure rates above a configurable threshold.\u000aFind unhealthy schedules that keep failing — for daily compounding, reliability reviews, or ops triage.\u000a{"argsType":"any","resultType":"unknown","description":"Per-schedule health check: failure rates and flagging unhealthy schedules."}'),'2026-06-11T22:38:27.192Z');
INSERT INTO script_embeddings VALUES('bb3189d0-d123-4443-8f1c-f07ff75a292f',X'','openai/text-embedding-3-small',unistr('Tool usage histogram from session_logs — top tools by call count over a time window, optionally filtered by agent.\u000aSee which MCP tools agents use most — for SDK gap analysis, optimization, or daily ops snapshots.\u000a{"argsType":"any","resultType":"unknown","description":"Tool usage histogram from session_logs — top tools by call count."}'),'2026-06-11T22:38:27.397Z');
INSERT INTO script_embeddings VALUES('82d56dac-c9d1-423c-b2ff-b1559bf24fa8',X'','openai/text-embedding-3-small',unistr('All-in-one swarm-wide daily ops snapshot: task completion/failure summary, real failure clusters (excludes superseded/cancelled bookkeeping), schedule health flags, tool usage top-25, memory health/pollution stats, seed-script candidate tool triplets, and a per-agent breakdown. Aggregates across ALL agents via direct read-only SQL.\u000aSingle-call daily compounding Phase 0 helper — replaces ~25 raw tool roundtrips with one compressed JSON result covering every agent. For daily evolution, self-scripting candidates, ops reviews, or heartbeat context.\u000a{"argsType":"any","resultType":"unknown","description":"Daily compounding insights — compressed JSON for Phase 0 evolution.\\n\\nSwarm-wide by design: every section aggregates across ALL agents via direct\\nread-only SQL (no per-agent scoping), so a single call replaces ~25 raw tool\\nroundtrips. Parametric via `days` + the `include*` flags."}'),'2026-06-11T22:38:27.550Z');
INSERT INTO script_embeddings VALUES('185a38f0-a97f-493f-9bbd-e5636bc7d814',X'','openai/text-embedding-3-small',unistr('3-axis memory quality evaluation: carry-forward context (do follow-up tasks retrieve useful memories from prior tasks?), follow preferences (are CLAUDE.md/IDENTITY.md/SOUL.md/TOOLS.md memories retrieved and useful?), and stay current (what fraction of retrieved memories are fresh vs stale?). Outputs a baseline report to agent-fs + a swarm Page.\u000aMeasure memory system health across OpenAI Dreaming-inspired axes — before/after baseline for architecture changes, blog-post numbers, daily quality monitoring.\u000a{"argsType":"any","resultType":"unknown","description":"3-axis memory quality evaluation with over-time trend tracking and KV-backed historical backfill."}'),'2026-06-11T22:38:27.716Z');
INSERT INTO script_embeddings VALUES('166dea9e-4f94-4eb4-b02e-b51e6921dc9c',X'','openai/text-embedding-3-small',unistr('Audit-as-code catalog check for schedules, workflows, and prompt/template drift. Clusters actionable findings by goal and can publish an authed HTML report page.\u000aRe-run the ops inventory audit in one call: duplicate/dead schedules, code-work routing risks, enabled workflow fixtures, structured-output gate gaps, prompt registry drift, stale hosts, and systemDefault skill duplicates.\u000a{"argsType":"any","resultType":"unknown","description":"Audit schedules, workflows, and prompt/template catalogs by goal, with optional authed page output."}'),'2026-06-11T22:38:27.930Z');
INSERT INTO script_embeddings VALUES('87c25434-456a-46ab-b322-76202af8c577',X'','openai/text-embedding-3-small',unistr('Post-restart heartbeat triage snapshot: deploy restart PR context, recent real failures, stuck offline-agent work, orphaned tasks, and superseded tasks missing resume children.\u000aRun immediately after a swarm restart to gather deterministic boot triage data in one read-only call before the Lead decides what to retry, cancel, or escalate.\u000a{"argsType":"any","resultType":"unknown","description":"Read-only post-restart triage snapshot for the heartbeat.boot-triage prompt."}'),'2026-06-11T22:38:28.085Z');
